-- ----------------------------
-- Table structure for gb_article_games
-- ----------------------------
DROP TABLE IF EXISTS `gb_article_games`;
CREATE TABLE `gb_article_games`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `article_id` bigint NOT NULL COMMENT '文章ID',
  `game_id` bigint NOT NULL COMMENT '游戏ID',
  `relation_source` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'manual' COMMENT '关联来源：manual-人工手动 ai-AI自动 import-批量导入 sync-同步',
  `relation_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'primary' COMMENT '关联类型：primary-主要关联 secondary-次要关联 related-相关推荐 mention-提及',
  `display_order` int NULL DEFAULT 1 COMMENT '显示顺序（用于模板变量排序，1=第一个）',
  `confidence_score` decimal(6, 4) NULL DEFAULT NULL COMMENT 'AI关联置信度（0.0000-1.0000）',
  `ai_platform_id` bigint NULL DEFAULT NULL COMMENT 'AI平台ID',
  `ai_reasoning` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT 'AI关联推理说明',
  `ai_metadata` json NULL COMMENT 'AI关联元数据（JSON格式）',
  `review_status` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '1' COMMENT '审核状态：0-待审核 1-已通过 2-已拒绝',
  `reviewed_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '审核人',
  `reviewed_at` datetime NULL DEFAULT NULL COMMENT '审核时间',
  `review_notes` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '审核备注',
  `is_featured` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '0' COMMENT '是否推荐展示：0-否 1-是',
  `click_count` int NULL DEFAULT 0 COMMENT '点击次数',
  `last_used_at` datetime NULL DEFAULT NULL COMMENT '最后使用时间',
  `del_flag` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '0' COMMENT '删除标志：0-存在 2-删除',
  `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' COMMENT '创建者',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' COMMENT '更新者',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '备注',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_article_game`(`article_id` ASC, `game_id` ASC) USING BTREE,
  INDEX `idx_article_id`(`article_id` ASC) USING BTREE,
  INDEX `idx_game_id`(`game_id` ASC) USING BTREE,
  INDEX `idx_relation_source`(`relation_source` ASC) USING BTREE,
  INDEX `idx_relation_type`(`relation_type` ASC) USING BTREE,
  INDEX `idx_review_status`(`review_status` ASC) USING BTREE,
  INDEX `idx_confidence_score`(`confidence_score` DESC) USING BTREE,
  INDEX `idx_ai_platform`(`ai_platform_id` ASC) USING BTREE,
  INDEX `idx_display_order`(`article_id` ASC, `display_order` ASC) USING BTREE,
  INDEX `idx_del_flag`(`del_flag` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 80 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '文章-游戏关联表 v2.0' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of gb_article_games
-- ----------------------------

-- ----------------------------
-- Table structure for gb_article_generations
-- ----------------------------
DROP TABLE IF EXISTS `gb_article_generations`;
CREATE TABLE `gb_article_generations`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `article_id` bigint NULL DEFAULT NULL COMMENT '文章ID',
  `site_id` bigint NOT NULL COMMENT '网站ID',
  `ai_platform_id` bigint NOT NULL COMMENT 'AI平台ID',
  `prompt_template_id` bigint NULL DEFAULT NULL COMMENT '提示词模板ID',
  `model_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '使用的模型',
  `prompt_content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '实际提示词内容',
  `generation_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'single' COMMENT '生成类型：single-单篇 batch-批量',
  `batch_task_id` bigint NULL DEFAULT NULL COMMENT '批量任务ID',
  `locale` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'zh-CN' COMMENT '生成语言',
  `generation_status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'pending' COMMENT '状态：pending-待执行 running-执行中 completed-已完成 failed-失败',
  `generated_title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '生成的标题',
  `generated_content` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '生成的内容',
  `input_tokens` int NULL DEFAULT 0 COMMENT '输入Token数',
  `output_tokens` int NULL DEFAULT 0 COMMENT '输出Token数',
  `total_cost` decimal(10, 6) NULL DEFAULT 0.000000 COMMENT '总消耗费用',
  `generation_time` int NULL DEFAULT 0 COMMENT '生成耗时（秒）',
  `error_message` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '错误信息',
  `quality_score` decimal(3, 2) NULL DEFAULT NULL COMMENT '质量评分',
  `github_run_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'GitHub Action Run ID',
  `github_run_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'GitHub Action Run URL',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_article_id`(`article_id` ASC) USING BTREE,
  INDEX `idx_site_id`(`site_id` ASC) USING BTREE,
  INDEX `idx_ai_platform`(`ai_platform_id` ASC) USING BTREE,
  INDEX `idx_batch_task`(`batch_task_id` ASC) USING BTREE,
  INDEX `idx_generation_status`(`generation_status` ASC) USING BTREE,
  INDEX `idx_create_time`(`create_time` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '文章生成记录表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of gb_article_generations
-- ----------------------------

-- ----------------------------
-- Table structure for gb_article_homepage_binding
-- ----------------------------
DROP TABLE IF EXISTS `gb_article_homepage_binding`;
CREATE TABLE `gb_article_homepage_binding`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `article_id` bigint NOT NULL COMMENT '文章ID',
  `game_id` bigint NULL DEFAULT NULL COMMENT '游戏ID（与game_box_id二选一）',
  `game_box_id` bigint NULL DEFAULT NULL COMMENT '游戏盒子ID（与game_id二选一）',
  `homepage_locale` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '主页语言代码（如：en, zh-CN, ja）',
  `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '创建者',
  `create_time` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '更新者',
  `update_time` datetime NULL DEFAULT NULL COMMENT '更新时间',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '备注',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_article_homepage`(`article_id` ASC, `homepage_locale` ASC) USING BTREE,
  UNIQUE INDEX `uk_game_homepage`(`game_id` ASC, `homepage_locale` ASC) USING BTREE,
  UNIQUE INDEX `uk_gamebox_homepage`(`game_box_id` ASC, `homepage_locale` ASC) USING BTREE,
  INDEX `idx_article_id`(`article_id` ASC) USING BTREE,
  INDEX `idx_game_id`(`game_id` ASC) USING BTREE,
  INDEX `idx_game_box_id`(`game_box_id` ASC) USING BTREE,
  INDEX `idx_homepage_locale`(`homepage_locale` ASC) USING BTREE,
  CONSTRAINT `chk_binding_target` CHECK (((`game_id` is not null) and (`game_box_id` is null)) or ((`game_id` is null) and (`game_box_id` is not null)))
) ENGINE = InnoDB AUTO_INCREMENT = 20 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '文章主页绑定表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of gb_article_homepage_binding
-- ----------------------------

-- ----------------------------
-- Table structure for gb_article_product_relations
-- ----------------------------
DROP TABLE IF EXISTS `gb_article_product_relations`;
CREATE TABLE `gb_article_product_relations`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `article_id` bigint NOT NULL COMMENT '文章ID',
  `product_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '产品类型：game-游戏 game_box-游戏盒子 drama-短剧',
  `product_id` bigint NOT NULL COMMENT '产品ID',
  `relation_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'auto' COMMENT '关联类型：auto-自动 manual-手动',
  `relevance_score` decimal(5, 4) NULL DEFAULT 0.0000 COMMENT '相关度评分',
  `is_primary` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '0' COMMENT '是否主关联：0-否 1-是',
  `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' COMMENT '创建者',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_article_product`(`article_id` ASC, `product_type` ASC, `product_id` ASC) USING BTREE,
  INDEX `idx_article_id`(`article_id` ASC) USING BTREE,
  INDEX `idx_product`(`product_type` ASC, `product_id` ASC) USING BTREE,
  INDEX `idx_relevance`(`relevance_score` DESC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '文章产品关联表' ROW_FORMAT = DYNAMIC;

