-- ----------------------------
-- View structure for v_ai_drama_relations_pending
-- ----------------------------
DROP VIEW IF EXISTS `v_ai_drama_relations_pending`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `v_ai_drama_relations_pending` AS select `ad`.`id` AS `id`,`ad`.`article_id` AS `article_id`,`a`.`title` AS `article_title`,`ad`.`drama_id` AS `drama_id`,`d`.`name` AS `drama_name`,`ad`.`confidence_score` AS `confidence_score`,`ad`.`ai_reasoning` AS `ai_reasoning`,`ad`.`create_time` AS `create_time` from ((`gb_article_dramas` `ad` left join `gb_articles` `a` on((`ad`.`article_id` = `a`.`id`))) left join `gb_dramas` `d` on((`ad`.`drama_id` = `d`.`id`))) where ((`ad`.`relation_source` = 'ai') and (`ad`.`review_status` = '0'));

-- ----------------------------
-- View structure for v_ai_game_relations_pending
-- ----------------------------
DROP VIEW IF EXISTS `v_ai_game_relations_pending`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `v_ai_game_relations_pending` AS select `ag`.`id` AS `id`,`ag`.`article_id` AS `article_id`,`a`.`title` AS `article_title`,`ag`.`game_id` AS `game_id`,`g`.`name` AS `game_name`,`ag`.`confidence_score` AS `confidence_score`,`ag`.`ai_reasoning` AS `ai_reasoning`,`ag`.`create_time` AS `create_time` from ((`gb_article_games` `ag` left join `gb_articles` `a` on((`ag`.`article_id` = `a`.`id`))) left join `gb_games` `g` on((`ag`.`game_id` = `g`.`id`))) where ((`ag`.`relation_source` = 'ai') and (`ag`.`review_status` = '0'));

-- ----------------------------
-- View structure for v_ai_gamebox_relations_pending
-- ----------------------------
DROP VIEW IF EXISTS `v_ai_gamebox_relations_pending`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `v_ai_gamebox_relations_pending` AS select `agb`.`id` AS `id`,`agb`.`article_id` AS `article_id`,`a`.`title` AS `article_title`,`agb`.`game_box_id` AS `game_box_id`,`gb`.`name` AS `gamebox_name`,`agb`.`confidence_score` AS `confidence_score`,`agb`.`ai_reasoning` AS `ai_reasoning`,`agb`.`create_time` AS `create_time` from ((`gb_article_game_boxes` `agb` left join `gb_articles` `a` on((`agb`.`article_id` = `a`.`id`))) left join `gb_game_boxes` `gb` on((`agb`.`game_box_id` = `gb`.`id`))) where ((`agb`.`relation_source` = 'ai') and (`agb`.`review_status` = '0'));

-- ----------------------------
-- View structure for v_ai_relations_statistics
-- ----------------------------
DROP VIEW IF EXISTS `v_ai_relations_statistics`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `v_ai_relations_statistics` AS select 'game' AS `product_type`,count(0) AS `total`,sum((case when (`gb_article_games`.`review_status` = '0') then 1 else 0 end)) AS `pending`,sum((case when (`gb_article_games`.`review_status` = '1') then 1 else 0 end)) AS `approved`,avg(`gb_article_games`.`confidence_score`) AS `avg_confidence` from `gb_article_games` where (`gb_article_games`.`relation_source` = 'ai') union all select 'gamebox' AS `gamebox`,count(0) AS `COUNT(*)`,sum((case when (`gb_article_game_boxes`.`review_status` = '0') then 1 else 0 end)) AS `SUM(CASE WHEN review_status='0' THEN 1 ELSE 0 END)`,sum((case when (`gb_article_game_boxes`.`review_status` = '1') then 1 else 0 end)) AS `SUM(CASE WHEN review_status='1' THEN 1 ELSE 0 END)`,avg(`gb_article_game_boxes`.`confidence_score`) AS `AVG(confidence_score)` from `gb_article_game_boxes` where (`gb_article_game_boxes`.`relation_source` = 'ai') union all select 'drama' AS `drama`,count(0) AS `COUNT(*)`,sum((case when (`gb_article_dramas`.`review_status` = '0') then 1 else 0 end)) AS `SUM(CASE WHEN review_status='0' THEN 1 ELSE 0 END)`,sum((case when (`gb_article_dramas`.`review_status` = '1') then 1 else 0 end)) AS `SUM(CASE WHEN review_status='1' THEN 1 ELSE 0 END)`,avg(`gb_article_dramas`.`confidence_score`) AS `AVG(confidence_score)` from `gb_article_dramas` where (`gb_article_dramas`.`relation_source` = 'ai');

-- ----------------------------
-- Procedure structure for sp_cleanup_old_articles_content
-- ----------------------------
DROP PROCEDURE IF EXISTS `sp_cleanup_old_articles_content`;
delimiter ;;
CREATE PROCEDURE `sp_cleanup_old_articles_content`(IN cleanup_days INT)
BEGIN
    DECLARE cleaned_count INT DEFAULT 0;
    
    -- 清理超过保留期的已发布文章内容
    UPDATE gb_articles 
    SET content = NULL
    WHERE 
        is_published = '1'
        AND published_at IS NOT NULL
        AND DATEDIFF(NOW(), published_at) > cleanup_days
        AND content IS NOT NULL
        AND storage_key IS NOT NULL;
    
    SET cleaned_count = ROW_COUNT();
    
    -- 记录清理日志到临时表（可选）
    VALUES (
        '文章内容清理',
        9,  -- 其他操作
        'sp_cleanup_old_articles_content',
        'SCHEDULED',
        1,  -- 后台用户
        'system',
        NOW(),
        0   -- 成功
    );
    
    -- 返回清理结果
    SELECT CONCAT('已清理 ', cleaned_count, ' 篇文章的 content 字段') AS result;
    
    -- 优化表（回收空间）
    OPTIMIZE TABLE gb_articles;
END
;;
delimiter ;

-- ----------------------------
-- Event structure for evt_cleanup_old_articles
-- ----------------------------
DROP EVENT IF EXISTS `evt_cleanup_old_articles`;
delimiter ;;
CREATE EVENT `evt_cleanup_old_articles`
ON SCHEDULE
EVERY '1' DAY STARTS '2025-12-25 02:00:00'
ON COMPLETION PRESERVE
COMMENT '定时清理旧文章content字段，保留30天内的文章内容'
DO CALL sp_cleanup_old_articles_content(30)
;;
delimiter ;

SET FOREIGN_KEY_CHECKS = 1;
