INSERT INTO `gb_games` VALUES (25, 1, 3, '漫画英雄3D（0.05折次元乱斗）', '1、0.05折次元动漫大集结\r\n2、升级登录送千抽，连续登录送樱花时装\r\n3、创角送路飞（霸王色），红色装备套装\r\n4、签到送万元代金券，珍稀材料\r\n5、丰富战令，高招、金币、经验、钻石送不停', NULL, '卡牌', 'official', 'https://cp.u2game99.com/storage/operator/20251021/be33199deb6b22fb228d91a8b8a495d0.png', 'https://cp.u2game99.com/storage/operator/20251021/3bac64da81e363d05cee52f41a2ba59b.jpg', '[\"https://cp.u2game99.com/storage/operator/20251021/543c16bee9d8701843614d8e52d84f8c.jpg\", \"https://cp.u2game99.com/storage/operator/20251021/081c2685352ffe49534004c15d133d8f.jpg\", \"https://cp.u2game99.com/storage/operator/20251021/864f3cb5ee7ea5ae61e41bb15d0ba790.jpg\", \"https://cp.u2game99.com/storage/operator/20251021/c699c07cd19408a3328160db028108b2.jpg\", \"https://cp.u2game99.com/storage/operator/20251021/c660e9780856d4a73f199f025cb45beb.jpg\"]', 'https://mp4.277sy.com/sp/13886.mp4', '《漫画英雄3D（0.05折次元乱斗）》是一款颠覆传统的横版卡牌手游，集结《海贼王》《鬼灭之刃》《火影忍者》《进击的巨人》《死神》等超多顶流动漫的经典角色，打破次元壁垒，打造史诗级跨作品联动战场！在这里，路飞与佐助并肩作战，炭治郎携手祢豆子对抗巨人，黑崎一护与五条悟展开灵力对决……所有不可能的梦幻组合，皆由你亲手缔造！', '0.05折全次元动漫大乱斗', NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1500', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1500', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1500', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1500', 'both', NULL, 0.50, 0.30, 0.30, 0.50, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-10-17 14:35:31', '1', '0', '0', 0, '1', '2', 'admin', '2025-12-26 07:39:49', 'admin', '2025-12-26 09:49:14', '导入数据：{\"id\":1500,\"addtime\":\"2025-10-17 14:35:31\",\"updatetime\":\"2025-10-29 09:00:00\"}');
INSERT INTO `gb_games` VALUES (26, 1, NULL, '刃境', '上线超值豪礼送不停！', NULL, '角色扮演', 'official', 'https://cp.u2game99.com/storage/operator/20251028/5a41193955978508bb385b4eaea13e2f.png', 'https://cp.u2game99.com/storage/operator/20251028/ff81c426d88c09939d1a55f219275a41.jpg', '[\"https://cp.u2game99.com/storage/operator/20251028/540053a2e71ca309ffbba1d0474da8ca.jpg\", \"https://cp.u2game99.com/storage/operator/20251028/3307aaf015c33dddedc5058f74d22590.png\", \"https://cp.u2game99.com/storage/operator/20251028/777fc465696c868e99b47d6e4a929250.jpg\", \"https://cp.u2game99.com/storage/operator/20251028/2366804492d9ebca3f8e9f0bbf02d5b7.jpg\", \"https://cp.u2game99.com/storage/operator/20251028/52c56cddb1ac7792e9168e8a458cb5ae.jpg\"]', 'https://mp4.277sy.com/sp/13911.mp4', '《刃境》是一款 俯视角硬核动作游戏，结合了肉鸽与装备构筑玩法，支持多人联机和自由交易的冒险游戏。拉上你的小伙伴一起踏入神秘莫测的魔界。\n在这个充满未知与挑战的世界，你将扮演一位勇敢无畏的人类。意外闯入魔界后，幸运地获得刃神认可，从而能够掌控各种强大神秘的刃。通过巧妙组合装备词条以及 Roguelike 的局内养成元素，你可以塑造出独一无二的战斗套路，实现从初出茅庐的新手到魔界纵横捭阖的传奇英雄的华丽转变。', '你将作为初入异世界的冒险者参与到抵抗魔王的恢弘史诗中！', NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1524', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1524', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1524', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1524', 'android', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-10-24 15:27:45', '1', '0', '0', 0, '1', '2', 'admin', '2025-12-26 07:39:49', '', '2025-12-26 09:49:14', '导入数据：{\"id\":1524,\"addtime\":\"2025-10-24 15:27:45\",\"updatetime\":\"2025-10-29 10:00:00\"}');
INSERT INTO `gb_games` VALUES (27, 1, NULL, '刃境', NULL, NULL, '角色扮演', 'official', 'https://cp.u2game99.com/storage/operator/20251028/5a41193955978508bb385b4eaea13e2f.png', 'https://cp.u2game99.com/storage/operator/20251028/ff81c426d88c09939d1a55f219275a41.jpg', '[\"https://cp.u2game99.com/storage/operator/20251028/540053a2e71ca309ffbba1d0474da8ca.jpg\", \"https://cp.u2game99.com/storage/operator/20251028/3307aaf015c33dddedc5058f74d22590.png\", \"https://cp.u2game99.com/storage/operator/20251028/777fc465696c868e99b47d6e4a929250.jpg\", \"https://cp.u2game99.com/storage/operator/20251028/2366804492d9ebca3f8e9f0bbf02d5b7.jpg\", \"https://cp.u2game99.com/storage/operator/20251028/52c56cddb1ac7792e9168e8a458cb5ae.jpg\"]', 'https://mp4.277sy.com/sp/13911.mp4', '《刃境》是一款 俯视角硬核动作游戏，结合了肉鸽与装备构筑玩法，支持多人联机和自由交易的冒险游戏。拉上你的小伙伴一起踏入神秘莫测的魔界。\n在这个充满未知与挑战的世界，你将扮演一位勇敢无畏的人类。意外闯入魔界后，幸运地获得刃神认可，从而能够掌控各种强大神秘的刃。通过巧妙组合装备词条以及 Roguelike 的局内养成元素，你可以塑造出独一无二的战斗套路，实现从初出茅庐的新手到魔界纵横捭阖的传奇英雄的华丽转变。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1524', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1524', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1524', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1524', 'android', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-10-24 15:27:45', '1', '0', '0', 0, '1', '2', 'admin', '2025-12-26 08:16:15', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"你将作为初入异世界的冒险者参与到抵抗魔王的恢弘史诗中！\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13911.mp4\",\"text_cps\":\"\",\"new\":1,\"yuyue\":0,\"gametype\":\"角色扮演\",\"addtime\":\"2025-10-24 15:27:45\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:0\",\"hw_cps_cpa\":\"CPS推广:20\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20251028/5a41193955978508bb385b4eaea13e2f.png\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1524\",\"qrcode\"