INSERT INTO `gb_games` VALUES (54, 1, NULL, '云上大陆（0.1折云上怀旧版）', NULL, NULL, '冒险', 'discount', 'https://www.u2game99.com/data/upload/game/20251225/694c9f580c4b3.gif', 'https://www.u2game99.com/data/upload/game/20251211/693a88d3243d0.jpg', '[\"https://cp.u2game99.com/storage/operator/20251212/8bc547c527ca75d43b048437450d4ff9.jpg\", \"https://cp.u2game99.com/storage/operator/20251212/37e4e8d7f3b38b199474dcd424e8f6be.jpg\", \"https://cp.u2game99.com/storage/operator/20251212/eaee18a8304fdc9251acf7a22f61adac.jpg\", \"https://cp.u2game99.com/storage/operator/20251212/751102b360bdc0ec444ea67c3a97c11c.jpg\", \"https://cp.u2game99.com/storage/operator/20251212/08ce01535633a02026e44ea49c744c59.jpg\"]', 'https://mp4.277sy.com/sp/13833.mp4', '《云上大陆》是一款奇幻世界冒险题材的3D放置挂机RPG手游；在这个遥远星系的云上大陆，玩家将扮演一名冒险者，在俄刻阿诺斯之神的庇护下，一路探险来到了欧斯之城，加入冒险者公会与智慧高超的矮人族、身手敏捷的精灵族一起并肩作战，抵御邪恶龙族和强大兽人族的入侵、通过欧斯勇者竞技场层层选拔、驯服幼龙、收服坐骑，完成勇者试炼，接受女神的“英雄王者”授勋，成为云上大陆的守护者，守护云上大陆和平！', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1449', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1449', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1449', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1449', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-09-22 17:12:04', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:39', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"云上大陆怀旧版，异世界休闲冒险放置RPG\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13833.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"冒险\",\"addtime\":\"2025-09-22 17:12:04\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://www.u2game99.com/data/upload/game/20251225/694c9f580c4b3.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1449\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/1449.html\",\"weburl_qr\":\"[base64已省略]\",\"dwzdownurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1449\",\"downurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1449\",\"dwzdownurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1449\",\"gamename\":\"云上大陆（0.1折云上怀旧版）\",\"excerpt\":\"《云上大陆》是一款奇幻世界冒险题材的3D放置挂机RPG手游；在这个遥远星系的云上大陆，玩家将扮演一名冒险者，在俄刻阿诺斯之神的庇护下，一路探险来到了欧斯之城，加入冒险者公会与智慧高超的矮人族、身手敏捷的精灵族一起并肩作战，抵御邪恶龙族和强大兽人族的入侵、通过欧斯勇者竞技场层层选拔、驯服幼龙、收服坐骑，完成勇者试炼，接受女神的“英雄王者”授勋，成为云上大陆的守护者，守护云上大陆和平！\",\"id\":1449,\"game_source\":\"\",\"device_type\":2,\"edition\":1,\"pic_xuanchuan\":\"\",\"strict\":0,\"userfc\":0,\"updatetime\":\"2025-12-25 08:00:00\",\"box_content\":\"★上线秒送超级豪礼 — 登录即送2000元真充卡，搭配神级坐骑【战斗鸡】，轻轻松松就能领先全场！\\r\\n★ 活跃即有超强助力 — 完成目标任务即可领取极品SP套装，战力瞬间狂飙，推图打BOSS都不在话下！\\r\\n★ 创新玩法震撼登场 — 全新【万能魔球】，一次存钻石，每天都能产出海量利息，让钻石翻倍增长，从此不怕缺资源！\\r\\n★ 豪华奖励天天爆 — 活跃可为魔球充能，每天都有海量幻化抽奖机会，炫酷外观轻松入手！\\r\\n★ 副本爆率全面拉满 — BOSS、副本掉落大幅提升，满星装备随便刷，更有真充卡、魔法币疯狂掉落，极品幻化触手可及！\\r\\n★ 推主线送万抽大奖 — 每闯一关就能轻松领取奖励，累计送出10000抽+神坛券，万抽豪礼直接白嫖！\\r\\n★ 七日狂欢绝版直送 — 登录就送【魔龙·风龙神】，第六天即可集齐炫彩龙神套装，第七天更送绝版时装，全服稀有，独此一家！\\r\\n\",\"pic2\":\"https://www.u2game99.com/data/upload/game/20251211/693a88d3243d0.jpg\",\"pic3\":\"https://www.u2game99.com/data/upload/game/20251211/693a88d9b3f95.jpg\",\"pic4\":\"https://www.u2game99.com/data/upload/game/20251211/693a88e102873.jpg\",\"cps_ratio\":0,\"hw_ratio\":0,\"hw_firstpay\":0.01,\"hw_otherpay\":0.01,\"firstpay\":0.01,\"otherpay\":0.01}');
INSERT INTO `gb_games` VALUES (55, 1, NULL, '天灵诀(0.05折免单江湖)', NULL, NULL, '挂机', 'discount', 'https://cp.u2game99.com/storage/operator/20251222/0581b279da42a92924fac8ede911e15f.gif', 'https://cp.u2game99.com/storage/operator/20251222/6011b8adc61f59096ae698e7df4b4b49.jpg', '[\"https://cp.u2game99.com/storage/operator/20251222/cc289fdde9b9097e9fd9a97759381b8b.jpg\", \"https://cp.u2game99.com/storage/operator/20251222/190427c8083c6049747b9250abe5d0a4.jpg\", \"https://cp.u2game99.com/storage/operator/20251222/3ea4d66fb176e06da4974284e0fce1cb.jpg\", \"https://cp.u2game99.com/storage/operator/20251222/b07d99e0583a31bff8f25cc836c1fae3.jpg\", \"https://cp.u2game99.com/storage/operator/20251222/c4117cff457c5264d7579bb03b4d0c53.jpg\"]', 'https://mp4.277sy.com/sp/14119.mp4', '何为江湖，此题似三岁孩童间嬉闹时的玩笑，似学宫知府千年也难解之谜，江湖的本质，是形形色色的侠义肝胆还是毒爪利刺间的尔虞我诈，平平凡凡的无名小卒，又有何等能耐可知这天地中的千变万化，当踏入江湖之中，深陷其中，抽丝剥茧的武道绝门，仿佛一息之功汇于一念，江湖的险境，是试金石，是验型镜，只有遵从本心之人，方可得以尚存，若是不知其责之重，怎可称为侠字，以人为本，念人为心，因为有人的地方，就有江湖，江湖数载无捷达，自有侠客行天下。\r\n漫漫武侠路，一念入江湖！江湖群雄武侠挂机手游横空出世！\r\n大侠，请听我言~~~~\r\n你本是芸芸众生之中的无名小卒，你的儿时梦想，将会是你豪侠之路的开始！', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1715', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1715', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1715', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1715', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-12-16 15:16:12', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:39', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"绝世武侠开箱，挂机出大侠\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/14119.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"挂机\",\"addtime\":\"2025-12-16 15:16:12\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20251222/0581b279da42a92924fac8ede911e15f.gif\",\"version\":0,\"c_version\