INSERT INTO `gb_games` VALUES (57, 1, NULL, '风暴迷城（0.05折送不限时代金）', NULL, NULL, '卡牌', 'discount', 'https://cp.u2game99.com/storage/operator/20251218/4a8da09b6f7bfbc72a2f26ae917b2693.gif', 'https://cp.u2game99.com/storage/operator/20251218/212be536cfb5387f6e9e3b0eb3fe7e23.jpg', '[\"https://cp.u2game99.com/storage/operator/20251218/3a4289b8f26541558a868d382d9ea318.jpg\", \"https://cp.u2game99.com/storage/operator/20251218/71a27ce9f3328b732d59fd6898581c83.jpg\", \"https://cp.u2game99.com/storage/operator/20251218/d847d461b2b9974a1356101689510977.jpg\", \"https://cp.u2game99.com/storage/operator/20251218/cb9e8f7e935f4f2ddd4c94eb9f58ff73.jpg\", \"https://cp.u2game99.com/storage/operator/20251218/38067b05283424dda234735fa49f13dd.jpg\"]', 'https://mp4.277sy.com/sp/14097.mp4', '《风暴迷城》是一款国风系、泛二次元、现代反穿越神话题材的概念范畴的回合制放置挂机卡牌游戏，《风暴迷城》的世界观中讲述了封神时代结束后各个界域被结界屏障封闭，使得各大界域无法流通，为了争夺灵气的故事。\r\n随着时间的推移各个界域内的灵气逐渐减少，导致法力受到严重的削弱，经历了漫长的灵气寂灭时代后结界开始松动，也逐渐可以穿越结界通往其他界域，不知何时界域中出现了传闻说凡间众生的信仰之力是界域灵气复苏的资源。\r\n人间因为信仰之力早已进入灵气再次复苏的时代，此时凡间已经到了21世纪，人间科技的飞速发展使神话时代在人间的影响力已经荡然无存。面对如此形势，部分神灵们选择接受人间的管理，以此换取在人间获取信仰供奉的许可，还有一部分神灵不愿意接受管理偷偷藏匿在人间，为了管理神灵和灵能相关事务和技术开发，由人神合作创办的集团公司，公司主要业务为开发灵能科技和驱除因灵气所滋生的祟魔。公司下辖的“御灵使”负责处理所有灵能相关事务。\r\n主角在机缘巧合下加入了“御灵使”负责处理灵能相关事务，在维护平衡和对抗邪恶途中发生的一系列冒险故事。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1696', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1696', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1696', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1696', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-12-10 11:10:14', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:39', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"永久0.05折，天天享1296代金。\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/14097.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-12-10 11:10:14\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\