INSERT INTO `gb_games` VALUES (58, 1, NULL, '仙坠凡尘（0.1折气灵师打金版）', NULL, NULL, '角色扮演', 'discount', 'https://cp.u2game99.com/storage/operator/20251219/8428f70311e1c2a98a16c4980f2c2373.gif', 'https://cp.u2game99.com/storage/operator/20251219/f6b0d865a8c25ee89c1bbb9fc019fa9f.jpg', '[\"https://cp.u2game99.com/storage/operator/20251219/a83dda31a6a166a230b51bee0492b6c1.jpg\", \"https://cp.u2game99.com/storage/operator/20251219/09848be3e8f89e5ec33f3593c152a184.jpg\", \"https://cp.u2game99.com/storage/operator/20251219/8409407a614e31bc8ec3b6122c853a89.jpg\", \"https://cp.u2game99.com/storage/operator/20251219/304c6354e685e5acfe587c6ad25e50de.jpg\", \"https://cp.u2game99.com/storage/operator/20251219/4014cce8b466b232f0e3a2fc6b58b246.jpg\"]', 'https://mp4.277sy.com/sp/14025.mp4', '在这个充满东方玄幻色彩的仙侠世界中，你将体验到独特的游戏玩法与极致的战斗体验。游戏采用顶级3D超清画质，将宏伟的仙侠世界展现得淋漓尽致。从神秘的星辰秘境，到强大的上古神兽，每一个细节都为你精心打造。捕捉并培养专属神兽，让它与你并肩作战，助你在这片大陆上无往不胜！此外，多职业自由转职系统，让你在战斗中体验多种角色的乐趣，仙魔随心切换，任意选择你的成长之路。\r\n\r\n全服BOSS争夺战即将打响，跨服竞技场等你来战，与顶尖高手一决高下，争夺最强荣耀与豪华奖励。装备属性永不贬值，极品装备可自由交易，助你轻松提升战力，成为修仙界的传奇。超大无缝地图自由探索，唯美仙侠风景如诗如画，带你走进一个如梦如幻的修仙世界。赶快叫上好友，开辟属于你的仙侠传奇，登顶三界巅峰！', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1629', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1629', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1629', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1629', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-11-20 15:01:07', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:39', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"终身0.1折激爽版沉浸式打金仙侠手游\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/14025.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"角色扮演\",\"addtime\":\"2025-11-20 15:01:07\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20251219/8428f70311e1c2a9