INSERT INTO `gb_games` VALUES (59, 1, NULL, '剑舞乾坤（0.05返5倍代金券）', NULL, NULL, '角色扮演', 'discount', 'https://cp.u2game99.com/storage/operator/20251211/827f6ab41dff8e9925bfe62eae327298.gif', 'https://cp.u2game99.com/storage/operator/20251211/1629323cf583dba2b028013ae64dc8fe.jpg', '[\"https://cp.u2game99.com/storage/operator/20251211/782c55930ec6463d17dd57230ac03357.jpg\", \"https://cp.u2game99.com/storage/operator/20251211/9447e031b0e3040cf909ae3c350a2dc3.jpg\", \"https://cp.u2game99.com/storage/operator/20251211/d7d796dd34468b5bb7b5a5d811c78933.jpg\", \"https://cp.u2game99.com/storage/operator/20251211/17f8bcc443c76f5086476aca63e6b052.jpg\", \"https://cp.u2game99.com/storage/operator/20251211/4b9a5f70952f6b2bfa54ee8d2f655d89.jpg\"]', 'https://mp4.277sy.com/sp/14078.mp4', '《剑舞乾坤》是一款深受玩家喜爱的纯正武侠风题材动作类手游，游戏以独特的武侠世界为背景，将玩家带入一个充满江湖气息、万人国战的宏大场景，让你在战斗中体验武侠世界的魅力与激情。在游戏中，你将扮演一位身怀绝技的武侠英雄，与来自全国各地的玩家一同踏上江湖征程。游戏采用了高质量的图像和流畅的动作设计，呈现出一个个栩栩如生的武侠角色和精彩的战斗场面。你可以自由选择不同的门派、武器和技能，打造属于自己的独特战斗风格，展现出超凡的武艺。\r\n', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1678', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1678', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1678', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1678', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-12-04 10:50:10', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:39', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"仙侠国战经典永留存，炫酷玩法等你来解锁\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/14078.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"角色扮演\",\"addtime\":\"2025-12-04 10:50:10\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20251211/827f6ab41dff8e9925bfe62eae327298.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=