INSERT INTO `gb_games` VALUES (67, 1, NULL, '万灵幻想（0.1折每日送6480）', NULL, NULL, '卡牌', 'discount', 'https://cp.u2game99.com/storage/operator/20251216/02d6046f5e869fd10c016d61f7f39396.gif', 'https://cp.u2game99.com/storage/operator/20251215/86ea3676a10cc41e3c90f5122ad6b4ff.jpg', '[\"https://cp.u2game99.com/storage/operator/20251215/e8de083d03d48796e3008d7c82553a9f.jpg\", \"https://cp.u2game99.com/storage/operator/20251215/22d60b7a75549115807338d2aa28b7e1.jpg\", \"https://cp.u2game99.com/storage/operator/20251215/b551e22183333f8b09f3b15e13cdcaec.jpg\", \"https://cp.u2game99.com/storage/operator/20251215/c32a173f27bdd8da8c780e4cb028367b.jpg\", \"https://cp.u2game99.com/storage/operator/20251215/6c2d5f4f03e58c3b5b46a6ba1b348613.jpg\"]', 'https://mp4.277sy.com/sp/14102.mp4', '故事发生在名为“艾丽娅”的巨大世界树上，玩家将扮演着艾丽娅女神从异世界召唤而来并拥有净化邪祟能力的“指挥官”，成为这个世界的救世主，邂逅并率领各具特色守护者们展开探索世界、拯救世界、消灭邪恶根源的冒险旅程。\r\n◆新卡秒上，高颜值与实力兼顾\r\n百媚萌娘轻松养成，一键同步等级装备。选择最适合的她，打造只属于你的美少女联盟。\r\n◆养成减负，护肝放置爽拿收益\r\n挂机升级无压力，睡觉都能收获大宝藏。现实生活繁忙的救世主们也能轻松爽玩。\r\n◆爽快推关，深度技能搭配系统\r\n创新的技能顺序设定系统，自由布阵在战斗体验上更有挑战性与趣味性。有限的技能数量，无限的组合可能！', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1700', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1700', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1700', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1700', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-12-11 10:55:56', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:39', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"每天送6480代金券\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/14102.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-12-11 10:55:56\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20251216/02d6046f5e869fd10c016d61f7f39396.gif\",\"version\":0,\"c_version\":