INSERT INTO `gb_games` VALUES (68, 1, NULL, '猎魔（0.1折6480代金爽玩版）', NULL, NULL, '挂机', 'discount', 'https://cp.u2game99.com/storage/operator/20251217/664b3071358ae0ecd135c6977e7cb0d6.gif', 'https://cp.u2game99.com/storage/operator/20251217/724ecec0433eb5f0020d4c7c257b0dc6.jpg', '[\"https://cp.u2game99.com/storage/operator/20251217/cf7b2359f179d1b33661b3553f64155f.jpg\", \"https://cp.u2game99.com/storage/operator/20251217/e57e492e17929feb9320236a5245d9bb.jpg\", \"https://cp.u2game99.com/storage/operator/20251217/fa7be5c764d147d5a19abe62d4ea0dbd.jpg\", \"https://cp.u2game99.com/storage/operator/20251217/411cb59dfb32688854c28f2d1c666271.jpg\", \"https://cp.u2game99.com/storage/operator/20251217/6024f00d46e3d1e595c4193bdb853ebe.jpg\"]', 'https://mp4.277sy.com/sp/14122.mp4', '身临其境地感受到从凡人历经千劫终为道祖的修仙之路。\r\n道祖之后，修仙尽头，又是何样景象？\r\n是天道侵蚀身陨化道，还是胜天半子重建新世？\r\n在那尽头处是一场与天道的无止境的轮回决战，所有修真者将无可避免的卷入这场洪流之中', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1718', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1718', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1718', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1718', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-12-17 10:44:28', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:39', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"0.1折打怪开箱，每日送6480代金券\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/14122.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"挂机\",\"addtime\":\"2025-12-17 10:44:28\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20251217/664b3071358ae0ecd135c6977e7cb0d6.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1718\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/1718.html\",\"weburl_qr\