INSERT INTO `gb_games` VALUES (73, 1, NULL, '聊斋搜神记（0.05折开局6480）', NULL, NULL, '挂机', 'discount', 'https://cp.u2game99.com/storage/operator/20251217/b95531c8485b97633112616dc06c7469.gif', 'https://cp.u2game99.com/storage/operator/20251217/dbb2eb4c5620bde05a51cd37da3860b5.jpg', '[\"https://cp.u2game99.com/storage/operator/20251217/5e80748d571d0c08703cfbf768841b5d.jpg\", \"https://cp.u2game99.com/storage/operator/20251217/88527a5110926e527e22c2fd4b8cfeca.jpg\", \"https://cp.u2game99.com/storage/operator/20251217/ab1f640abbaac6450546806499fcf5f2.jpg\", \"https://cp.u2game99.com/storage/operator/20251217/7566048018ddff22dcc23829b10604a4.jpg\", \"https://cp.u2game99.com/storage/operator/20251217/517b2475d354b4a16fc3fbbf7012c261.jpg\"]', 'https://mp4.277sy.com/sp/14079.mp4', '《聊斋搜神记》​踏入阴森诡谲的聊斋世界！你将化身茅山道士，携符箓桃木剑，于乱葬岗斩狐妖、破鬼蜮，誓扫世间邪祟！​\r\n作为扫清邪魔鬼怪的动作类的游戏，游戏暗藏多重养成玄机：装备、套装、御灵等线交织，而装备与套装最易上手成型 —— 一件极品装备助你抢先克邪，一套神装更能让你战力飙升，化身降魔战神！副本惊魂、BOSS 血斗，皆为获取神装的必闯险途！​\r\n其余养成线暗藏福利：每日小额礼包、限时特惠活动，为不同玩家备好驱邪道具！速速入手，战力暴涨，在跨服除魔战中力压群雄，夺海量奖励，满载荣光而归！', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1679', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1679', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1679', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1679', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-12-04 14:03:08', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:39', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"永久享0.05折，3.28元解锁逆天金手指。\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/14079.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"挂机\",\"addtime\":\"2025-12-04 14:03:08\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20251217/b95531c8485b97633112616dc06c7469.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1679\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/1679.html\",\"weburl_qr\":\"[base64已省略]\",\"dwzdownurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1679\",\"downurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1679\",\"dwzdownurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1679\",\"gamename\":\"聊斋搜神记（0.05折开局6480）\",\"excerpt\":\"《聊斋搜神记》​踏入阴森诡谲的聊斋世界！你将化身茅山道士，携符箓桃木剑，于乱葬岗斩狐妖、破鬼蜮，誓扫世间邪祟！​\\r\\n作为扫清邪魔鬼怪的动作类的游戏，游戏暗藏多重养成玄机：装备、套装、御灵等线交织，而装备与套装最易上手成型 —— 一件极品装备助你抢先克邪，一套神装更能让你战力飙升，化身降魔战神！副本惊魂、BOSS 血斗，皆为获取神装的必闯险途！​\\r\\n其余养成线暗藏福利：每日小额礼包、限时特惠活动，为不同玩家备好驱邪道具！速速入手，战力暴涨，在跨服除魔战中力压群雄，夺海量奖励，满载荣光而归！\",\"id\":1679,\"game_source\":\"\",\"device_type\":2,\"edition\":1,\"pic_xuanchuan\":\"\",\"strict\":0,\"userfc\":0,\"updatetime\":\"2025-12-18 09:00:00\",\"box_content\":\"【开服福利】输入礼包码 lzss888，立领6480代金券，助你开局即巅峰。\\r\\n【永久折扣】永久0.05折扣，轻松解锁逆天特权，金手指5倍增效，属性瞬爆斩妖除魔，制霸全服。\\r\\n【登录有礼】上线累送500万元宝，商城任选轻松畅买，神兵珍器超易获取。\\r\\n【闯关壕礼】在线闯关即赠VIP豪礼，直升V10，升级海量装备材料狂收，成长飞驰。\\r\\n【七日神装】连续登录七日，狂送神兵+翅膀+时装套装，战力瞬提，斩鬼灭邪一念之间。\\r\\n【挂机丰收】全天放置轻松得百万资源，元宝银两材料自动到手，角色武器随心养成。\\r\\n【庆典狂欢】全服共庆完成任务，赢取至尊神兵，战力法力双飙升，即刻横扫三界！\",\"pic2\":\"https://cp.u2game99.com/storage/operator/20251217/dbb2eb4c5620bde05a51cd37da3860b5.jpg\",\"pic3\":\"https://www.u2game99.com/data/upload/game/20251217/6942147feb0fb.jpg\",\"pic4\":\"https://www.u2game99.com/data/upload/game/20251217/6942148784719.jpg\",\"cps_ratio\":0,\"hw_ratio\":0,\"hw_firstpay\":0.005,\"hw_otherpay\":0.005,\"firstpay\":0.005,\"otherpay\":0.005}');
INSERT INTO `gb_games` VALUES (74, 1, NULL, '吞噬星空：黎明（0.05全场买1送10版）', NULL, NULL, '卡牌', 'discount', 'https://www.u2game99.com/data/upload/game/20251224/694bba4886fb2.gif', 'https://www.u2game99.com/data/upload/game/20251224/694bba09c0712.jpg', '[\"https://cp.u2game99.com/storage/operator/20251210/dd17c0711dca83e9437cba0141ce5236.jpg\", \"https://cp.u2game99.com/storage/operator/20251210/99b80f6cef0e281695e76387714ea452.jpg\", \"https://cp.u2game99.com/storage/operator/20251210/ea08bea9ae8a76b8c28e24b60b07e3c4.jpg\", \"https://cp.u2game99.com/storage/operator/20251210/12e1b7278301be50761dc12694bff901.jpg\", \"https://cp.u2game99.com/storage/operator/20251210/22420c16d47b2d63845ef61111d70b65.jpg\"]', 'https://mp4.277sy.com/sp/14089.mp4', '【剧情还原】“477 万字原著完整复刻”：主线覆盖 “大涅槃时期” 至 “战神宫崛起” 47 个篇章，关键战役（如雾岛争夺战）配动态过场与原班配音，同步动漫第三季剧情\r\n【角色阵容】“近百位高科技化 3D 角色”：1:1 还原罗峰、雷神、洪等动画主角团，五大职业（武者 / 精神念师 / 守护 / 医者 / 刺客），专属技能树与专武系统\r\n【战斗体验】“回合制 + 星能技能组合”：支持自动作战，技能可自由搭配；三维空间移动操控，PVE 复刻经典战役，PVP 含 1v1 与百人星团混战\r\n【装备进化】“纳米级改造 + 多属性分支”：武器可光能 / 电磁 / 生化三系进化，装备与角色同步养成，六大系统助力无限成长\r\n【世界观】“未来废土 + 科幻修真”：融合辐射风暴、机械废墟等场景，Unity 引擎打造高清 3D 废土世界，沉浸式对抗变异巨兽', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1689', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1689', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1689', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1689', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-12-08 09:50:59', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:39', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"顶级人气IP官方正版吞噬星空\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/14089.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-12-08 09:50:59\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://www.u2game99.com/data/upload/game/20251224/694bb