INSERT INTO `gb_games` VALUES (80, 1, NULL, '百川铸魂录（0.1代金狂送版）', NULL, NULL, '卡牌', 'discount', 'https://cp.u2game99.com/storage/operator/20251208/1192d46bf40638e4cd60d04ee68353f1.gif', 'https://cp.u2game99.com/storage/operator/20251208/0e4ac92979fc955d183159a00a502002.jpg', '[\"https://cp.u2game99.com/storage/operator/20251208/8411fab3c8a995bd0b954089c541279c.jpg\", \"https://cp.u2game99.com/storage/operator/20251208/d0e63a0d83a9bf1c3f29a9b32b5f2d59.jpg\", \"https://cp.u2game99.com/storage/operator/20251208/525fc059094b41be5913ade78f524637.jpg\", \"https://cp.u2game99.com/storage/operator/20251208/a2395daa428769d04ae34bd03942c0f2.jpg\", \"https://cp.u2game99.com/storage/operator/20251208/e8520fd4190e93fc63f883d6ce79127b.jpg\"]', 'https://mp4.277sy.com/sp/14081.mp4', '《百川铸魂录》是一款以历史上著名兵器拟人为题材横板3D策略卡牌手游。\r\n游戏以全球各地著名古代兵器的传说作为蓝本进行创作，将古兵器拟人化，构建了一个以古代华夏文明为基础的架空世界。\r\n讲述在架空的世界里，一种叫“ 刃灵”的灵体，能够通过冷兵器化形拥有实体，热衷杀伐予夺，致使生灵涂炭。\r\n而玩家扮演的主角， 乃是神锻师的后裔，为阻止战祸降临，在神锻先祖的指引下，再次踏上了成为神锻师的旅程。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1681', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1681', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1681', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1681', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-12-04 16:47:06', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:39', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"全新0.1折国风卡牌手游重制归来，上线赠送每日648代金券\",\"interchangeable_role\":0,\"video\":\"https://mp4.277sy.com/sp/14081.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-12-04 16:47:06\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20251208/1192d46bf40638e4cd60d04ee68353f1.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1681\",\"q