INSERT INTO `gb_games` VALUES (83, 1, NULL, '群英之战（0.05黑钟馗抓鬼版）', NULL, NULL, '卡牌', 'discount', 'https://cp.u2game99.com/storage/operator/20251210/94f0357c874f7a501d76fdbac82f06f5.gif', 'https://cp.u2game99.com/storage/operator/20251210/7bb3b44184867e7f012fab5fc3097530.jpg', '[\"https://cp.u2game99.com/storage/operator/20251210/c2978430072f6a770e36e36f443d3925.jpg\", \"https://cp.u2game99.com/storage/operator/20251210/36380299c3eae96cbaa60fd42c8715b3.jpg\", \"https://cp.u2game99.com/storage/operator/20251210/257436f08554f4313d33bc629e431f63.jpg\", \"https://cp.u2game99.com/storage/operator/20251210/879dae93fb6ac70a9253a8c5347e9e24.jpg\", \"https://cp.u2game99.com/storage/operator/20251210/6aba608a2f438a1d077c05df8c10d2b1.jpg\"]', 'https://mp4.277sy.com/sp/14085.mp4', '《群英之战》是一款真3D三国无双割草动作手游，收集三国群雄武将，与你一同驰骋沙场！带领吕布，关羽，赵云等绝世名将参与两汉三国近百场经典战役，让玩家体验“一骑当千、横扫千军”快感的动作游戏。还加入了伏羲、女娲、妲己、炎帝这四位神话角色与玩家一同征战，无上限自由成长空间，革命性全屏互动操作，主机级操控打击感，点划横扫，爽快连击，配合华丽武将技能特效，享受万军从中取上将首级的碾压快感。更有单人、3V3、军团等多种丰富PVP模式燃战天下英豪，与卧龙凤雏一同谋略天下！武将割草，自由强化，指破千军，唯我无双！', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1685', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1685', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1685', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1685', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-12-05 13:38:38', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:39', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"0.05折随心充，三国任横行。\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/14085.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-12-05 13:38:38\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20251210/94f0357c874f7a501d76fdbac82f06f5.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.c