INSERT INTO `gb_games` VALUES (84, 1, NULL, '叫我大酋长（卡牌0.1折）', NULL, NULL, '卡牌', 'discount', 'https://cp.u2game99.com/storage/operator/20251211/82cb9fbad3b3a27c1d135fe297992aaa.png', 'https://cp.u2game99.com/storage/operator/20251211/b20a9c309b67685d58b1458c8ba4e144.jpg', '[\"https://cp.u2game99.com/storage/operator/20251211/300c178bd3a6ba03d1cf90e58d035917.jpg\", \"https://cp.u2game99.com/storage/operator/20251211/a8806b4cdf71177bbb27861d15f67a94.jpg\", \"https://cp.u2game99.com/storage/operator/20251211/d95824eda57b84726fd0774485ac8ae0.jpg\", \"https://cp.u2game99.com/storage/operator/20251211/eb2250d89ef52565d3302a244348a3a7.jpg\", \"https://cp.u2game99.com/storage/operator/20251211/9112cc3b43c85ef0975154995b1dac7f.jpg\"]', 'https://mp4.277sy.com/sp/14105.mp4', '《叫我大酋长》是一款大型卡牌角色扮演类型网络游戏（RPG），玩家在手机中安装后即可运行。玩家将扮演魔幻世界中的一名领主，通过获取角色卡牌，招募强者英雄，构建专属的英雄阵容，闯荡充满奇幻与神秘色彩的幻想世界，展开波澜壮阔的大冒险。玩家在游戏中可以相互结盟，也可以进行斗争，在战火纷飞的大陆中找寻胜利的曙光。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1702', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1702', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1702', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1702', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-12-11 15:21:04', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:39', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"原价0.1折放置魔幻卡牌手游！\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/14105.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-12-11 15:21:04\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20251211/82cb9fbad3b3a27c1d135fe297992aaa.png\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1702\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/