INSERT INTO `gb_games` VALUES (85, 1, NULL, '不朽大陆(0.1折进游送代金券)', NULL, NULL, '卡牌', 'discount', 'https://www.u2game99.com/data/upload/game/20251211/693a40aaeebde.png', 'https://cp.u2game99.com/storage/operator/20251211/ba30258b52e4b760f3f77ca2e781209f.jpg', '[\"https://cp.u2game99.com/storage/operator/20251211/64dff83f355b15c07996f96e6fb80f97.jpg\", \"https://cp.u2game99.com/storage/operator/20251211/0bd0f977e19e7920c1e2a22cf345628e.jpg\", \"https://cp.u2game99.com/storage/operator/20251211/75efdfa5ed488551b283ed0da825e9a4.jpg\", \"https://cp.u2game99.com/storage/operator/20251211/21df946914b92328d662110fcde05b6c.jpg\", \"https://cp.u2game99.com/storage/operator/20251211/74c8a6723552977ed603cd0e568e76b1.jpg\"]', 'https://mp4.277sy.com/sp/14075.mp4', '地球上爆发了生化危机，全球感染了未知的病毒。你是一名出色的指挥官，将带领着地球上的组织势力，开启寻找病毒源头和解放城市之路。在寻找的过程中，发现了这一切都是外星人入侵地球的手段，甚至挖掘到守卫基地的高层中的阴谋诡计。于是，一场守卫地球的战争就此拉开了序幕……', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1675', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1675', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1675', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1675', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-12-02 16:52:27', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:39', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"登录即送万抽，无门槛代金券连领28天\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/14075.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-12-02 16:52:27\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:0\",\"hw_cps_cpa\":\"CPS推广:30\",\"coupon_repeat\":\"\",\"pic1\":\"https://www.u2game99.com/data/upload/game/20251211/693a40aaeebde.png\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1675\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/1675.html\",\"weburl_qr\":\"[base64已省略]\",\"dwzdownurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1675\",\"downurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1675\",\"dwzdownurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1675\",\"gamename\":\"不朽大陆(0.1折进游送代金券)\",\"excerpt\":\"地球上爆发了生化危机，全球感染了未知的病毒。你是一名出色的指挥官，将带领着地球上的组织势力，开启寻找病毒源头和解放城市之路。在寻找的过程中，发现了这一切都是外星人入侵地球的手段，甚至挖掘到守卫基地的高层中的阴谋诡计。于是，一场守卫地球的战争就此拉开了序幕……\",\"id\":1675,\"game_source\":\"\",\"device_type\":2,\"edition\":1,\"pic_xuanchuan\":\"\",\"strict\":0,\"userfc\":1,\"updatetime\":\"2025-12-12 10:00:00\",\"box_content\":\"【暴打丧尸，守卫人类家园】\\r\\n战斗吧，英雄们！千变万化的载具机甲可契合不同的战场及战斗模式给予小队强大的助力。\\r\\n【策略搭配，打造酷炫队伍！】\\r\\n50+名个性英雄、千变万化的机甲等你召唤！随心养成，一键置换0损耗，上百种套路任你配，酷炫MVP阵容由你创！\\r\\n【福利爆仓，玩就送10000抽！】\\r\\n开局就送10000抽！海量福利疯狂送！每天都是福利大狂欢！\\r\\n【10+互动小游戏，其乐无穷！】\\r\\n这里不止1种玩法，10+种特色副本、小游戏邀你挑战！爬塔、Roguelike、射击、造机甲、夹娃娃、探索寻宝全都有！只有你想不到，没有玩不到~\\r\\n【轻松挂机，护发又护肝！】\\r\\n拒绝内卷，护肝护发！放置挂机，解放双手，躺着挂机就暴富，秒杀BOSS没压力！\\r\\n【迎新福利送SS自选】\\r\\n新服进游免费领迎新豪华福利，直升VIP6特权等级，充值卡豪礼、6星预备军官，还有极品SS英雄任君挑选\\r\\n【新服七天送SSS英雄】\\r\\n每天登录领取超级英雄，连登七日免费领顶级SSS英雄自选，上阵助力战力暴涨，碾压刷图速通毫无压力\\r\\n【海量真充卡免费送】\\r\\n趣味大富翁跑酷，无上限送充值碎片，还有签到福利送海量充值卡，可直接兑换真充卡，直升满VIP不是梦\\r\\n【连续28天领648代金劵】\\r\\n全网保真福利大开门，每日登录免费送648代金劵，最高可领18144元！良心无门槛无时效性，平民也能玩得爽\",\"pic2\":\"https://cp.u2game99.com/storage/operator/20251211/ba30258b52e4b760f3f77ca2e781209f.jpg\",\"pic3\":\"https://www.u2game99.com/data/upload/game/20251211/693a40a5881ac.jpg\",\"pic4\":\"https://www.u2game99.com/data/upload/game/20251211/693a40b2de1f4.jpg\",\"cps_ratio\":0,\"hw_ratio\":0,\"hw_firstpay\":0.01,\"hw_otherpay\":0.01,\"firstpay\":0.01,\"otherpay\":0.01}');
