INSERT INTO `gb_games` VALUES (88, 1, NULL, '霸气英雄（0.1折千元代金券天天送）', NULL, NULL, '卡牌', 'discount', 'https://cp.u2game99.com/storage/operator/20251203/d6b2412cf679287e0f3ef15f6a134595.gif', 'https://cp.u2game99.com/storage/operator/20251203/a6461f8a354ced4dec9bfd38abd264ea.jpg', '[\"https://cp.u2game99.com/storage/operator/20251203/fb1ab44d03584430a39a41bf26a4bf6a.jpg\", \"https://cp.u2game99.com/storage/operator/20251203/7314458834b726e0294aa8af357a25db.jpg\", \"https://cp.u2game99.com/storage/operator/20251203/acb16184147173b56371c415c10151d3.jpg\", \"https://cp.u2game99.com/storage/operator/20251203/2272f4a30ede3c952e5c01ebd4b0bb2f.jpg\", \"https://cp.u2game99.com/storage/operator/20251203/1b5309be7b89a5f7326d32a8b4ed4ac9.jpg\"]', 'https://mp4.277sy.com/sp/14051.mp4', '全新一代的新封神概念之作《霸气英雄》是一款封神剧情策略回合制手游，游戏融合幻想与历史，构筑RPG全新大地图封神宇宙，讲述第一次封神大战后，玩家作为天命者将再次踏上封神之路，斩妖除魔、对抗神明，重启封神榜的冒险故事。游戏高度还原封神经典场景玩法，多样的场景互动解谜，封神剧情带来沉浸式游戏体验；同时还有镇守凌霄阁、封神争霸、圣地争夺等多种革新玩法等待你的挑战！与您一同进入神魔乱舞的时代，掌控三界，重启封神之路，封神世界等你来称霸！', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1653', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1653', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1653', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1653', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-11-26 16:41:03', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:39', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"掌控三界，重启封神之路，封神世界等你来称霸！\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/14051.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-11-26 16:41:03\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:0\",\"hw_cps_cpa\":\"CPS推广:30\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20251203/d6b2412cf679287e0f3ef15f6a134595.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1653\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/1653.html\",\"weburl_qr\":\"[base64已省略]\",\"dwzdownurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1653\",\"downurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1653\",\"dwzdownurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1653\",\"gamename\":\"霸气英雄（0.1折千元代金券天天送）\",\"excerpt\":\"全新一代的新封神概念之作《霸气英雄》是一款封神剧情策略回合制手游，游戏融合幻想与历史，构筑RPG全新大地图封神宇宙，讲述第一次封神大战后，玩家作为天命者将再次踏上封神之路，斩妖除魔、对抗神明，重启封神榜的冒险故事。游戏高度还原封神经典场景玩法，多样的场景互动解谜，封神剧情带来沉浸式游戏体验；同时还有镇守凌霄阁、封神争霸、圣地争夺等多种革新玩法等待你的挑战！与您一同进入神魔乱舞的时代，掌控三界，重启封神之路，封神世界等你来称霸！\",\"id\":1653,\"game_source\":\"\",\"device_type\":2,\"edition\":1,\"pic_xuanchuan\":\"\",\"strict\":0,\"userfc\":1,\"updatetime\":\"2025-12-12 08:00:00\",\"box_content\":\"★充值比例1：100，货币：元宝\\r\\n★【千元代金券天天送】\\r\\n每日赠送1000代金券，日常养成不缺资源，不氪也能一路开红。\\r\\n★【新手专享直升V5】\\r\\n免费获得炫酷时装与高额属性加成，新人一上线就能享受大佬般的爽感。\\r\\n★【百万元宝开局】\\r\\n登录即送百万元宝，灵宠、神装、助战畅爽升级，前期成长一路绿灯。\\r\\n★【极品神宠登场】\\r\\n登录15天免费送超凡灵宠雷震子！稀有度爆表的神宠陪你闯图飞天。\\r\\n★【豪华首充不膨胀】\\r\\n多档首充赠礼大幅加码：绝版灵宠、绝色仙子、酷炫神兵一次到位，开局战力飞跃。\\r\\n★【免费礼包超值抢购】\\r\\n稀有称号、传世之宝、绝世橙宠应有尽有，元宝抢购登录通通返还。\",\"pic2\":\"https://cp.u2game99.com/storage/operator/20251203/a6461f8a354ced4dec9bfd38abd264ea.jpg\",\"pic3\":\"https://www.u2game99.com/data/upload/game/20251203/692fadec45fcf.jpg\",\"pic4\":\"https://www.u2game99.com/data/upload/game/20251203/692fadf17635c.jpg\",\"cps_ratio\":0,\"hw_ratio\":0,\"hw_firstpay\":0.01,\"hw_otherpay\":0.01,\"firstpay\":0.01,\"otherpay\":0.01}');
INSERT INTO `gb_games` VALUES (89, 1, NULL, '冒险与召唤（新石器0.05折双倍代金）', NULL, NULL, '放置', 'discount', 'https://cp.u2game99.com/storage/operator/20251128/a88ce7dcfccc520953b71e02a91f4994.gif', 'https://cp.u2game99.com/storage/operator/20251128/e769d475d1f777067ec610f3fccf1c67.jpg', '[\"https://cp.u2game99.com/storage/operator/20251128/c3a0f910b21d16b55d2eb12130561831.jpg\", \"https://cp.u2game99.com/storage/operator/20251128/aaae043e1946fc9f06cd001c33337cb7.jpg\", \"https://cp.u2game99.com/storage/operator/20251128/0cf8759b41f514dfa2621ba391d2dbff.jpg\", \"https://cp.u2game99.com/storage/operator/20251128/d221f9c18c7999d5560b32f65f78ed2d.jpg\", \"https://cp.u2game99.com/storage/operator/20251128/8e026473e64eb0ca381faebe33339dc4.jpg\"]', 'https://mp4.277sy.com/sp/14036.mp4', '《冒险与召唤》是一款休闲放置的开箱小游戏，玩家将作为生活在石器时代的小原人，与众多远古异兽为伴。但不需要通过对抗远古怪物获得装备，也不需要闯过一个个难关提升等级，只要不停的打开眼前的宝箱，各种远古神级装备唾手可得，游戏中还有各种上古坐骑，可爱萌宠与你一起探险石器时代，使你可以充分感受石器时代的魅力。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1640', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1640', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1640', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1640', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-11-21 16:09:20', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:39', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"全场0.05折，每天送二千元代金体验原始石器冒险\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/14036.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"放置\",\"addtime\":\"2025-11-21 16:09:20\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20251128/a88ce7dcfccc520953b71e02a91f4994.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1640\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/1640.html\",\"weburl_qr\":\"[base64已省略]\",\"dwzdownurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1640\",\"downurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1640\",\"dwzdownurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1640\",\"gamename\":\"冒险与召唤（新石器0.05折双倍代金）\",\"excerpt\":\"《冒险与召唤》是一款休闲放置的开箱小游戏，玩家将作为生活在石器时代的小原人，与众多远古异兽为伴。但不需要通过对抗远古怪物获得装备，也不需要闯过一个个难关提升等级，只要不停的打开眼前的宝箱，各种远古神级装备唾手可得，游戏中还有各种上古坐骑，可爱萌宠与你一起探险石器时代，使你可以充分感受石器时代的魅力。\",\"id\":1640,\"game_source\":\"\",\"device_type\":2,\"edition\":1,\"pic_xuanchuan\":\"\",\"strict\":0,\"userfc\":0,\"updatetime\":\"2025-12-10 08:00:00\",\"box_content\":\"★超休闲开箱放置养成，简单的挂机对战，动动手指就可以轻松通关~\\r\\n★每日在线即送2000代金券，可代替现金支付任何礼包\\r\\n★7天签到送极品坐骑-赤焰\\r\\n★家园玩法送大量贝壳\\r\\n\",\"pic2\":\"https://cp.u2game99.com/storage/operator/20251128/e769d475d1f777067ec610f3fccf1c67.jpg\",\"pic3\":\"https://www.u2game99.com/data/upload/game/20251128/69293c3a79ad2.jpg\",\"pic4\":\"https://www.u2game99.com/data/upload/game/20251128/69293c41ea987.jpg\",\"cps_ratio\":0,\"hw_ratio\":0,\"hw_firstpay\":0.005,\"hw_otherpay\":0.005,\"firstpay\":0.005,\"otherpay\":0.005}');
INSERT INTO `gb_games` VALUES (90, 1, NULL, '战神烈歌（杀戮血脉专属神器）', NULL, NULL, '挂机', 'bt', 'https://cp.u2game99.com/storage/operator/20251209/1d2258fb2fc064ef1a49973a88fe9f64.gif', 'https://cp.u2game99.com/storage/operator/20251209/f360d6193694d6b915a0c04c77984685.jpg', '[\"https://cp.u2game99.com/storage/operator/20251209/c8efbfddf8e482000e608dd87ee4a0bb.jpg\", \"https://cp.u2game99.com/storage/operator/20251209/9a5e5be642e313da47699601f0cabdb5.jpg\", \"https://cp.u2game99.com/storage/operator/20251209/c1d34c410f34bdf4105333114aa1a7ba.jpg\", \"https://cp.u2game99.com/storage/operator/20251209/31b86b36f2ff620b68c6ab8da946f789.jpg\", \"https://cp.u2game99.com/storage/operator/20251209/cce211ee7d2e90034b8331c63a6710c8.jpg\"]', 'https://mp4.277sy.com/sp/14087.mp4', '1. 开局登顶，神技免费领 \r\n自动回收系统：挂机自动清理背包，神装材料一键收取，资源积累快人一步！ \r\n三大神技：开局即解锁 半月弯刀、逐日剑法、开天神斩，战力瞬间登顶！ \r\n永久赞助免费送：多倍爆率、刀刀切割，开服即巅峰！ \r\n2. 千件真专属，BUFF独此一家 \r\n唯一专属装备库：上千件独立设计的专属神器，每件自带独特技能与BUFF——吸血、反伤、瞬移、群攻，打破传统装备套路！ \r\n真·专属效果：装备不再只是数值堆砌，每件专属激活独特战斗风格，搭配无限，打造只属于你的战神之路！ \r\n3. 血脉觉醒，百变战斗流派 \r\n上古血脉传承：激活血脉之力，解锁狂暴、霸体、穿透、回复等数十种BUFF，自由组合构建专属流派！ \r\n血脉融合觉醒：多重血脉叠加激活隐藏效果，输出、生存、控制全面突破，每一次战斗都是策略的胜利！ \r\n4. 实物海量爆，充值货币无限刷 \r\n真实福利派送：击败怪海量爆实物奖励，实物可兑换海量灵符！  \r\n5. 史诗剧情闯关，红包拿到手软 \r\n沉浸式大陆史诗：探索上古战场，剧情任务环环相扣，每一次抉择都影响战局！ \r\n充值红包狂送：通关剧情即送充值红包，使用可增加累计充值，边玩边送永不停！ \r\n', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1687', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1687', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1687', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1687', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-12-05 14:58:30', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:39', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"开局登顶，神技免费领 \",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/14087.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"挂机\",\"addtime\":\"2025-12-05 14:58:30\",\"g