INSERT INTO `gb_games` VALUES (99, 1, NULL, '小小驯龙师（开局养成霸王龙内置0.1折）', NULL, NULL, '卡牌', 'bt', 'https://cp.u2game99.com/storage/operator/20251127/7d43d8581ac3e689026a3ac19d7c6175.png', 'https://cp.u2game99.com/storage/operator/20251127/51980dffceda633ae59a3f7d7368bde1.jpg', '[\"https://cp.u2game99.com/storage/operator/20251127/314fba105e5f7d46c4235f96cd689c09.jpg\", \"https://cp.u2game99.com/storage/operator/20251127/8badcd64289f7496bb903c3ed71e6f31.jpg\", \"https://cp.u2game99.com/storage/operator/20251127/3fba2f7b5db018baa06184a407e23d48.jpg\", \"https://cp.u2game99.com/storage/operator/20251127/297d19fa83da0860493141af56e6d5b8.jpg\", \"https://cp.u2game99.com/storage/operator/20251127/7fc10ee88b3b3af0cd890c793c23c816.jpg\"]', 'https://mp4.277sy.com/sp/14048.mp4', '小小驯龙师是一款集恐龙收集，培养，PVE剧情副本，装备收集，交互系统，跨服战斗为一体的回合挂机类闯关游戏。 在游戏中，玩家将化身驯龙师，指挥自家发现里的远古恐龙们排兵布阵，研究恐龙进化奥秘。游戏中有很多关卡，节奏较快，操作简单，容易上手，玩家只需要跟着点点点，战力就能得到疯狂提升，轻量化则让它具备随时随地挂机摸鱼的特点，不要花费长时间进行游戏，利用碎片化时间也能玩。除此之外，游戏本身的设计是将恐龙和广受机甲融合进行了一个结合，形象上也非常霸气。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1650', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1650', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1650', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1650', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-11-26 10:15:36', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:39', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"小小驯龙师是一款多福利，集恐龙闯关游戏\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/14048.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-11-26 10:15:36\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:0\",\"hw_cps_cpa\":\"CPS推广:45\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20251127/7d43d8581ac3e689026a3ac19d7c6175.png\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1