INSERT INTO `gb_games` VALUES (108, 1, NULL, '火柴人无限（0.05折魔王登场）', NULL, NULL, '卡牌', 'discount', 'https://cp.u2game99.com/storage/operator/20251201/fac650dc7413fd420696152a5d2de4a8.gif', 'https://cp.u2game99.com/storage/operator/20251201/d9298373160f916e760521cdcc99b023.jpg', '[\"https://cp.u2game99.com/storage/operator/20251201/24e4569b4d80f1c89bb5e1bd7a171af7.jpg\", \"https://cp.u2game99.com/storage/operator/20251201/cfe9d4a014e5fd556698a2418815baf0.jpg\", \"https://cp.u2game99.com/storage/operator/20251201/192d2ba88f78e75ecfcb4afd99f7b7ff.jpg\", \"https://cp.u2game99.com/storage/operator/20251201/9ea12983748dedce634d1cbd40b46a5c.jpg\", \"https://cp.u2game99.com/storage/operator/20251201/2be87305ddf2261f88b1f245ea8407b1.jpg\"]', 'https://mp4.277sy.com/sp/14043.mp4', '火柴人无限是一款塔防元素的手游，采用经典的水墨风场景，还加入了roguelike、策略等玩法，玩家可以自由选择各职业的火柴人进行战斗，指挥英勇无畏的火柴人战士，构筑坚固的防线，抵御一波又一波来势汹汹的敌人。您可以灵活运用各种独特的火柴人战士，如无限穿透的鸡哥、全屏气功波的狗空、弹射弹道的小丑女、范围输出的剑心等等。来应对潮水般涌来的敌人，您需要迅速做出决策，合理利用有限的资源，巧妙布置防线，升级火柴人战士，以应对不断增强的敌军攻势，每一次的选择都可能影响战斗的胜负，每一次的挑战都是对策略和应变能力的考验。拥有快节奏的战斗模式、趣味的助战系统以及巧妙的策略布局玩法，让你和火柴一起开启超爽的对决。快来加入这场激烈的塔防之战，守护属于火柴人的家园！', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1645', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1645', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1645', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1645', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-11-25 13:51:39', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:39', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"火柴人无限是一款塔防元素的手游\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/14043.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-11-25 13:51:39\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20251201/fac650dc7413fd420696152a5d2de