INSERT INTO `gb_games` VALUES (112, 1, NULL, '最强武装', NULL, NULL, '卡牌', 'official', 'https://cp.u2game99.com/storage/operator/20251202/33bd0b31eaea8c4346abd65b4c8c3b48.png', 'https://cp.u2game99.com/storage/operator/20251202/d7e7aa088871e8f8c8eab9017a313068.jpg', '[\"https://cp.u2game99.com/storage/operator/20251202/f48a9ba36f1c8e6eac5c8ef204147ce7.jpg\", \"https://cp.u2game99.com/storage/operator/20251202/7bfedbc382ffd9f58e46e82118510277.jpg\", \"https://cp.u2game99.com/storage/operator/20251202/dfd4a31798a96676f20eaeaf15a7b521.jpg\", \"https://cp.u2game99.com/storage/operator/20251202/1b140f93b9d700b517789cebe67bdd27.jpg\", \"https://cp.u2game99.com/storage/operator/20251202/8627eccba5f48f1b471eae5c4bd68791.jpg\"]', 'https://mp4.277sy.com/sp/14050.mp4', '《最强武装》完美集结历代高达机体，1:1还原经典战役，点燃宇宙世纪之魂！在殖民卫星的纷争中，成为传奇机师，率领小队对抗吉翁残党，迎战终极BOSS「夏亚」，书写属于你的高达史诗！', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1652', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1652', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1652', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1652', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-11-26 15:23:55', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:39', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"每日十连免费送，高级机体轻松获得，零氪全收集不是梦！\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/14050.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-11-26 15:23:55\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:0\",\"hw_cps_cpa\":\"CPS推广:15\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20251202/33bd0b31eaea8c4346abd65b4c8c3b48.png\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1652\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/1652.html\",\"weburl_qr\":\"[base64已省略]\",\"dwzdownurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1652\",\"downurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1652\",\"dwzdownurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1652\",\"gamename\":\"最强武装\",\"excerpt\":\"《最强武装》完美集结历代高达机体，1:1还原经典战役，点燃宇宙世纪之魂！在殖民卫星的纷争中，成为传奇机师，率领小队对抗吉翁残党，迎战终极BOSS「夏亚」，书写属于你的高达史诗！\",\"id\":1652,\"game_source\":\"\",\"device_type\":2,\"edition\":0,\"pic_xuanchuan\":\"\",\"strict\":0,\"userfc\":0,\"updatetime\":\"2025-12-03 10:00:00\",\"box_content\":\"福利一：登录即送——免费领取【无限正义高达】！\\r\\n登录即可获得限定机体【无限正义高达】，通关活动收集幸运石，还可兑换终极目标——SSR+【强袭自由高达】！\\r\\n\\r\\n福利二：公测献礼——上线即领二十连抽！\\r\\n登录游戏即可通过【公测好礼】礼包码领取【十连抽×2】及【钻石×300】，助你开局抽到心仪机体！\\r\\n\\r\\n福利三：建造保底——十连必中五星机体！\\r\\n每次【十连抽】建造均保底1台五星机体，核心战力稳稳到手，打造属于你的无敌战队！\\r\\n\\r\\n福利四：成长晋阶——升级即享VIP、UR+机体！\\r\\n活动期间，提升指挥官等级即可获得总价值900元的VIP经验奖励，更有SSR、SSR+、UR机体免费领取！\\r\\n\\r\\n福利五：万抽放送——累计1W抽，福利拉满！\\r\\n公测期间，专属终身福利限时开放！累计可免费领取高达【10000招募券】，轻松打造最强阵容！\\r\\n\\r\\n福利六：签到馈赠——每日登录皆有惊喜！\\r\\n坚持每日签到，轻松领取海量机体图纸、VIP经验、联邦许可证与养成材料，资源拿到手软！\",\"pic2\":\"https://cp.u2game99.com/storage/operator/20251202/d7e7aa088871e8f8c8eab9017a313068.jpg\",\"pic3\":\"https://www.u2game99.com/data/upload/game/20251202/692e879165d70.jpg\",\"pic4\":\"https://www.u2game99.com/data/upload/game/20251202/692e8c2b5fb65.jpg\",\"cps_ratio\":0,\"hw_ratio\":0,\"hw_firstpay\":1,\"hw_otherpay\":1,\"firstpay\":1,\"otherpay\":1}');
INSERT INTO `gb_games` VALUES (113, 1, NULL, '豆豆打僵尸（小镇奇兵）', NULL, NULL, '卡牌', 'official', 'https://www.u2game99.com/data/upload/game/20251128/692947bbb82f5.gif', 'https://cp.u2game99.com/storage/operator/20251128/8fa855cb09695a600388fa54cadded47.jpg', '[\"https://cp.u2game99.com/storage/operator/20251128/de37a44de648b5b002b60d0eb1c164cb.jpg\", \"https://cp.u2game99.com/storage/operator/20251128/d1cb594d40eefcf85119af725161c203.jpg\", \"https://cp.u2game99.com/storage/operator/20251128/07bb0be2511bd000062b4de9fb341fab.jpg\", \"https://cp.u2game99.com/storage/operator/20251128/e5e4a7a7b15f409050b5d5f07771e7e4.jpg\", \"https://cp.u2game99.com/storage/operator/20251128/af1c3fd8433e361ffecdaad21c7e1d03.jpg\"]', 'https://mp4.277sy.com/sp/14027.mp4', '休闲放置卡牌手游《豆豆打僵尸》火爆开启！游戏结合了休闲放置与卡牌策略，你不仅可以自动战斗，解放双手，也可以集结风格各异的伙伴，挂机自动养成，组成独一无二的阵容为你而战！Q萌画风搭配幽默设定，还有养僵尸、密室求生等趣味玩法，带给你前所未有的解压体验！现在登录即送110抽，连续签到领取史诗英雄，闯关赢取海量资源！快来组建你的专属军团，守护小镇，开启一场轻松又上头的僵尸征服之旅吧！', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1631', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1631', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1631', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1631', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-11-20 17:59:16', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:39', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"灵阵巧布，策略无穷！\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/14027.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-11-20 17:59:16\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:0\",\"hw_cps_cpa\":\"CPS推广:15\",\"coupon_repeat\":\"\",\"pic1\":\"https://www.u2game99.com/data/upload/game/20251128/692947bbb82f5.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1631\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/163