INSERT INTO `gb_games` VALUES (115, 1, NULL, '黑暗信仰（0.05折福利版）', NULL, NULL, '经营', 'discount', 'https://cp.u2game99.com/storage/operator/20251127/ddfd94bc2d4700ff690b4dcb9c4061b6.png', 'https://cp.u2game99.com/storage/operator/20251127/b5d5b82618a666db8df962db6bc1cafd.jpg', '[\"https://cp.u2game99.com/storage/operator/20251127/b6e860adbd1d97c82bc7fb61f7e18733.jpg\", \"https://cp.u2game99.com/storage/operator/20251127/5655e646f1f3df1bcca326daacf8b001.jpg\", \"https://cp.u2game99.com/storage/operator/20251127/f0cfcd20d07055048fc7e533ef6c9a23.jpg\", \"https://cp.u2game99.com/storage/operator/20251127/9316607198fd14475b2023eac91eb6a4.jpg\", \"https://cp.u2game99.com/storage/operator/20251127/01817a5ccfdd085700e7ede70bbb6957.jpg\"]', 'https://mp4.277sy.com/sp/14040.mp4', '《黑暗信仰（0.05折福利版）》是一款二次元美女代言人养成的模拟人生经营类游戏。全新0.05折福利版本，超多款动漫女神代言人等你招募组成专属代言人团队，作为一个已经在广告界摸爬滚打好几年的你，将真实模拟创业，招募各类代言人经营各类代言以提升收益和商业身份、最终成为商业大亨，同时游戏内具备丰富的养成系统，女神代言人、可萌宠物、炫酷跑车等，招募动漫女神，极致奢华的体验，斗智斗勇争夺市场，合理搭配资源，各类经典玩法等你探索征服！！游戏精彩活动不间断，赶紧来组建最强代言设计人，轰动整个设计界成为知名大咖！！', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1642', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1642', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1642', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1642', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-11-25 09:59:10', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:39', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"《黑暗信仰（0.05折福利版）》是一款二次元美女代言人养成的模拟人生经营类游戏。\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/14040.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"经营\",\"addtime\":\"2025-11-25 09:59:10\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20251127/ddfd94bc2d4700ff690b4dcb9c4061b6.png\",\"version\":0,\"c_version\":0,\"downurl\