INSERT INTO `gb_games` VALUES (117, 1, NULL, '真·战三国（0.05折全武将送千充）', NULL, NULL, '卡牌', 'discount', 'https://cp.u2game99.com/storage/operator/20251124/548d7eb7bdd0cc60bf3a939c3bea7e4d.gif', 'https://cp.u2game99.com/storage/operator/20251124/9f7c56e86659eca0ec72d18a1acb13f8.jpg', '[\"https://cp.u2game99.com/storage/operator/20251124/d9824d22a7bded444a8da898549fc856.jpg\", \"https://cp.u2game99.com/storage/operator/20251124/3e8049b1bd6f21c01393dc9fc0ae9b59.jpg\", \"https://cp.u2game99.com/storage/operator/20251124/3a9fbea2b590c967ddb752b3621eac30.jpg\", \"https://cp.u2game99.com/storage/operator/20251124/3756d80ed60f93b6a3f65e999855d8a6.jpg\", \"https://cp.u2game99.com/storage/operator/20251124/46c7740bb7d2696cebd84c8fdc1d1c3b.jpg\"]', 'https://mp4.277sy.com/sp/14024.mp4', '《真战三国》一款以三国乱世为背景的战争策略类手游，烽烟蔽日山河碎，豪杰横空乱世生！邀您执剑入局，亲赴万箭齐发的赤壁、铁甲轰鸣的长坂坡，在史诗级古战场上书写传奇！实时国战将九州烽火点燃，百万雄师在同一屏幕上激烈厮杀，云梯和撞车破城而入，洛阳、许昌、成都，每一座城池都是血与火交织的勋章。更有经典战役在此复刻，领地经营中暗藏玄机。通过升星、天赋、宝物和神器等多维度的养成方式，打造一支无与伦比的军团。在乱世之中，是选择偏安一隅，还是勇往直前逐鹿中原？踏入这片壮丽的大地图，用刀剑书写属于你的三国传奇，一统山河就在今朝！', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1628', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1628', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1628', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1628', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-11-20 10:09:21', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:39', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"每日送千元代金，活跃再送永久代金券。\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/14024.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-11-20 10:09:21\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20251124/548d7eb7bdd0cc60bf3a939c3bea7e4d.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1628\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/1628.html\",\"weburl_qr\":\"[base64已省略]\",\"dwzdownurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1628\",\"downurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1628\",\"dwzdownurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1628\",\"gamename\":\"真·战三国（0.05折全武将送千充）\",\"excerpt\":\"《真战三国》一款以三国乱世为背景的战争策略类手游，烽烟蔽日山河碎，豪杰横空乱世生！邀您执剑入局，亲赴万箭齐发的赤壁、铁甲轰鸣的长坂坡，在史诗级古战场上书写传奇！实时国战将九州烽火点燃，百万雄师在同一屏幕上激烈厮杀，云梯和撞车破城而入，洛阳、许昌、成都，每一座城池都是血与火交织的勋章。更有经典战役在此复刻，领地经营中暗藏玄机。通过升星、天赋、宝物和神器等多维度的养成方式，打造一支无与伦比的军团。在乱世之中，是选择偏安一隅，还是勇往直前逐鹿中原？踏入这片壮丽的大地图，用刀剑书写属于你的三国传奇，一统山河就在今朝！\",\"id\":1628,\"game_source\":\"\",\"device_type\":2,\"edition\":1,\"pic_xuanchuan\":\"\",\"strict\":0,\"userfc\":0,\"updatetime\":\"2025-12-02 09:00:00\",\"box_content\":\"1.游戏内充值全部0.05折，特权解锁无限资源每日再领3280充值卡！三国霸业起步即巅峰\\r\\n2.签到送全武将！0元解锁全阵容，强度武魂直接拉满\\r\\n3. 嘉年华赠送满星刘备！玄德执剑立帐前，蜀汉霸业启新篇\\r\\n4. 闯关解锁满星张飞！翼德横矛破敌阵，通关即获万夫勇\\r\\n5. 每日天降1000 代金券！零氪也能战巅峰，真金福利天天领\\r\\n6. 签到双礼震撼来袭！核心红将 +1000充值券，神将福利两手抓\\r\\n7. 每日活跃赠送永久代金券！越肝越赚无上限，福利永不打烊\\r\\n8. 天天 100 连抽狂欢！千卡保底任你开，欧气爆棚出绝世\",\"pic2\":\"https://cp.u2game99.com/storage/operator/20251124/9f7c56e86659eca0ec72d18a1acb13f8.jpg\",\"pic3\":\"https://www.u2game99.com/data/upload/game/20251125/69254e72c8a68.jpg\",\"pic4\":\"https://www.u2game99.com/data/upload/game/20251125/69254e7eda92d.jpg\",\"cps_ratio\":0,\"hw_ratio\":0,\"hw_firstpay\":0.005,\"hw_otherpay\":0.005,\"firstpay\":0.005,\"otherpay\":0.005}');
