INSERT INTO `gb_games` VALUES (132, 1, NULL, '耀世格斗（0.05双倍代金券版）', NULL, NULL, '卡牌', 'discount', 'https://cp.u2game99.com/storage/operator/20251111/8ddda276dd14dcbaba80695b61d0c846.gif', 'https://cp.u2game99.com/storage/operator/20251111/c6871df69e7fd4688e4cf3d15a0191c7.jpg', '[\"https://cp.u2game99.com/storage/operator/20251111/88a9fc0a8fe33e973e75f1c0e7a8ebdc.jpg\", \"https://cp.u2game99.com/storage/operator/20251111/a2427322b05d3efb7086a6b43b832bec.jpg\", \"https://cp.u2game99.com/storage/operator/20251111/16e12ab5eb29bc200bb906df75243932.jpg\", \"https://cp.u2game99.com/storage/operator/20251111/ef0b74129cdd5f39b11879bc7e458c5c.jpg\", \"https://cp.u2game99.com/storage/operator/20251111/00c6768086e9d254b527d9abf06884b2.jpg\"]', 'https://mp4.277sy.com/sp/13979.mp4', '耀世格斗是一款龙珠IP挂机卡牌游戏，可获取并使用龙珠IP里的大部分经典人物。\r\n除了最经典的龙珠与龙珠Z的人物外，游戏还汇集了龙珠GT、龙珠超、龙珠超级英雄等其他世界观里的龙珠人物。\r\n在游戏中，玩家将扮演一位在龙珠世界里游历的小队长，收集并培养自己喜欢的英雄队伍，体验最经典的龙珠激斗，\r\n并在挂机模式下自动战斗，享受轻松的游戏乐趣。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1589', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1589', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1589', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1589', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-11-11 15:43:21', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:40', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"耀世格斗是一款龙珠IP挂机卡牌游戏。\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13979.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-11-11 15:43:21\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20251111/8ddda276dd14dcbaba80695b61d0c846.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1589\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/1589.html\",\"weburl_qr\":\"[base64已省略]\",\"dwzdownurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1589\",\"downurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1589\",\"dwzdownurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1589\",\"gamename\":\"耀世格斗（0.05双倍代金券版）\",\"excerpt\":\"耀世格斗是一款龙珠IP挂机卡牌游戏，可获取并使用龙珠IP里的大部分经典人物。\\r\\n除了最经典的龙珠与龙珠Z的人物外，游戏还汇集了龙珠GT、龙珠超、龙珠超级英雄等其他世界观里的龙珠人物。\\r\\n在游戏中，玩家将扮演一位在龙珠世界里游历的小队长，收集并培养自己喜欢的英雄队伍，体验最经典的龙珠激斗，\\r\\n并在挂机模式下自动战斗，享受轻松的游戏乐趣。\",\"id\":1589,\"game_source\":\"\",\"device_type\":2,\"edition\":1,\"pic_xuanchuan\":\"\",\"strict\":0,\"userfc\":1,\"updatetime\":\"2025-11-27 08:00:00\",\"box_content\":\"1.全场充值0.05折\\r\\n所有充值项0.05折，原价648现仅需3.24即可购买。首次购买9900代金券更可享50%超值返利。\\r\\n2.充值返100%代金券\\r\\n任意充值即刻返现百分百代金券，充多少返多少，一次充值双倍福利！\\r\\n3.每日送代金券加倍升级，完成任务每日即可领取1000代金券，福利拿到手软！\\r\\n4.海量代金券、充值卡免费送\\r\\n推动主线提升等级还可额外获赠海量代金券，最高可得万元代金券！不花钱也能拿钻石、升VIP，轻松变大佬！\\r\\n5.高星超强队伍、超人气英雄免费送\\r\\n推动游戏进程、完成活动任务即可免费获得11星超强输出队伍及超人气英雄超蓝悟空，通关还送最强单体爆发T0战力超赛悟空，轻松冲榜。\\r\\n6.升特权拿野兽孙悟饭\\r\\n升级特权可拿野兽孙悟饭，最高可获六个，轻松升级获取英雄两不误。\\r\\n7.免费送千抽\\r\\n每日登录即可获得免费抽卡次数。累计最高可获得1500抽。\",\"pic2\":\"https://cp.u2game99.com/storage/operator/20251111/c6871df69e7fd4688e4cf3d15a0191c7.jpg\",\"pic3\":\"https://www.u2game99.com/data/upload/game/20251111/6913000cce80f.jpg\",\"pic4\":\"https://www.u2game99.com/data/upload/game/20251111/691300141a7b6.jpg\",\"cps_ratio\":0,\"hw_ratio\":0,\"hw_firstpay\":0.005,\"hw_otherpay\":0.005,\"firstpay\":0.005,\"otherpay\":0.005}');
INSERT INTO `gb_games` VALUES (133, 1, NULL, '调皮小动物（0.1折）', NULL, NULL, '卡牌', 'discount', 'https://cp.u2game99.com/storage/operator/20251121/89e386d0e0c2ba4fdc8d0653684e53d7.png', 'https://cp.u2game99.com/storage/operator/20251121/d1a9d939c71aae8315562e7a8fd3d9d3.jpg', '[\"https://cp.u2game99.com/storage/operator/20251121/6e3dc39effee7688f2dcc7451285296a.jpg\", \"https://cp.u2game99.com/storage/operator/20251121/8d141aec32450eb828634ba9b32389a5.jpg\", \"https://cp.u2game99.com/storage/operator/20251121/ec738dea2ffdc3f354a1e60ae784469d.jpg\", \"https://cp.u2game99.com/storage/operator/20251121/e97af52fe0c90113b668e8c264f9edaa.jpg\", \"https://cp.u2game99.com/storage/operator/20251121/1cc88479ddf21261fe8d3afaca871bdd.jpg\"]', 'https://mp4.277sy.com/sp/13995.mp4', '《调皮小动物》是一款0.1折的模拟经营游戏。在文明独特的动物世界里，你收到了二大爷留下来的遗产并开启了创业之旅。在探索地下洞穴的同时结识各种员工共筑商业帝国，你将派遣员工与地下承包商谈判开发其他洞穴，将打造萌宠庄园享受悠闲时光，将学习制作料理成为一代食神，还有更多趣味玩法等着你！来建立一个属于你的商业帝国吧！', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1601', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1601', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1601', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1601', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-11-13 16:23:40', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:40', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"轻松治愈模拟经营手游，自由打造动物商业帝国！\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13995.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-11-13 16:23:40\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:0\",\"hw_cps_cpa\":\"CPS推广:30\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20251121/89e386d0e0c2ba4fdc8d0653684e53d7.png\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1601\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/1601.html\",\"weburl_qr\":\"[base64已省略]\",\"dwzdownurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1601\",\"downurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1601\",\"dwzdownurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1601\",\"gamename\":\"调皮小动物（0.1折）\",\"excerpt\":\"《调皮小动物》是一款0.1折的模拟经营游戏。在文明独特的动物世界里，你收到了二大爷留下来的遗产并开启了创业之旅。在探索地下洞穴的同时结识各种员工共筑商业帝国，你将派遣员工与地下承包商谈判开发其他洞穴，将打造萌宠庄园享受悠闲时光，将学习制作料理成为一代食神，还有更多趣味玩法等着你！来建立一个属于你的商业帝国吧！\",\"id\":1601,\"game_source\":\"\",\"device_type\":2,\"edition\":1,\"pic_xuanchuan\":\"\",\"strict\":0,\"userfc\":0,\"updatetime\":\"2025-11-26 10:00:00\",\"box_content\":\"1、终身0.1折，一分耕耘，百倍收获！\\r\\n2、天道酬勤，千抽狂欢盛宴梦幻开局！\\r\\n3、每日签到，ss级员工免费领！\",\"pic2\":\"https://cp.u2game99.com/storage/operator/20251121/d1a9d939c71aae8315562e7a8fd3d9d3.jpg\",\"pic3\":\"https://www.u2game99.com/data/upload/game/20251124/6923b7939d884.png\",\"pic4\":\"https://www.u2game99.com/data/upload/game/20251124/6923b79d85488.png\",\"cps_ratio\":0,\"hw_ratio\":0,\"hw_firstpay\":0.01,\"hw_otherpay\":0.01,\"firstpay\":0.01,\"otherpay\":0.01}');
INSERT INTO `gb_games` VALUES (134, 1, NULL, '逍遥九重天（登录送自选SP）', NULL, NULL, '卡牌', 'discount', 'https://www.u2game99.com/data/upload/game/20251125/6925026d12183.gif', 'https://cp.u2game99.com/storage/operator/20251118/4da51e782e5a5460f0adef821f733e37.jpg', '[\"https://cp.u2game99.com/storage/operator/20251118/60b77c17e97203c68f6989492dce5e72.jpg\", \"https://cp.u2game99.com/storage/operator/20251118/48966d511e21e955d0a16f0851f84a0e.jpg\", \"https://cp.u2game99.com/storage/operator/20251118/dde97cc2c4594d0cd8794b95242a3876.jpg\", \"https://cp.u2game99.com/storage/operator/20251118/1450a9466ab2692975a617a8a9424cba.jpg\", \"https://cp.u2game99.com/storage/operator/20251118/191df6c29ca06ffae68d0af0bbe16fa4.jpg\"]', 'https://mp4.277sy.com/sp/14000.mp4', '《逍遥九重天》是一款国风修仙养成手游。上古时期，魔尊罗睺与诸神决战，因力竭不敌，盛怒之下欲自爆元神与诸神同归于尽。此时无极仙尊站了出来，以自身化为结界，消弭了这场浩劫。\r\n魔尊罗睺和无极双双陨落后，徒留一缕神识堕入人间，在历经沧桑后，凝聚成为了天地灵胎。沧海桑田，须臾万年。作为天地灵胎转世的你，即将踏上入世修仙之路，寻觅属于自己的机缘。在你离开仙山那一刻，整个仙魔世界都有所感，于是，一场新的仙魔争端，就此展开……', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1605', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1605', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1605', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1605', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-11-14 14:06:19', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:40', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"登陆免费获取万抽\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/14000.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-11-14 14:06:19\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://www.u2game99.com/data/upload/game/20251125/6925026d12183.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1605\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/1605.html\",\"weburl_qr\":\"[base64已省略]\",\"dwzdownurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1605\",\"downurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1605\",\"dwzdownurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1605\",\"gamename\":\"逍遥九重天（登录送自选SP）\",\"excerpt\":\"《逍遥九重天》是一款国风修仙养成手游。上古时期，魔尊罗睺与诸神决战，因力竭不敌，盛怒之下欲自爆元神与诸神同归于尽。此时无极仙尊站了出来，以自身化为结界，消弭了这场浩劫。\\r\\n魔尊罗睺和无极双双陨落后，徒留一缕神识堕入人间，在历经沧桑后，凝聚成为了天地灵胎。沧海桑田，须臾万年。作为天地灵胎转世的你，即将踏上入世修仙之路，寻觅属于自己的机缘。在你离开仙山那一刻，整个仙魔世界都有所感，于是，一场新的仙魔争端，就此展开……\",\"id\":1605,\"game_source\":\"\",\"device_type\":2,\"edition\":1,\"pic_xuanchuan\":\"\",\"strict\":0,\"userfc\":1,\"updatetime\":\"2025-11-26 09:00:00\",\"box_content\":\"【仙游三界】万抽福利登陆即可领取，连续领取还可再提稀有SP神将\\r\\n【签到盲盒】每日签到免费领取海量灵玉，激活特权更有机会获得“太古玉如意”\\r\\n【在线奖励】在线领取随机SSR神将，还有SSR+自选宝箱免费拿\\r\\n【登陆好礼】连续登陆可领SSR+妖族核心-孙悟空，还有多种壕礼领不停\\r\\n【通关主线】闯主关-招募卷、SSR碎片等等资源拿不停\",\"pic2\":\"https://cp.u2game99.com/storage/operator/20251118/4da51e782e5a5460f0adef821f733e37.jpg\",\"pic3\":\"https://www.u2game99.com/data/upload/game/20251119/691d17b678575.jpg\",\"pic4\":\"https://www.u2game99.com/data/upload/game/20251125/69257f71999cc.jpg\",\"cps_ratio\":0,\"hw_ratio\":0,\"hw_firstpay\":0.3,\"hw_otherpay\":0.3,\"firstpay\":0.3,\"otherpay\":0.3}');
INSERT INTO `gb_games` VALUES (135, 1, NULL, '萌星物语（登录送5星英雄）', NULL, NULL, '卡牌', 'discount', 'https://cp.u2game99.com/storage/operator/20251124/d105df0a67ccd2ee92fd379de7230c73.png', 'https://cp.u2game99.com/storage/operator/20251124/c01f0eb5e37c460a8b6535df20c604f9.jpg', '[\"https://www.u2game99.com/data/upload/game/20251209/6937e795536e4.jpg\", \"https://www.u2game99.com/data/upload/game/20251209/6937e79a2bf55.jpg\", \"https://www.u2game99.com/data/upload/game/20251209/6937e79f07174.jpg\", \"https://www.u2game99.com/data/upload/game/20251209/6937e7a40c04d.jpg\", \"https://www.u2game99.com/data/upload/game/20251209/6937e7a95255f.jpg\"]', 'https://mp4.277sy.com/sp/13905.mp4', '《萌星物语（登录送5星英雄）》是一款动作卡牌放置手游，英雄组合、策略搭配由你操控！游戏玩法多样，奖励丰厚，放置挂机、轻松休闲，彻底解放双手。在伊利翁大陆，玩家可通过英雄搭配创造出瞬息万变的战局，实现技能打断、集火、击杀、技能组合等众多高阶玩法，趣味性十足。游戏中超爽的抽卡体验、绚烂的英雄技能、多样的技能组合等着你的探索，赶快加入《萌星物语》来体验不一样的爽快吧！', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1518', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1518', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1518', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1518', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-10-23 14:21:53', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:40', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"《萌星物语（登录送5星英雄）》是一款动作卡牌放置手游\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13905.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-10-23 14:21:53\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:0\",\"hw_cps_cpa\":\"CPS推广:30\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20251124/d105df0a67ccd2ee92fd379de7230c73.png\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1518\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/1518.html\",\"weburl_qr\":\"[base64已省略]\",\"dw