INSERT INTO `gb_games` VALUES (143, 1, NULL, '无尽寒冬（玄蛇高爆打金）', NULL, NULL, '挂机', 'bt', 'https://cp.u2game99.com/storage/operator/20251121/c69a121c5780328d13865bf034d23e1a.gif', 'https://cp.u2game99.com/storage/operator/20251121/76b11b488ab34c5801a182256507a1a2.jpg', '[\"https://cp.u2game99.com/storage/operator/20251121/e951240b8e0f6c2ae464f35f70576e75.jpg\", \"https://cp.u2game99.com/storage/operator/20251121/a764d4f6f7d57b4f96e39d5689099614.jpg\", \"https://cp.u2game99.com/storage/operator/20251121/d293eaa5ee88ad58152fbd7bd5881657.jpg\", \"https://cp.u2game99.com/storage/operator/20251121/ef1e4046f7ca9dcf916a3f237ee98789.jpg\", \"https://cp.u2game99.com/storage/operator/20251121/70d413ba75479dfc7d0efe6b3ccbbaf8.jpg\"]', 'https://mp4.277sy.com/sp/14006.mp4', '无尽寒冬是一款重塑经典的传奇手游巨作，以其独特的魅力和海量福利，引领着玩家们踏上一场前所未有的冒险之旅。这款游戏不仅仅是对昔日经典的致敬，更是融入了创新元素，为玩家们带来耳目一新的游戏体验。\r\n【福利盛宴，全民狂欢】 踏入《无尽寒冬》的广袤世界，你会发现这里不仅打怪能够爆出充币，让每一场战斗都充满价值，每日签到更有真充奖励相赠，确保每位玩家都能享受到实实在在的回馈。一上线，即可领取豪华大礼包，内含丰富的资源与道具，助你快速成长，踏上强者之路。\r\n【专属剧情，独有装备】 游戏特别设计了专属剧情线，让每个玩家都能沉浸在一个专属于自己的传奇故事中。随着剧情的推进，你将有机会获得独一无二的专属装备，这些装备不仅外观华丽，更是拥有强大的属性加成，是散人玩家的福音，让你在没有团队支持的情况下也能所向披靡。\r\n【极速战斗，畅爽体验】 《无尽寒冬》优化了战斗系统，实现了超高速的攻速和极具震撼力的切割效果，让每一次战斗都变得畅快淋漓。2024年全新推出的福利版本，更是在游戏平衡性和可玩性上下足了功夫，确保每位玩家都能享受到极致的游戏乐趣。\r\n【广阔世界，无尽探索】 游戏世界地图广阔无垠，包含多个风格迥异的大陆，每个大陆都有其独特的故事和挑战，等待着勇者们去揭开它们的秘密。全新的奖励体系覆盖游戏的每一个角落，无论是探索未知地域、完成艰巨任务还是挑战强大BOSS，都有丰厚的奖励等着你，助你在称霸路上一往无前。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1611', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1611', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1611', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1611', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-11-14 15:12:46', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:40', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"无尽寒冬是一款重塑经典的传奇手游巨作，\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/14006.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"挂机\",\"addtime\":\"2025-11-14 15:12:46\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:65\",\"hw_cps_cpa\":\"CPS海外推广:45\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20251121/c69a121c5780328d13865bf034d23e1a.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1611\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/1611.html\",\"weburl_qr\":\"[base64已省略]\",\"dwzdownurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1611\",\"downurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1611\",\"dwzdownurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1611\",\"gamename\":\"无尽寒冬（玄蛇高爆打金）\",\"excerpt\":\"无尽寒冬是一款重塑经典的传奇手游巨作，以其独特的魅力和海量福利，引领着玩家们踏上一场前所未有的冒险之旅。这款游戏不仅仅是对昔日经典的致敬，更是融入了创新元素，为玩家们带来耳目一新的游戏体验。\\r\\n【福利盛宴，全民狂欢】 踏入《无尽寒冬》的广袤世界，你会发现这里不仅打怪能够爆出充币，让每一场战斗都充满价值，每日签到更有真充奖励相赠，确保每位玩家都能享受到实实在在的回馈。一上线，即可领取豪华大礼包，内含丰富的资源与道具，助你快速成长，踏上强者之路。\\r\\n【专属剧情，独有装备】 游戏特别设计了专属剧情线，让每个玩家都能沉浸在一个专属于自己的传奇故事中。随着剧情的推进，你将有机会获得独一无二的专属装备，这些装备不仅外观华丽，更是拥有强大的属性加成，是散人玩家的福音，让你在没有团队支持的情况下也能所向披靡。\\r\\n【极速战斗，畅爽体验】 《无尽寒冬》优化了战斗系统，实现了超高速的攻速和极具震撼力的切割效果，让每一次战斗都变得畅快淋漓。2024年全新推出的福利版本，更是在游戏平衡性和可玩性上下足了功夫，确保每位玩家都能享受到极致的游戏乐趣。\\r\\n【广阔世界，无尽探索】 游戏世界地图广阔无垠，包含多个风格迥异的大陆，每个大陆都有其独特的故事和挑战，等待着勇者们去揭开它们的秘密。全新的奖励体系覆盖游戏的每一个角落，无论是探索未知地域、完成艰巨任务还是挑战强大BOSS，都有丰厚的奖励等着你，助你在称霸路上一往无前。\",\"id\":1611,\"game_source\":\"\",\"device_type\":2,\"edition\":2,\"pic_xuanchuan\":\"\",\"strict\":0,\"userfc\":0,\"updatetime\":\"2025-11-23 08:00:00\",\"box_content\":\"1、超变神器单职业，玩法多，搭配多！\\r\\n2、低消打金，活动奖励多，上线即开爽！\\r\\n3、怪好打，装备好打，地图也多！\\r\\n4、大陆多，系统多！让你不会枯燥！\\r\\n5、攻城热血，公会攻沙，紫禁之巅，决出王者！\",\"pic2\":\"https://cp.u2game99.com/storage/operator/20251121/76b11b488ab34c5801a182256507a1a2.jpg\",\"pic3\":\"https://www.u2game99.com/data/upload/game/20251121/692016a627784.jpg\",\"pic4\":\"https://www.u2game99.com/data/upload/game/20251121/692016ae29a05.jpg\",\"cps_ratio\":0,\"hw_ratio\":0,\"hw_firstpay\":1,\"hw_otherpay\":1,\"firstpay\":1,\"otherpay\":1}');
