INSERT INTO `gb_games` VALUES (153, 1, NULL, '勇者大暴走(0.05折千元代金升级版)', NULL, NULL, '卡牌', 'discount', 'https://cp.u2game99.com/storage/operator/20251118/77bacf77ec16a954df4c3663607d6c51.gif', 'https://cp.u2game99.com/storage/operator/20251118/d82ce831e0ee52b5b91f859dabd957cb.jpg', '[\"https://cp.u2game99.com/storage/operator/20251118/0b10df0715c1b4b8c81c0bb2cc08a2b5.jpg\", \"https://cp.u2game99.com/storage/operator/20251118/16ad1bb3286ee51b810479d2acbcecb8.jpg\", \"https://cp.u2game99.com/storage/operator/20251118/cace4934f3b54d39c5a10a6f0461fe0e.jpg\", \"https://cp.u2game99.com/storage/operator/20251118/066939087e1b530c25f99fa463df6016.jpg\", \"https://cp.u2game99.com/storage/operator/20251118/473eed481efcd16c668f958147c60c84.jpg\"]', 'https://mp4.277sy.com/sp/14001.mp4', '《勇者大暴走》是一款以修仙世界中觉醒的\"天命者\"为主视角展开的卡牌RPG手游。玩家将穿越至破碎重组的洪荒世界，在仙魔共存的洪荒大陆上，既能修炼古老秘术，又可驾驭各种玄幻坐骑，与幻化人形的上古神兽、觉醒器灵的洪荒至宝并肩作战，在虚实交织的世界中书写属于自己的传奇史诗。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1607', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1607', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1607', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1607', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-11-14 14:32:01', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:40', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"别卷了，一起修仙吧！\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/14001.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-11-14 14:32:01\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20251118/77bacf77ec16a954df4c3663607d6c51.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1607\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/1607.html\",\"weburl_qr\":\"[base64已省略]\",\"dwzdownurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1607\",\"downurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1607\",\"dwzdownurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1607\",\"gamename\":\"勇者大暴走(0.05折千元代金升级版)\",\"excerpt\":\"《勇者大暴走》是一款以修仙世界中觉醒的\\\"天命者\\\"为主视角展开的卡牌RPG手游。玩家将穿越至破碎重组的洪荒世界，在仙魔共存的洪荒大陆上，既能修炼古老秘术，又可驾驭各种玄幻坐骑，与幻化人形的上古神兽、觉醒器灵的洪荒至宝并肩作战，在虚实交织的世界中书写属于自己的传奇史诗。\",\"id\":1607,\"game_source\":\"\",\"device_type\":2,\"edition\":1,\"pic_xuanchuan\":\"\",\"strict\":0,\"userfc\":0,\"updatetime\":\"2025-11-20 09:00:00\",\"box_content\":\"★【永久0.05折】648元只需要3.24元！绝对真实！\\r\\n★【每日代金】首日起每天均送1000代金券，更可升级成2000代金券，福利多多！\\r\\n★【版本福利】开局即送9大特权卡，9大特权免费激活，永久白嫖！\\r\\n★【创角福利】创角白嫖绝版称号，再送极品橙色伙伴及大量货币！\\r\\n★【刷金福利】每日开启宝箱均有几率额外获得随机数量的红包，红包可用于充值货币或购买刷金礼包，还可用于兑换灵石、金石、伙伴招募等奖励！\\r\\n★【在线福利】在线即可获得1648现金点和600连抽，极品伙伴&amp;兽灵随便抽，修仙之路不孤单！\\r\\n★【活跃福利】日常任务每天送100现金点！\\r\\n★【通关奖励】赠送2000伙伴招募+2000兽灵招募+20万现金点！主线通关每章还送100现金券！\\r\\n★【放置挂机】佛系修仙，自动推关解放双手，一身神装轻轻松松！\",\"pic2\":\"https://cp.u2game99.com/storage/operator/20251118/d82ce831e0ee52b5b91f859dabd957cb.jpg\",\"pic3\":\"https://www.u2game99.com/data/upload/game/20251119/691d276407528.jpg\",\"pic4\":\"https://www.u2game99.com/data/upload/game/20251119/691d276cd60fa.jpg\",\"cps_ratio\":0,\"hw_ratio\":0,\"hw_firstpay\":0.005,\"hw_otherpay\":0.005,\"firstpay\":0.005,\"otherpay\":0.005}');
INSERT INTO `gb_games` VALUES (154, 1, NULL, '风之剑舞（0.1折神契）', NULL, NULL, '卡牌', 'discount', 'https://www.u2game99.com/data/upload/game/20251203/692fe516dc3f8.gif', 'https://www.u2game99.com/data/upload/game/20251203/692fe526e4540.jpg', '[\"https://www.u2game99.com/data/upload/game/20251203/692fe56617f44.jpg\", \"https://www.u2game99.com/data/upload/game/20251203/692fe56b53eaf.jpg\", \"https://www.u2game99.com/data/upload/game/20251203/692fe57040fd4.jpg\", \"https://www.u2game99.com/data/upload/game/20251203/692fe575d0af0.jpg\", \"https://www.u2game99.com/data/upload/game/20251203/692fe57a6c8f9.jpg\"]', 'https://mp4.277sy.com/sp/13962.mp4', '天地巨变神明有缺，当诸神陨落成星，你作为被众神选中的指引者，将继承残缺神格踏入这场横跨三千维度、贯穿东西方神话的异界大陆，在这个多元种族魔法交织的世界里重塑秩序！\r\n在这里，常胜将军赵子龙的龙胆亮银枪尖迸发的星芒能冻结时间之河；战争女神雅典娜能与东方仙术共鸣，魔王撒旦与齐天大圣孙悟空在时空展开维度战争。\r\n他们都将成为你麾下最强战力，改写诸神黄昏的史诗由你执笔，此刻，觉醒神格，撕裂时空，以凡人之躯点燃全息魔幻世界的终极狂想盛宴，风之剑舞（0.1折神契）大门已经敞开，而你，就是那个主导一切命运的主宰者！', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1573', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1573', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1573', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1573', 'android', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-11-06 16:44:47', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:40', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"0.1折开启神明契约，缔造你的异世界传说！\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13962.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-11-06 16:44:47\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:0\",\"hw_cps_cpa\":\"CPS推广:30\",\"coupon_repeat\":\"\",\"pic1\":\"https://www.u2game99.com/data/upload/game/20251203/692fe516dc3f8.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1573\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/1573.html\",\"weburl_qr\":\"