INSERT INTO `gb_games` VALUES (161, 1, NULL, '英雄如约而至(0.05折代金天天送)', NULL, NULL, '卡牌', 'discount', 'https://cp.u2game99.com/storage/operator/20251117/70a8b9fd367672e8ece316ba85e31ff5.gif', 'https://cp.u2game99.com/storage/operator/20251117/24a834f5d5c7117d10c09958befef9fb.jpg', '[\"https://cp.u2game99.com/storage/operator/20251117/207b091e30d14ec30c260e80ac28c808.jpg\", \"https://cp.u2game99.com/storage/operator/20251117/4a72d5639eb7ba009cc941de25ae1a33.jpg\", \"https://cp.u2game99.com/storage/operator/20251117/371ee33cd79ef225b4d52d9573ae8cbb.jpg\", \"https://cp.u2game99.com/storage/operator/20251117/3f15c1677cfe8393f965118608a99647.jpg\", \"https://cp.u2game99.com/storage/operator/20251117/22eefb54aeb2938a2a58afc11ccdda3d.jpg\"]', 'https://mp4.277sy.com/sp/13973.mp4', '即刻踏入二次元风格构筑的奇幻世界，开启一场交织着未知挑战与惊喜奇遇的塔防冒险之旅！在这里，没有枯燥的重复探索，只有充满新鲜感的关卡设计，每前进一步都可能遇见全新剧情与隐藏彩蛋。\r\n上百位风格迥异的精灵角色已整装待发，静待你的召唤。无论是萌系治愈型、酷飒输出型，还是辅助控场型，每个精灵都拥有独一无二的专属技能与背景故事。你可以自由搭配阵容，从技能互补到属性克制，在策略组合间打造出能横扫千军、无坚不摧的专属战队。\r\n随着冒险不断深入，丰厚福利将持续送达，稀有道具、限定资源轻松获取；全新卡牌也会逐步解锁，让你的队伍搭配有更多可能性，为旅程注入源源不断的新鲜与刺激。\r\n更值得期待的是，游戏采用放置对决的轻松操作模式，无需时刻紧盯屏幕，指尖轻点即可开启热血战斗。战斗时炫酷特效铺满全场，精灵技能释放极具冲击力，每一次交锋都是策略博弈与视觉盛宴的双重狂欢，带你沉浸式感受塔防卡牌对战的独特魅力！', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1583', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1583', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1583', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1583', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-11-10 13:53:32', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:40', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"主线通关原地暴富，代金券天天领花到手软！\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13973.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-11-10 13:53:32\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\