INSERT INTO `gb_games` VALUES (162, 1, NULL, '风暴迷城（0.1折每日1296代金）', NULL, NULL, '卡牌', 'discount', 'https://cp.u2game99.com/storage/operator/20251029/2f250d87e7f230182aa4f9a612443f8c.gif', 'https://cp.u2game99.com/storage/operator/20251029/5682690f95c21dab32ce9f0d560dcf1e.jpg', '[\"https://cp.u2game99.com/storage/operator/20251029/c43730be4e0ca2b8c7c4aa8663f3c533.jpg\", \"https://cp.u2game99.com/storage/operator/20251029/ce951f5fe6b451c7a36e3d26851ba842.jpg\", \"https://cp.u2game99.com/storage/operator/20251029/a40727a3a7295fdd6b3dc0d99831a9bf.jpg\", \"https://cp.u2game99.com/storage/operator/20251029/b06a01048ac2bfe276c146646ce25c6c.jpg\", \"https://cp.u2game99.com/storage/operator/20251029/ffdcf6de0c81df9a4cbb037492b0095f.jpg\"]', 'https://mp4.277sy.com/sp/13900.mp4', '《风暴迷城》是一款国风系、泛二次元、现代反穿越神话题材的概念范畴的回合制放置挂机卡牌游戏，《风暴迷城》的世界观中讲述了封神时代结束后各个界域被结界屏障封闭，使得各大界域无法流通，为了争夺灵气的故事。\r\n', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1514', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1514', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1514', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1514', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-10-22 11:15:13', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:40', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"每日送双倍648代金，签到再送648充值券。\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13900.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-10-22 11:15:13\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20251029/2f250d87e7f230182aa4f9a612443f8c.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1514\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/1514.html\",\"weburl_qr\":\"[base64已省略]\",\"dwzdownurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1514\",\"downurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1514\",\"dwzdownurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1514\",\"gamename\":\"风暴迷城（0.1折每日1296代金）\",\"excerpt\":\"《风暴迷城》是一款国风系、泛二次元、现代反穿越神话题材的概念范畴的回合制放置挂机卡牌游戏，《风暴迷城》的世界观中讲述了封神时代结束后各个界域被结界屏障封闭，使得各大界域无法流通，为了争夺灵气的故事。\\r\\n\",\"id\":1514,\"game_source\":\"\",\"device_type\":2,\"edition\":1,\"pic_xuanchuan\":\"\",\"strict\":0,\"userfc\":0,\"updatetime\":\"2025-11-18 09:00:00\",\"box_content\":\"【永久 0.1 折】：永久0.1超低折扣，首充不到一块钱直接把氪金自由揣兜里，再也不用费力攒钻！​\\r\\n【每日双份 648】：上线先领 648 代金券，做完日常再领 648，抽卡、买道具根本花不完，钻石堆成山！​\\r\\n【创角直接躺赢】：刚建号就送 SSR 后羿，输出拉满；还有万元充值券 + 绝版称号，主线直接一路平推！​\\r\\n【八日登录狂送】：第二天 SSR 随便选，第三天传说装备套到手，第八天直接抱走 SP 神话英雄，天天都有新惊喜！​\\r\\n【零氪满 V】：升级就给 VIP 经验，不用花钱，轻松冲到满 V，特权随便用，拒绝氪金绑架！​\\r\\n【签到白嫖 648】：每天签个到，648 充值卡直接领，日积月累直接攒出 “巨款”，福利简单到离谱！​\\r\\n【万抽爽到飞起】：天天都能抽，抽够万次还送 SP 神话英雄，欧气直接拉满，再也不用当 “非酋”！​\\r\\n【战力拿哪吒】：只要战力达标，顶级 SP 哪吒直接带回家，战力拉满后全服横着走，当大佬就是这么简单！\",\"pic2\":\"https://cp.u2game99.com/storage/operator/20251029/5682690f95c21dab32ce9f0d560dcf1e.jpg\",\"pic3\":\"https://www.u2game99.com/data/upload/game/20251030/6903316168cc9.jpg\",\"pic4\":\"https://www.u2game99.com/data/upload/game/20251030/6903316ac99a2.jpg\",\"cps_ratio\":0,\"hw_ratio\":0,\"hw_firstpay\":0.01,\"hw_otherpay\":0.01,\"firstpay\":0.01,\"otherpay\":0.01}');
INSERT INTO `gb_games` VALUES (163, 1, NULL, '破晓九天（0.05折返1倍现金券）', NULL, NULL, '卡牌', 'discount', 'https://cp.u2game99.com/storage/operator/20251118/e20733113fac041acde3b7a5bbd41fb6.gif', 'https://cp.u2game99.com/storage/operator/20251105/3ac7bec4f23d62aea16ff84690ff92be.jpg', '[\"https://cp.u2game99.com/storage/operator/20251105/22d967803bd7eb5533d9d220c79cb403.jpg\", \"https://cp.u2game99.com/storage/operator/20251105/37d024487c6971dc25e494a367c458ca.jpg\", \"https://cp.u2game99.com/storage/operator/20251105/0bd492083cf570738e28c1b0d4d7568c.jpg\", \"https://cp.u2game99.com/storage/operator/20251105/83d64fbaafa45e1573c9fa984cc40617.jpg\", \"https://cp.u2game99.com/storage/operator/20251105/b86b627d2cbb86ee540a8737f675f383.jpg\"]', 'https://mp4.277sy.com/sp/13958.mp4', '在《破晓九天》中，玩家将扮演一位三国时期的主公，与历史上著名的战略家和勇猛的武将们并肩作战。你需要收集不同的卡牌，每张卡牌代表一个武将，通过合理的搭配组成强大的阵容。卡牌的属性和技能各不相同，玩家可以根据自己的战术喜好进行选择，制定独特的战略。 除了卡牌搭配，还有各种战役和挑战等待着玩家去完成，通过战胜敌人，提升自己的排名和声望。 《破晓九天》采用了精美写实的画面风格，每一个战斗场景都充满了震撼力和视觉享受。游戏还精心打磨了角色形象和细节，让玩家能够感受到历史上伟大将领的英勇和智慧。 如果你是一个喜欢策略游戏和历史文化的爱好者，那么《破晓九天》将带给你前所未有的游戏体验。快来组建属于自己的三国强大阵容，征服敌人，成为真正的三国霸主！！\r\n', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1569', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1569', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1569', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1569', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-11-05 15:02:11', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:40', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"《破晓九天》是一款以中国古代经典历史文学《三国演义》为世界观背景的大型回合制策略卡牌手游。\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13958.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-11-05 15:02:11\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/2025111