INSERT INTO `gb_games` VALUES (166, 1, NULL, '天下无双HD（0.1折官途风云记）', NULL, NULL, '角色扮演', 'discount', 'https://cp.u2game99.com/storage/operator/20251112/d869a7dff2147fb6f0f6576b8a730d77.gif', 'https://cp.u2game99.com/storage/operator/20251112/4ea3976a54f04174456e79511e3484c3.jpg', '[\"https://cp.u2game99.com/storage/operator/20251112/a9cc58c73a3212a12c47c580f97a6e95.jpg\", \"https://cp.u2game99.com/storage/operator/20251112/47d4d6043e6e2753a4093b8ffb1917f5.jpg\", \"https://cp.u2game99.com/storage/operator/20251112/2ac7df24d53417f106b789b3e04a8c21.jpg\", \"https://cp.u2game99.com/storage/operator/20251112/a6b394fd092753fadb13d3159b79af17.jpg\", \"https://cp.u2game99.com/storage/operator/20251112/f9294cdef934f6591eae2e09cc0599fa.jpg\"]', 'https://mp4.277sy.com/sp/13950.mp4', '“你”作为主角，回到大明，出生贫寒，但刻苦读书，最终金榜题名，获得皇上御赐官位，从此身负重任，胸怀抱负，立志惩奸除恶，朝着成为“大官员”的目标砥砺前行，从九品芝麻官到一品官员，直至权倾朝野的故事，能够让玩家身临其境体检官场的尔虞我诈。\r\n游戏着重于玩法与剧情的相结合，让玩家回到古香古色的清廷世界。告别枯燥乏味的刷怪升级，抛弃模式单一的经营玩法，为玩家缔造了一出高潮迭起、剧情跌宕起伏的故事。\r\n钱权掌握手中，就必须有佳人作伴。柳叶眉，杏核眼，樱桃小口，杨柳细腰，说话燕语莺声，一顾倾城的佳人形象加上别具匠心的妻妾养成系统，让你在乱世之中尽显柔情。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1563', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1563', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1563', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1563', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-11-04 14:18:08', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:40', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"一款角色扮演的当官游戏\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13950.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"角色扮演\",\"addtime\":\"2025-11-04 14:18:08\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20251112/d869a7dff2147fb6f0f6576b8a730d77.gif\",\"version\":0,\"c_version\":0,\"down