INSERT INTO `gb_games` VALUES (170, 1, NULL, '魂之追梦（0.1折）', NULL, NULL, '卡牌', 'discount', 'https://cp.u2game99.com/storage/operator/20251114/e6af0217af44c4fdb7f80df5496805c5.png', 'https://cp.u2game99.com/storage/operator/20251114/23037b1b7625f2cdef8be9eef3af7bd0.jpg', '[\"https://cp.u2game99.com/storage/operator/20251114/4909bedc005081741cebfdea6a03610a.jpg\", \"https://cp.u2game99.com/storage/operator/20251114/9d3089f98e203e2ebeba5f0b4789f312.jpg\", \"https://cp.u2game99.com/storage/operator/20251114/952b7fdbd30091bbe31fbcb1ea7ec456.jpg\", \"https://cp.u2game99.com/storage/operator/20251114/0528eb9ef6d11692d8b02bfa20e0dd55.jpg\", \"https://cp.u2game99.com/storage/operator/20251114/087e3bb2b46162abe17fb91e6cb443bf.jpg\"]', 'https://mp4.277sy.com/sp/13941.mp4', '\"《魂之追梦》——当诸神相遇，谁主沉浮？\r\n在命运之树的庇护下，一座横跨东西的神殿之城巍然耸立。\r\n这里是奥林匹斯山的余晖与东方仙侠的云海交汇之地，是北欧战神与华夏猛将并肩作战的战场，踏上征服诸神之阶的荣耀之路！\r\n《魂之追梦》是一款融合西方神话史诗与东方传奇英雄的策略卡牌手游，带你穿越时空，集结亚瑟、奥丁、雷神托尔、孙悟空、吕布、宫本武藏等百位神魔英灵，开启一场跨越文明的终极之战！\r\n恢弘世界观：从北欧诸神到希腊众神，从埃及法老到凯尔特精灵，数百位神话英雄集结于此，等待你召唤觉醒。\r\n唯美画风：精致卡牌立绘，每一帧都宛如一幅神话画卷。\r\n海量英雄卡牌：UR、SSR、SR等稀有卡牌，通过“心愿召唤”、“幸运转盘”、“限时活动”获取，打造属于你的神之战队。\r\n自由搭配阵容：元素相克、技能联动、羁绊加成，策略深度拉满，每一场战斗都是智慧的较量！\"', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1554', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1554', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1554', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1554', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-11-03 14:17:10', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:40', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"《魂之追梦》——当诸神相遇，谁主沉浮？\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13941.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-11-03 14:17:10\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:0\",\"hw_cps_cpa\":\"CPS推广:30\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game