INSERT INTO `gb_games` VALUES (171, 1, NULL, '艾尔指挥官（0.1折决战无限城）', NULL, NULL, '卡牌', 'discount', 'https://cp.u2game99.com/storage/operator/20251114/546e6cdf2b78c9d5696f5a96cfbf831d.gif', 'https://cp.u2game99.com/storage/operator/20251114/3aa4cc1c09334be76a2263a3f9d39856.jpg', '[\"https://cp.u2game99.com/storage/operator/20251114/b0af8f57832878823ad0b80bdb5efd44.jpg\", \"https://cp.u2game99.com/storage/operator/20251114/4cf539475252a515a30a64f1b68146a6.jpg\", \"https://cp.u2game99.com/storage/operator/20251114/5dc1da73d4f7df0a01c241fdceb3ba73.jpg\", \"https://cp.u2game99.com/storage/operator/20251114/0fe76d007219cc134da331b751890a08.jpg\", \"https://cp.u2game99.com/storage/operator/20251114/3cc7a723054aa5645d9f353c7409df06.jpg\"]', 'https://mp4.277sy.com/sp/13957.mp4', '踏入《艾尔指挥官》的世界，一场惊心动魄的斩鬼冒险就此展开！\r\n在这里，你将化身鬼杀队的英勇战士，与灶门炭治郎、祢豆子等熟悉的角色并肩作战。运用水之呼吸、炎之呼吸等华丽且强大的技能，在刀光剑影中与恶鬼展开殊死搏斗。\r\n游戏完美复刻动漫经典场景，阴森的鬼屋、静谧的森林，每一处细节都栩栩如生，让你身临其境。紧张刺激的战斗节奏，拳拳到肉的打击感，给你带来前所未有的游戏体验。\r\n无论是单人挑战关卡，突破自我极限，还是与好友组队开黑，共同对抗强大的鬼王，都能让你感受到热血与激情。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1568', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1568', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1568', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1568', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-11-05 10:48:47', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:40', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"踏入《艾尔指挥官》的世界，一场惊心动魄的斩鬼冒险就此展开！\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13957.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-11-05 10:48:47\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20251114/546e6cdf2b78c9d5696f5a96cfbf831d.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1568\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/1568.html\",\"weburl_qr\":\"[base64已省略]\",\"dwzdownurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1568\",\"downurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1568\",\"dwzdownurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1568\",\"gamename\":\"艾尔指挥官（0.1折决战无限城）\",\"excerpt\":\"踏入《艾尔指挥官》的世界，一场惊心动魄的斩鬼冒险就此展开！\\r\\n在这里，你将化身鬼杀队的英勇战士，与灶门炭治郎、祢豆子等熟悉的角色并肩作战。运用水之呼吸、炎之呼吸等华丽且强大的技能，在刀光剑影中与恶鬼展开殊死搏斗。\\r\\n游戏完美复刻动漫经典场景，阴森的鬼屋、静谧的森林，每一处细节都栩栩如生，让你身临其境。紧张刺激的战斗节奏，拳拳到肉的打击感，给你带来前所未有的游戏体验。\\r\\n无论是单人挑战关卡，突破自我极限，还是与好友组队开黑，共同对抗强大的鬼王，都能让你感受到热血与激情。\",\"id\":1568,\"game_source\":\"\",\"device_type\":2,\"edition\":1,\"pic_xuanchuan\":\"\",\"strict\":0,\"userfc\":1,\"updatetime\":\"2025-11-15 09:00:00\",\"box_content\":\"★【永久0.1折】完美复刻动漫经典场景-无限城决战篇来袭，全新0.1折版本，绝对真实折扣！\\r\\n★【每日签到】每日领取不限时648元代金券，礼包买买买！\\r\\n★【创角福利】开局就送传说SSR炎柱“炼狱杏寿郎”，高频灼烧，烈系核心输出！\\r\\n★【七日签到】次日直升7星炼狱杏寿郎，5日直升10星炼狱杏寿郎，七日更有炼狱杏寿郎专武-狱焚涤罪！\\r\\n★【在线奖励】首日在线送整套千年血气自选，技能伤害暴涨！\\r\\n★【十万抽】达成活跃每日领取100抽，总计送出100000抽！\\r\\n★【鬼灭新秀】七日任务送5星神器“日轮刀”，斩邪驱鬼，所向披靡！\\r\\n★【产出翻倍】材料产出翻10倍！材料狗粮不用愁！\",\"pic2\":\"https://cp.u2game99.com/storage/operator/20251114/3aa4cc1c09334be76a2263a3f9d39856.jpg\",\"pic3\":\"https://www.u2game99.com/data/upload/game/20251114/6916eda626e0b.jpg\",\"pic4\":\"https://www.u2game99.com/data/upload/game/20251114/6916edb0d57af.jpg\",\"cps_ratio\":0,\"hw_ratio\":0,\"hw_firstpay\":0.01,\"hw_otherpay\":0.01,\"firstpay\":0.01,\"otherpay\":0.01}');
INSERT INTO `gb_games` VALUES (172, 1, NULL, '2047（0.1折天天送648）', NULL, NULL, '卡牌', 'discount', 'https://www.u2game99.com/data/upload/game/20251113/6915a3cc1a8c9.png', 'https://www.u2game99.com/data/upload/game/20251113/6915a3d69110b.jpg', '[\"https://www.u2game99.com/data/upload/game/20251113/6915a61708db8.jpg\", \"https://www.u2game99.com/data/upload/game/20251113/6915a61cc9279.jpg\", \"https://www.u2game99.com/data/upload/game/20251113/6915a6221e6c6.jpg\", \"https://www.u2game99.com/data/upload/game/20251113/6915a628d44e6.jpg\", \"https://www.u2game99.com/data/upload/game/20251113/6915a62e3122c.jpg\"]', 'https://mp4.277sy.com/sp/13965.mp4', '丧尸病毒正在全球蔓延！\r\n人类最大的堡垒城市Z城已遭入侵！您将统领不断壮大的军队征服此城，成为真正的领导者。同时必须在这崩坏的世界中学会生存之道。\r\n成为抵抗入侵的领袖\r\n在这片混乱中，您已将Z城设为根据地。高墙用以抵御尸群，保护墙内民众——他们是幸存者最后的希望。\r\n招募英雄增强实力\r\n入侵永无止境，尸潮将愈发凶猛。是时候招募更多英雄组建超凡战队，每位成员都拥有独特个性与能力。\r\n探索剧情收集物资\r\n生存需要人口、装备、补给和武器。探索未知领域获取资源，扩大要塞与势力范围。\r\n守护珍视之人\r\n作为指挥官，保护心爱的佳人是您的职责。与她们约会并提供安全庇护，记住她们既是人类最后的希望，也是这黑暗世界中的光芒。\r\n创建战盟协同作战\r\n您可与伙伴建立可靠战盟，通过谈判、战斗甚至背叛击溃敌人！与人性的博弈相比，屠杀丧尸不过是儿戏。\r\n处理政务重建家园\r\n建造发电厂与军火库、处理市政事务、强化城防巡逻、清理死亡公路、举办庆典...更重要的是携手重建家园，带领民众走向光明未来。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1575', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1575', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1575', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1575', 'android', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-11-07 09:28:58', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:40', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"末日重生，0.1折爽刷尸潮爆神装！天天送代金券！\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13965.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-11-07 09:28:58\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://www.u2game99.com/data/upload/game/20251113/6