INSERT INTO `gb_games` VALUES (173, 1, NULL, '荣耀战争（0.1折送十万充值）', NULL, NULL, '策略', 'discount', 'https://cp.u2game99.com/storage/operator/20251104/a810562a6aab0c965b98c2502f7a50b6.gif', 'https://cp.u2game99.com/storage/operator/20251104/b4778a2577a8f61becfafb6421683c40.jpg', '[\"https://cp.u2game99.com/storage/operator/20251104/1bc9f6f91a2e6c817384b11a185752bf.jpg\", \"https://cp.u2game99.com/storage/operator/20251104/c6b0ac4ba39686dcf8deeedc095ba6ee.jpg\", \"https://cp.u2game99.com/storage/operator/20251104/480d52a0422c7391e8b7f7468c7b87a6.jpg\", \"https://cp.u2game99.com/storage/operator/20251104/4627e4315a0262e4d6580fda133ca81e.jpg\", \"https://cp.u2game99.com/storage/operator/20251104/5d0b719267549da895c4a9d9f992b41e.jpg\"]', 'https://mp4.277sy.com/sp/13909.mp4', '《荣耀战争》是一款以未来科幻为理念的趣味塔防游戏。写实科幻的美术风格，结合庞大的世界观剧情，描绘出神秘的星际色彩，带给你全新刺激的宇宙冒险战斗。在这款游戏当中，你将化身为保卫宇宙，击退邪恶势力入侵的指挥官。联同四大阵营强势英雄人物，他们全员随时待命，听候指挥，立刻组建专属于你的军团阵容。更有烧脑策略、硬核副本、实时竞技等多种玩法，不断进行探索冒险。激烈战役将上演，等你开启身临其境的星战，谱写你的史诗荣耀。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1522', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1522', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1522', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1522', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-10-24 13:54:23', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:40', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"开局即最强输出，日常累送十万充值。\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13909.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"策略\",\"addtime\":\"2025-10-24 13:54:23\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20251104/a810562a6aab0c965b98c2502f7a50b6.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1522\",\"qrcode\":