INSERT INTO `gb_games` VALUES (174, 1, NULL, '新誓记（0.05折无限城决战）', NULL, NULL, '卡牌', 'discount', 'https://cp.u2game99.com/storage/operator/20251110/29d53ce588090ebf18f6d9b92b2a0c1a.gif', 'https://cp.u2game99.com/storage/operator/20251110/1d6ff9dd7829d8328662d28e44b008aa.jpg', '[\"https://cp.u2game99.com/storage/operator/20251110/13a740a7d6734310a64669d5111ea979.jpg\", \"https://cp.u2game99.com/storage/operator/20251110/7695c563a66d549481c7a8639bca972b.jpg\", \"https://cp.u2game99.com/storage/operator/20251110/dd29bf558c46a670cac813d1e66be678.jpg\", \"https://cp.u2game99.com/storage/operator/20251110/1fb27903644dbbc0e10d5e4736dc3468.jpg\", \"https://cp.u2game99.com/storage/operator/20251110/772f7ba13841b002884d398b87cc26e5.jpg\"]', 'https://mp4.277sy.com/sp/13850.mp4', '《新誓记》是一款国产3D狩猎共斗动作手游，主打真实物理碰撞打击感、跨服组队共斗和变身BOSS玩法，以日本战国武者对抗妖魔为背景，融合大世界探索与多武器战斗系统。', '禁海外推广', NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1466', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1466', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1466', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1466', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-09-28 14:41:50', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:40', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"鬼灭之刃，斩鬼觉醒！首续0.05折，创角即送超强UR无一郎\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13850.mp4\",\"text_cps\":\"禁海外推广\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-09-28 14:41:50\",\"gn_extension\":1,\"hw_extension\":0,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20251110/29d53ce588090ebf18f6d9b92b2a0c1a.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1466\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/1466.html\",\"weburl_qr\":\"[base64已省略]\",