INSERT INTO `gb_games` VALUES (190, 1, NULL, '剑开仙门(0.05折送无限抽)', NULL, NULL, '卡牌', 'discount', 'https://cp.u2game99.com/storage/operator/20251105/06e890d9744305b2ec71dcb46ba54e7a.gif', 'https://cp.u2game99.com/storage/operator/20251105/49bf03dd92f7a1618f2b3601b92969f7.jpg', '[\"https://cp.u2game99.com/storage/operator/20251105/8aa92da5466b200cc4b3e05403c2430f.jpg\", \"https://cp.u2game99.com/storage/operator/20251105/df91bd46974c1305b63521d907b4b031.jpg\", \"https://cp.u2game99.com/storage/operator/20251105/85fbe7498a8890c4ecfd06ab2302e34f.jpg\", \"https://cp.u2game99.com/storage/operator/20251105/59fbaaf1266f929c2c7339c4773bd21a.jpg\", \"https://cp.u2game99.com/storage/operator/20251105/bf7ff52bf41480150238549b24fdf8d6.jpg\"]', 'https://mp4.277sy.com/sp/13922.mp4', '化身转世大能，执掌一方仙门 ——《剑开仙门》以高自由度放置玩法，圆你专属修仙掌门梦！开局多种身份任选，从富贵世家到半魔血脉，灵根天赋各有乾坤。​\r\n宗门发展全凭心意：是潜心培养弟子，激活祝融、九尾等山海经神话角色的仙缘羁绊，还是派遣 “工具人” 打理丹房、灵田？挂机即可累积修为，轻松突破筑基、元婴等境界，离线也能稳步飞升。​\r\n踏遍山海寻机缘：昆仑仙山藏珍宝，异兽秘境遇彩蛋，更能征服千宗习得独门功法，或送茶论道广结仙缘。全新山海经版本已上线，捕捉毕方、应龙等异兽，争夺东皇钟等上古灵宝，组队跨服对抗魔界，声望与实力并肩成长。​\r\n无需肝氪也能畅享乐趣，每一次选择都是独属于你的仙门传奇！', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1535', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1535', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1535', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1535', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-10-28 16:12:54', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:41', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"执仙门，山海放置爽飞升\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13922.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-10-28 16:12:54\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20251105/06e890d9744305b2ec71dcb46ba54e7a.gif\",\"version\":0,\"c_v