INSERT INTO `gb_games` VALUES (192, 1, NULL, '魔法来袭（0.1折神域纪元）', NULL, NULL, '角色扮演', 'discount', 'https://www.u2game99.com/data/upload/game/20251121/692015204d565.gif', 'https://www.u2game99.com/data/upload/game/20251121/6920152749667.jpg', '[\"https://www.u2game99.com/data/upload/game/20251121/69201559056af.jpg\", \"https://www.u2game99.com/data/upload/game/20251121/6920155d80320.jpg\", \"https://www.u2game99.com/data/upload/game/20251121/692015622b08d.jpg\", \"https://www.u2game99.com/data/upload/game/20251121/692015666e7d4.jpg\", \"https://www.u2game99.com/data/upload/game/20251121/6920156d9e963.jpg\"]', 'https://mp4.277sy.com/sp/13835.mp4', '神级美学魔幻RPG大作《魔法来袭》！游戏深度还原MMO核心玩法，多种突破乐趣更多。美术全面升级，超清画质高精度建模，震撼的战斗技能效果丝滑多变，自动挂机刷怪也能帧帧打得漂亮。上千套华美造型，强化流光表现让装备更炫：有大排面的高贵坐骑、炫彩夺目的大翅膀、给力强化不断生成的神器神装等，给你颜值新高度！更有精灵跟随助战，天神随时附体畅享实力碾压全场的痛快。游戏可在线转职自由体验多职业乐趣，进击血色之地、恶魔要塞暴涨经验，于新剧情中亦可追忆回味青春荣光！还有战盟盟主虚位以待，激烈的跨服战甚至百团大战一触即发，快来沉浸式探索唯美的魔幻世界，燃动你的战盟之魂吧！', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1451', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1451', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1451', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1451', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-09-23 10:32:55', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:41', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"神魔变身，暗黑神王君临天下！\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13835.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"角色扮演\",\"addtime\":\"2025-09-23 10:32:55\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://www.u2game99.com/data/upload/game/20251121/692015204d565.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1451\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/1451.htm