INSERT INTO `gb_games` VALUES (197, 1, NULL, '勇者传承（0.1折死神激斗）', NULL, NULL, '卡牌', 'discount', 'https://cp.u2game99.com/storage/operator/20251028/812b9d235e4bef375f20c9a86e02b6e3.png', 'https://cp.u2game99.com/storage/operator/20251028/ecca626051ab1d5d49f63aabea130eb3.jpg', '[\"https://cp.u2game99.com/storage/operator/20251028/30836085eb7121f87b90a516b0f9f288.jpg\", \"https://cp.u2game99.com/storage/operator/20251028/c3327d5252a6501cf01cf40c78de34ef.jpg\", \"https://cp.u2game99.com/storage/operator/20251028/f41c8317a31f038c7cc9789528ede938.jpg\", \"https://cp.u2game99.com/storage/operator/20251028/d29a7db5822ef65ee8a1974441948ef9.jpg\", \"https://cp.u2game99.com/storage/operator/20251028/98c403e2116bb18d5167cb91124420ce.jpg\"]', 'https://mp4.277sy.com/sp/13884.mp4', '《勇者传承（0.1折死神激斗）》是一款以原作中的剧情脉络为核心，对人物、场景进行精细还原，对角色能力、游戏玩法进行深度定制，经典呈现玩家难以忘怀的死神世界。在游戏中，玩家以主角的身份与视角面对强敌、收集资源、磨练技巧，培养自己的最强死神。人气角色大集结，黑崎一护、朽木白哉、朽木露琪亚等数位死神人气角色登场，专属定制技能，每一位登场角色都将给你:“没错，这就是他(她)的感觉!\"。热血沸腾的梦幻对决到放置类游戏轻松休闲，重燃战斗之魂，体验热血酣畅的灵压对决!', '禁海外推广', NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1498', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1498', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1498', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1498', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-10-16 15:57:02', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:41', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"魂息不绝，刃鸣不止\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13884.mp4\",\"text_cps\":\"禁海外推广\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-10-16 15:57:02\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20251028/812b9d235e4bef375f20c9a86e02b6e3.png\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS1