INSERT INTO `gb_games` VALUES (201, 1, NULL, '群英天下(0.05折送全图鉴武将)', NULL, NULL, '卡牌', 'discount', 'https://cp.u2game99.com/storage/operator/20251030/64062cb1a4b68322b6215b7e191d5319.gif', 'https://cp.u2game99.com/storage/operator/20251030/66c370a2bd590cc6a8e40511677704d7.jpg', '[\"https://cp.u2game99.com/storage/operator/20251030/f9eea6ca0f6a355492fcc2aab3dd8175.jpg\", \"https://cp.u2game99.com/storage/operator/20251030/3c1cffc5d0a1f3f031009c5b48f0c693.jpg\", \"https://cp.u2game99.com/storage/operator/20251030/58add83ffb1ce3d3ce8d064b8dd218f3.jpg\", \"https://cp.u2game99.com/storage/operator/20251030/3f3b688a5fe4870d07d1aa63f4cb4f0e.jpg\", \"https://cp.u2game99.com/storage/operator/20251030/660ec6398bb8ae21e3c9103f793469ad.jpg\"]', 'https://mp4.277sy.com/sp/13924.mp4', '作为 2025 年现象级三国题材手游，《群英天下》以创新放置卡牌玩法，重塑烽火三国世界。PVE 玩法层层递进，剿灭叛军体验即时战斗爽感，洞窟探秘解锁传世珍宝与历史谜题，破阵降敌尽显兵法谋略。\r\nPVP 竞技更具张力，战场夺宝考验临场决策，名将对决可随心培养专属阵容，城池攻防再现史诗级古代战争。智能放置系统平衡策略深度与休闲体验，上百位特色名将支持自由搭配，打造独门战术。\r\n游戏凭借精美画面、深度策略与多元社交，重新定义三国手游标准，让每位玩家都能亲手书写专属三国传奇。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1537', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1537', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1537', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1537', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-10-29 10:04:29', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:41', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"三国战略放置版游戏\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13924.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-10-29 10:04:29\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20251030/64062cb1a4b68322b6215b7e191d5319.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1537\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/1537.html\",\"weburl_qr\":\"[base64已省略]\",\"dwzdownurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1537\",\"downurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1537\",\"dwzdownurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1537\",\"gamename\":\"群英天下(0.05折送全图鉴武将)\",\"excerpt\":\"作为 2025 年现象级三国题材手游，《群英天下》以创新放置卡牌玩法，重塑烽火三国世界。PVE 玩法层层递进，剿灭叛军体验即时战斗爽感，洞窟探秘解锁传世珍宝与历史谜题，破阵降敌尽显兵法谋略。\\r\\nPVP 竞技更具张力，战场夺宝考验临场决策，名将对决可随心培养专属阵容，城池攻防再现史诗级古代战争。智能放置系统平衡策略深度与休闲体验，上百位特色名将支持自由搭配，打造独门战术。\\r\\n游戏凭借精美画面、深度策略与多元社交，重新定义三国手游标准，让每位玩家都能亲手书写专属三国传奇。\",\"id\":1537,\"game_source\":\"\",\"device_type\":2,\"edition\":1,\"pic_xuanchuan\":\"\",\"strict\":0,\"userfc\":0,\"updatetime\":\"2025-11-02 09:00:00\",\"box_content\":\"1、每日赠送10亿群英币，主城升级进入狂飙模式\\r\\n2、每日登录抽武将，红将橙将任意领\\r\\n3、每日免费领648元代金劵，最高可升级1000元代金劵\\r\\n4、每日签到送海量充值卡、累签可领1600元代金劵\\r\\n5、免费送巅峰神将组合，直送15星突破SS金将\\r\\n6、新服冲级即送50000充值卡\\r\\n7、创角奖励送V15特权，专属称号\\r\\n8、通关主线关卡送1000连抽\",\"pic2\":\"https://cp.u2game99.com/storage/operator/20251030/66c370a2bd590cc6a8e40511677704d7.jpg\",\"pic3\":\"https://www.u2game99.com/data/upload/game/20251030/690336a235ba1.jpg\",\"pic4\":\"https://www.u2game99.com/data/upload/game/20251030/690336b02f35f.jpg\",\"cps_ratio\":0,\"hw_ratio\":0,\"hw_firstpay\":0.005,\"hw_otherpay\":0.005,\"firstpay\":0.005,\"otherpay\":0.005}');
