INSERT INTO `gb_games` VALUES (204, 1, NULL, '一念山海', NULL, NULL, '挂机', 'official', 'https://cp.u2game99.com/storage/operator/20251016/ecdac46eb414516a51e8afc003715274.png', 'https://cp.u2game99.com/storage/operator/20251016/4aaa2975dc0796e71033c58352a53e4e.jpg', '[\"https://www.u2game99.com/data/upload/game/20251022/68f84ec306448.jpg\", \"https://www.u2game99.com/data/upload/game/20251022/68f84ed2036c7.jpg\", \"https://www.u2game99.com/data/upload/game/20251022/68f84f01bd7d7.jpg\", \"https://www.u2game99.com/data/upload/game/20251022/68f84f10e2883.jpg\", \"https://www.u2game99.com/data/upload/game/20251022/68f84f38c3c72.jpg\"]', 'https://mp4.277sy.com/sp/13857.mp4', '《一念山海》是一款沉浸式国风3D放置手游。以《山海经》为背景，为你呈现一个充满东方奇幻色彩的世界。在这里，你可以御剑飞行，穿梭于云雾之间，修炼仙法，净化世间妖邪，邂逅珍奇异兽，锻造传说神兵，体验从凡尘到仙尊的华丽转变。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1472', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1472', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1472', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1472', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-10-10 10:20:32', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:41', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"《一念山海》是一款国风3D放置挂机RPG手游；\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13857.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"挂机\",\"addtime\":\"2025-10-10 10:20:32\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:55\",\"hw_cps_cpa\":\"CPS海外推广:35\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20251016/ecdac46eb414516a51e8afc003715274.png\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1472\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/1472.html\",\"weburl_qr\":\"[base64已省略]\",\"dwzdownurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1472\",\"downurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1472\",\"dwzdownurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1472\",\"gamename\":\"一念山海\",\"excerpt\":\"《一念山海》是一款沉浸式国风3D放置手游。以《山海经》为背景，为你呈现一个充满东方奇幻色彩的世界。在这里，你可以御剑飞行，穿梭于云雾之间，修炼仙法，净化世间妖邪，邂逅珍奇异兽，锻造传说神兵，体验从凡尘到仙尊的华丽转变。\",\"id\":1472,\"game_source\":\"\",\"device_type\":2,\"edition\":0,\"pic_xuanchuan\":\"\",\"strict\":0,\"userfc\":0,\"updatetime\":\"2025-10-30 10:00:00\",\"box_content\":\"【悠然自得，剑随心至】\\r\\n放下尘世的纷扰，我们为你提炼了修仙的精髓，自动化的技能释放、简洁的操作、轻松的放置体验，让你在每一刻的闲暇中都能感受成长的喜悦。\\r\\n【妖灵契约，助力飞升】\\r\\n从尘世的小妖到天界的仙童，皆能成为你的伙伴。游戏中的山海经异兽等待着与你相遇，共同谱写一段邂逅。\\r\\n【霓裳羽衣，千面风华】\\r\\n丰富的外观任你挑选，亲手锻造稀世装备。解锁多样的造型搭配，让你在修仙路上绽放独特的风采。\\r\\n【仙缘结契，共赴红尘】\\r\\n在这里，你既可以独自探索，也可以与他人携手并进。结交有缘的仙友，一同踏上探险之旅，并肩对抗强敌。\\r\\n【宠爱加冕，悠然自得】\\r\\n游戏里还有丰厚的资源和奖励，让你在正常游玩中就能收获满满，即使不花钱，也能享受到畅快淋漓的游戏乐趣，确保你的修仙之路，一帆风顺。\",\"pic2\":\"https://cp.u2game99.com/storage/operator/20251016/4aaa2975dc0796e71033c58352a53e4e.jpg\",\"pic3\":\"https://www.u2game99.com/data/upload/game/20251022/68f84cf151ecf.jpg\",\"pic4\":\"https://www.u2game99.com/data/upload/game/20251022/68f84e036ff6d.jpg\",\"cps_ratio\":0,\"hw_ratio\":0,\"hw_firstpay\":1,\"hw_otherpay\":1,\"firstpay\":1,\"otherpay\":1}');
