INSERT INTO `gb_games` VALUES (214, 1, NULL, '大屠龙(复古三职六流派)', NULL, NULL, '角色扮演', 'bt', 'https://www.u2game99.com/data/upload/game/20251024/68fb3031b5f5c.gif', 'https://cp.u2game99.com/storage/operator/20251024/dfb749a8fda10be2faca9c4593bf6037.jpg', '[\"https://cp.u2game99.com/storage/operator/20251024/e99ff193d38fee3009854def0a9c5806.jpg\", \"https://cp.u2game99.com/storage/operator/20251024/01bc2b0dc377607e075dba757987ccbb.jpg\", \"https://cp.u2game99.com/storage/operator/20251024/ee837c5cafe93926ddacca60f7704cc5.jpg\", \"https://cp.u2game99.com/storage/operator/20251024/e551a6205485824dc26daa7917f2315f.jpg\", \"https://cp.u2game99.com/storage/operator/20251024/72e64a2ee817673b6fa5586b164e6ff0.jpg\"]', 'https://mp4.277sy.com/sp/13898.mp4', '《大屠龙(复古三职六流派)》是一款1.80复古微变多职业版本传奇手游，它的“微变”是属性上融合微变设定，也可以理解为游戏玩法系统上“微微变化”，用创新设计对冲了复古版本的单一性，让玩家能够打得更爽。其中六大流派包括：战士的攻速真伤流剑圣、爆发烈火流狂战；法师的召唤控制流冰法、爆发团战流雷法；道士的双宝宝流兽道、爆发火符流符道；游戏内除了熟悉的微变套装加成外，还有天赋系统、成长盾牌、配饰、武器锻造、宝石镶嵌等玩法，激战沙城自然也必不可少，散人追梦热血铸就新传奇，快来加入吧。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1512', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1512', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1512', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1512', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-10-21 14:14:12', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:41', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"《大屠龙(复古三职六流派)》是一款1.80复古微变多职业版本传奇手游\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13898.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"角色扮演\",\"addtime\":\"2025-10-21 14:14:12\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:65\",\"hw_cps_cpa\":\"CPS海外推广:45\",\"coupon_repeat\":\"\",\"pic1\":\"https://www.u2game99.com/data/upload/game/20251024/68fb3031b5f5c.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1512\",\