INSERT INTO `gb_games` VALUES (220, 1, NULL, '蚁族崛起（0.05折送典藏吕布）', NULL, NULL, '卡牌', 'discount', 'https://cp.u2game99.com/storage/operator/20251021/55a4a44440c83bc65b08b9a9f080d949.png', 'https://cp.u2game99.com/storage/operator/20251021/943704efadb50b2fb062e44438a4c8c6.jpg', '[\"https://cp.u2game99.com/storage/operator/20251021/ce3b5d13510d3fcbda8180f2b33cc673.jpg\", \"https://cp.u2game99.com/storage/operator/20251021/2ee74c71ba73e59ad34f5dd6d7892592.jpg\", \"https://cp.u2game99.com/storage/operator/20251021/8fe83d1726853262201d6ab67540a562.jpg\", \"https://cp.u2game99.com/storage/operator/20251021/39d589598f7b14a85950101cbf7aef96.jpg\", \"https://cp.u2game99.com/storage/operator/20251021/935caa8ac251ce72c7792f2071a876b8.jpg\"]', 'https://mp4.277sy.com/sp/13891.mp4', '这是一款以蚂蚁元素为题材的国战战争手游，游戏中你将作为蚁族统帅，建造你的专属蚂蚁王国。神机妙算的三国英雄、智勇双全的凯撒，还有数位出类拔萃的豪将，都等待你招募入队，成为蚁族中坚！通过资源囤积、城防修建、战力提升，将一方蚁穴壮大成为兵「蚁」强壮的王国城邦！与百万玩家结盟或是为敌，抵御强敌进攻，联手攻克城池，战无不胜，攻无不取，成为地下世界的霸主！', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1505', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1505', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1505', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1505', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-10-17 17:16:03', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:41', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"终身0.05折，进游送百抽，典藏吕布免费拿\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13891.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-10-17 17:16:03\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20251021/55a4a44440c83bc65b08b9a9f080d949.png\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1505\",\"qrcode\":\"[base64已省略]\",\"weburl\"