INSERT INTO `gb_games` VALUES (229, 1, NULL, '咕噜王国大冒险（内置0.1折）', NULL, NULL, '割草', 'bt', 'https://cp.u2game99.com/storage/operator/20251013/80aa59ed8b897d1e43e2459efc6811e6.png', 'https://cp.u2game99.com/storage/operator/20251013/b86f98c24c5f16c3b6c965cfdd80ec1d.jpg', '[\"https://cp.u2game99.com/storage/operator/20251013/b7f84dedde824bf6647290f854a530e0.jpg\", \"https://cp.u2game99.com/storage/operator/20251013/3a668079f30842c38fa769952f45761d.jpg\", \"https://cp.u2game99.com/storage/operator/20251013/5d82cd7368419d063ccdf716a2771116.jpg\", \"https://cp.u2game99.com/storage/operator/20251013/798eb9c4a6918c831cf16c5d6978858e.jpg\", \"https://cp.u2game99.com/storage/operator/20251013/246e09c2b10a77f699f03a904f71341d.jpg\"]', 'https://mp4.277sy.com/sp/13512.mp4', '《咕噜王国大冒险》是一款Rougelike勇者养成闯关类手游。这款游戏有着十分真实游戏画质，并且游戏角色Q萌可爱。玩家可以在游戏中开启异次元冒险之旅，玩家作为降临这个世界的勇者，需要召集伙伴一起挑战异世界未知的危险。这里有着超多可爱的宠物坐骑和生活在本土的勇者部落等待你的探索。这款游戏作为一款款Rougelike冒险手游，玩家每次进入游戏都可以获得随机的技能，通过这些技能可能有时候会给玩家极大的帮助哦。同时玩家每次进入关卡都可能会随机匹配到不一样的游戏地图。这往往能够获得更多的奖励。怪物、地图、障碍物、陷阱等，也是随机组合而成的。快来游戏中获取强大力量，或寻求珍宝，打造属性出色的神器快速提升战力吧。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1159', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1159', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1159', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1159', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-06-25 11:50:09', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:41', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"0.1割草手游，满屏暴击爽到飞起。\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13512.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"割草\",\"addtime\":\"2025-06-25 11:50:09\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:65\",\"hw_cps_cpa\":\"CPS海外推广:45\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20251013/80aa59ed8b897d1e43e2459efc6811e6.png\",\"version\":0,\"c