INSERT INTO `gb_games` VALUES (234, 1, NULL, '切菜狂人（0.1折五倍版）', NULL, NULL, '放置', 'discount', 'https://cp.u2game99.com/storage/operator/20251009/2f00590a65f79c72673772135a265f96.gif', 'https://cp.u2game99.com/storage/operator/20251009/cafb3706536dc46dacd4fdd3b0059142.jpg', '[\"https://cp.u2game99.com/storage/operator/20251009/f7b0b6837c8b00577f20e4daac02718f.jpg\", \"https://cp.u2game99.com/storage/operator/20251009/1aa0e0fcc8eaedfb3522a6e0212e6e5f.jpg\", \"https://cp.u2game99.com/storage/operator/20251009/15ee49e34577bea56a654126029f5bfa.jpg\", \"https://cp.u2game99.com/storage/operator/20251009/ca8be752de3b2cb18f2d1ed329166b46.jpg\", \"https://cp.u2game99.com/storage/operator/20251009/2faed120e12a297e419995ca86822e76.jpg\"]', 'https://mp4.277sy.com/sp/13836.mp4', '《切菜狂人》是一款超上头的Q版休闲挂机游戏。水果蔬菜混搭，形象搞怪萌态百变，新英雄新玩法，悟空、哪吒、八戒、赵云、关羽、吕布应有尽有，多样英雄任意搭配阵容，轻松闯关，还有大战僵尸，爬塔等趣味玩法，欢乐集结，畅玩不腻！创角648充值卡，悟空师徒与你一同过关斩将，绝世厨神竞技，食神之塔，艰险重重，你将勇往直行，击败强大敌人！', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1452', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1452', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1452', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1452', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-09-23 14:09:56', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:41', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"无限0.1折畅玩厨神争霸、上线就送西游师徒三人组\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13836.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"放置\",\"addtime\":\"2025-09-23 14:09:56\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:0\",\"hw_cps_cpa\":\"CPS推广:30\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20251009/2f00590a65f79c72673772135a265f96.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1452\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.