INSERT INTO `gb_games` VALUES (235, 1, NULL, '斗破苍穹：巅峰对决（送绝品斗者）', NULL, NULL, '动作', 'official', 'https://cp.u2game99.com/storage/operator/20251009/ba3a67b316e757d4085e135a69780747.png', 'https://cp.u2game99.com/storage/operator/20251009/bd35f546b6973845c042eb5ec35634f1.jpg', '[\"https://cp.u2game99.com/storage/operator/20251009/f7af84d29263b48390c77980a4a2e009.jpg\", \"https://cp.u2game99.com/storage/operator/20251009/e6514a5e2a03bae5db293436f38693db.jpg\", \"https://cp.u2game99.com/storage/operator/20251009/24f198f5c6b0f17be7082396d1c762b9.jpg\", \"https://cp.u2game99.com/storage/operator/20251009/63860b12aa276eaa17184b1f3a69a022.jpg\", \"https://cp.u2game99.com/storage/operator/20251009/a1ce7056938106f772857091d7878ac1.jpg\"]', 'https://mp4.277sy.com/sp/13838.mp4', '《斗破苍穹：巅峰对决（送绝品斗者）》是一款以斗破苍穹动画剧情为背景的3D动作类手机游戏，玩家将扮演主角 萧炎 ，通过收复异火、修炼斗气进行冒险。战斗系统采用3D动作设计，还原佛怒火莲、玄冰龙翔等原著斗技特效，支持连招操作和实时PVP对决。 游戏还有赛季制PVP模式，无装备和数值碾压，仅靠操作决胜负，带你体验极致操作带来的胜利喜悦！', '禁海外推广', NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1454', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1454', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1454', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1454', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-09-23 15:18:32', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:41', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"《斗破苍穹：巅峰对决（送绝品斗者）》是一款以斗破苍穹动画剧情为背景的3D动作类手机游戏\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13838.mp4\",\"text_cps\":\"禁海外推广\",\"new\":0,\"yuyue\":0,\"gametype\":\"动作\",\"addtime\":\"2025-09-23 15:18:32\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:10\",\"hw_cps_cpa\":\"CPS海外推广:6\",\"coupon_repeat\":\"可重复领取\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20251009/ba3a67b316e757d4085e135a69780747.png\",\"version\":0,\"c_version\":\"173\",\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1454\",\"qr