INSERT INTO `gb_games` VALUES (240, 1, NULL, '思仙（觉醒重生系统）', NULL, NULL, '回合', 'bt', 'https://cp.u2game99.com/storage/operator/20250926/b188cc1eb7ba07aa6287735eac426e4e.png', 'https://cp.u2game99.com/storage/operator/20250926/895a16eaa77bdbed21fa204768ea3799.jpg', '[\"https://cp.u2game99.com/storage/operator/20250926/27f3c16eba77a598eb030613dd35a869.jpg\", \"https://cp.u2game99.com/storage/operator/20250926/96046b49bfe1ec9e34f7d7cb30df5dc8.jpg\", \"https://cp.u2game99.com/storage/operator/20250926/170ef5dce87f4282c2be74ea9f373578.jpg\", \"https://cp.u2game99.com/storage/operator/20250926/ea42ba684d79c6f40d888e8b77b612fe.jpg\", \"https://cp.u2game99.com/storage/operator/20250926/38bba85c1dc10b14feca1837ea4342bf.jpg\"]', 'https://mp4.277sy.com/sp/13832.mp4', '《思仙》是一款经典回合制手游，游戏打造了轻松休闲的游戏模式，区别于传统回合制的升级速度，思仙升级速度极快，并且首创16人同屏挑战BOSS模式，可以在回合制中感受众人一起争夺boss的特殊玩法，本服大幅提升了boss的掉率和掉落物品，许多珍惜物品均可通过挑战boss获得包括各种幻化、天罡、地煞、神魔装备、神兽等，同时获得的这些道具还可以通过黑市出售，实现轻松挂机，刷怪赚币。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1448', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1448', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1448', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1448', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-09-22 14:48:42', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:41', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"满级大佬重生开局觉醒升级就送全属性100个零\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13832.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"回合\",\"addtime\":\"2025-09-22 14:48:42\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:65\",\"hw_cps_cpa\":\"CPS海外推广:45\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20250926/b188cc1eb7ba07aa6287735eac426e4e.png\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1448\",\"qrcode\":\"[base64已省略]\",\"webur