INSERT INTO `gb_games` VALUES (247, 1, NULL, '黑月（0.1折每日送现金）', NULL, NULL, '角色扮演', 'discount', 'https://www.u2game99.com/data/upload/game/20250919/68cd1a2c7c6e7.png', 'https://www.u2game99.com/data/upload/game/20250923/68d24153633ed.jpg', '[\"https://cp.u2game99.com/storage/operator/20250919/5185001bb6eb9de4a5a179087f1cdf01.jpg\", \"https://cp.u2game99.com/storage/operator/20250919/244ee832b7706aee65f5c0adc6c7f7f8.jpg\", \"https://cp.u2game99.com/storage/operator/20250919/e24cabe65ce07fbcc666c246cad23115.jpg\", \"https://cp.u2game99.com/storage/operator/20250919/e7e7c0ed54404e8390713e6acd88b46c.jpg\", \"https://cp.u2game99.com/storage/operator/20250919/e0d9a2d00c9ca356f193f69f6c4ac55e.jpg\"]', 'https://mp4.277sy.com/sp/13777.mp4', '《黑月（0.1折每日送现金）》是一款横版格斗手游，游戏讲述了黑月再次降临，主角们共同抵抗黑月入侵的故事。在命运的安排下，成为黑月学院主角团一员的你，肩负起了守护人类世界和平的重任。揭秘黑月降临的阴谋，探寻魔女消失的记忆，一场关乎世界存亡的冒险之旅即将展开。黑月元年，世界上空有大量黑粒子汇聚，汇聚成一轮黑月，世界突然与另一个平行时空发生了耦合，无数来自高维异种生物杀戮机器从『黑月』入侵，人类经过数十年惨烈的抗争，终于以巨大的牺牲封印了『黑月』，换来了人类和平的喘息时机！\r\n然而，没有消失的黑月死门，像高悬的达摩克利斯之剑，让人类在末日的威胁下暗流涌动挣扎着寻求不同的出路。而你，作为降临世界的『命运之子』，又将把世界的未来推向何方？', '禁海外推广', NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1397', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1397', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1397', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1397', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-09-05 13:52:49', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:41', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"指尖华尔兹，超燃DIY横版格斗手游\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13777.mp4\",\"text_cps\":\"禁海外推广\",\"new\":0,\"yuyue\":0,\"gametype\":\"角色扮演\",\"addtime\":\"2025-09-05 13:52:49\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://www.u2game99.com/data/upload/game/20250919/68cd1a2c7c6e7.png\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1397\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/1397.html\",\"weburl_qr\":\"[base64已省略]\",\"dwzdownurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1397\",\"downurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1397\",\"dwzdownurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1397\",\"gamename\":\"黑月（0.1折每日送现金）\",\"excerpt\":\"《黑月（0.1折每日送现金）》是一款横版格斗手游，游戏讲述了黑月再次降临，主角们共同抵抗黑月入侵的故事。在命运的安排下，成为黑月学院主角团一员的你，肩负起了守护人类世界和平的重任。揭秘黑月降临的阴谋，探寻魔女消失的记忆，一场关乎世界存亡的冒险之旅即将展开。黑月元年，世界上空有大量黑粒子汇聚，汇聚成一轮黑月，世界突然与另一个平行时空发生了耦合，无数来自高维异种生物杀戮机器从『黑月』入侵，人类经过数十年惨烈的抗争，终于以巨大的牺牲封印了『黑月』，换来了人类和平的喘息时机！\\r\\n然而，没有消失的黑月死门，像高悬的达摩克利斯之剑，让人类在末日的威胁下暗流涌动挣扎着寻求不同的出路。而你，作为降临世界的『命运之子』，又将把世界的未来推向何方？\",\"id\":1397,\"game_source\":\"\",\"device_type\":2,\"edition\":1,\"pic_xuanchuan\":\"\",\"strict\":0,\"userfc\":1,\"updatetime\":\"2025-09-27 09:00:00\",\"box_content\":\"1、0.1折每日送现金，每天登陆领取648现金点券\\r\\n2、登录七天送SSR超凡奥义、SSR宠物宝箱，七日成长送UR级神选武装\\r\\n3、创角即送VIP8，完成主线赠黯晶*18888、恐龙玩偶套装*1、珈蓝黑翼（翅膀）*1、现金点券等\\r\\n4、神选特权助力救赎之战，武装升星送海量黯晶及绝版时装苍蓝混沌\",\"pic2\":\"https://www.u2game99.com/data/upload/game/20250923/68d24153633ed.jpg\",\"pic3\":\"https://www.u2game99.com/data/upload/game/20250919/68cd19fbe8dec.jpg\",\"pic4\":\"https://www.u2game99.com/data/upload/game/20250919/68cd19ffea545.jpg\",\"cps_ratio\":0,\"hw_ratio\":0,\"hw_firstpay\":0.01,\"hw_otherpay\":0.01,\"firstpay\":0.01,\"otherpay\":0.01}');
INSERT INTO `gb_games` VALUES (248, 1, NULL, '史小坑的黑暗料理（0.1折）', NULL, NULL, '冒险', 'discount', 'https://cp.u2game99.com/storage/operator/20250922/d47145370af4f38ed4025ab38a8ca67f.png', 'https://cp.u2game99.com/storage/operator/20250922/0116b03f9dbb5204436ee0f81063aa08.jpg', '[\"https://cp.u2game99.com/storage/operator/20250922/a706a223059d8a22fd94fbbad0ce1ac5.jpg\", \"https://cp.u2game99.com/storage/operator/20250922/c82bb2adae413bf561551c162982de79.jpg\", \"https://cp.u2game99.com/storage/operator/20250922/845357e5f4dc5843d3974bdf7a4c7c4e.jpg\", \"https://cp.u2game99.com/storage/operator/20250922/24ad69d4901d5fe2f8b07275526faa14.jpg\", \"https://cp.u2game99.com/storage/operator/20250922/1cc307867bca4e0b4b35a45b0bddfead.jpg\"]', 'https://mp4.277sy.com/sp/13713.mp4', '《史小坑的黑暗料理》是一款佣兵+RPG和烹饪元素结合的游戏。玩家将扮演一个勇敢的冒险者队长，带领小队探索未知的领域，与各种怪物和挑战战斗，解锁强大的技能和装备，最终揭开隐藏在故事背后的真相。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1340', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1340', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1340', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1340', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-08-20 14:13:07', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:41', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"招募佣兵，探索秘境，用‘黑暗料理’喂出最强战力\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13713.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"冒险\",\"addtime\":\"2025-08-20 14:13:07\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20250922/d47145370af4f38ed4025ab38a8ca67f.png\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1340\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/1340.html\",\"weburl_qr\":\"[base64已省略]\",