INSERT INTO `gb_games` VALUES (249, 1, NULL, '天子令（七雄争霸正版0.1折）', NULL, NULL, '策略', 'discount', 'https://www.u2game99.com/data/upload/game/20250928/68d9058b7550e.gif', 'https://cp.u2game99.com/storage/operator/20251210/79ffe62e3d537135fea194c4c3e5f44b.jpg', '[\"https://cp.u2game99.com/storage/operator/20250917/a40ecf1b4273f0cafb8d5dd950d5c785.jpg\", \"https://cp.u2game99.com/storage/operator/20250917/19da385d606d95adf0889f4749d14bc8.jpg\", \"https://cp.u2game99.com/storage/operator/20250917/fe85c1b0bf632b72ed17b6ceafdb20c4.jpg\", \"https://cp.u2game99.com/storage/operator/20250917/1ec67f485045b902b528fe7440857ea4.jpg\", \"https://cp.u2game99.com/storage/operator/20250917/879b191d87e8afba44f39998c1b64737.jpg\"]', 'https://mp4.277sy.com/sp/13772.mp4', '岁月如梭，烽烟未息！十年前，我们并肩征战沙场，在战国七雄的版图上挥斥方遒，十年后，《天子令（七雄争霸正版0.1折）》手游承载万亿玩家的青春记忆，以 ​​「经典重铸版」​​ 之姿邀您再续战国史诗！现版本全场物价0.1折，首充仅需0.01元！更有海量充值卡赠予，助您七国争雄！游戏内将中原地区分为燕、韩、赵、魏、齐、楚、秦七大国，玩家可在本国地图内迁移城池、建立联盟，在国战中互相反复争夺。不同国家的玩家也可以集体远征攻打其他国家。我们在延续经典的千重楼、钓鱼等玩法的同时，更有实时国战、跨服远征、联盟战场、逐鹿中原。游戏内有多兵种进行搭配及克制，感受克敌制胜，以少胜多的胜利快感。玩家通过发展自己的城池，增加势力范围，培养独当一面的无敌武将，不断壮大实力，与朋友建立联盟，架设丝绸之路，高筑墙，广积粮，招兵买马，称霸全国，问鼎天下！战国烽火因您重燃，这杯十年的酒，敬永不落幕的争霸之心！', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1392', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1392', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1392', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1392', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-09-04 09:32:53', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:41', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"七雄争霸正版0.1折！\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13772.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"策略\",\"addtime\":\"2025-09-04 09:32:53\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://www.u2game99.com/data/uploa