INSERT INTO `gb_games` VALUES (254, 1, NULL, '三国如龙传（网易首款0.05折）', NULL, NULL, '回合', 'discount', 'https://cp.u2game99.com/storage/operator/20251022/8494a1bb80424473fa3f95cb9140237c.gif', 'https://cp.u2game99.com/storage/operator/20251022/8ea74989cb21ae6a290dfd83f372e4af.jpg', '[\"https://cp.u2game99.com/storage/operator/20250915/b0b746e7bc36bf27478552e9dbd8c534.jpg\", \"https://cp.u2game99.com/storage/operator/20250915/4c05b5e51b0b4674feaee6227ad9bc64.jpg\", \"https://cp.u2game99.com/storage/operator/20250915/6c71719881fbcec7b22713651e53a9cf.jpg\", \"https://cp.u2game99.com/storage/operator/20250915/81288daaeb911af7a5c119220070fb38.jpg\", \"https://cp.u2game99.com/storage/operator/20250915/88657ae246cc660312be76f3e02762cf.jpg\"]', 'https://mp4.277sy.com/sp/13749.mp4', '《三国如龙传》是网易次世代回合制MMO幻想大作,革新打造全空间战场，打破回合制游戏禁锢，战斗自由走位、自创阵法，全新引入骑战系统，以谋略定胜负！三国名将绿色收集，自由搭配打造最强阵容；真实再现百城十三州大地图，回合制也能跨服国战；浪漫结婚、兄弟知己、封土建邦，让你亲身领略高仿真乱世社交。\r\n', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1373', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1373', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1373', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1373', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-08-28 11:34:49', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:41', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"网易首款0.05折免费版\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13749.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"回合\",\"addtime\":\"2025-08-28 11:34:49\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20251022/8494a1bb80424473fa3f95cb9140237c.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1373\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/103