INSERT INTO `gb_games` VALUES (256, 1, NULL, '佣兵突击队（0.1折日日送代金）', NULL, NULL, '割草', 'discount', 'https://cp.u2game99.com/storage/operator/20250917/daae8730b365012bfd733848e27f47dc.gif', 'https://cp.u2game99.com/storage/operator/20250917/3eceb33ed6d5046f0a8d00431654ccd9.jpg', '[\"https://cp.u2game99.com/storage/operator/20250917/fcfbe7b1b5e8ecaa5f02820e41550396.jpg\", \"https://cp.u2game99.com/storage/operator/20250917/694ab269014bcf8d7b267eef9cbb06ba.jpg\", \"https://cp.u2game99.com/storage/operator/20250917/fcdd6565dc38ca6e7b9c13503fbbf958.jpg\", \"https://cp.u2game99.com/storage/operator/20250917/3b92d03e84acd9aa1ad3343962f760e8.jpg\", \"https://cp.u2game99.com/storage/operator/20250917/2ee8d5f8940309caafaf39eb1f205d4c.jpg\"]', 'https://mp4.277sy.com/sp/13796.mp4', '《佣兵突击队（0.1折日日送代金）》是一款别具一格的肉鸽割草游戏。你将扮演一位拥有非凡潜力的佣兵，与其他幸存者并肩作战，拿起武器，挑战强大的敌人！敌人的力量依然不容小觑，稍有不慎便会陷入危机！在这艰难的时刻，竭尽全力，想方设法生存下去吧！\r\n', '禁海外推广', NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1414', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1414', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1414', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1414', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-09-11 13:55:26', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:41', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"割草无双！指尖狂潮，席卷千军万马！\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13796.mp4\",\"text_cps\":\"禁海外推广\",\"new\":0,\"yuyue\":0,\"gametype\":\"割草\",\"addtime\":\"2025-09-11 13:55:26\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20250917/daae8730b365012bfd733848e27f47dc.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1414\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/1414.html\