INSERT INTO `gb_games` VALUES (257, 1, NULL, '釜底抽薪（十二门派夺仙缘）', NULL, NULL, '挂机', 'bt', 'https://cp.u2game99.com/storage/operator/20250922/7a1e33b32053e42f6a8397082bab8c13.gif', 'https://cp.u2game99.com/storage/operator/20250922/6f1dcd241c75ee04fa186153dc8c4930.jpg', '[\"https://cp.u2game99.com/storage/operator/20250922/329981d1dccd17d390b5af6631d1379b.jpg\", \"https://cp.u2game99.com/storage/operator/20250922/e53643036c0162bce7ec3fb2c5f3ba3e.jpg\", \"https://cp.u2game99.com/storage/operator/20250922/bd44486b7951dcf61ce75d061f5e0251.jpg\", \"https://cp.u2game99.com/storage/operator/20250922/284e9fd51700ed2c009470d755283d87.jpg\", \"https://cp.u2game99.com/storage/operator/20250922/8ee35b7763153069b1d5724ec438cd8a.jpg\"]', 'https://mp4.277sy.com/sp/13824.mp4', '《釜底抽薪（十二门派夺仙缘）》确实是一款极具创新与情怀的经典传奇游戏。玩家不仅可以自由选择十二门派，踏上充满挑战的“征神之路”，还能通过游戏内玩法获取充值券，真正实现公平竞技，无需依赖直接充值，大大提升了游戏的可玩性与策略性。丰富的职业路线、多样的副本挑战、跨服对决以及隐藏奇遇等玩法，让每一位玩家都能找到属于自己的成长节奏。无论是喜欢单打独斗的高手，还是热衷团队协作的宗门战将，都能在这个世界中大放异彩。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1440', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1440', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1440', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1440', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-09-19 18:00:43', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:41', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"十二门派选择，修仙之路险阻\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13824.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"挂机\",\"addtime\":\"2025-09-19 18:00:43\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:65\",\"hw_cps_cpa\":\"CPS海外推广:45\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20250922/7a1e33b32053e42f6a8397082bab8c13.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1440\",\"qrcode\":\"[base64已省略]