INSERT INTO `gb_games` VALUES (260, 1, NULL, '云墨剑舞（3.5折十二时辰）', NULL, NULL, '角色扮演', 'discount', 'https://cp.u2game99.com/storage/operator/20250917/3b82d5f05034423dabac7abc5151ebc9.gif', 'https://cp.u2game99.com/storage/operator/20250916/e6aedc8945c624aae264c360b3b89df0.jpg', '[\"https://cp.u2game99.com/storage/operator/20250916/71cfbd09e3b4e9503caa9fdb73d1b04c.jpg\", \"https://cp.u2game99.com/storage/operator/20250916/9597aff325d1e7c145a888114bf5564f.jpg\", \"https://cp.u2game99.com/storage/operator/20250916/2662c4368b0784bb96b2e6d1e0eb7d09.jpg\", \"https://cp.u2game99.com/storage/operator/20250916/75a5e2ab7fb41e891273f888f96c8106.jpg\", \"https://cp.u2game99.com/storage/operator/20250916/8f4178585102f636bbbdf5515a4c2bad.jpg\"]', 'https://mp4.277sy.com/sp/13812.mp4', '这是一款以盛世大唐长安为背景的MMORPG仙侠手游，还原了古代元素，高品质的游戏画面、唯美清新的视觉效果，宏伟壮丽的古典场景，风格各异的技能，丰富多变的副本、战斗系统，极具仙侠风的武学招式，大型帮派战据点战等运用均可给玩家带来身临其境的难忘体验；职业搭配更平衡，提升途径更多变，每个人都能玩出自己的套路，寻找最适合的发展路线，让我们在这飘摇乱世之中寻找属于自己的仙侠路！', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1429', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1429', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1429', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1429', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-09-16 15:30:39', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:41', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"以大唐长安为背景的仙侠手游登录送元宝券\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13812.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"角色扮演\",\"addtime\":\"2025-09-16 15:30:39\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:0\",\"hw_cps_cpa\":\"CPS推广:30\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20250917/3b82d5f05034423dabac7abc5151ebc9.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1429\",\"qrcode\":\"[base64已省略]\",\