INSERT INTO `gb_games` VALUES (261, 1, NULL, '镜界（0.1折领千抽豪礼）', NULL, NULL, '卡牌', 'discount', 'https://cp.u2game99.com/storage/operator/20250912/8f0efd0b5b75f21e1b6a6599de411fa9.gif', 'https://www.u2game99.com/data/upload/game/20250912/68c3ecd42fc9b.jpg', '[\"https://cp.u2game99.com/storage/operator/20250912/88f55faf839e7665f39e52c800f90a91.jpg\", \"https://cp.u2game99.com/storage/operator/20250912/c269aa1c8412c0f092fd4953574ce01c.jpg\", \"https://cp.u2game99.com/storage/operator/20250912/7c2674e4c1e9910a80d867cd3ebb4ca6.jpg\", \"https://cp.u2game99.com/storage/operator/20250912/87f0d9fc7de376dc796115965bcf27ed.jpg\", \"https://cp.u2game99.com/storage/operator/20250912/f2c0ebf7ac1be08cfe62226377eea2ac.jpg\"]', 'https://mp4.277sy.com/sp/13798.mp4', '【死神】官方正版授权卡牌手游重磅来袭！收录动漫经典角色，精致立绘还原卍解名场面！收集本命死神、破面、灭却师，组建最强番队，策略搭配释放终极奥义！沉浸式剧情重现空座町大战，原创番外解锁未曝光的魂界秘辛！', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1416', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1416', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1416', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1416', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-09-11 16:24:32', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:41', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"成为守护荣耀的最强主宰！\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13798.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-09-11 16:24:32\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:0\",\"hw_cps_cpa\":\"CPS推广:30\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20250912/8f0efd0b5b75f21e1b6a6599de411fa9.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1416\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/1416.html\",\"weburl_qr\":\"[base64已省略]\",\"dwzdownurl\":\"https://qd.