INSERT INTO `gb_games` VALUES (266, 1, NULL, '镇魂街：破晓（0.1折正版授权）', NULL, NULL, '卡牌', 'discount', 'https://www.u2game99.com/data/upload/game/20251106/690c6f7c84ca0.gif', 'https://www.u2game99.com/data/upload/game/20251106/690c6f51e77a8.jpg', '[\"https://cp.u2game99.com/storage/operator/20250916/be821a5f3c72bda7dc59d12e18ce8c16.jpg\", \"https://cp.u2game99.com/storage/operator/20250916/45969c75ccf92536b311e210f21e2d13.jpg\", \"https://cp.u2game99.com/storage/operator/20250916/6d589f8ebe8e79b3b82a8be1e61fb044.jpg\", \"https://cp.u2game99.com/storage/operator/20250916/59faf9a07c2a77ddc2e6b337cb50d0a8.jpg\", \"https://cp.u2game99.com/storage/operator/20250916/7df732ae8fbcd48e712ad70db3e418fc.jpg\"]', 'https://mp4.277sy.com/sp/13692.mp4', '高人气超燃国漫《镇魂街》正版IP授权放置卡牌手游《镇魂街：破晓》重磅来袭！\r\n历时3年匠心打造，完美还原经典角色、技能和场景！\r\n镇魂将，唤醒你的武神躯，组建镇魂天团，和曹焱兵一起为了守护罗刹街而战吧！\r\n\r\n【超燃国漫 经典重现】\r\n完美还原动画剧情，与曹焱兵、夏玲、许褚等众多经典角色一起对抗神武营天罡龙棋将，守护罗刹街！\r\n\r\n【多维策略 人灵合击】\r\n游戏打破传统回合制玩法，以放置卡牌打斗为核心，独创了“人灵合击”玩法，不同的寄灵人和守护灵相互自由搭配出万种变化！\r\n\r\n【3D视觉 角色收集】\r\n近百位高度还原的角色，每一位都有独一无二的技能设计，卡牌创新结合MMO元素，打造3D版“罗刹街”！\r\n\r\n【千抽福利 全面护肝】\r\n千抽福利满满，开局自带曹焱兵、典韦、许诸，还可以免费获得天罡龙棋将和满星守护灵典韦、赵云，阵容轻松成型!离线收益不中断，超多资源助力镇魂将快速成长，战力拉满，养成无压力！', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1320', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1320', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1320', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1320', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-08-13 11:33:03', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:41', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"天天送648元代金券，全场礼包随心购！\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13692.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-08-13 11:33:03\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"htt