INSERT INTO `gb_games` VALUES (272, 1, NULL, '轩辕剑龙舞云山（0.1折网易国风回合）', NULL, NULL, '回合', 'discount', 'https://www.u2game99.com/data/upload/game/20251021/68f73f5370419.gif', 'https://www.u2game99.com/data/upload/game/20251021/68f7400f25565.jpg', '[\"https://cp.u2game99.com/storage/operator/20250826/566836ced9c7dbf6d52a7b0b2a4395d5.jpg\", \"https://cp.u2game99.com/storage/operator/20250826/25ebe3567d756c635837771fb70e60bd.jpg\", \"https://cp.u2game99.com/storage/operator/20250826/f4de4e6eaf2ff71505b66ab4b4e91927.jpg\", \"https://cp.u2game99.com/storage/operator/20250826/d57e1e675b15ea81a649408d2f7017b9.jpg\", \"https://cp.u2game99.com/storage/operator/20250826/4ddec5e7b2e3e793eba40c93662eb849.jpg\"]', 'https://mp4.277sy.com/sp/13705.mp4', '《轩辕剑龙舞云山》是网易获台湾大宇正版授权，基于 “轩辕剑” IP 自研的作品。融合网易成熟技术与创意，带来独特体验。\r\n游戏故事设定在唐朝由盛转衰之时。既有经典剧情，也有原创的时空穿越剧情，讲述安禄山叛乱、琉璃会高层失踪、墨家后人现世等情节，还涉及上古十大神器，各势力展开正邪较量。\r\n玩法上，在回合制战斗基础上创新，加入 “克制” 与 “追击” 系统，玩家需搭配阵容策略战斗，还有护驾灵佑，策略组合多样。游戏也有弹琴、画画等丰富休闲玩法，让玩家体验古人风雅。\r\n美术采用 “新国风轻写实” 画风，借鉴国画水墨技法并创新，展现传统国风场景。音乐上，《云山逸韵》专辑收录 11 首曲目，各场景旋律独特，营造沉浸式氛围。\r\n在这里，你将拥有一段独一无二的国风游戏记忆，不容错过。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1333', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1333', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1333', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1333', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-08-18 11:21:36', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:41', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"网易原班人马打造全新IP\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13705.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"回合\",\"addtime\":\"2025-08-18 11:21:36\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://www.u2game99.com/data/upload/game/20251021/68f73f5370419.gif\",\"version\":0,\"c_versi