INSERT INTO `gb_games` VALUES (273, 1, NULL, '魔灵幻想（0.1折免费版）', NULL, NULL, '卡牌', 'discount', 'https://www.u2game99.com/data/upload/game/20250902/68b65ff01fce3.png', 'https://www.u2game99.com/data/upload/game/20250912/68c39749ad18b.jpg', '[\"https://p1.277sy.com/2025/09/12/68c392d65e897.jpg\", \"https://p1.277sy.com/2025/09/02/68b6637e126f4.jpg\", \"https://p1.277sy.com/2025/09/02/68b6637e13412.jpg\", \"https://p1.277sy.com/2025/09/02/68b6637e14120.jpg\", \"https://p1.277sy.com/2025/09/02/68b6637e15179.jpg\"]', 'https://mp4.277sy.com/sp/13738.mp4', '《魔灵幻想》是一款竖屏日系二次元风格放置卡牌类放置手游。本游戏采用了怪物进化的特色题材，每个角色都具有幼年期、成长期、完全体，三个形态。每个形态都有独有的原画和战斗角色，特别是在三阶进化成了非常漂亮的二次元妹子，给玩家的成长感带来不一样的感受。在设定方面，我们拥有风、水、火、木、光、暗6个元素，在战斗的对抗上拥有更丰富的战斗策略维度。这是一个强调玩家相互对抗并在此环境下一起成长的游戏，最终的目标是在灭亡的危机中拯救精灵和人类两个世界。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1363', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1363', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1363', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1363', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-08-26 09:57:52', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:41', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"一款日系二次元竖屏放置卡牌手游\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13738.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-08-26 09:57:52\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://www.u2game99.com/data/upload/game/20250902/68b65ff01fce3.png\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1363\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/1363.html\",\"weburl_qr\":\"[base64已省略]\",\"dwzdownurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1363\",\"downurlmash\":\"https://qd.u2game99.com/down.html?