INSERT INTO `gb_games` VALUES (275, 1, NULL, '文明与众神（0.1折云上圣歌送亿钻）', NULL, NULL, '角色扮演', 'discount', 'https://www.u2game99.com/data/upload/game/20251224/694b96968f79c.png', 'https://www.u2game99.com/data/upload/game/20251224/694b961ed5352.jpg', '[\"https://www.u2game99.com/data/upload/game/20250925/68d4f20eda7e2.jpg\", \"https://www.u2game99.com/data/upload/game/20250925/68d4f212e657a.jpg\", \"https://www.u2game99.com/data/upload/game/20250925/68d4f216a22a7.jpg\", \"https://www.u2game99.com/data/upload/game/20250925/68d4f21cc28da.jpg\", \"https://www.u2game99.com/data/upload/game/20250925/68d4f222c0ad1.jpg\"]', 'https://mp4.277sy.com/sp/13663.mp4', '《文明与众神）》是一款以西方架空魔幻风格为背景的即时战斗类手机网络游戏。在游戏中，玩家将扮演“救世团”成员，踏上寻找五位创世神像的征程。玩家将在游戏中一步步了解到这个世界的背景，自身之前的经历，通过寻求伙伴，强化武器提升自己，通过加入佣兵团获得大家的帮助，与此同时，玩家还可以通过自身或多人组队对世界中的邪恶发起征讨以获得更加强力的武器装备，除此之外，通过竞技场，佣兵之王，泳池派对等玩法还可以让玩家一步一步成为这个世界的救世主，最终拯救这个世界。通过游戏，玩家能够获得逻辑思维的锻炼，体验异世界不同人生的乐趣。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1294', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1294', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1294', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1294', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-08-06 17:35:46', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:42', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"超爽高爆异世界，极品时装免费送！\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13663.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"角色扮演\",\"addtime\":\"2025-08-06 17:35:46\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://www.u2game99.com/data/upload/game/20251224/694b96968f79c.png\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1294\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/1294.html\",\"weburl_qr\":\"[base64已省略]\",\"dwzdownurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1294\",\"downurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1294\",\"dwzdownurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1294\",\"gamename\":\"文明与众神（0.1折云上圣歌送亿钻）\",\"excerpt\":\"《文明与众神）》是一款以西方架空魔幻风格为背景的即时战斗类手机网络游戏。在游戏中，玩家将扮演“救世团”成员，踏上寻找五位创世神像的征程。玩家将在游戏中一步步了解到这个世界的背景，自身之前的经历，通过寻求伙伴，强化武器提升自己，通过加入佣兵团获得大家的帮助，与此同时，玩家还可以通过自身或多人组队对世界中的邪恶发起征讨以获得更加强力的武器装备，除此之外，通过竞技场，佣兵之王，泳池派对等玩法还可以让玩家一步一步成为这个世界的救世主，最终拯救这个世界。通过游戏，玩家能够获得逻辑思维的锻炼，体验异世界不同人生的乐趣。\",\"id\":1294,\"game_source\":\"\",\"device_type\":2,\"edition\":1,\"pic_xuanchuan\":\"\",\"strict\":0,\"userfc\":1,\"updatetime\":\"2025-09-11 08:00:00\",\"box_content\":\"1.无限打金高爆版本，暴打老板亿万钻石山等你挖！\\r\\n2.冬日套装升级免费拿全套，炫酷时装套装助你成为异世界的最亮之星！\\r\\n3.海量培养道具、极品时装、巨额战力丹药\\t即刻赠送！\\r\\n4.白送640充值卡兑换海量钻石，商城神品随便拿，轻松涨战力！\\r\\n5.BOSS爆率拉满，顶级装备道具遍地捡！\\r\\n6.爆肝魔王本，狂领百亿代金券补贴，福利拉满！\",\"pic2\":\"https://www.u2game99.com/data/upload/game/20251224/694b961ed5352.jpg\",\"pic3\":\"https://www.u2game99.com/data/upload/game/20251224/694b962505de4.jpg\",\"pic4\":\"https://www.u2game99.com/data/upload/game/20251224/694b9e68b91fb.jpg\",\"cps_ratio\":0,\"hw_ratio\":0,\"hw_firstpay\":0.01,\"hw_otherpay\":0.01,\"firstpay\":0.01,\"otherpay\":0.01}');
INSERT INTO `gb_games` VALUES (276, 1, NULL, '都市冒险高手（0.1折千抽9星光暗）', NULL, NULL, '卡牌', 'discount', 'https://cp.u2game99.com/storage/operator/20250904/b82ed0a17ea1f62a5b730e1e7029c066.gif', 'https://www.u2game99.com/data/upload/game/20250905/68ba926cb3adf.jpg', '[\"https://cp.u2game99.com/storage/operator/20250904/3ae080ddb6d43b62f207ab1d7b334ebf.jpg\", \"https://cp.u2game99.com/storage/operator/20250904/bcfb46bc82d87d9f72fbabdc5d162dfc.jpg\", \"https://cp.u2game99.com/storage/operator/20250904/9e58f1e3192b87dd4185adf5b0fe86d8.jpg\", \"https://cp.u2game99.com/storage/operator/20250904/0df1fbcb2be907e38db2b1a3ed6cc93c.jpg\", \"https://cp.u2game99.com/storage/operator/20250904/15a32d37243b937a2d8e85b57d09ee40.jpg\"]', 'https://mp4.277sy.com/sp/13736.mp4', '《都市冒险高手》是一款末日废土风格的卡牌角色扮演游戏，以未来都市为背景，玩家将面对不同的地图、关卡和变异生物来构筑最强\"异能者对抗都市中的破坏者。\r\n故事源于2077夏夜，一颗陨石划过天际，降落在G城中心处，一股神秘气体向外蔓延，被气体感染的生物变得凶暴异常。随着这些怪物增多，幸存者们无奈退至西部，建造“壁垒\'抵御怪物，休整生息。\r\n随着时间流逝，少部分幸存者们逐渐掌握神秘气体的力量，被称为\"异能者”，物资的圆乏令幸存者们不得不提起兵刃，组建“战队\",走出\"壁垒”，寻觅物资，建设家园。\r\n', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1361', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1361', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1361', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1361', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-08-25 15:00:16', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:42', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"寻觅物资，建设家园\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13736.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-08-25 15:00:16\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20250904/b82ed0a17ea1f62a5b730e1e7029c066.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?a