INSERT INTO `gb_games` VALUES (279, 1, NULL, '奇门(0.05折送黑神话无常)', NULL, NULL, '放置', 'discount', 'https://cp.u2game99.com/storage/operator/20250904/65f3d290a39257fc93ef6b2d21223368.gif', 'https://www.u2game99.com/data/upload/game/20250904/68b901dece37f.jpg', '[\"https://cp.u2game99.com/storage/operator/20250904/569f81095e56db734b45c8e1ef1b152d.jpg\", \"https://cp.u2game99.com/storage/operator/20250904/a0eefc7059cfda29e278e945641acbda.jpg\", \"https://cp.u2game99.com/storage/operator/20250904/62b3c4db610783d2ae18ca3df2543fae.jpg\", \"https://cp.u2game99.com/storage/operator/20250904/d9563a21c9dd6cf82f728ec0e6e5a8e4.jpg\", \"https://cp.u2game99.com/storage/operator/20250904/244251f7c1eb5339d4076e79a8be69ab.jpg\"]', 'https://mp4.277sy.com/sp/13754.mp4', '踏入美轮美奂的 3D 修真世界，沉浸式体验云雾缭绕的仙山、波光粼粼的灵湖，每一处场景都细腻入微，仿佛身临其境。在这里，你将踏上寻找神兵利器的冒险之旅，多职业随心觉醒，无论是近身搏杀的热血，还是远程制敌的谋略，都能尽情施展。​\r\n游戏玩法丰富多样，组队对战中与好友并肩作战，修罗战场内挑战极限，排位赛上争夺荣耀之巅，还能在交易市场摆摊买卖，或是循着线索追踪仇敌。背负灭魔斩妖的重任，借助传说之力，一路披荆斩棘，成就属于你的修真传奇。​\r\n精致细腻的人物建模，搭配真实自然的环境渲染，呈现出媲美端游的次世代画面，带你领略一场极致的修真美学盛宴。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1378', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1378', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1378', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1378', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-08-29 17:08:17', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:42', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"绝美3D修真，畅享多元仙旅\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13754.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"放置\",\"addtime\":\"2025-08-29 17:08:17\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20250904/65f3d290a39257fc93ef6b2d21223368.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game9