INSERT INTO `gb_games` VALUES (292, 1, NULL, '凡人修仙传：星海飞驰', NULL, NULL, '放置', 'official', 'https://p1.277sy.com/2025/07/29/68882f9c82b64.gif', 'https://cp.u2game99.com/storage/operator/20250729/8fd65eaeafba8bd7a6ef22a2572a5aba.jpg', '[\"https://cp.u2game99.com/storage/operator/20250729/a31796e6e536cf1e5019787c5a6b886e.jpg\", \"https://cp.u2game99.com/storage/operator/20250729/bfdde81a4be5b1eeabc4af518e67e3cc.jpg\", \"https://cp.u2game99.com/storage/operator/20250729/9348c7f92e7533e4368dc88286d6bc9a.jpg\", \"https://cp.u2game99.com/storage/operator/20250729/06ae153a5fecd61d499d1457f471fdc6.jpg\", \"https://cp.u2game99.com/storage/operator/20250729/5bc8ef9d3c34ab394eb2451ecacc1a1d.jpg\"]', 'https://mp4.277sy.com/sp/13608.mp4', '《凡人修仙传（星海飞驰）》是由起点白金级作家忘语同名小说《凡人修仙传》正版授权改编的微社交组团修炼手游，\r\n游戏充分还原小说内庞大浩瀚的修仙体系，以组团模式连接道友与道友之间的缘法，比肩共赴坎坷难行的修仙之路。\r\n坚信只要像韩立那样拥有不曾动摇的修仙之心，所有道友终将超凡脱世登峰造极！\r\n\r\n游戏特色\r\n1、轻松放置修仙\r\n\r\n支持离线挂机，自动累积修为、淬炼灵根，灵宠养成、法宝蕴养全程托管。\r\n\r\n2、策略深度玩法\r\n\r\n跨服天梯实时竞技，挑战全服道友；宗门共修互助渡劫，万人仙盟共抗心魔入侵。\r\n\r\n3、视听沉浸体验\r\n\r\n水墨动态绘卷勾勒山河万象，飞剑凌空、丹炉凝雾，国风仙韵十足。', '禁止海外推广', NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1245', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1245', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1245', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1245', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-07-21 15:21:06', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:42', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"正版授权改编手游\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13608.mp4\",\"text_cps\":\"禁止海外推广\",\"new\":0,\"yuyue\":0,\"gametype\":\"放置\",\"addtime\":\"2025-07-21 15:21:06\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:1\",\"hw_cps_cpa\":\"CPS海外推广:1\",\"coupon_repeat\":\"\",\"pic1\":\"https://p1.277sy.com/2025/07/29/68882f9c82b64.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1245\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/1245.html\",\"weburl_qr\":\"[base64已省略]\",\"dwzdownurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1245\",\"downurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1245\",\"dwzdownurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1245\",\"gamename\":\"凡人修仙传：星海飞驰\",\"excerpt\":\"《凡人修仙传（星海飞驰）》是由起点白金级作家忘语同名小说《凡人修仙传》正版授权改编的微社交组团修炼手游，\\r\\n游戏充分还原小说内庞大浩瀚的修仙体系，以组团模式连接道友与道友之间的缘法，比肩共赴坎坷难行的修仙之路。\\r\\n坚信只要像韩立那样拥有不曾动摇的修仙之心，所有道友终将超凡脱世登峰造极！\\r\\n\\r\\n游戏特色\\r\\n1、轻松放置修仙\\r\\n\\r\\n支持离线挂机，自动累积修为、淬炼灵根，灵宠养成、法宝蕴养全程托管。\\r\\n\\r\\n2、策略深度玩法\\r\\n\\r\\n跨服天梯实时竞技，挑战全服道友；宗门共修互助渡劫，万人仙盟共抗心魔入侵。\\r\\n\\r\\n3、视听沉浸体验\\r\\n\\r\\n水墨动态绘卷勾勒山河万象，飞剑凌空、丹炉凝雾，国风仙韵十足。\",\"id\":1245,\"game_source\":\"\",\"device_type\":2,\"edition\":0,\"pic_xuanchuan\":\"\",\"strict\":0,\"userfc\":1,\"updatetime\":\"2025-08-26 08:00:00\",\"box_content\":\"1.上线即送万抽-万抽即送SP韩立\\r\\n2.登录即送墨彩环\\r\\n3.满足等级条件更送头像框·御宵龙吟*以及专属SSSR历飞雨\\r\\n4.次日登录即可领取SSSR南宫婉，7日登录可领取火龙童子\\r\\n5.通关更可获得SP南宫婉\",\"pic2\":\"https://cp.u2game99.com/storage/operator/20250729/8fd65eaeafba8bd7a6ef22a2572a5aba.jpg\",\"pic3\":\"https://p1.277sy.com/2025/07/29/68882f9c8497f.jpg\",\"pic4\":\"https://mp4.277sy.com/frame/13608.jpeg\",\"cps_ratio\":0,\"hw_ratio\":0,\"hw_firstpay\":1,\"hw_otherpay\":1,\"firstpay\":1,\"otherpay\":1}');
INSERT INTO `gb_games` VALUES (293, 1, NULL, '荣誉守卫战（0.1折签到送超赛）', NULL, NULL, '卡牌', 'discount', 'https://cp.u2game99.com/storage/operator/20250819/56cd20f71da9dd02627acee807cc75c7.gif', 'https://www.u2game99.com/data/upload/game/20250819/68a44a2b27b6f.jpg', '[\"https://cp.u2game99.com/storage/operator/20250819/e049b120905593079a7ef05beee315ab.jpg\", \"https://cp.u2game99.com/storage/operator/20250819/7bf97170de1fcc9ea1e4291170f6a085.jpg\", \"https://cp.u2game99.com/storage/operator/20250819/045ba5bed6af6da33ee2bf315b651bd5.jpg\", \"https://cp.u2game99.com/storage/operator/20250819/68442132e7f0515382514533beb4c7f2.jpg\", \"https://cp.u2game99.com/storage/operator/20250819/b36a0fda2adf3c16b74e2468c6bcac36.jpg\"]', 'https://mp4.277sy.com/sp/13671.mp4', '《荣誉守卫战》是一款人气七龙珠动漫题材卡牌手游。玩家将跟随悟空等众多熟悉的角色一同展开冒险。黑暗势力再次在宇宙中蠢蠢欲动，威胁着各个星球的和平与安宁。玩家作为被选中的勇士，需要组建强大的龙珠战士队伍，与邪恶势力展开激烈的回合制战斗，最终拯救宇宙！游戏融入多种玩法：主线闯关、修行历练、武道会、卡林塔、天神殿、军团战！培养强大阵容，保卫世界！', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1302', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1302', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1302', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1302', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-08-08 11:29:00', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:42', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"集结最强战士，指尖引爆热血激战！\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13671.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-08-08 11:29:00\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20250819/56cd20f71da9dd02627acee807cc75c7.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1302\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.co