INSERT INTO `gb_games` VALUES (296, 1, NULL, '我守护的家园（千抽福利）', NULL, NULL, '卡牌', 'official', 'https://cp.u2game99.com/storage/operator/20250820/9de0fb2e3b1c6e1afb39fddc897bc21f.png', 'https://www.u2game99.com/data/upload/game/20250821/68a67c3b8c72f.jpg', '[\"https://cp.u2game99.com/storage/operator/20250820/5ba852972a7546c6ff674a4e8662f64e.jpg\", \"https://cp.u2game99.com/storage/operator/20250820/c83594727dd43918508eba5bc66d8cde.jpg\", \"https://cp.u2game99.com/storage/operator/20250820/b3a4bcb95b92f7a0e72386bb44c687c6.jpg\", \"https://cp.u2game99.com/storage/operator/20250820/f300f05a89f4a013089aeee3d7af8a15.jpg\", \"https://cp.u2game99.com/storage/operator/20250820/f028a2c3b428156679e00620cceb6963.jpg\"]', 'https://mp4.277sy.com/sp/13681.mp4', '当三国名将齐齐穿越回石器时代，会产生什么样的碰撞？原创三国+石器时代+放置挂机！在这里，你可以化身一条“咸鱼主公”，带着你的部下，躺着变强——离线挂机也能收获资源，一键领取海量奖励！游戏采用q萌三国画风，武将们既能正经打仗，也能摆烂摸鱼：甄姬拿着羽毛扇、吕布扛着石头戟……爆笑剧情颠覆传统！体验不一样的三国！\r\n\r\n特色玩法：\r\n【全新三国】：原创石器时代的三国名将，Q版角色萌趣搞笑，战斗特效华丽而不浮夸!\r\n【放置养成】：采用自动战斗+离线收益的放置玩法，无需长时间在线，睡觉、上班也能轻松升级！\r\n【轻松战斗】：全自动战斗，轻策略，单手就能激情pk！\r\n【福利拉满】：登录即送蜀国名将SSR“张飞”，更有千抽福利，抽到爽。648？不存在的！\r\n\r\n口号：“躺平即正义，咸鱼终成王！”\r\n适合懒人玩家、三国爱好者和沙雕网友，快来体验最不卷的三国！', '禁止海外推广', NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1311', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1311', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1311', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1311', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-08-11 15:06:59', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:42', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"躺平即正义，咸鱼终成王！\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13681.mp4\",\"text_cps\":\"禁止海外推广\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-08-11 15:06:59\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:0\",\"hw_cps_cpa\":\"CPS推广:15\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/stora