INSERT INTO `gb_games` VALUES (297, 1, NULL, '梦境食旅（送SSR员工嫦娥）', NULL, NULL, '经营', 'official', 'https://cp.u2game99.com/storage/operator/20250821/babda6cf934e3e726f2c04212c60ac38.png', 'https://cp.u2game99.com/storage/operator/20250821/c8e2d6e49611f06931871fbe7bc18091.jpg', '[\"https://cp.u2game99.com/storage/operator/20250821/5e8676b970d7f612424b06f9ac87373a.jpg\", \"https://cp.u2game99.com/storage/operator/20250821/911d440f3b553b3549ab64a1b48c3c7f.jpg\", \"https://cp.u2game99.com/storage/operator/20250821/ceb06a98d76628f16097ae0dd3c915ce.jpg\", \"https://cp.u2game99.com/storage/operator/20250821/8e93fb44722fb9c611bb2f4d503280df.jpg\", \"https://cp.u2game99.com/storage/operator/20250821/0219922252644cc902f115d1693b042f.jpg\"]', 'https://mp4.277sy.com/sp/13699.mp4', '《梦境食旅》是一款美食类模拟养成游戏，融合了餐馆经营、员工收集，战斗和趣味小游戏等多种玩法。 在游戏中，你将享受亲自经营餐馆的乐趣，遇见各种奇怪的顾客，并带领来自异世界的伙伴们一起探索梦境灵界，寻找来自世界各地的美味食谱，展开一段奇妙的旅程。 \r\n\r\n【经营餐馆，邂逅美味】 \r\n-在梦境灵界中开一家属于你的餐馆，邂逅来自各个次元的奇异客人，用一份你的专属美食，换取一段精彩的故事，在经营中寻找烹饪的意义。\r\n \r\n【童话伙伴，携手同行】 \r\n-你不在孤身一人，在梦境灵界中破开次元，招募来自童话传说中的数十位伙伴，高冷优雅的红皇后，尊贵自信的青蛙王子，腹黑萝莉小红帽，闲云野鹤般的姜子牙… 与他们一同经营你的餐馆，经历梦境里一段段笑泪交加的大冒险。\r\n \r\n【绮丽装扮，随心搭配】 \r\n-在这里，我们为你准备了温馨古典的欧式家居，静谧祥和的动物森林，古朴典雅的东方韵味，奇幻迷人的魔法学院，神秘的阿拉伯之夜… 各式主题装扮，任你自由搭配，打造专属于你的梦幻餐馆。 \r\n\r\n【梦境冒险，寻觅佳肴】 \r\n-拉上伙伴勇闯梦灵岛，在出人意料的随机事件中，寻回散落的珍贵菜单，面对梦境世界中混沌的危机，与童话中的伙伴一起揭秘梦境世界不为人知的故事。', '禁止海外推广', NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1327', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1327', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1327', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1327', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-08-14 16:16:40', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:42', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"经营梦境餐馆，烹饪美味佳肴\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13699.mp4\",\"text_cps\":\"禁止海外推广\",\"new\":0,\"yuyue\":0,\"gametype\":\"经营\",\"addtime\":\"2025-08-14 16:16:40\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:50\",\"hw_cps_cpa\":\"CPS海外推广:30\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20250821/babda6cf934e3e726f2c04212c60ac38.png\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1327\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/1327.html\",\"weburl_qr\":\"[base64已省略]\",\"dwzdownurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1327\",\"downurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1327\",\"dwzdownurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1327\",\"gamename\":\"梦境食旅（送SSR员工嫦娥）\",\"excerpt\":\"《梦境食旅》是一款美食类模拟养成游戏，融合了餐馆经营、员工收集，战斗和趣味小游戏等多种玩法。 在游戏中，你将享受亲自经营餐馆的乐趣，遇见各种奇怪的顾客，并带领来自异世界的伙伴们一起探索梦境灵界，寻找来自世界各地的美味食谱，展开一段奇妙的旅程。 \\r\\n\\r\\n【经营餐馆，邂逅美味】 \\r\\n-在梦境灵界中开一家属于你的餐馆，邂逅来自各个次元的奇异客人，用一份你的专属美食，换取一段精彩的故事，在经营中寻找烹饪的意义。\\r\\n \\r\\n【童话伙伴，携手同行】 \\r\\n-你不在孤身一人，在梦境灵界中破开次元，招募来自童话传说中的数十位伙伴，高冷优雅的红皇后，尊贵自信的青蛙王子，腹黑萝莉小红帽，闲云野鹤般的姜子牙… 与他们一同经营你的餐馆，经历梦境里一段段笑泪交加的大冒险。\\r\\n \\r\\n【绮丽装扮，随心搭配】 \\r\\n-在这里，我们为你准备了温馨古典的欧式家居，静谧祥和的动物森林，古朴典雅的东方韵味，奇幻迷人的魔法学院，神秘的阿拉伯之夜… 各式主题装扮，任你自由搭配，打造专属于你的梦幻餐馆。 \\r\\n\\r\\n【梦境冒险，寻觅佳肴】 \\r\\n-拉上伙伴勇闯梦灵岛，在出人意料的随机事件中，寻回散落的珍贵菜单，面对梦境世界中混沌的危机，与童话中的伙伴一起揭秘梦境世界不为人知的故事。\",\"id\":1327,\"game_source\":\"\",\"device_type\":2,\"edition\":0,\"pic_xuanchuan\":\"\",\"strict\":0,\"userfc\":0,\"updatetime\":\"2025-08-22 10:00:00\",\"box_content\":\"1、创角奖励：【SSR员工嫦娥】、【开业庆典装扮*2】、【开业庆典头像框*1】、【钻石*888】、【召唤之证*20】\\r\\n2、8日登录：登录即送海量召唤之证、橙色珍稀厨具、SSR菜谱、SSR员工青行灯\\r\\n3、萌新福利：新人专属福利，启程任务带您一路畅通，赢取SSR员工白雪公主\\r\\n4、幸运2048抽：每日抽不停，获得大量钻石、召唤之证、以及丰厚奖励\\r\\n5、福利签到：签到送海量钻石、召唤之证、SSF员工嫦娥、以及丰厚奖励\\r\\n6、馆长挑战：每日体验不一样的挑战，与馆长们同台比拼，赢取丰厚奖励，更有强力超稀有SSR员工酒吞童子等您来拿！\\r\\n7、钻石礼包：首次购买获得十倍返利，额外获得召唤之证，SR/SSR碎片\",\"pic2\":\"https://cp.u2game99.com/storage/operator/20250821/c8e2d6e49611f06931871fbe7bc18091.jpg\",\"pic3\":\"https://p1.277sy.com/2025/08/21/68a683d150f6a.jpg\",\"pic4\":\"https://p1.277sy.com/2025/08/21/68a683d150514.jpg\",\"cps_ratio\":0,\"hw_ratio\":0,\"hw_firstpay\":1,\"hw_otherpay\":1,\"firstpay\":1,\"otherpay\":1}');
