INSERT INTO `gb_games` VALUES (299, 1, NULL, '破阵勇士（燃烧小宇宙）', NULL, NULL, '卡牌', 'official', 'https://p1.277sy.com/2025/08/18/68a29a9ca83dd.png', 'https://www.u2game99.com/data/upload/game/20250819/68a3d0afb2326.jpg', '[\"https://p1.277sy.com/2025/08/18/68a29a9ca86cf.jpg\", \"https://p1.277sy.com/2025/08/18/68a29a9ca8b58.jpg\", \"https://p1.277sy.com/2025/08/18/68a29a9ca8faa.jpg\", \"https://p1.277sy.com/2025/08/18/68a29a9ca93ad.jpg\", \"https://p1.277sy.com/2025/08/18/68a29a9ca9813.jpg\"]', 'https://mp4.277sy.com/sp/13682.mp4', '天马流星拳划破次元，圣斗士集结，《破阵勇士》黄金圣衣闪耀再现！小宇宙系统点燃，觉醒你的第八感，全系斗士待你召唤，共同为守卫和平而战！				\r\n				\r\n【3D还原 忠于原著】				\r\n环绕音效重现热血战役，逼真的场景，呐喊式的战斗，与儿时记忆重叠的主线剧情，是幻想？不！是真实！				\r\n				\r\n【玩转策略 热血激情】				\r\n顶级音效，奏响热血战斗的乐章！拳拳到肉的热血对决，圣衣带来的属性质变，用智力达成你的目标！				\r\n				\r\n【星座加成 合成革新】				\r\n陪伴角色成长，解锁更深层的星座故事，多种策略玩法多维养成，技能装备全新合成思路，创新才耐玩！				\r\n				\r\n【数值平衡 福利白给】				\r\n新服狂欢豪礼送足一个月！人均欧皇轻松集卡轻松养成，高概率高收益，每个玩家都能爆发小宇宙！				\r\n				\r\n准备好成为圣斗士了吗！用拳头守护大地，用爱见证每个蜕变，快来释放小宇宙，创造属于你的神话！				\r\n', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1312', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1312', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1312', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1312', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-08-11 15:07:59', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:42', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"圣斗士集结圣域，黄金圣衣闪耀觉醒\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13682.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-08-11 15:07:59\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:0\",\"hw_cps_cpa\":\"CPS推广:15\",\"coupon_repeat\":\"\",\"pic1\":\"https://p1.277sy.com/2025/08/18/68a29a9ca83dd.png\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1312\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"htt