INSERT INTO `gb_games` VALUES (307, 1, NULL, '辰东群侠传（3折定制版）', NULL, NULL, '卡牌', 'discount', 'https://cp.u2game99.com/storage/operator/20250815/f576ff0f4a2b2038f780f05c94a12c75.png', 'https://cp.u2game99.com/storage/operator/20250812/1c07e484f73e1e8f8f2eb617cf5feef5.png', '[\"https://cp.u2game99.com/storage/operator/20250812/350808bea65f36af99789a0cedd62819.png\", \"https://cp.u2game99.com/storage/operator/20250812/bba188e78cf6845e372259885fa964d1.png\", \"https://cp.u2game99.com/storage/operator/20250812/732f5f5c2dd44de5aedf85951cca3050.png\", \"https://cp.u2game99.com/storage/operator/20250812/7c95dd34ff18003a83a0a5a065bc980b.png\", \"https://cp.u2game99.com/storage/operator/20250812/df9906dd6fa1c933df12f5a926f4fd7d.png\"]', 'https://mp4.277sy.com/sp/13597.mp4', '《辰东群侠传》是一款正版遮天ip授权的东方玄幻修仙放置卡牌游戏。\n玩家将在这个世界中重温原著的经典情节，同时也将体验到全新的原创剧情。\n一步一步深入这个世界，与楚风、叶凡等熟知的角色并肩作战，面对来自神秘势力的危机。\n', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1235', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1235', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1235', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1235', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-07-16 14:53:12', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:42', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"正版授权东方玄幻修仙放置卡牌游戏\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13597.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-07-16 14:53:12\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20250815/f576ff0f4a2b2038f780f05c94a12c75.png\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1235\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/1235.html\",\"weburl_qr\":\"[base6