INSERT INTO `gb_games` VALUES (312, 1, NULL, '切菜狂人（1折免费版）', NULL, NULL, '放置', 'discount', 'https://cp.u2game99.com/storage/operator/20250805/a6c7bf88c080f8fccdbe5f053e467e53.png', 'https://cp.u2game99.com/storage/operator/20250805/21cd29232d17ca9148a13d376484eb44.jpg', '[\"https://cp.u2game99.com/storage/operator/20250805/0acb9607b63c31321844487df14b501c.jpg\", \"https://cp.u2game99.com/storage/operator/20250805/7ad37a15b090910d518be924b835eaa8.jpg\", \"https://cp.u2game99.com/storage/operator/20250805/2b9565b332abff6ebc4261e091cabdaf.jpg\", \"https://cp.u2game99.com/storage/operator/20250805/b7cf1259771fafab65df85d92a5f29ae.jpg\", \"https://cp.u2game99.com/storage/operator/20250805/58b02111c47cd7d2957a7e909f7274f4.jpg\"]', NULL, '《切菜狂人（1折免费版）》是Q版拟人画风的休闲放置挂机游戏，玩家在游戏中扮演一位绝世食神，通过指挥蔬菜大军与怪物作战，培养成为一个顶尖食神。游戏提供了多种多样的蔬菜角色供玩家选择，并允许玩家自由搭配组合，打造一个独特的蔬菜世界。游戏的主要活动包括招募狂欢、装备狂欢和战宠狂欢，这些活动分为不同的阶段，每个阶段都有其特定的目标和奖励。', '禁海外推广', NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1258', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1258', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1258', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1258', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-07-25 14:32:29', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:42', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"Q版拟人画风的休闲放置挂机游戏\",\"interchangeable_role\":1,\"video\":\"\",\"text_cps\":\"禁海外推广\",\"new\":0,\"yuyue\":0,\"gametype\":\"放置\",\"addtime\":\"2025-07-25 14:32:29\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:0\",\"hw_cps_cpa\":\"CPS推广:30\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20250805/a6c7bf88c080f8fccdbe5f053e467e53.png\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1258\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/1258.html\",\"weburl_qr\":\"[base64已省略]\",\