INSERT INTO `gb_games` VALUES (314, 1, NULL, '黎明召唤（0.05折返100%代金券）', NULL, NULL, '角色扮演', 'discount', 'https://p1.277sy.com/2025/07/31/688b35048b900.gif', 'https://cp.u2game99.com/storage/operator/20250801/42bd6bb53f79ba9480edac19d7280954.jpg', '[\"https://p1.277sy.com/2025/08/04/6890afd4540e3.jpg\", \"https://p1.277sy.com/2025/08/04/6890afd4548be.jpg\", \"https://p1.277sy.com/2025/08/04/6890afd4550d1.jpg\", \"https://p1.277sy.com/2025/08/04/6890afd4557e0.jpg\", \"https://p1.277sy.com/2025/08/04/6890afd455cae.jpg\"]', 'https://mp4.277sy.com/sp/13611.mp4', '冥王神殿里是何人悄然苏醒？九重尖塔上是谁的阴影盘旋？征服之岛中又是什么蠢蠢欲动？古神的低语，令天空变色！\r\n恶魔的咆哮，让大地战栗！幻兽的崛起，让沧海惊惧！勇士游侠，法师贤者，全都集结于此！\r\n用勇气、智慧、坚毅、决心突破重重难关，击败邪恶强敌！拨开云雾吹散阴霾，让《黎明召唤》照耀这个世界！\r\n\r\n游戏特色：\r\n暗黑美术 魔幻纪元\r\n全3D精致建模，次世代渲染技术，再现经典暗黑美术。玩家化身英雄。勇者集结于此，探索神秘的天使大陆，协助天使击溃恶魔，体验不一样的魔幻史诗。\r\n\r\n百变造型 随从坐骑\r\n霸气铠甲、优雅礼服、休闲泳装??百种时装自由搭配，打造个性十足，实力爆表的角色。更有数十种坐骑、随从供你挑选，伴你一起在这个神秘的魔幻世界冒险。\r\n\r\n花式冒险 多种副本\r\n装备超高爆率，一键挂机，暴打BOSS，轻松护肝，神装入手就是这么简单。随机副本，多种玩法，告别无聊的刷刷刷，一起来开动脑筋，挑战极速通关！\r\n\r\n热血PK 激情对战\r\n你若要战，随时奉陪！野外PK突袭玩家，世界BOSS全服乱斗，天梯对决冲击排名，公会开战制霸全服，多种PVP玩法搭配炫酷特效，让你尽情释放战斗热血！\r\n', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1247', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1247', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1247', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1247', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-07-22 09:24:29', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:42', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"0.05折神魔之争，100%反代金券\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13611.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"角色扮演\",\"addtime\":\"2025-07-22 09:24:29\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://p1.277sy.com/2025/07/31/688b35048b900.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1247\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/1247.html\",\"weburl_qr\":\"[base64已省略]\",\"dwzdownurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1247\",\"downurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1247\",\"dwzdownurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1247\",\"gamename\":\"黎明召唤（0.05折返100%代金券）\",\"excerpt\":\"冥王神殿里是何人悄然苏醒？九重尖塔上是谁的阴影盘旋？征服之岛中又是什么蠢蠢欲动？古神的低语，令天空变色！\\r\\n恶魔的咆哮，让大地战栗！幻兽的崛起，让沧海惊惧！勇士游侠，法师贤者，全都集结于此！\\r\\n用勇气、智慧、坚毅、决心突破重重难关，击败邪恶强敌！拨开云雾吹散阴霾，让《黎明召唤》照耀这个世界！\\r\\n\\r\\n游戏特色：\\r\\n暗黑美术 魔幻纪元\\r\\n全3D精致建模，次世代渲染技术，再现经典暗黑美术。玩家化身英雄。勇者集结于此，探索神秘的天使大陆，协助天使击溃恶魔，体验不一样的魔幻史诗。\\r\\n\\r\\n百变造型 随从坐骑\\r\\n霸气铠甲、优雅礼服、休闲泳装??百种时装自由搭配，打造个性十足，实力爆表的角色。更有数十种坐骑、随从供你挑选，伴你一起在这个神秘的魔幻世界冒险。\\r\\n\\r\\n花式冒险 多种副本\\r\\n装备超高爆率，一键挂机，暴打BOSS，轻松护肝，神装入手就是这么简单。随机副本，多种玩法，告别无聊的刷刷刷，一起来开动脑筋，挑战极速通关！\\r\\n\\r\\n热血PK 激情对战\\r\\n你若要战，随时奉陪！野外PK突袭玩家，世界BOSS全服乱斗，天梯对决冲击排名，公会开战制霸全服，多种PVP玩法搭配炫酷特效，让你尽情释放战斗热血！\\r\\n\",\"id\":1247,\"game_source\":\"\",\"device_type\":2,\"edition\":1,\"pic_xuanchuan\":\"\",\"strict\":0,\"userfc\":1,\"updatetime\":\"2025-08-08 08:00:00\",\"box_content\":\"1.【充值福利】所有充值永享0.05折返1倍代金券\\r\\n\\r\\n2.【进游豪礼】开局送XR幻化4件套、8888大礼包\\r\\n\\r\\n3.【满星福利】累计7天登陆送满星XR时装套\\r\\n\\r\\n4.【送2000代金券】活跃度奖励天天送2000代金券\\r\\n\\r\\n5.【送10000充值卡】做任务天天最高领10000充值卡\\r\\n\\r\\n6.【送1000抽】做任务天天最高领1000抽寻宝券\",\"pic2\":\"https://cp.u2game99.com/storage/operator/20250801/42bd6bb53f79ba9480edac19d7280954.jpg\",\"pic3\":\"https://p1.277sy.com/2025/07/31/688b35048e0b6.jpg\",\"pic4\":\"https://p1.277sy.com/2025/07/31/688b3772c09ca.jpg\",\"cps_ratio\":0,\"hw_ratio\":0,\"hw_firstpay\":0.005,\"hw_otherpay\":0.005,\"firstpay\":0.005,\"otherpay\":0.005}');
