INSERT INTO `gb_games` VALUES (317, 1, NULL, '绝世仙王（我欲封天）', NULL, NULL, '角色扮演', 'official', 'https://p1.277sy.com/2025/07/24/6881deec5869e.png', 'https://cp.u2game99.com/storage/operator/20250731/4d3c79d204e0b4edd1194ab1698cbb62.jpg', '[\"https://p1.277sy.com/2025/07/24/6881df2940d59.png\", \"https://p1.277sy.com/2025/07/24/6881df2941391.png\", \"https://p1.277sy.com/2025/07/24/6881df2941943.png\", \"https://p1.277sy.com/2025/07/24/6881df2941f32.png\", \"https://p1.277sy.com/2025/07/24/6881df294251d.png\"]', 'https://mp4.277sy.com/sp/12198.mp4', '次时代3DMMO仙魔手游《绝世仙王》隆重登场。混沌初开，寰宇新诞。魔族残害生灵，嗜血成性。天帝少昊，悲天悯人，封魔族于无尽深渊，遣仙族以镇之。千年后，政通人和，百废俱兴，天明地清，四海升平。天帝见心愿已了，遂遨游天外，不问苍生。然魔族贼心不死，无尽深渊封印动荡，诛魔宝塔摇摇欲坠，昆仑蜀山先后失守，作为天帝之子的你，是否能百战成神，继承众生之意志，一举消灭魔族！', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1189', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1189', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1189', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1189', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-07-02 10:00:40', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:42', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"继承众生之意志，一举消灭魔族\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/12198.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"角色扮演\",\"addtime\":\"2025-07-02 10:00:40\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:55\",\"hw_cps_cpa\":\"CPS海外推广:35\",\"coupon_repeat\":\"\",\"pic1\":\"https://p1.277sy.com/2025/07/24/6881deec5869e.png\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1189\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/1189.html\",\"weburl_qr\":\"[base64已省略]\",\"dwzdownurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1189\",\"downurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1189\",\"dwzdownurlmash\":\"https://qd.u