INSERT INTO `gb_games` VALUES (318, 1, NULL, '大当家之路（0.1折红颜版）', NULL, NULL, '放置', 'discount', 'https://www.u2game99.com/data/upload/game/20250924/68d35c9d581b6.PNG', 'https://www.u2game99.com/data/upload/game/20250806/68933e631a36c.jpg', '[\"https://cp.u2game99.com/storage/operator/20250725/c92d9d7ff7e0adf245e31d990627c173.jpg\", \"https://cp.u2game99.com/storage/operator/20250725/53111bf11bfa22dc914b223ba3148a28.jpg\", \"https://cp.u2game99.com/storage/operator/20250725/51477cf91e23196e47970866ef4373e3.jpg\", \"https://cp.u2game99.com/storage/operator/20250725/c02016bdc03da34c84f07249a4c1fb78.jpg\", \"https://cp.u2game99.com/storage/operator/20250725/3ed665132d30fc4b53f8522e296980fe.jpg\"]', 'https://mp4.277sy.com/sp/13547.mp4', '《大当家之路》是一款的古风模拟经商手游。当第一缕晨光洒在青石巷口，当算盘珠子的脆响惊醒沉睡的街市，你将在这座苏醒的宋代古城开启一段传奇商途。三载春秋伏案，只为重现一幅会呼吸的古代商业长卷。今日诚邀诸位执掌商印，共绘这卷属于您的\"清明上河图\"。\r\n', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1191', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1191', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1191', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1191', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-07-02 11:45:57', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:42', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"共绘这卷属于您的&quot;清明上河图&quot;\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13547.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"放置\",\"addtime\":\"2025-07-02 11:45:57\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://www.u2game99.com/data/upload/game/20250924/68d35c9d581b6.PNG\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1191\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/1191.html\",\"weburl_qr\":\"[base64已省略]\",\"dwzdownurl\":\"htt