INSERT INTO `gb_games` VALUES (336, 1, NULL, '神陵武装（真·原价0.1折）', NULL, NULL, '角色扮演', 'discount', 'https://www.u2game99.com/data/upload/game/20250805/68917163c7235.gif', 'https://www.u2game99.com/data/upload/game/20250805/68917177ec2f6.jpg', '[\"https://www.u2game99.com/data/upload/game/20250805/6891721e116e2.jpg\", \"https://www.u2game99.com/data/upload/game/20250805/68917224ab7a9.jpg\", \"https://www.u2game99.com/data/upload/game/20250805/68917239c6156.jpg\", \"https://www.u2game99.com/data/upload/game/20250805/6891725a4adee.jpg\", \"https://www.u2game99.com/data/upload/game/20250805/68917260dcce5.jpg\"]', 'https://mp4.277sy.com/sp/13407.mp4', '《神陵武装》是3D横版格斗游戏，拥有十大职业，独特的技能树系统，可自主选择天赋技能，搭配属于自己的专属连招；绿色公平的PK系统，数值平衡，全凭操作，秀出你的大神风采；特色深渊史诗副本，体验前所未有的独特掉落机制，与伙伴畅享爆金之旅；\r\n\r\n黑暗笼罩万物，魔神肆虐人间，为了对抗邪恶的魔神，数以万计的冒险家集结一心，培养出十二位实力超绝的勇者，他们不顾危险进入被污染的诅咒之岛，突破黑暗气息的封锁，直面魔神！', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1061', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1061', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1061', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1061', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-05-16 17:24:38', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:42', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"真·原价0.1折全职觉醒，勇士集结\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13407.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"角色扮演\",\"addtime\":\"2025-05-16 17:24:38\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://www.u2game99.com/data/upload/game/20250805/68917163c7235.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1061\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/1061.html\",\"weburl_qr\":\"[base64已省略]\",\"dwzdownurl\":\"https://qd.u2game