INSERT INTO `gb_games` VALUES (337, 1, NULL, '封神让我来', NULL, NULL, '卡牌', 'official', 'https://cp.u2game99.com/storage/operator/20250703/f8aca422903b781035b55d90e1d02225.gif', 'https://cp.u2game99.com/storage/operator/20250703/44718e3e66d272d38c53b19ff80b1125.jpg', '[\"https://cp.u2game99.com/storage/operator/20250703/ce21d60f440f531b524b8b3b42613fcd.jpg\", \"https://cp.u2game99.com/storage/operator/20250703/fec539a65c1b08bb631a6cd5d81b23c8.jpg\", \"https://cp.u2game99.com/storage/operator/20250703/f6123318ccc060a79d7bdf1a34bbb5f1.jpg\", \"https://cp.u2game99.com/storage/operator/20250703/89c3a7bd511cc2e3f5d4462f00cd80bd.jpg\", \"https://cp.u2game99.com/storage/operator/20250703/fc98a30a0ef45e3740e2b0e12e65e067.jpg\"]', 'https://mp4.277sy.com/sp/13537.mp4', '《封神让我来》是放置挂机类游戏，独特国风，温暖友爱，简单不伤肝。全新高自由度RPG玩法，自定义修仙封神，百位神将等你结缘，千种奇遇横穿三界，沉浸式体验封神宇宙。\r\n封神榜怎么上榜，又是谁定的规矩？阐教截教谁对谁错，仙家妖魔又是谁正谁邪？？\r\n', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1182', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1182', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1182', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1182', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-07-01 11:44:35', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:42', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"天命由何人所定，为何不可逆天而行\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13537.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-07-01 11:44:35\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:0\",\"hw_cps_cpa\":\"CPS推广:35\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20250703/f8aca422903b781035b55d90e1d02225.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1182\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/1182.html\",\"weburl_qr\":\"[ba