INSERT INTO `gb_games` VALUES (343, 1, NULL, '新斗罗大陆（GM免费版）', NULL, NULL, '卡牌', 'bt', 'https://cp.u2game99.com/storage/operator/20250630/56e4cda9d30fe2f9b668ec5e24887713.png', 'https://cp.u2game99.com/storage/operator/20250912/0f42ce6845d14560e1ed6497ee56e01f.jpg', '[\"https://cp.u2game99.com/storage/operator/20250912/f6d55303204080e5e3d13e62cff80fbd.jpg\", \"https://cp.u2game99.com/storage/operator/20250912/831d97e23fa22724837356b12cc16f12.jpg\", \"https://cp.u2game99.com/storage/operator/20250912/e6bb32355f216394066f708c538da7a0.jpg\", \"https://cp.u2game99.com/storage/operator/20250912/e98a6ccd89ac5242706d822242920a67.jpg\", \"https://cp.u2game99.com/storage/operator/20250912/8d88d87c09d573a0f124ca26afd81797.jpg\"]', 'https://mp4.277sy.com/sp/13513.mp4', '《新斗罗大陆》是阅文游戏制作发行的手机游戏。该作由唐家三少原著正版改编，是动画《斗罗大陆》官方合作手游，正版授权，100%遵循原著，真实还原小说经典剧情和场景，代入感爆棚；\r\n游戏背景设定在一个名为斗罗大陆的武魂世界，玩家将跟随主角唐三，从十二岁入学史莱克学院开始，与小舞等伙伴一起经历层层考验，踏上魂师修炼之路。游戏特色包括正版授权的剧情还原、自由操控的战斗系统、超萌Q版画风和丰富的培养系统。玩家可以体验到冲锋、瞬间闪移、集火、残血斩杀等战斗激情，同时游戏还提供了副本系统、杀戮之都、斗魂场、猎魂森林等多种玩法。 ', '禁海外推广', NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1160', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1160', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1160', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1160', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-06-25 14:30:32', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:42', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"官方正版授权合作手游\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13513.mp4\",\"text_cps\":\"禁海外推广\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-06-25 14:30:32\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:6\",\"hw_cps_cpa\":\"CPS海外推广:6\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20250630/56e4cda9d30fe2f9b668ec5e24887713.png\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1160\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/1160.html\",\"weburl_qr\":\"[base64已省略]\",\"dwzdownurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1160\",\"downurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1160\",\"dwzdownurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1160\",\"gamename\":\"新斗罗大陆（GM免费版）\",\"excerpt\":\"《新斗罗大陆》是阅文游戏制作发行的手机游戏。该作由唐家三少原著正版改编，是动画《斗罗大陆》官方合作手游，正版授权，100%遵循原著，真实还原小说经典剧情和场景，代入感爆棚；\\r\\n游戏背景设定在一个名为斗罗大陆的武魂世界，玩家将跟随主角唐三，从十二岁入学史莱克学院开始，与小舞等伙伴一起经历层层考验，踏上魂师修炼之路。游戏特色包括正版授权的剧情还原、自由操控的战斗系统、超萌Q版画风和丰富的培养系统。玩家可以体验到冲锋、瞬间闪移、集火、残血斩杀等战斗激情，同时游戏还提供了副本系统、杀戮之都、斗魂场、猎魂森林等多种玩法。 \",\"id\":1160,\"game_source\":\"\",\"device_type\":2,\"edition\":2,\"pic_xuanchuan\":\"\",\"strict\":0,\"userfc\":0,\"updatetime\":\"2025-07-02 09:00:00\",\"box_content\":\"福利1：每日送100元可拆分限时代金券\\r\\n福利2：内置0.1折商城充值钻石\\r\\n福利3：内置GM工具，可解锁部分特权\\r\\n福利4：首充免费领取SP唐三\\r\\n福利5：GM余额免费充值\\r\\n福利6：充值比例1:1000钻石\",\"pic2\":\"https://cp.u2game99.com/storage/operator/20250912/0f42ce6845d14560e1ed6497ee56e01f.jpg\",\"pic3\":\"https://www.u2game99.com/data/upload/game/20250912/68c3c0b7a782c.jpg\",\"pic4\":\"https://www.u2game99.com/data/upload/game/20250912/68c3c112065e3.jpg\",\"cps_ratio\":0,\"hw_ratio\":0,\"hw_firstpay\":0.45,\"hw_otherpay\":0.45,\"firstpay\":0.35,\"otherpay\":0.35}');
INSERT INTO `gb_games` VALUES (344, 1, NULL, '少年三国志：零（首款少三系0.1折） ', NULL, NULL, '回合', 'discount', 'https://www.u2game99.com/data/upload/game/20251202/692e81ef1d4f8.png', 'https://www.u2game99.com/data/upload/game/20251225/694ce7aae938c.png', '[\"https://www.u2game99.com/data/upload/game/20250917/68ca6e9833973.jpg\", \"https://www.u2game99.com/data/upload/game/20250917/68ca6e9deeef0.jpg\", \"https://www.u2game99.com/data/upload/game/20250917/68ca6ea21e391.jpg\", \"https://www.u2game99.com/data/upload/game/20250917/68ca6ea521645.jpg\", \"https://www.u2game99.com/data/upload/game/20250917/68ca6ea99810f.jpg\"]', 'https://mp4.277sy.com/sp/13420.mp4', '《少年三国志：零》是游族「少年三国志」系列全新力作。独创4x4布局，流派组合千变万化，兵将军师皆有可为。品质升级，龙魂觉醒，称霸九州战场！\r\n【4X4布阵，策略制胜】\r\n4×4布阵，独创颠覆性策略卡牌玩法！三国名将划至重、轻、步、盾、弓、谋六种职业，玩家可以根据兵种相克的特点自由部署，以奇制胜！\r\n【公平竞技，跨服争锋】\r\n全新赛季制玩法，豪华福利，多样副本等你探索！实时匹配，激烈对决一触即发！\r\n【军师控场，奇计百出】\r\n军师出战，神机妙算掌控全局！技能融合、威力叠加，实时决策、局势扭转，尽享即时战略快感！\r\n【猛将强兵，自由搭配】\r\n不同流派，豪华阵容，打造极富创意的战斗体系。小兵能逆袭，武将皆C位！快来pick你心目中的神将精兵！', '禁海外推广', 'https://www.u2game99.com/data/upload/source/20250926/68d65bf42615b.jpg', NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1079', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1079', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1079', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1079', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-05-22 14:00:06', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:42', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"少年三国志系列首款0.1折\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13420.mp4\",\"text_cps\":\"禁海外推广\",\"new\":0,\"yuyue\":0,\"gametype\":\"回合\",\"addtime\":\"2025-05-22 14:00:06\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://www.u2game99.com/data/upload/game/20251202/692e81ef1d4f8.png\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1079\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/1079.html\",\"weburl_qr\":\"[base64已省略]\",\"dwzdownurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1079\",\"downurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1079\",\"dwzdownurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1079\",\"gamename\":\"少年三国志：零（首款少三系0.1折） \",\"excerpt\":\"《少年三国志：零》是游族「少年三国志」系列全新力作。独创4x4布局，流派组合千变万化，兵将军师皆有可为。品质升级，龙魂觉醒，称霸九州战场！\\r\\n【4X4布阵，策略制胜】\\r\\n4×4布阵，独创颠覆性策略卡牌玩法！三国名将划至重、轻、步、盾、弓、谋六种职业，玩家可以根据兵种相克的特点自由部署，以奇制胜！\\r\\n【公平竞技，跨服争锋】\\r\\n全新赛季制玩法，豪华福利，多样副本等你探索！实时匹配，激烈对决一触即发！\\r\\n【军师控场，奇计百出】\\r\\n军师出战，神机妙算掌控全局！技能融合、威力叠加，实时决策、局势扭转，尽享即时战略快感！\\r\\n【猛将强兵，自由搭配】\\r\\n不同流派，豪华阵容，打造极富创意的战斗体系。小兵能逆袭，武将皆C位！快来pick你心目中的神将精兵！\",\"id\":1079,\"game_source\":\"https://www.u2game99.com/data/upload/source/20250926/68d65bf42615b.jpg\",\"device_type\":2,\"edition\":1,\"pic_xuanchuan\":\"\",\"strict\":0,\"userfc\":1,\"updatetime\":\"2025-07-01 08:00:00\",\"box_content\":\"【上线豪礼】创角赠3星张飞，直升橙品横扫三国，还送200连抽+648 黄金券！\\r\\n【真龙试炼】免费完成真龙试炼，张飞直升满星18资质，飞升成神\\r\\n【真实代金】每日 648 通宝券（不限时、可拆分），每周额外再送 1000通宝券及百连抽等奖励\\r\\n【少年打金】每日最高万元打金额度，送尊贵特权、战令和大量礼包\\r\\n【每日签到】每日送 648 黄金券，月累计再送 5000 黄金券、自选金色宝物+自选军师\\r\\n【开局特权】七大特权免费领，两大特权再进阶更畅爽\\r\\n【在线福利】在线30 分钟即得 648 通宝券+200连抽\\r\\n【七日登录】首日即领百连抽，登录再送648通宝券x3、核心军师+双满星主将\",\"pic2\":\"https://www.u2game99.com/data/upload/game/20251225/694ce7aae938c.png\",\"pic3\":\"https://www.u2game99.com/data/upload/game/20251225/694ce7d03f4e7.jpg\",\"pic4\":\"https://www.u2game99.com/data/upload/game/20251225/694ce7d82b39c.jpg\",\"cps_ratio\":0,\"hw_ratio\":0,\"hw_firstpay\":0.01,\"hw_otherpay\":0.01,\"firstpay\":0.01,\"otherpay\":0.01}');
INSERT INTO `gb_games` VALUES (345, 1, NULL, '龙神万相：神战', NULL, NULL, '卡牌', 'official', 'https://cp.u2game99.com/storage/operator/20250624/eac7a37e9400e4f8a10132f43765245f.png', 'https://cp.u2game99.com/storage/operator/20250624/567e58c764c27fa50e2e83f5223b4a83.jpg', '[\"https://cp.u2game99.com/storage/operator/20250624/cc941041af94d2a2ca9fb177c4af87a7.jpg\", \"https://cp.u2game99.com/storage/operator/20250624/ed783f5bacabb8c57ac9260b3d188954.jpg\", \"https://cp.u2game99.com/storage/operator/20250624/cfc3a308e13ec204cc2eab5aea79f0dc.jpg\", \"https://cp.u2game99.com/storage/operator/20250624/edbb0dc117b7f8f5d276633536972b9e.jpg\", \"https://cp.u2game99.com/storage/operator/20250624/d9552f3a4f56c35efb925ee843293193.jpg\"]', 'https://mp4.277sy.com/sp/13490.mp4', '《龙神万相：神战》是由热血国漫《西行纪》正版授权改编而成的策略卡牌手游，你将成为西行小队中的一员，重启西行之路，游戏中设计了丰富的PVP和PVE玩法，如：跨越阴阳、巅峰竞技、龙神八部、修罗来袭、王者之战、跨越阴阳等，每个玩法别具趣味性和竞技感，满足玩家对西行路上的挑战和探索。一起重燃热血西行魂，这一次，不为苍生，只为自己！ ', '禁海外推广', NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1140', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1140', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1140', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1140', 'android', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-06-17 17:16:47', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:42', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"真实还原热血西行之旅\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13490.mp4\",\"text_cps\":\"禁海外推广\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-06-17 17:16:47\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:0\",\"hw_cps_cpa\":\"CPS推广:15\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20250624/eac7a37e9400e4f8a10132f43765245f.png\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1140\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game9