INSERT INTO `gb_games` VALUES (346, 1, NULL, '飓风三国', NULL, NULL, '策略', 'official', 'https://www.u2game99.com/data/upload/game/20250623/68591bfec0b37.png', 'https://www.u2game99.com/data/upload/game/20250623/68591e5cc6df5.jpg', '[\"https://www.u2game99.com/data/upload/game/20250623/68591eae14a7a.jpg\", \"https://www.u2game99.com/data/upload/game/20250623/68591eae294fa.jpg\", \"https://www.u2game99.com/data/upload/game/20250623/68591eae16152.jpg\", \"https://www.u2game99.com/data/upload/game/20250623/68591eafd0933.jpg\", \"https://www.u2game99.com/data/upload/game/20250623/68591eb00c95e.jpg\"]', 'https://mp4.277sy.com/sp/13486.mp4', '《飓风三国》是将三国历史和战斗合二为一的策略游戏。多职业战争策略、自由组合武将阵容、SLG 全新3D大世界、三国名将任你搭配、赛季制对抗策略玩法，并且采用季节系统来影响游戏的策略和战斗的场景。高度还原真实三国历史战争多种战略玩法。体验前所未有的SLG沙盘乐趣和激动人心的三国征战。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1137', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1137', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1137', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1137', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-06-16 15:16:06', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:42', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"攻城略地，体验三国争霸的乐趣‌\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13486.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"策略\",\"addtime\":\"2025-06-16 15:16:06\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:55\",\"hw_cps_cpa\":\"CPS海外推广:35\",\"coupon_repeat\":\"\",\"pic1\":\"https://www.u2game99.com/data/upload/game/20250623/68591bfec0b37.png\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1137\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/1137.html\",\"weburl_qr\":\"[base64已省略]\",\"dwzdownurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1137\",\"downurlmash\":\"https://qd.u2game99.com/dow