INSERT INTO `gb_games` VALUES (348, 1, NULL, '神州风闻录（0.1免费版）', NULL, NULL, '角色扮演', 'discount', 'https://p1.277sy.com/2025/06/05/6841525716e18.png', 'https://cp.u2game99.com/storage/operator/20250604/1949abe709a2c76b8c951374be0adca8.jpg', '[\"https://cp.u2game99.com/storage/operator/20250604/754173fcb9d70828dc2fb488bda6ac27.jpg\", \"https://cp.u2game99.com/storage/operator/20250604/18cc0dab92ceb03379f63f905f6e8589.jpg\", \"https://cp.u2game99.com/storage/operator/20250604/df82bcc5ea89b3350d86be1faeeb504f.jpg\", \"https://cp.u2game99.com/storage/operator/20250604/30ede9e2469228f2b039ea19c9132418.jpg\", \"https://cp.u2game99.com/storage/operator/20250604/0b0a1fc1fcee2ad5216761d43463996f.jpg\"]', 'https://mp4.277sy.com/sp/13333.mp4', '神州世界烽烟四起\r\n神秘人携其爪牙为祸四方\r\n救世主们\r\n唤醒被封印的侍从\r\n与神秘人抗争，拯救神州世界吧！\r\n\r\n《神州风闻录》作为一款以山海经为题材的策略放置卡牌，将致力于打造神话世界，与玩家们共同书写神话故事。\r\n\r\n- 超萌治愈，飒气十足\r\n不同于市面上千篇一律的大长腿，黑丝或萝莉，独特的画风带你领略山海异兽也有Q萌的一面。\r\n\r\n- 放置休闲，轻松娱乐\r\nPvE/PvP/GvG，可同时多线并行多个玩法，更有自动挂机保肝护肾！\r\n\r\n- 搭配至上，越战逆袭\r\n变换阵法及侍从站位，动动指尖实现越战逆袭，体验丰富策略纵深！\r\n\r\n- 活动丰富，挑战自我\r\n定期开放特色活动，即可轻松完成领取保底，也可向最高难度发起挑战，赢取最高荣耀！', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=997', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=997', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=997', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=997', 'android', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-04-25 13:47:26', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:42', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"结缘异兽来冒险！\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13333.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"角色扮演\",\"addtime\":\"2025-04-25 13:47:26\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://p1.277sy.com/2025/06/05/6841525716e18.png\",\"version\":0,\"c_version\":0,\"downur