INSERT INTO `gb_games` VALUES (349, 1, NULL, '拯救小宇宙（0.1折鬼灭之刃）', NULL, NULL, '卡牌', 'discount', 'https://www.u2game99.com/data/upload/game/20250731/688ae5c325e2d.gif', 'https://cp.u2game99.com/storage/operator/20250731/9098f05168cde8cd6ea0bb06b00322f2.jpg', '[\"https://www.u2game99.com/data/upload/game/20250722/687f55d6b7e2b.jpg\", \"https://www.u2game99.com/data/upload/game/20250722/687f55dd8eca2.jpg\", \"https://www.u2game99.com/data/upload/game/20250722/687f55e374fce.jpg\", \"https://www.u2game99.com/data/upload/game/20250722/687f55e951369.jpg\", \"https://www.u2game99.com/data/upload/game/20250722/687f55ef92976.jpg\"]', 'https://mp4.277sy.com/sp/13344.mp4', '拯救小宇宙（0.1折鬼灭之刃）是一款改编自热门动漫《鬼灭之刃》的卡牌手游，高度还原的原著精彩剧情，是体验游戏玩法的特色之一，游戏人物和技能也都设计的十分精美，旨在给玩家营造一个身临其境的“鬼灭”环境。玩法上属于卡牌策略手游，下收集不同卡牌，组成最强阵容，根据敌属性制定正确战术，不断培养并强化卡牌能力，提高队伍实力。此外游戏内提供了多种社交玩法，加入公会，与其他玩家组队探索，挑战强敌；参加公会战，增进互动及提高游戏黏性。其次丰富的PvE与PvP玩法亦可满足不同玩家需求，可千万不要错过哟~ \r\n\r\n===【特色亮点】===\r\n1、高人气动漫IP转化：《拯救小宇宙》基于热门动漫《鬼灭之刃》改编而至，游戏里拥有相同的人物，故事和世界观，深受动漫迷的喜爱。\r\n2、卡牌策略游戏：玩家需要收集不同的卡牌来发展阵容和进行关卡 challenge。需要合理的阵容搭配和策略应用来决定战斗结果。\r\n3、放置养成元素：融入放置养成手游的玩法，玩家需要通过擂台等手段来获得资源，并利用这些资源来养成和强化卡牌，提高战斗力。\r\n4、多元化战斗角色：游戏中玩家可以扮演动漫人物如炭治郎，祢豆子，我妻善逸等，并选择不同属性的阵容如烈火，流水，风雷，血鬼来进行战斗。\r\n5、剧情关卡设计：游戏按动漫剧情设计了不同的副本关卡，玩家可以体验动漫中的剧情設定，边缘角色也在游戏中起到重要作用，增加玩家乐趣。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1007', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1007', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1007', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1007', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-04-28 11:50:30', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:42', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"0.1折高人气IP动漫鬼灭之刃\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13344.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-04-28 11:50:30\",\"gn_extension\":1,\"hw_extension\":1