INSERT INTO `gb_games` VALUES (351, 1, NULL, '战魂旅人（新世界伟大航道）', NULL, NULL, '卡牌', 'official', 'https://cp.u2game99.com/storage/operator/20250610/173081c49d6c84de6fa94041ca2eac49.png', 'https://cp.u2game99.com/storage/operator/20250610/d46e40157d2ececc054c5d752bf719cc.png', '[\"https://cp.u2game99.com/storage/operator/20250610/88fb4d02744de9c5f0d1d616544396a4.jpg\", \"https://cp.u2game99.com/storage/operator/20250610/1d7167d15323d98c0ad3f82275c096f1.jpg\", \"https://cp.u2game99.com/storage/operator/20250610/5f36ea1c3b729900378fbdccb73d8978.jpg\", \"https://cp.u2game99.com/storage/operator/20250610/6e32b52372c1c5c064c6c1468df3fc14.jpg\", \"https://cp.u2game99.com/storage/operator/20250610/aecbbe29eeac4a2ded8cf66f60ef9a0e.jpg\"]', 'https://mp4.277sy.com/sp/13455.mp4', '《战魂旅人》创新手办风打造航海新征途！全新玩法诠释剧情，视觉观赏效果提升，音效搭配战斗节奏，让每位船长都能用上钟爱的伙伴组成强大旅团，共同踏上一段充满挑战与奇遇的航海宝藏寻觅之路，将传奇书写在每一寸海域！\r\n\r\n----游戏特色----\r\n【浪尖传奇 动画体验】\r\n匠心打造3D超长主线新剧情，高质感立体角色，场景一比一还原！\r\n\r\n【豪华阵容 零损卡池】\r\n十大伙伴齐上阵，多种阵型搭配，无损换角，你喜爱的角色都能用！\r\n\r\n【全屏特效 热血启航】\r\n大制作定制角色性格打斗技能特效，指尖上演绎航海传说的奥义！\r\n\r\n【资源满舱 供应不停】\r\n登录享特权，签到福利常刷新，资源不停送，每次航海都满载而归！\r\n\r\n【社交互动 跨服竞技】\r\n分时段竞技场合理安排，跨服公会对决，新增家园社区，趣味互动！\r\n\r\n海浪翻涌，大海在呼唤各位勇者！伙伴的意志支撑起不灭的火种！燃烧吧！让神明见证，把船长的名字刻进传说！命运的齿轮转动了，属于各位船长的时代来临了！集结伙伴，扬起风帆，向着宝藏，全速前进！', '禁海外推广', NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1105', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1105', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1105', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1105', 'android', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-06-03 16:17:27', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:42', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"航海3D横板策略卡牌手游，成为航海王者！\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13455.mp4\",\"text_cps\":\"禁海外推广\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-06-03 16:17:27\",\"gn_extension\":1,\"hw_extension\":