INSERT INTO `gb_games` VALUES (352, 1, NULL, '我叫MT：归来（保真0.05折福利版）', NULL, NULL, '放置', 'discount', 'https://cp.u2game99.com/storage/operator/20250528/eef7567ccc4821b498538dffed676f29.gif', 'https://cp.u2game99.com/storage/operator/20250528/4badd212ae8525eb42c199250395d2fa.jpg', '[\"https://www.u2game99.com/data/upload/game/20250612/684a7d9a61e07.jpg\", \"https://www.u2game99.com/data/upload/game/20250612/684a7d9a8e374.jpg\", \"https://www.u2game99.com/data/upload/game/20250612/684a7d9ac8632.jpg\", \"https://www.u2game99.com/data/upload/game/20250612/684a7d9fc036e.jpg\", \"https://www.u2game99.com/data/upload/game/20250612/684a7da029d7b.jpg\"]', 'https://mp4.277sy.com/sp/13360.mp4', '正版动画授权的3D放置卡牌手游《我叫 MT：归来》0.05 折版本重磅来袭！它完美再现动漫角色，让你与哀木涕、傻馒等经典形象再度相聚，带来纯正卡牌体验。玩家能组建五人小队勇闯艾泽大陆，这里上百种 BOSS、数十个大型副本，每日都有全新冒险涌现，时刻刺激着你的挑战欲。海量坐骑、宠物、神器散落各处，收集它们可大幅增强实力，助你在战斗中更胜一筹。战斗机制丰富多样，面对狂暴、复活等特色鲜明的 BOSS，需巧用 “集火”“控制” 策略应对，极其考验策略与操作。而且游戏充满欢乐氛围，在体验与动漫角色并肩作战的热血激情同时，还能尽享社交互动的无穷乐趣，快来加入《我叫 MT：归来》开启属于你的传奇冒险之旅吧！', '禁海外推广', NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1020', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1020', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1020', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1020', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-05-06 15:15:48', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:42', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"保真0.05折福利版\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13360.mp4\",\"text_cps\":\"禁海外推广\",\"new\":0,\"yuyue\":0,\"gametype\":\"放置\",\"addtime\":\"2025-05-06 15:15:48\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20250528/eef7567ccc4821b498538dffed676f29.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1020\",