INSERT INTO `gb_games` VALUES (355, 1, NULL, '美食大乱斗（0.1折免费版）', NULL, NULL, '卡牌', 'discount', 'https://www.u2game99.com/data/upload/game/20250630/6861ec62862ad.gif', 'https://www.u2game99.com/data/upload/game/20250630/6861eba32e1b7.jpg', '[\"https://www.u2game99.com/data/upload/game/20250619/6853d5bdb2b2b.jpg\", \"https://www.u2game99.com/data/upload/game/20250619/6853d5d2e3e2f.jpg\", \"https://www.u2game99.com/data/upload/game/20250619/6853d5d9b82b1.jpg\", \"https://www.u2game99.com/data/upload/game/20250619/6853d5e1e3cf3.jpg\", \"https://www.u2game99.com/data/upload/game/20250619/6853d5e8d84aa.jpg\"]', 'https://mp4.277sy.com/sp/13410.mp4', '《美食大乱斗》是一款以美食拟人化的高颜值手游，在游戏中玩家将会化身为命运之子，穿越到灵界大陆之中，通过招募并培养来自世界各地的食之精灵组件最强战队，突破重重险阻，探险神秘的灵界，寻找迷雾背后隐藏的真相。\r\n\r\n【吃货的美食江湖】		\r\n各具地域特色的食之精灵，美食的每一个瞬间，无不是画师的精心绘制		\r\n		\r\n【美食之间的羁绊】		\r\n不同的食物间既可是挚友，也能是死敌，不同的食物间碰撞出全新的美味		\r\n		\r\n【挂机即可来白嫖】		\r\n只要每日坚持挂机即可白嫖各种免费资源，如果你能微氪会让你游戏更爽		\r\n		\r\n【收集各色美味】		\r\n作为一个干饭人，还有什么能比收集到各种不同口味，不同特色的美食更有吸引力？', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1064', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1064', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1064', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1064', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-05-19 16:51:09', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:42', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"全场享0.1折，天天送6480代金劵\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13410.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-05-19 16:51:09\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://www.u2game99.com/data/upload/game/20250630/6861ec62862ad.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1064\",\"qrcode\":\"[base64已省略