INSERT INTO `gb_games` VALUES (357, 1, NULL, '西游记之托塔天王（0.05折天天送代金）', NULL, NULL, '卡牌', 'discount', 'https://cp.u2game99.com/storage/operator/20250710/c3c2223cddce0e5791a0a1d4c7fbceac.gif', 'https://cp.u2game99.com/storage/operator/20250710/2836aa39be728bc73a2fefbbe9cc3679.jpg', '[\"https://cp.u2game99.com/storage/operator/20250519/1460f36f1b91c4048ec98b6d0891618b.jpg\", \"https://cp.u2game99.com/storage/operator/20250519/0b33b4faeb751b59672d2ab58f3a0740.jpg\", \"https://cp.u2game99.com/storage/operator/20250519/18253727149b7fbfb1498ff992d1f5e5.jpg\", \"https://cp.u2game99.com/storage/operator/20250519/0f5685d356be0ebe19c3302b06339e07.jpg\", \"https://cp.u2game99.com/storage/operator/20250519/2037a1bfdaf57ea65a55b9cddb980349.jpg\"]', 'https://mp4.277sy.com/sp/13388.mp4', '《西游记之托塔天王》三界全员颜值在线，国风立绘令人眼前一亮，西游人物形象还原。玩家在完成西游取经的世界中冒险战斗，提升自己，打造神将队伍。每个玩家拥有属于自己的洞天福地，可以进行种植仙树。也可前往灵界试炼探索。休闲挂机玩法，玩家可以用过挂机、云游、灵界试炼放置玩法获取游戏资源来提升自己，养成神将。神将分解、重置可以返还养成资源，万象法阵玩法可以同步神将等级，减少了养成压力。新的西行即将开始，期待与仙友们共闯三界。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1046', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1046', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1046', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=1046', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-05-13 16:33:48', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:42', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"宿命轮回，因果未了再西行。\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13388.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-05-13 16:33:48\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20250710/c3c2223cddce0e5791a0a1d4c7fbceac.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1046\",\"qrco