INSERT INTO `gb_games` VALUES (363, 1, NULL, '群英天下 (0.05折千元代金神将版)  ', NULL, NULL, '策略', 'discount', 'https://www.u2game99.com/data/upload/game/20250929/68da4e0f66d69.gif', 'https://www.u2game99.com/data/upload/game/20250929/68da4e1fe15f8.jpg', '[\"https://www.u2game99.com/data/upload/game/20250929/68da4e92ad2aa.jpg\", \"https://www.u2game99.com/data/upload/game/20250929/68da4e9905c3a.jpg\", \"https://www.u2game99.com/data/upload/game/20250929/68da4ea1d1f7f.jpg\", \"https://www.u2game99.com/data/upload/game/20250929/68da4ea727b47.jpg\", \"https://www.u2game99.com/data/upload/game/20250929/68da4eac60ee4.jpg\"]', 'https://mp4.277sy.com/sp/13184.mp4', '《群英天下》是2025年备受瞩目的三国题材策略手游巨作，以创新性的放置卡牌玩法为核心，完美还原了那个烽火连天的英雄时代。游戏通过多元化的玩法设计，为玩家构建了一个极具沉浸感的三国战场。\r\n在PVE玩法方面：\r\n剿灭叛军：体验快节奏的即时战斗，率领精锐之师扫荡四方\r\n洞窟探秘：探索隐藏着传世珍宝的神秘地穴，揭开三国未解之谜\r\n破阵降敌：运用兵法韬略破解上古奇阵，展现统帅之才\r\nPVP竞技系统同样精彩纷呈：\r\n战场夺宝：与其他玩家展开宝物争夺，考验临场应变能力\r\n名将对决：收集培养三国名将，打造专属英雄阵容\r\n城池攻防：指挥千军万马参与史诗级城战，体验真实的古代战争\r\n游戏独创的智能放置系统让玩家既能享受策略布阵的乐趣，又能轻松获得成长收益。上百位三国名将各具特色，玩家可自由搭配组合，开发独门战术。无论是运筹帷幄的军师，还是冲锋陷阵的猛将，都能在这里找到属于自己的战场。\r\n《群英天下》以精美的画面表现、深度的策略玩法、丰富的社交互动，重新定义了三国手游的体验标准，让每位玩家都能书写属于自己的三国传奇。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=868', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=868', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=868', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=868', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-03-26 17:43:53', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:43', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"三国策略卡牌，指尖争霸！\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13184.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"策略\",\"addtime\":\"2025-03-26 17:43:53\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://www.u2game99.com/data/upload/game/20250929/68da4e