INSERT INTO `gb_games` VALUES (365, 1, NULL, '上古纷争（0.1折免费版）', NULL, NULL, '放置', 'discount', 'https://p1.277sy.com/2025/04/22/680712e874f7c.png', 'https://cp.u2game99.com/storage/operator/20250425/2cd68dd26951ce4b11ef2ce3eebe3014.jpg', '[\"https://cp.u2game99.com/storage/operator/20250425/df3533497f5fa82f981a5ae1a05ce17a.jpg\", \"https://cp.u2game99.com/storage/operator/20250425/32a1e6dd9633f9b5d233f4717705cca0.jpg\", \"https://cp.u2game99.com/storage/operator/20250425/8baa7455aaf190a8c4a73ea1d8ecdbf9.jpg\", \"https://cp.u2game99.com/storage/operator/20250425/8838797b67cebafdd91056338096c7a2.jpg\", \"https://cp.u2game99.com/storage/operator/20250425/fe08cb85b0d5fbd38e5f6f3641cc20d3.jpg\"]', 'https://mp4.277sy.com/sp/13165.mp4', '为了争夺上古世界的统治，无数神魔在无尽岁月的争斗中陨落，最终形成了主宰世界的六大阵营。\r\n然而，跨越万载的和平下，是黑暗势力不断滋长的野心。战火重燃，有志之士纷涌而起，谁能为世界再次带来和平？\r\n\r\n【游戏特色】\r\n·放置战斗，挂机变强\r\n点开战斗便无需关注战场，自由切换至其他场景，护肝护眼，轻松闯关！\r\n挂机也能获得奖励，你的英雄们将一直为你自动战斗，一觉睡醒就能变强！\r\n\r\n·告别羁绊，阵容随心\r\n去除一般卡牌游戏的羁绊系统，仅保留六大阵营的克制关系，彻底释放英雄，让阵容搭配更加随心所欲！\r\n\r\n·良心抽卡，十连必金\r\n不需要苦苦攒保底，十连召唤必得五星金卡，卡池无锁定，五星无废卡！\r\n\r\n·无损回退，自由养成\r\n已经培养的英雄，可以通过回退返还所有消耗的材料和英雄，妈妈再也不用担心我养错英雄了！\r\n\r\n·真实画风，享受旅途\r\n对二次元已经审美疲劳？壮丽唯美的景色，精致真实的人物，带你领略别样的异世界之旅！', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=850', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=850', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=850', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=850', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-03-20 15:14:37', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:43', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"神魔放置，登录送百抽，0.1折送6480代金劵\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13165.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"放置\",\"addtime\":\"2025-03-20 15:14:37\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pi