INSERT INTO `gb_games` VALUES (366, 1, NULL, '乱世逐鹿（0.1折权谋天下）', NULL, NULL, '策略', 'discount', 'https://p1.277sy.com/2025/04/25/680b5ce3003a9.gif', 'https://cp.u2game99.com/storage/operator/20250427/4af94f8b92510fa9b4a2b50b19d745db.jpg', '[\"https://cp.u2game99.com/storage/operator/20250427/83e62fa8c685bccd50e7a7bd45b20091.jpg\", \"https://cp.u2game99.com/storage/operator/20250427/50a2d20205eccc566556c3c7e8ab7c81.jpg\", \"https://cp.u2game99.com/storage/operator/20250427/e8cd42745093639b46839fb76094309c.jpg\", \"https://cp.u2game99.com/storage/operator/20250427/bde00b4636dc3f05722bfca65ad78b98.jpg\", \"https://cp.u2game99.com/storage/operator/20250427/01c43431c49387b729c3bf37f6b6edc1.jpg\"]', 'https://mp4.277sy.com/sp/13248.mp4', '《乱世逐鹿(0.1折权谋天下》是一款是三国时代为背景所打造的次世代策略手游，该游戏内世界观和关卡设定由著名作家打造，其游戏剧情完美还原了汉末和三国时代的风云变幻，即温酒斩华雄、火烧洛阳到后面的三分天下等壮阔场景，玩家可以参与其中，招募熟悉的历史人物，无论是风华绝代的貂蝉还是人中吕布的奉先，都可以收集起来并组成流派打法，游戏内采用即时制战斗玩法，需要玩家时刻把控局势的变化，操作你手下的士兵取得一场场战斗的胜利，且还得需要注意关卡的层层设定，你需要灵活运用武将的特性来进行挑战。让我们一起亲历群雄逐鹿中原，成就一方霸主！', '禁海外推广', NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=924', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=924', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=924', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=924', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-04-10 14:59:09', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:43', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"三国时代背景次世代策略手游\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13248.mp4\",\"text_cps\":\"禁海外推广\",\"new\":0,\"yuyue\":0,\"gametype\":\"策略\",\"addtime\":\"2025-04-10 14:59:09\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://p1.277sy.com/2025/04/25/680b5ce3003a9.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=924\",\"qrcode\":\"[base64已省略]\",\"we