INSERT INTO `gb_games` VALUES (376, 1, NULL, '天堂魔狱（0.05折百倍爆率千金版）', NULL, NULL, '角色扮演', 'discount', 'https://cp.u2game99.com/storage/operator/20251218/26c43e5d451a911a3436f45432f54531.png', 'https://cp.u2game99.com/storage/operator/20251218/14c32f5badd8b6a834a51c36ddf999aa.jpg', '[\"https://cp.u2game99.com/storage/operator/20250408/9f3670a75ae9ad3f463464314db6e6aa.jpg\", \"https://cp.u2game99.com/storage/operator/20250408/cd182e709aa581bd95c5e7f6d59bdc9e.jpg\", \"https://cp.u2game99.com/storage/operator/20250408/ec215bb490de3c7dc3cc677ab24598e5.jpg\", \"https://cp.u2game99.com/storage/operator/20250408/d800415755168a6136c894596c05c88d.jpg\", \"https://cp.u2game99.com/storage/operator/20250408/3bfb62eabfeb97859c05fd3f06206465.jpg\"]', 'https://mp4.277sy.com/sp/12786.mp4', '【2025年度巨献】3D仙侠手游巅峰之作《天堂魔狱》震撼登场！踏入绝美仙境，启程主线奇缘，由顶尖引擎精心雕琢的仙侠世界全面展开。无界大地图，随心瞬移，每一处细腻场景等你来自由探索。五大职业，各具特色，任你挑选，开启专属修仙之旅。即时战斗，热血江湖，恩怨情仇即刻上演！历经磨砺，等级飙升，转生飞仙，攀登魔狱之巅，成就无上荣耀。真实社交，精准匹配，修仙路上不再孤单。《天堂魔狱》独创情缘系统，助你邂逅命中注定的另一半，共建梦幻家园，双修共进，修为提升快人一步！此刻，仙侠之旅已为你铺展，你，准备好了吗？《天堂魔狱》，等你来战！', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=501', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=501', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=501', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=501', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2024-12-25 17:12:06', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:43', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"全场尊享0.05折，解锁百倍爆率，获千元通票！\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/12786.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"角色扮演\",\"addtime\":\"2024-12-25 17:12:06\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20251218/26c43e5d451a911a3436f45432f54531.png\",\"version\":0,\"c_version\":0,\"downurl\":\"