INSERT INTO `gb_games` VALUES (377, 1, NULL, '武林争霸（0.1折九品芝麻官）', NULL, NULL, '角色扮演', 'discount', 'https://cp.u2game99.com/storage/operator/20250326/427052a092cb58f6ce30293c93a80fd0.gif', 'https://cp.u2game99.com/storage/operator/20250326/8c5cc9db1343b32c239e79159919c819.jpg', '[\"https://cp.u2game99.com/storage/operator/20250326/43fd5e4b8d40567368bba0b743417ec6.jpg\", \"https://cp.u2game99.com/storage/operator/20250326/af88615e5842271db7f3880c6b8b76a4.jpg\", \"https://cp.u2game99.com/storage/operator/20250326/c8a1db1b10da80a36626685b41527180.jpg\", \"https://cp.u2game99.com/storage/operator/20250326/b6e4a19d4de2402f0fc62a99a39f2cd2.jpg\", \"https://cp.u2game99.com/storage/operator/20250326/1681f6710486fec8a03588da282d1339.jpg\"]', 'https://mp4.277sy.com/sp/13120.mp4', '《武林争霸》是一款模拟当官类手游，玩家穿越回大清，寒窗苦读，金榜题名；游戏中编写了大量当官破案剧情，让玩家沉浸到断案的游戏中。\r\n游戏着重于玩法与剧情的相结合，让玩家回到古香古色的清廷世界。告别枯燥乏味的刷怪升级，抛弃模式单一的经营玩法，为玩家缔造了一出高潮迭起、剧情跌宕起伏的故事。\r\n游戏中还融入了古风精致场景设计，华丽服装随心切换，官场对决指尖厮杀，全服激斗战斗到底，联姻拉拢官场势力，在大清执掌朝纲。断案追凶声名鹊起，妻妾相伴逍遥自在，多角度呈现官场如鱼得水的快乐生活；体会古色古香的清廷世界，感受一段逍遥的当官生活。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=812', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=812', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=812', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=812', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-03-12 17:33:43', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:43', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"智斗官场，权谋天下\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13120.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"角色扮演\",\"addtime\":\"2025-03-12 17:33:43\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20250326/427052a092cb58f6ce30293c93a80fd0.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.