INSERT INTO `gb_games` VALUES (378, 1, NULL, '公元（魔法波特内置0.1折）', NULL, NULL, '放置', 'bt', 'https://cp.u2game99.com/storage/operator/20250326/407fe2942e0f11b31e86e720eeeaef33.png', 'https://cp.u2game99.com/storage/operator/20250326/2e6cf6182fe625470f87619fa6eba40f.jpg', '[\"https://cp.u2game99.com/storage/operator/20250326/6b4156c2b00950ba0c23e3d8b0d11a9d.jpg\", \"https://cp.u2game99.com/storage/operator/20250326/7b17ddce758cab2187c54405d838c35c.jpg\", \"https://cp.u2game99.com/storage/operator/20250326/504c81dd4089a22039acd1ff5e910a70.jpg\", \"https://cp.u2game99.com/storage/operator/20250326/9f4c66d93f64b1faaa8ca2817286244d.jpg\", \"https://cp.u2game99.com/storage/operator/20250326/93a85532635b6aedb9be53dbb2e42e94.jpg\"]', 'https://mp4.277sy.com/sp/13150.mp4', '《公元（魔法波特内置0.1折）》是一款充满魔法与冒险的手游游戏，玩家将踏上一段充满挑战和神秘的旅程。在这个充满魔法的世界中，玩家将扮演一名年轻的魔法学徒，开启一场前所未有的魔幻冒险之旅。\r\n\r\n玩家将穿越神秘的森林、古老的城市废墟和神秘的魔法学院，面对各种魔法生物和邪恶势力的挑战。在这里，点亮神秘魔晶球是冒险的开端。魔晶球散发的光芒不仅照亮前行的路，更能激发强大的魔法力量，帮助你在探索中披荆斩棘。\r\n\r\n在游戏中，玩家需要学习各种强大的魔法技能，与拥有特殊能力的伙伴同行，解开古老魔法的秘密，与黑暗势力对抗，并最终成长为屹立在整片大陆上的传奇人物。\r\n\r\n游戏中充满了各种挑战和隐藏的宝藏，玩家需要通过点亮魔晶球和战斗来不断提升自己的魔法能力。同时，玩家还可以与其他玩家组成公会，共同探索世界、挑战强大的魔法生物和参加激烈的公会战。\r\n\r\n《公元（魔法波特内置0.1折）》以其精美的画面、丰富的剧情和刺激的游戏玩法，为玩家打造了一个充满魔法与冒险的奇幻世界，让玩家沉浸其中，体验无尽的乐趣与刺激。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=839', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=839', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=839', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=839', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-03-18 15:38:16', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:43', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"玩家将扮演一名年轻的魔法学徒，开启一场前所未有的魔幻冒险之旅\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13150.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"放置\",\"addtime\":\"2025-03-18 15:38:16\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:65\"