INSERT INTO `gb_games` VALUES (385, 1, NULL, '王者猎人（送自选红将）', NULL, NULL, '卡牌', 'official', 'https://cp.u2game99.com/storage/operator/20250227/175578fa0c1ec118f0a33e7bd325e76b.gif', 'https://cp.u2game99.com/storage/operator/20250227/a4845d7d58aa336af01324e5f16c05b0.jpg', '[\"https://cp.u2game99.com/storage/operator/20250227/36f9f5eab93b5339439b338014d932b7.jpg\", \"https://cp.u2game99.com/storage/operator/20250227/4ffb7c10ba34c11ee61789f042afe202.jpg\", \"https://cp.u2game99.com/storage/operator/20250227/66ad22c2ba6cb5657cfdfead77eca34c.jpg\", \"https://cp.u2game99.com/storage/operator/20250227/84a2191522b99ce9cb2a3b30c249fd60.jpg\", \"https://cp.u2game99.com/storage/operator/20250227/10d4d184e1faf5c33789739efa59aa7b.jpg\"]', 'https://mp4.277sy.com/sp/13024.mp4', '在宠物的王者世界里，峡谷汇聚着东西方的传奇英雄，为了终极的上分目标，召唤师把狗将们招募到麾下，向峡谷深处探险，带领狗将冲锋陷阵，征战四方，攻水晶打BOSS，朝着最强王者猎人的目标前进。全新萌系犬将放置游戏《王者猎人》正式上线，在这里，你可以邂逅来自不同文化里的狗将英雄，无论是三国、西游，还是西方天神，都应有尽有。在这里没有复杂难懂的系统，只需搭配好你的狗将阵容，随手点点就能轻松闯关！经典的回合制作战，更是策略十足，给你永不枯燥的游戏体验。召唤师们，快来挑选你的狗将，和他们一起横扫小怪，讨伐巨兽，登上最终的荣耀之塔！', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=728', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=728', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=728', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=728', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2025-02-24 17:42:05', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:43', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"自选红将任意组合\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/13024.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2025-02-24 17:42:05\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:6\",\"hw_cps_cpa\":\"CPS海外推广:6\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20250227/175578fa0c1ec118f0a33e7bd325e76b.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.