INSERT INTO `gb_games` VALUES (400, 1, NULL, '魂色（决战无限城）', NULL, NULL, '卡牌', 'official', 'https://cp.u2game99.com/storage/operator/20250111/6016c0866815d76babf30ff474eba78e.png', 'https://p1.277sy.com/2025/01/13/6784dfd0146d1.jpg', '[\"https://cp.u2game99.com/storage/operator/20250111/3672fc640f8cc4899474a354b07a0a4d.jpg\", \"https://cp.u2game99.com/storage/operator/20250111/31a9af405c2d39ff01d1f14d344d8251.jpg\", \"https://cp.u2game99.com/storage/operator/20250111/79ebd16ed7949958d46af5bf7ccce0b0.jpg\", \"https://cp.u2game99.com/storage/operator/20250111/078fc6a1833e599ce8db05db4d662005.jpg\", \"https://cp.u2game99.com/storage/operator/20250111/0ec2f2219e3bc43ef99b430757fc0b84.jpg\"]', 'https://mp4.277sy.com/sp/12822.mp4', '《魂色》是一款鬼灭3D横板即时战斗卡牌游戏。在这款游戏中，你将邂逅一系列耳熟能详的动漫角色。通过不同的抽卡形式，你将收集到心仪的人物，与你并肩作战。共同开启一段充满挑战与惊喜的冒险旅程。你将带领众多鬼杀队员，踏上一段充满未知与挑战的探索之旅。	', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=533', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=533', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=533', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=533', 'android', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2024-12-31 15:05:50', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:43', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"鬼灭3D横板即时战斗卡牌游戏\",\"interchangeable_role\":0,\"video\":\"https://mp4.277sy.com/sp/12822.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2024-12-31 15:05:50\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:40\",\"hw_cps_cpa\":\"CPS海外推广:20\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20250111/6016c0866815d76babf30ff474eba78e.png\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=533\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/533.html\",\"weburl_qr\":\"[base64已省略]\",\"dwzdownurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=533\",\"downurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=533\",\"dwzdownurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=533\",\"gamename\":\"魂色（决战无限城）\",\"excerpt\":\"《魂色》是一款鬼灭3D横板即时战斗卡牌游戏。在这款游戏中，你将邂逅一系列耳熟能详的动漫角色。通过不同的抽卡形式，你将收集到心仪的人物，与你并肩作战。共同开启一段充满挑战与惊喜的冒险旅程。你将带领众多鬼杀队员，踏上一段充满未知与挑战的探索之旅。\\t\",\"id\":533,\"game_source\":\"\",\"device_type\":0,\"edition\":0,\"pic_xuanchuan\":\"\",\"strict\":0,\"userfc\":1,\"updatetime\":\"2025-01-15 10:00:00\",\"box_content\":\"服专享：海量活动来袭！\\r\\n每日签到：海量钻石和大量英雄等。\\r\\n千抽大礼：核心SSR 角色随便选!\\r\\n等级礼包：达成一定等级即可获得丰厚奖励！\\r\\n七日目标：七天大狂欢！\\r\\n登录有礼：送超强英雄！\",\"pic2\":\"https://p1.277sy.com/2025/01/13/6784dfd0146d1.jpg\",\"pic3\":\"https://p1.277sy.com/2025/01/13/6784dfd014ddc.jpg\",\"pic4\":\"https://mp4.277sy.com/frame/12822.jpeg\",\"cps_ratio\":0,\"hw_ratio\":0,\"hw_firstpay\":1,\"hw_otherpay\":1,\"firstpay\":1,\"otherpay\":1}');
INSERT INTO `gb_games` VALUES (401, 1, NULL, '幻想神话志（0.1折免费版）', NULL, NULL, '卡牌', 'discount', 'https://cp.u2game99.com/storage/operator/20250107/ca74adbef94a1feac40aa43b268c2d26.png', 'https://p1.277sy.com/2025/01/06/677b7aefee912.jpg', '[\"https://p1.277sy.com/2025/01/06/677b7aefed792.jpg\", \"https://p1.277sy.com/2025/01/06/677b7aefedaf0.jpg\", \"https://p1.277sy.com/2025/01/06/677b7aefede7f.jpg\", \"https://p1.277sy.com/2025/01/06/677b7aefee1ec.jpg\", \"https://p1.277sy.com/2025/01/06/677b7aefee544.jpg\"]', 'https://mp4.277sy.com/sp/12815.mp4', '幻想异世界，养成自走棋，高颜值卡牌《幻想神话志》与大家见面啦！\r\n\r\n【养成自走棋，高能双羁绊】\r\n四大职业：战士、法师、射手、刺客\r\n七大种族：人族、灵族、妖族、鬼族、仙族、神族、魔族\r\n自走棋模式的双重羁绊设定，阵容与布阵决定一切！而且英雄的种族并非唯一，[人仙]两族的姜子牙、[神妖]两族的哪吒、[魔鬼]两族的共工、[妖仙]两族的猪八戒...阵容更加多变，善于布阵就有无限的可能！\r\n\r\n【全视频立绘，轻科技国风】\r\n独特的科技中国风+全英雄动态视频=不一样的视觉享受！突破传统国风的束缚，轻科技与神话异世界的完美结合，带来全新的体验！全英雄动态视频展现是我们不拘一格的态度，只为呈现一个绮丽的三界。\r\n\r\n【真一键升级，真轻松游戏】\r\n所有英雄等级共享，真正的一键升级，不需要繁琐得回退资源，加上自动爬塔、后台推图，轻松护肝，享受游戏！\r\n\r\n【跨服竞技场，押注神魔抽】\r\n[仙道大会]每周一开启，自由报名，选择一个合适的分组可能有惊喜哦！冠军赛阶段开启押注模式，甚至能押神魔抽卡券，各位预测达人们大显身手的时候到了！\r\n\r\n【探索大世界，装备自己造】\r\n英雄达到100级之后，神话大世界开启！多人同屏，自由探索，搜集材料，打造游戏中提升大量属性的团队装备[灵宝]，上百个不同的随机词条让你的灵宝绝对独一无二！', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=529', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=529', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=529', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=529', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2024-12-30 16:05:17', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:43', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"幻想异世界，养成自走棋\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/12815.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2024-12-30 16:05:17\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20