INSERT INTO `gb_games` VALUES (404, 1, NULL, '全城警戒（0.1折极速版）', NULL, NULL, '策略', 'discount', 'https://cp.u2game99.com/storage/operator/20241227/211b51f04fe9b9930243151e98e13eb6.png', 'https://cp.u2game99.com/storage/operator/20241227/795f043ff025523dafaf38587c2ca63f.jpg', '[\"https://cp.u2game99.com/storage/operator/20241227/6516e35fb92adcb8b7afb46bc2f35029.jpg\", \"https://cp.u2game99.com/storage/operator/20241227/5161a439cecc138da46e403327a5df27.jpg\", \"https://cp.u2game99.com/storage/operator/20241227/077efaea2bc31a4993d2c6f1c5fe1b2f.jpg\", \"https://cp.u2game99.com/storage/operator/20241227/36a6c7ad962ad624a4005aa08d0f3066.jpg\", \"https://cp.u2game99.com/storage/operator/20241227/06505acb3d6f8a894492b90f6d968ea0.jpg\"]', 'https://mp4.277sy.com/sp/12791.mp4', '《全城警戒》是一款以策略、战争、军事为题材的战争策略手游。\r\n游戏采用独特的3D建模2D渲染技术，使画面更加精细、逼真，立体感更强，技术支持更全面，功能更完善，制作更精美！采用策略战斗，6个位置4种兵种巧妙搭配，多种战斗场景，体验不同地形和战役的趣味！', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=506', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=506', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=506', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=506', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2024-12-25 17:34:35', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:43', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"百余坦克兵种，多种策略搭配！\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/12791.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"策略\",\"addtime\":\"2024-12-25 17:34:35\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20241227/211b51f04fe9b9930243151e98e13eb6.png\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=506\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/506.html\",\"weburl_qr\":\"[base64已省略]\",\"dwzdownurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=506\",\"downurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=506\",\"dwzdownurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=506\",\"gamename\":\"全城警戒（0.1折极速版）\",\"excerpt\":\"《全城警戒》是一款以策略、战争、军事为题材的战争策略手游。\\r\\n游戏采用独特的3D建模2D渲染技术，使画面更加精细、逼真，立体感更强，技术支持更全面，功能更完善，制作更精美！采用策略战斗，6个位置4种兵种巧妙搭配，多种战斗场景，体验不同地形和战役的趣味！\",\"id\":506,\"game_source\":\"\",\"device_type\":2,\"edition\":1,\"pic_xuanchuan\":\"\",\"strict\":0,\"userfc\":1,\"updatetime\":\"2024-12-29 09:30:00\",\"box_content\":\"【军事战争，真实体验】\\r\\n简约设计清晰大气的UI布局，兼顾美观和实用性，但氛围上完美突出现代战争、中东战争的氛围感，在关卡中体验经典战役，在战斗中感受炮火氛围！\\r\\n【百余兵种，策略搭配】\\r\\n兵种是游戏中最核心的玩法内容，游戏都是围绕着拥有更多更高级的兵种而发展基地。其他的系统也都是为了让自己的兵种更强。更高级的战争工厂可以造更高级的部队！\\r\\n【多线养成，合理分配】\\r\\n丰富的培养体系，多线的养成方向，满足指挥官的养成收集欲望，拥有配件、装甲、技能等系统，合理分配资源，收集从不间断。\\r\\n【资源抢夺，胜者为王】\\r\\n资源的获取途径可以是矿场生产、矿点占领、玩家掠夺，你会不会也来参与这一场资源的危机引发的战争？\\r\\n【万人同屏，战地争霸】\\r\\n会当凌绝顶，一览众山小！这是一种什么样的成就感？战地争霸就是游戏中霸主的排行榜，只要你够强，就可以享受全服第一的荣耀。排行榜前面的强者，还能每天活得非常丰厚的系统奖励！\\r\\n【轻松上手，巧妙搭配】\\r\\n游戏玩法通俗易懂，轻松上手操作，兵种巧妙搭配，真实军旅体验！\",\"pic2\":\"https://cp.u2game99.com/storage/operator/20241227/795f043ff025523dafaf38587c2ca63f.jpg\",\"pic3\":\"\",\"pic4\":\"https://mp4.277sy.com/frame/12791.jpeg\",\"cps_ratio\":0,\"hw_ratio\":0,\"hw_firstpay\":0.01,\"hw_otherpay\":0.01,\"firstpay\":0.01,\"otherpay\":0.01}');
