INSERT INTO `gb_games` VALUES (408, 1, NULL, '末日来袭（0.05折免费版卡牌）', NULL, NULL, '卡牌', 'discount', 'https://cp.u2game99.com/storage/operator/20241216/3a6c967546bcffe6ab8f4d191aa0282e.gif', 'https://www.u2game99.com/data/upload/game/20241220/676519ef9eb0e.jpg', '[\"https://cp.u2game99.com/storage/operator/20241216/fb0193c4c9f83ad994cb9e9563812bba.jpg\", \"https://cp.u2game99.com/storage/operator/20241216/ddde481a63e0fbee83d73c26b099a07b.jpg\", \"https://cp.u2game99.com/storage/operator/20241216/5cc6f53db8268a13859312692feacc6d.jpg\", \"https://cp.u2game99.com/storage/operator/20241216/b2c71cdec407ec1e637f90503081bdf1.jpg\", \"https://cp.u2game99.com/storage/operator/20241216/8391cef48bcac3f97ea2495226b602a1.jpg\"]', 'https://mp4.277sy.com/sp/12738.mp4', '警报声骤然响起，感染者的嘶吼与人群的喧闹交织成一片混乱。惊恐的尖叫声在空气中回荡，宣告着末日的到来。人们在逃命的洪流中挣扎，有人被无情的尸潮吞没，有人匆忙登上了离城的末班车。你未能及时驾车逃离，但幸运的是，在整座城市被淹没之前，你成功逃脱。你奔跑在荒芜的街道上，身后是无尽的黑暗和未知的恐惧。\r\n这就是你的故事，一个关于生存与挣扎的故事。虽然前方仍有未知的挑战和困难等待着你，但你依然要勇敢地面对，因为只有这样，你才能在这场末日的浩劫中存活下来。\r\n\r\n1、【建造专属地堡】\r\n狂暴机械随时会发动袭击，您首先要制作地下堡垒作为保护基地，逃避怪物偷袭！搜集求生物资，防止遭遇饥馑；升级科技建筑，矿场、农场、实验室、练兵营...通通搞起来，强化城堡的武装力量！\r\n2、【末日探险】\r\n为了生存与发展，您除了挖掘地底世界，也需要走出地堡，在荒野废墟中收集资源、探究未知瑰宝；运用雷达搜索末日情报，解救受伤的幸存者同伴。但一定要小心，野外处处都是敌人和失控机械！\r\n3、【英雄集结】\r\n招募不同个性与才能的英雄作为同伴，组建一支多元化的开拓者分队与您并肩作战，增强战役实力！您还能够根据喜爱和特点拟定团队组合，战略搭配，帮助您取得战役的最终成功。\r\n', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=458', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=458', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=458', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=458', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2024-12-16 14:42:41', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:43', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"0.05折免费版末日卡牌生存\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/12738.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"卡牌\",\"addtime\":\"2024-12-16 14:42:41\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://cp.u2game99.com/storage/operator/20241216/3a6c967546bcffe6ab8f4d191aa0282e.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=458\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/458.html\",\"weburl_qr\":\"[base64已省略]\",\"dwzdownurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=458\",\"downurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=458\",\"dwzdownurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=458\",\"gamename\":\"末日来袭（0.05折免费版卡牌）\",\"excerpt\":\"警报声骤然响起，感染者的嘶吼与人群的喧闹交织成一片混乱。惊恐的尖叫声在空气中回荡，宣告着末日的到来。人们在逃命的洪流中挣扎，有人被无情的尸潮吞没，有人匆忙登上了离城的末班车。你未能及时驾车逃离，但幸运的是，在整座城市被淹没之前，你成功逃脱。你奔跑在荒芜的街道上，身后是无尽的黑暗和未知的恐惧。\\r\\n这就是你的故事，一个关于生存与挣扎的故事。虽然前方仍有未知的挑战和困难等待着你，但你依然要勇敢地面对，因为只有这样，你才能在这场末日的浩劫中存活下来。\\r\\n\\r\\n1、【建造专属地堡】\\r\\n狂暴机械随时会发动袭击，您首先要制作地下堡垒作为保护基地，逃避怪物偷袭！搜集求生物资，防止遭遇饥馑；升级科技建筑，矿场、农场、实验室、练兵营...通通搞起来，强化城堡的武装力量！\\r\\n2、【末日探险】\\r\\n为了生存与发展，您除了挖掘地底世界，也需要走出地堡，在荒野废墟中收集资源、探究未知瑰宝；运用雷达搜索末日情报，解救受伤的幸存者同伴。但一定要小心，野外处处都是敌人和失控机械！\\r\\n3、【英雄集结】\\r\\n招募不同个性与才能的英雄作为同伴，组建一支多元化的开拓者分队与您并肩作战，增强战役实力！您还能够根据喜爱和特点拟定团队组合，战略搭配，帮助您取得战役的最终成功。\\r\\n\",\"id\":458,\"game_source\":\"\",\"device_type\":2,\"edition\":1,\"pic_xuanchuan\":\"\",\"strict\":0,\"userfc\":1,\"updatetime\":\"2024-12-23 08:00:00\",\"box_content\":\"★全场笔笔0.05折， 拒绝数值膨胀\\r\\n★充值比例1:10，每日签到领众多福利\\r\\n★天天送1000元现金券，轻松畅游末日之旅\\r\\n★上线送VIP10，尊享各类特权\\r\\n★末日福利送海量石油，免除货币烦恼\\r\\n★生存指南送满阶S级守护者达里纳\",\"pic2\":\"https://www.u2game99.com/data/upload/game/20241220/676519ef9eb0e.jpg\",\"pic3\":\"\",\"pic4\":\"https://mp4.277sy.com/frame/12738.jpeg\",\"cps_ratio\":0,\"hw_ratio\":0,\"hw_firstpay\":0.005,\"hw_otherpay\":0.005,\"firstpay\":0.005,\"otherpay\":0.005}');
INSERT INTO `gb_games` VALUES (409, 1, NULL, '远征2', NULL, NULL, '角色扮演', 'official', 'https://p1.277sy.com/2024/12/16/675ff3ec8c7fa.png', NULL, '[\"https://p1.277sy.com/2024/12/16/675ff3995ff24.jpg\", \"https://p1.277sy.com/2024/12/16/675ff39960254.jpg\", \"https://p1.277sy.com/2024/12/16/675ff399605de.jpg\", \"https://p1.277sy.com/2024/12/16/675ff39960921.jpg\", \"https://p1.277sy.com/2024/12/16/675ff39960b8e.jpg\"]', 'https://mp4.277sy.com/sp/12740.mp4', '千人同屏，激情国战——首次在MMO游戏中引入大陆漂移合纵、跨服国家结盟、国战赛季等全新玩法。同时全职业可自由转职，通过技能与天赋的自由搭配，给玩家带来多种成长选择，游戏体验重磅升级。\r\n同时在全新渲染技术，加入实时拟真天气变幻，呈现出真实细腻而恢弘壮阔的国战世界，带来君临天下的沉浸感受。玩国战，就玩《远征2》，击败强国大一统，书写属于你的王者篇章！', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=460', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=460', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=460', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=460', 'android', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2024-12-16 15:44:34', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:43', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"经典国战还原，让你肾上腺素飙升，战个痛快\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/12740.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"角色扮演\",\"addtime\":\"2024-12-16 15:44:34\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:55\",\"hw_cps_cpa\":\"CPS海外推广:35\",\"coupon_repeat\":\"\",\"pic1\":\"https://p1.277sy.com/2024/12/16/675ff3ec8c7fa.png\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=460\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/460.html\",\"weburl_qr\":\"[base64已省略]\",\"dwzdownurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=460\",\"downurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=460\",\"dwzdownurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=460\",\"gamename\":\"远征2\",\"excerpt\":\"千人同屏，激情国战——首次在MMO游戏中引入大陆漂移合纵、跨服国家结盟、国战赛季等全新玩法。同时全职业可自由转职，通过技能与天赋的自由搭配，给玩家带来多种成长选择，游戏体验重磅升级。\\r\\n同时在全新渲染技术，加入实时拟真天气变幻，呈现出真实细腻而恢弘壮阔的国战世界，带来君临天下的沉浸感受。玩国战，就玩《远征2》，击败强国大一统，书写属于你的王者篇章！\",\"id\":460,\"game_source\":\"\",\"device_type\":0,\"edition\":0,\"pic_xuanchuan\":\"\",\"strict\":0,\"userfc\":1,\"updatetime\":\"2024-12-17 10:00:00\",\"box_content\":\"【千人同屏，万人共战】\\r\\n经典国战还原，任务刺探，合纵联盟，暗杀100%激情；次世代引擎护航，千人同屏不卡顿，让你畅享真正的国战乐趣。\\r\\n【跨服合纵，颠覆革新】\\r\\n引入大陆漂移，合纵暗战+跨服争霸更激情。更有国战赛季制等新模式助力，让你肾上腺素飙升，战个痛快。\\r\\n【主播陪玩，甜蜜情缘】\\r\\n美女主播入驻游戏，24小时甜蜜引导；更有附近交友，兄弟拉火等多元社交玩法引入，玩游戏也能遇到有趣的灵魂。\\r\\n【全职业转职，自由体验】\\r\\n全职业自由转职，技能与天赋自由搭配，体验自由成长，多样国战！\",\"pic2\":\"\",\"pic3\":\"\",\"pic4\":\"https://mp4.277sy.com/frame/12740.jpeg\",\"cps_ratio\":0,\"hw_ratio\":0,\"hw_firstpay\":1,\"hw_otherpay\":1,\"firstpay\":1,\"otherpay\":1}');
