INSERT INTO `gb_games` VALUES (411, 1, NULL, '明珠三国', NULL, NULL, '三国', 'official', 'https://www.u2game99.com/data/upload/game/20250625/685ba464044c2.png', 'https://www.u2game99.com/data/upload/game/20250625/685ba511662a8.jpg', '[\"https://www.u2game99.com/data/upload/game/20250625/685ba545a6d9f.png\", \"https://www.u2game99.com/data/upload/game/20250625/685ba54c8053a.png\", \"https://www.u2game99.com/data/upload/game/20250625/685ba553e7e4a.png\", \"https://www.u2game99.com/data/upload/game/20250625/685ba55a68ecf.png\", \"https://www.u2game99.com/data/upload/game/20250625/685ba560f018a.png\"]', 'https://mp4.277sy.com/sp/1576.mp4', '【延续经典 双倍经验乐翻天】\r\n新区“鹊桥相会”将延续经典,开区即享双倍经验活动在新服展开,让广大英雄做任务、打怪升级腾云驾雾一般！瞬间成为一代名将,做你的“牛人”,让别人瞻仰去吧！\r\n\r\n【开放新服 升级送新手礼包】\r\n新区新手玩家注册上线之后,将获得三国为新手玩家准备了丰厚的新手礼包,其囊括了双倍经验符、坐骑经验双倍符、坐骑口粮、还魂香包,通过奖励保送玩家70级,玩家将在短时间内完成华丽的蜕变！\r\n\r\n【开放新服 战功雨好礼不断】\r\n新区开放后,大汉朝廷将犒赏众将！每日12点-13点及19点-20点期间,只要英雄身处中立地区即可获得海量战功,更有雪岩白虎砸到你哦!惊喜不断不容错过!\r\n\r\n【新手福利 你冲VIP我买单】\r\n新手福利第一波,你冲VIP我买单,VIP等级满足活动要求的新用户,可在活动结束后获得该VIP等级所需元宝100%的返利，最高可享返利20万绑元，每个账号下仅限1个角色参与！', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=11', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=11', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=11', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=11', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2024-09-27 10:03:00', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:43', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"延续JAVA时代经典的MMORPG手游\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/1576.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"三国\",\"addtime\":\"2024-09-27 10:03:00\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:12\",\"hw_cps_cpa\":\"CPS海外推广:0\",\"coupon_repeat\":\"\",\"pic1\":\"https://www.u2game99.com/data/upload/game/20250625/685ba464044c2.png\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=11\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/11.html\",\"weburl_qr\":\"[base64已省略]\",\"dwzdownurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=11\",\"downurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=11\",\"dwzdownurlmash\":\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=11\",\"gamename\":\"明珠三国\",\"excerpt\":\"【延续经典 双倍经验乐翻天】\\r\\n新区“鹊桥相会”将延续经典,开区即享双倍经验活动在新服展开,让广大英雄做任务、打怪升级腾云驾雾一般！瞬间成为一代名将,做你的“牛人”,让别人瞻仰去吧！\\r\\n\\r\\n【开放新服 升级送新手礼包】\\r\\n新区新手玩家注册上线之后,将获得三国为新手玩家准备了丰厚的新手礼包,其囊括了双倍经验符、坐骑经验双倍符、坐骑口粮、还魂香包,通过奖励保送玩家70级,玩家将在短时间内完成华丽的蜕变！\\r\\n\\r\\n【开放新服 战功雨好礼不断】\\r\\n新区开放后,大汉朝廷将犒赏众将！每日12点-13点及19点-20点期间,只要英雄身处中立地区即可获得海量战功,更有雪岩白虎砸到你哦!惊喜不断不容错过!\\r\\n\\r\\n【新手福利 你冲VIP我买单】\\r\\n新手福利第一波,你冲VIP我买单,VIP等级满足活动要求的新用户,可在活动结束后获得该VIP等级所需元宝100%的返利，最高可享返利20万绑元，每个账号下仅限1个角色参与！\",\"id\":11,\"game_source\":\"\",\"device_type\":2,\"edition\":0,\"pic_xuanchuan\":\"\",\"strict\":0,\"userfc\":1,\"updatetime\":\"2024-12-03 00:00:00\",\"box_content\":\"1.装备升级不花钱，神级套装助你实力飙升。\\r\\n2.新版在线奖励和冲级奖励上线，带来更多福利和乐趣。\\r\\n3.完成指定成就目标，免费领永久跑环特权。\",\"pic2\":\"https://www.u2game99.com/data/upload/game/20250625/685ba511662a8.jpg\",\"pic3\":\"\",\"pic4\":\"https://www.u2game99.com/data/upload/game/20251219/6945066da48f8.jpg\",\"cps_ratio\":0,\"hw_ratio\":0,\"hw_firstpay\":0.46,\"hw_otherpay\":0.46,\"firstpay\":0.46,\"otherpay\":0.46}');
