INSERT INTO `gb_games` VALUES (415, 1, NULL, '楚汉争霸OL手游（0.1折）', NULL, NULL, '养成', 'discount', 'https://p1.277sy.com/2025/02/28/67c168afc9191.png', 'https://cp.u2game99.com/storage/operator/20241119/1f5d6a78b7be095bec2e846d19bb6af4.jpg', '[\"https://cp.u2game99.com/storage/operator/20241119/7c06141b27784de2ef562a69ea6eb6a7.jpg\", \"https://cp.u2game99.com/storage/operator/20241119/8ed729bf17c23682c59862f517a5f409.jpg\", \"https://cp.u2game99.com/storage/operator/20241119/e2988fc4fb3cf4da903cb67f72922013.jpg\", \"https://cp.u2game99.com/storage/operator/20241119/87bb8cfa56a14bae650b30ba4c3c7975.jpg\", \"https://cp.u2game99.com/storage/operator/20241119/3be26d0de17d5a75591accf1b8302849.jpg\"]', 'https://mp4.277sy.com/sp/12595.mp4', '《楚汉争霸OL手游》是一款古风类型的模拟古代经营游戏，它将带你穿越回古代，建造属性自己的一片天地，在这里，你可以当一个富可敌国的商业大亨，也可以组建联盟成就一方不朽的霸业，还是会泯灭与记忆之中？这一切的一切等待是你的选择。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=328', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=328', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=328', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=328', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2024-11-13 10:46:51', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:43', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"古风类型的模拟古代经营游戏\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/12595.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"养成\",\"addtime\":\"2024-11-13 10:46:51\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://p1.277sy.com/2025/02/28/67c168afc9191.png\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=328\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/328.html\",\"weburl_qr\":\"[base64已省略]\",\"dwzdownurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=328\",\"d