INSERT INTO `gb_games` VALUES (418, 1, NULL, '我欲修真（原价0.1折直充0氪版）', NULL, NULL, '角色扮演', 'discount', 'https://www.u2game99.com/data/upload/game/20251128/6928f50613245.png', 'https://www.u2game99.com/data/upload/game/20251128/6928f4b8eecd6.jpg', '[\"https://cp.u2game99.com/storage/operator/20241018/5a87f90402c02c02d0e3367950911096.jpg\", \"https://cp.u2game99.com/storage/operator/20241018/f2c46c557680140642975104725128da.jpg\", \"https://cp.u2game99.com/storage/operator/20241018/02d07eceee10c66fbeeffb8f4a937296.jpg\", \"https://cp.u2game99.com/storage/operator/20241018/e1a646d06bad4090b15a08e8b83f64b9.jpg\", \"https://cp.u2game99.com/storage/operator/20241018/f86c716bdfc93a67898df1a1af910f98.jpg\"]', NULL, '《我欲修真》3D仙侠世界，游戏采用即时战斗模式。在游戏中，玩家扮演的修仙者在与天地妖兽争夺中自发形成势力，抵御天灾人祸，妖兽肆虐的域外之地，借用天地之力成就更多可能，可前往探索星图猎场，捕获星兽获取材料炼金，探索存在于虚空中得上古遗迹，寻得古仙遗留，开启新得修炼方式，通过完成任务、剧情探索、打败BOSS、挑战副本、日常活动等玩法获取各种材料和资源，用以提升装备、获取灵骑、收集仙宠，强力变身，成就更多可能，开辟新的战场。	', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=135', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=135', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=135', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=135', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2024-10-10 10:05:44', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:43', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"原汁原味0.1折直充免费，物价完全保持原价\",\"interchangeable_role\":1,\"video\":\"\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"角色扮演\",\"addtime\":\"2024-10-10 10:05:44\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://www.u2game99.com/data/upload/game/20251128/6928f50613245.png\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=135\",\"qrcode\":\"[base64已省略]\",\"weburl\":\"https://www.u2game99.com/wg/1037/135.html\",\"weburl_qr\":\"[base64已省略]\",\"dw