INSERT INTO `gb_games` VALUES (421, 1, NULL, '上古修仙（0.1折封神归来）', NULL, NULL, '放置', 'discount', 'https://www.u2game99.com/data/upload/game/20251224/694b87111ab0f.gif', 'https://www.u2game99.com/data/upload/game/20251224/694b8719d57d7.jpg', '[\"https://www.u2game99.com/data/upload/game/20250714/6874a99b41e8e.jpg\", \"https://www.u2game99.com/data/upload/game/20250714/6874a9a250f37.jpg\", \"https://www.u2game99.com/data/upload/game/20250714/6874a9a8541d1.jpg\", \"https://www.u2game99.com/data/upload/game/20250714/6874a9af05f71.jpg\", \"https://www.u2game99.com/data/upload/game/20250714/6874a9b57e37c.jpg\"]', 'https://mp4.277sy.com/sp/11350.mp4', '《上古修仙0.1》是一款以收集养成各类神将，渡劫修仙百变外观，超爽3D打击感的RPG修仙类H5游戏，突破了传统仙侠的宠物模式，你可以在骑乘酷炫坐骑遨游三界的同时，收服上百个神将统统纳为己用。任意搭配最强的出战神将组合，配合神级灵将变身，天上地下，唯你独尊！\r\n\r\n一款2.5D修仙为背景的RPG手机游戏。游戏中玩家将扮演一名修仙者在各位神将的帮助下闯过各种关卡，玩家可以通过挑战BOSS、试炼获取装备，不断提升自身实力，最终成为一个逍遥自在的仙尊。\r\n\r\n游戏为修仙题材，在一个修仙的世界，主角为了自己能成为无拘无束的仙，不受世俗的束缚，踏上修仙之路，一路修行，只为成为独一无二的仙，剧情在一处神秘的上古遗迹开启，主角为了提升修为进入上古遗迹寻求机缘开始。', NULL, NULL, NULL, NULL, NULL, NULL, 'https://qd.u2game99.com/down.html?ag=GMS123&gid=23', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=23', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=23', 'https://qd.u2game99.com/down.html?ag=GMS123&gid=23', 'both', NULL, NULL, NULL, NULL, NULL, '0', NULL, '0', NULL, 0, 0.0, NULL, NULL, '2024-09-30 15:35:25', '0', '0', '0', 0, '1', '0', 'admin', '2025-12-26 08:42:43', '', '2025-12-26 09:49:14', '[导入源数据] {\"h5url\":\"\",\"h5\":0,\"welfare\":\"0.1折一路斩仙，神将集结问鼎仙尊\",\"interchangeable_role\":1,\"video\":\"https://mp4.277sy.com/sp/11350.mp4\",\"text_cps\":\"\",\"new\":0,\"yuyue\":0,\"gametype\":\"放置\",\"addtime\":\"2024-09-30 15:35:25\",\"gn_extension\":1,\"hw_extension\":1,\"cps_cpa\":\"CPS推广:60\",\"hw_cps_cpa\":\"CPS海外推广:40\",\"coupon_repeat\":\"\",\"pic1\":\"https://www.u2game99.com/data/upload/game/20251224/694b87111ab0f.gif\",\"version\":0,\"c_version\":0,\"downurl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=23\",\"qrcode\":\"[base64已省略]\",\"webur