INSERT INTO `sys_oper_log` VALUES (823, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1524\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1524\",\"category\":\"角色扮演\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20251028/ff81c426d88c09939d1a55f219275a41.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 07:32:05\",\"description\":\"《刃境》是一款 俯视角硬核动作游戏，结合了肉鸽与装备构筑玩法，支持多人联机和自由交易的冒险游戏。拉上你的小伙伴一起踏入神秘莫测的魔界。\\n在这个充满未知与挑战的世界，你将扮演一位勇敢无畏的人类。意外闯入魔界后，幸运地获得刃神认可，从而能够掌控各种强大神秘的刃。通过巧妙组合装备词条以及 Roguelike 的局内养成元素，你可以塑造出独一无二的战斗套路，实现从初出茅庐的新手到魔界纵横捭阖的传奇英雄的华丽转变。\",\"deviceSupport\":\"android\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1524\",\"gameType\":\"official\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20251028/5a41193955978508bb385b4eaea13e2f.png\",\"id\":23,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1524\",\"isHot\":\"0\",\"isNew\":\"1\",\"isRecommend\":\"0\",\"launchTime\":\"2025-10-24 15:27:45\",\"name\":\"刃境\",\"params\":{},\"promotionDesc\":\"你将作为初入异世界的冒险者参与到抵抗魔王的恢弘史诗中！\",\"remark\":\"导入数据：{\\\"id\\\":1524,\\\"addtime\\\":\\\"2025-10-24 15:27:45\\\",\\\"updatetime\\\":\\\"2025-10-29 10:00:00\\\"} [导入冲突:同站点已存在同名游戏ID=15]\",\"screenshots\":\"[\\\"https://cp.u2game99.com/storage/operator/20251028/540053a2e71ca309ffbba1d0474da8ca.jpg\\\",\\\"https://cp.u2game99.com/storage/operator/20251028/3307aaf015c33dddedc5058f74d22590.png\\\",\\\"https://cp.u2game99.com/storage/operator/20251028/777fc465696c868e99b47d6e4a929250.jpg\\\",\\\"https://cp.u2game99.com/storage/operator/20251028/2366804492d9ebca3f8e9f0bbf02d5b7.jpg\\\",\\\"https://cp.u2game99.com/storage/operator/20251028/52c56cddb1ac7792e9168e8a458cb5ae.jpg\\\"]\",\"siteId\":1,\"sortOrder\":0,\"status\":\"1\",\"subtitle\":\"上线超值