INSERT INTO `sys_oper_log` VALUES (824, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1500\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1500\",\"category\":\"卡牌\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20251021/3bac64da81e363d05cee52f41a2ba59b.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 07:32:05\",\"description\":\"《漫画英雄3D（0.05折次元乱斗）》是一款颠覆传统的横版卡牌手游，集结《海贼王》《鬼灭之刃》《火影忍者》《进击的巨人》《死神》等超多顶流动漫的经典角色，打破次元壁垒，打造史诗级跨作品联动战场！在这里，路飞与佐助并肩作战，炭治郎携手祢豆子对抗巨人，黑崎一护与五条悟展开灵力对决……所有不可能的梦幻组合，皆由你亲手缔造！\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1500\",\"gameType\":\"official\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20251021/be33199deb6b22fb228d91a8b8a495d0.png\",\"id\":24,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1500\",\"isHot\":\"0\",\"isNew\":\"1\",\"isRecommend\":\"0\",\"launchTime\":\"2025-10-17 14:35:31\",\"name\":\"漫画英雄3D（0.05折次元乱斗）\",\"params\":{},\"promotionDesc\":\"0.05折全次元动漫大乱斗\",\"remark\":\"导入数据：{\\\"id\\\":1500,\\\"addtime\\\":\\\"2025-10-17 14:35:31\\\",\\\"updatetime\\\":\\\"2025-10-29 09:00:00\\\"} [导入冲突:同站点已存在同名游戏ID=16]\",\"screenshots\":\"[\\\"https://cp.u2game99.com/storage/operator/20251021/543c16bee9d8701843614d8e52d84f8c.jpg\\\",\\\"https://cp.u2game99.com/storage/operator/20251021/081c2685352ffe49534004c15d133d8f.jpg\\\",\\\"https://cp.u2game99.com/storage/operator/20251021/864f3cb5ee7ea5ae61e41bb15d0ba790.jpg\\\",\\\"https://cp.u2game99.com/storage/operator/20251021/c699c07cd19408a3328160db028108b2.jpg\\\",\\\"https://cp.u2game99.com/storage/operator/20251021/c660e9780856d4a73f199f025cb45beb.jpg\\\"]\",\"siteId\":1,\"sortOrder\":0,\"status\":\"1\",\"subtitle\":\"1、0.05折次元动漫大集结\\r\\n2、升级登录送千抽，连续登录送樱花时装\\r\\n3、创角送路飞（霸王色），红色装备套装\\r\\n4、签到送万元代金券，珍稀材料\\r\\n5、丰富战令，高招、金币、经验、钻石送不停\",\"videoUrl\":\"https://mp4.277sy.com/sp/13886.mp4\"} ', '{\"msg\":\"操作成功\",\"code\":200,\"data\":24}', 0, NULL, '2025-12-26 07:32:06', 140);
