INSERT INTO `sys_oper_log` VALUES (879, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1524\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1524\",\"category\":\"角色扮演\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20251028/ff81c426d88c09939d1a55f219275a41.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:24:59\",\"description\":\"《刃境》是一款 俯视角硬核动作游戏，结合了肉鸽与装备构筑玩法，支持多人联机和自由交易的冒险游戏。拉上你的小伙伴一起踏入神秘莫测的魔界。\\n在这个充满未知与挑战的世界，你将扮演一位勇敢无畏的人类。意外闯入魔界后，幸运地获得刃神认可，从而能够掌控各种强大神秘的刃。通过巧妙组合装备词条以及 Roguelike 的局内养成元素，你可以塑造出独一无二的战斗套路，实现从初出茅庐的新手到魔界纵横捭阖的传奇英雄的华丽转变。\",\"deviceSupport\":\"android\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1524\",\"gameType\":\"official\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20251028/5a41193955978508bb385b4eaea13e2f.png\",\"id\":38,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1524\",\"isHot\":\"0\",\"isNew\":\"1\",\"isRecommend\":\"0\",\"launchTime\":\"2025-10-24 15:27:45\",\"name\":\"刃境\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"你将作为初入异世界的冒险者参与到抵抗魔王的恢弘史诗中！\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13911.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":1,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"角色扮演\\\",\\\"addtime\\\":\\\"2025-10-24 15:27:45\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:0\\\",\\\"hw_cps_cpa\\\":\\\"CPS推广:20\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20251028/5a41193955978508bb385b4eaea13e2f.png\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1524\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2