INSERT INTO `sys_oper_log` VALUES (912, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1449\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1449\",\"category\":\"冒险\",\"coverUrl\":\"https://www.u2game99.com/data/upload/game/20251211/693a88d3243d0.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:38\",\"description\":\"《云上大陆》是一款奇幻世界冒险题材的3D放置挂机RPG手游；在这个遥远星系的云上大陆，玩家将扮演一名冒险者，在俄刻阿诺斯之神的庇护下，一路探险来到了欧斯之城，加入冒险者公会与智慧高超的矮人族、身手敏捷的精灵族一起并肩作战，抵御邪恶龙族和强大兽人族的入侵、通过欧斯勇者竞技场层层选拔、驯服幼龙、收服坐骑，完成勇者试炼，接受女神的“英雄王者”授勋，成为云上大陆的守护者，守护云上大陆和平！\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1449\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://www.u2game99.com/data/upload/game/20251225/694c9f580c4b3.gif\",\"id\":54,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1449\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-09-22 17:12:04\",\"name\":\"云上大陆（0.1折云上怀旧版）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"云上大陆怀旧版，异世界休闲冒险放置RPG\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13833.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"冒险\\\",\\\"addtime\\\":\\\"2025-09-22 17:12:04\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://www.u2game99.com/data/upload/game/20251225/694c9f580c4b3.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1449\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1449.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]