INSERT INTO `sys_oper_log` VALUES (913, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1715\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1715\",\"category\":\"挂机\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20251222/6011b8adc61f59096ae698e7df4b4b49.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:38\",\"description\":\"何为江湖，此题似三岁孩童间嬉闹时的玩笑，似学宫知府千年也难解之谜，江湖的本质，是形形色色的侠义肝胆还是毒爪利刺间的尔虞我诈，平平凡凡的无名小卒，又有何等能耐可知这天地中的千变万化，当踏入江湖之中，深陷其中，抽丝剥茧的武道绝门，仿佛一息之功汇于一念，江湖的险境，是试金石，是验型镜，只有遵从本心之人，方可得以尚存，若是不知其责之重，怎可称为侠字，以人为本，念人为心，因为有人的地方，就有江湖，江湖数载无捷达，自有侠客行天下。\\r\\n漫漫武侠路，一念入江湖！江湖群雄武侠挂机手游横空出世！\\r\\n大侠，请听我言~~~~\\r\\n你本是芸芸众生之中的无名小卒，你的儿时梦想，将会是你豪侠之路的开始！\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1715\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20251222/0581b279da42a92924fac8ede911e15f.gif\",\"id\":55,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1715\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-12-16 15:16:12\",\"name\":\"天灵诀(0.05折免单江湖)\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"绝世武侠开箱，挂机出大侠\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/14119.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"挂机\\\",\\\"addtime\\\":\\\"2025-12-16 15:16:12\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20251222/0581b279da42a92924fac8ede911e15f.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1715\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1715.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1715\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1715\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1715\\\",\\\"gamename\\\":\\\"天灵诀(0.05折', '{\"msg\":\"操作成功\",\"code\":200,\"data\":55}', 0, NULL, '2025-12-26 08:42:39', 62);
