ownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1729\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1729\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1729\\\",\\\"gamename\\\":\\\"大屠龙(战法道三修送年卡)\\\",\\\"excerpt\\\":\\\"大屠龙(战法道三修送年卡)是一款三职业传奇手游，回味经典的同时创新融合三职业三修玩法，职业觉醒后一键切换职业。新区七日好礼、怪物首杀、在线奖励、等级奖励助力轻松开荒。顶赞可打，激活即领自动回收、范围拾取、小飞鞋功能，礼包码还能兑换周、月年卡特权，主打一个轻松爽玩！\\\",\\\"id\\', '{\"msg\":\"操作成功\",\"code\":200,\"data\":56}', 0, NULL, '2025-12-26 08:42:39', 72);
INSERT INTO `sys_oper_log` VALUES (915, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1696\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1696\",\"category\":\"卡牌\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20251218/212be536cfb5387f6e9e3b0eb3fe7e23.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:38\",\"description\":\"《风暴迷城》是一款国风系、泛二次元、现代反穿越神话题材的概念范畴的回合制放置挂机卡牌游戏，《风暴迷城》的世界观中讲述了封神时代结束后各个界域被结界屏障封闭，使得各大界域无法流通，为了争夺灵气的故事。\\r\\n随着时间的推移各个界域内的灵气逐渐减少，导致法力受到严重的削弱，经历了漫长的灵气寂灭时代后结界开始松动，也逐渐可以穿越结界通往其他界域，不知何时界域中出现了传闻说凡间众生的信仰之力是界域灵气复苏的资源。\\r\\n人间因为信仰之力早已进入灵气再次复苏的时代，此时凡间已经到了21世纪，人间科技的飞速发展使神话时代在人间的影响力已经荡然无存。面对如此形势，部分神灵们选择接受人间的管理，以此换取在人间获取信仰供奉的许可，还有一部分神灵不愿意接受管理偷偷藏匿在人间，为了管理神灵和灵能相关事务和技术开发，由人神合作创办的集团公司，公司主要业务为开发灵能科技和驱除因灵气所滋生的祟魔。公司下辖的“御灵使”负责处理所有灵能相关事务。\\r\\n主角在机缘巧合下加入了“御灵使”负责处理灵能相关事务，在维护平衡和对抗邪恶途中发生的一系列冒险故事。\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1696\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20251218/4a8da09b6f7bfbc72a2f26ae917b2693.gif\",\"id\":57,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1696\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-12-10 11:10:14\",\"name\":\"风暴迷城（0.05折送不限时代金）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"永久0.05折，天天享1296代金。\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/14097.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"卡牌\\\",\\\"addtime\\\":\\\"2025-12-10 11:10:14\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20251218/4a8da09b6f7bfbc72a2f26ae917b2693.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1696\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1696.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1696\\\",', '{\"msg\":\"操作成功\",\"code\":200,\"data\":57}', 0, NULL, '2025-12-26 08:42:39', 80);
INSERT INTO `sys_oper_log` VALUES (916, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1629\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1629\",\"category\":\"角色扮演\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20251219/f6b0d865a8c25ee89c1bbb9fc019fa9f.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:38\",\"description\":\"在这个充满东方玄幻色彩的仙侠世界中，你将体验到独特的游戏玩法与极致的战斗体验。游戏采用顶级3D超清画质，将宏伟的仙侠世界展现得淋漓尽致。从神秘的星辰秘境，到强大的上古神兽，每一个细节都为你精心打造。捕捉并培养专属神兽，让它与你并肩作战，助你在这片大陆上无往不胜！此外，多职业自由转职系统，让你在战斗中体验多种角色的乐趣，仙魔随心切换，任意选择你的成长之路。\\r\\n\\r\\n全服BOSS争夺战即将打响，跨服竞技场等你来战，与顶尖高手一决高下，争夺最强荣耀与豪华奖励。装备属性永不贬值，极品装备可自由交易，助你轻松提升战力，成为修仙界的传奇。超大无缝地图自由探索，唯美仙侠风景如诗如画，带你走进一个如梦如幻的修仙世界。赶快叫上好友，开辟属于你的仙侠传奇，登顶三界巅峰！\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1629\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20251219/8428f70311e1c2a98a16c4980f2c2373.gif\",\"id\":58,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1629\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-11-20 15:01:07\",\"name\":\"仙坠凡尘（0.1折气灵师打金版）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"终身0.1折激爽版沉浸式打金仙侠手游\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/14025.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"角色扮演\\\",\\\"addtime\\\":\\\"2025-11-20 15:01:07\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20251219/8428f70311e1c2a98a16c4980f2c2373.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1629\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1629.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1629\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1629\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?', '{\"msg\":\"操作成功\",\"code\":200,\"data\":58}', 0, NULL, '2025-12-26 08:42:39', 80);
INSERT INTO `sys_oper_log` VALUES (917, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1678\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1678\",\"category\":\"角色扮演\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20251211/1629323cf583dba2b028013ae64dc8fe.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:38\",\"description\":\"《剑舞乾坤》是一款深受玩家喜爱的纯正武侠风题材动作类手游，游戏以独特的武侠世界为背景，将玩家带入一个充满江湖气息、万人国战的宏大场景，让你在战斗中体验武侠世界的魅力与激情。在游戏中，你将扮演一位身怀绝技的武侠英雄，与来自全国各地的玩家一同踏上江湖征程。游戏采用了高质量的图像和流畅的动作设计，呈现出一个个栩栩如生的武侠角色和精彩的战斗场面。你可以自由选择不同的门派、武器和技能，打造属于自己的独特战斗风格，展现出超凡的武艺。\\r\\n\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1678\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20251211/827f6ab41dff8e9925bfe62eae327298.gif\",\"id\":59,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1678\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-12-04 10:50:10\",\"name\":\"剑舞乾坤（0.05返5倍代金券）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"仙侠国战经典永留存，炫酷玩法等你来解锁\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/14078.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"角色扮演\\\",\\\"addtime\\\":\\\"2025-12-04 10:50:10\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20251211/827f6ab41dff8e9925bfe62eae327298.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1678\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":