INSERT INTO `sys_oper_log` VALUES (927, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1705\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1705\",\"category\":\"挂机\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20251218/a8fda10046b2857454a7034a4b0e3f5a.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:38\",\"description\":\"【釜底抽薪】全新震撼来袭！刀刀暴击，爽到停不下来！\\r\\n1、登录即送豪礼\\r\\n上线即享【全屏攻击】【范围自动拾取】【资源自动回收】【刀刀切割】四大神技！开局即巅峰，横扫全图零压力，爆装爽感拉满！\\r\\n2、七日赠礼·每日惊喜不断\\r\\n连登七天，每日领取独家神装、海量元宝、觉醒灵石！七天战力狂飙，轻松称霸江湖不是梦！\\r\\n3、专属天赋系统·百变组合\\r\\n天赋自由搭配，暴力输出、不死肉盾、极致控场…你的战斗风格由你定义，打造只属于你的巅峰战力！\\r\\n4、青铜神树·挖宝狂赚积分\\r\\n神树一挖，惊喜爆发！挖宝得积分，直接兑换极品神器、炫酷时装、稀有材料——白嫖也能穿神装！\\r\\n5、伏魔录·躺赢超高属性\\r\\n超简单任务，挂机即可完成！挑战伏魔BOSS，通关即送超高战力属性，轻松养成，爽快变强！\\r\\n\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1705\",\"gameType\":\"bt\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20251218/7b58bec3d2ca483de036bd06cd744511.gif\",\"id\":69,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1705\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-12-12 09:51:36\",\"name\":\"釜底抽薪（散人追梦神器专属）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"【釜底抽薪】全新震撼来袭！刀刀暴击，爽到停不下来！\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/14108.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"挂机\\\",\\\"addtime\\\":\\\"2025-12-12 09:51:36\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:65\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:45\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20251218/7b58bec3d2ca483de036bd06cd744511.gif\\\",\\\"vers