INSERT INTO `sys_oper_log` VALUES (931, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1689\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1689\",\"category\":\"卡牌\",\"coverUrl\":\"https://www.u2game99.com/data/upload/game/20251224/694bba09c0712.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:38\",\"description\":\"【剧情还原】“477 万字原著完整复刻”：主线覆盖 “大涅槃时期” 至 “战神宫崛起” 47 个篇章，关键战役（如雾岛争夺战）配动态过场与原班配音，同步动漫第三季剧情\\r\\n【角色阵容】“近百位高科技化 3D 角色”：1:1 还原罗峰、雷神、洪等动画主角团，五大职业（武者 / 精神念师 / 守护 / 医者 / 刺客），专属技能树与专武系统\\r\\n【战斗体验】“回合制 + 星能技能组合”：支持自动作战，技能可自由搭配；三维空间移动操控，PVE 复刻经典战役，PVP 含 1v1 与百人星团混战\\r\\n【装备进化】“纳米级改造 + 多属性分支”：武器可光能 / 电磁 / 生化三系进化，装备与角色同步养成，六大系统助力无限成长\\r\\n【世界观】“未来废土 + 科幻修真”：融合辐射风暴、机械废墟等场景，Unity 引擎打造高清 3D 废土世界，沉浸式对抗变异巨兽\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1689\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://www.u2game99.com/data/upload/game/20251224/694bba4886fb2.gif\",\"id\":74,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1689\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-12-08 09:50:59\",\"name\":\"吞噬星空：黎明（0.05全场买1送10版）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"顶级人气IP官方正版吞噬星空\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/14089.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"卡牌\\\",\\\"addtime\\\":\\\"2025-12-08 09:50:59\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://www.u2game99.com/data/upload/game/20251224/694bba4886fb2.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1689\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1689.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1689\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1689\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZ', '{\"msg\":\"操作成功\",\"code\":200,\"data\":74}', 0, NULL, '2025-12-26 08:42:39', 80);
INSERT INTO `sys_oper_log` VALUES (932, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1679\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1679\",\"category\":\"挂机\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20251217/dbb2eb4c5620bde05a51cd37da3860b5.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:38\",\"description\":\"《聊斋搜神记》​踏入阴森诡谲的聊斋世界！你将化身茅山道士，携符箓桃木剑，于乱葬岗斩狐妖、破鬼蜮，誓扫世间邪祟！​\\r\\n作为扫清邪魔鬼怪的动作类的游戏，游戏暗藏多重养成玄机：装备、套装、御灵等线交织，而装备与套装最易上手成型 —— 一件极品装备助你抢先克邪，一套神装更能让你战力飙升，化身降魔战神！副本惊魂、BOSS 血斗，皆为获取神装的必闯险途！​\\r\\n其余养成线暗藏福利：每日小额礼包、限时特惠活动，为不同玩家备好驱邪道具！速速入手，战力暴涨，在跨服除魔战中力压群雄，夺海量奖励，满载荣光而归！\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1679\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20251217/b95531c8485b97633112616dc06c7469.gif\",\"id\":73,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1679\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-12-04 14:03:08\",\"name\":\"聊斋搜神记（0.05折开局6480）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"永久享0.05折，3.28元解锁逆天金手指。\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/14079.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"挂机\\\",\\\"addtime\\\":\\\"2025-12-04 14:03:08\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20251217/b95531c8485b97633112616dc06c7469.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1679\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1679.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1679\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1679\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1679\\\",\\\"gamename\\\":\\\"聊斋搜神记（0.05折开局6480）\\\",\\\"excerpt\\\":\\\"《聊斋搜神', '{\"msg\":\"操作成功\",\"code\":200,\"data\":73}', 0, NULL, '2025-12-26 08:42:39', 71);
INSERT INTO `sys_oper_log` VALUES (933, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1672\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1672\",\"category\":\"卡牌\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20251208/4f0518b5f7a4937c97021f3631992f07.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:38\",\"description\":\"《深渊突击》重磅来袭！以经典火影世界观为基底，延续轻量化开箱核心玩法！通过开箱集结火影强者，挖掘人物技能联动潜力，重现忍界经典战术配合。无论是小队突袭还是大规模团战，每位忍者的独特作用都将左右胜负，让你以策略为纲，驾驭强者之力，登顶忍界之巅！在忍界秘境中凭开箱欧气角逐巅峰，书写独属于你的忍者传奇！\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1672\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20251208/7bc13c0ecbbcc8084e2c0bb95a702a5d.gif\",\"id\":75,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1672\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-12-02 15:28:09\",\"name\":\"深渊突击（0.1折忍界开箱传说）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"GM后台免费激活\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/14072.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"卡牌\\\",\\\"addtime\\\":\\\"2025-12-02 15:28:09\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:0\\\",\\\"hw_cps_cpa\\\":\\\"CPS推广:30\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20251208/7bc13c0ecbbcc8084e2c0bb95a702a5d.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1672\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1672.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1672\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1672\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1672\\\",\\\"gamename\\\":\\\"深渊突击（0.1折忍界开箱传说）\\\",\\\"excerpt\\\":\\\"《深渊突击》重磅来袭！以经典火影世界观为基底，延续轻量化开箱核心玩法！通过开箱集结火影强者，挖掘人物技能联动潜力，重现忍界经典战术配合。无论是小队突袭还是大规模团战，每位忍者的独特作用都将左右胜负，让你以策略为纲，驾驭强者之力，登顶忍界之巅！在忍界秘境中', '{\"msg\":\"操作成功\",\"code\":200,\"data\":75}', 0, NULL, '2025-12-26 08:42:39', 91);
