INSERT INTO `sys_oper_log` VALUES (949, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1687\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1687\",\"category\":\"挂机\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20251209/f360d6193694d6b915a0c04c77984685.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:39\",\"description\":\"1. 开局登顶，神技免费领 \\r\\n自动回收系统：挂机自动清理背包，神装材料一键收取，资源积累快人一步！ \\r\\n三大神技：开局即解锁 半月弯刀、逐日剑法、开天神斩，战力瞬间登顶！ \\r\\n永久赞助免费送：多倍爆率、刀刀切割，开服即巅峰！ \\r\\n2. 千件真专属，BUFF独此一家 \\r\\n唯一专属装备库：上千件独立设计的专属神器，每件自带独特技能与BUFF——吸血、反伤、瞬移、群攻，打破传统装备套路！ \\r\\n真·专属效果：装备不再只是数值堆砌，每件专属激活独特战斗风格，搭配无限，打造只属于你的战神之路！ \\r\\n3. 血脉觉醒，百变战斗流派 \\r\\n上古血脉传承：激活血脉之力，解锁狂暴、霸体、穿透、回复等数十种BUFF，自由组合构建专属流派！ \\r\\n血脉融合觉醒：多重血脉叠加激活隐藏效果，输出、生存、控制全面突破，每一次战斗都是策略的胜利！ \\r\\n4. 实物海量爆，充值货币无限刷 \\r\\n真实福利派送：击败怪海量爆实物奖励，实物可兑换海量灵符！  \\r\\n5. 史诗剧情闯关，红包拿到手软 \\r\\n沉浸式大陆史诗：探索上古战场，剧情任务环环相扣，每一次抉择都影响战局！ \\r\\n充值红包狂送：通关剧情即送充值红包，使用可增加累计充值，边玩边送永不停！ \\r\\n\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1687\",\"gameType\":\"bt\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20251209/1d2258fb2fc064ef1a49973a88fe9f64.gif\",\"id\":90,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1687\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-12-05 14:58:30\",\"name\":\"战神烈歌（杀戮血脉专属神器）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"开局登顶，神技免费领 \\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/14087.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"挂机\\\",\\\"addtime\\\":\\\"2025-12-05 14:58:30\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:65\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:45\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20251209/1d2258fb2fc064ef1a49973a88fe9f64.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1687\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1687.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\"', '{\"msg\":\"操作成功\",\"code\":200,\"data\":90}', 0, NULL, '2025-12-26 08:42:40', 71);
