INSERT INTO `sys_oper_log` VALUES (972, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1628\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1628\",\"category\":\"卡牌\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20251124/9f7c56e86659eca0ec72d18a1acb13f8.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:39\",\"description\":\"《真战三国》一款以三国乱世为背景的战争策略类手游，烽烟蔽日山河碎，豪杰横空乱世生！邀您执剑入局，亲赴万箭齐发的赤壁、铁甲轰鸣的长坂坡，在史诗级古战场上书写传奇！实时国战将九州烽火点燃，百万雄师在同一屏幕上激烈厮杀，云梯和撞车破城而入，洛阳、许昌、成都，每一座城池都是血与火交织的勋章。更有经典战役在此复刻，领地经营中暗藏玄机。通过升星、天赋、宝物和神器等多维度的养成方式，打造一支无与伦比的军团。在乱世之中，是选择偏安一隅，还是勇往直前逐鹿中原？踏入这片壮丽的大地图，用刀剑书写属于你的三国传奇，一统山河就在今朝！\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1628\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20251124/548d7eb7bdd0cc60bf3a939c3bea7e4d.gif\",\"id\":117,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1628\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-11-20 10:09:21\",\"name\":\"真·战三国（0.05折全武将送千充）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"每日送千元代金，活跃再送永久代金券。\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/14024.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"卡牌\\\",\\\"addtime\\\":\\\"2025-11-20 10:09:21\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20251124/548d7eb7bdd0cc60bf3a939c3bea7e4d.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1628\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1628.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1628\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1628\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1628\\\",\\\"gamename\\\":\\\"真·战三国（0.05折全武将送千充）\\\",\\\"excerpt\\\":\\\"《', '{\"msg\":\"操作成功\",\"code\":200,\"data\":117}', 0, NULL, '2025-12-26 08:42:40', 52);
