INSERT INTO `sys_oper_log` VALUES (976, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1660\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1660\",\"category\":\"卡牌\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20251130/0428fb99e0a1f3f0743c1f0d6534e2a0.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:39\",\"description\":\"我们不做无聊的挂机，只做真正值得投入的三国策略大作！热血三国放置手游《合体三国》0.1折打金版本正式引爆！0.1折超低折扣原封不动，全新引入福利打金系统！现放置挂机不仅掉落千元充值卡，还能兑换海量稀有资源，离线也生效！完成免费任务壕送一亿元宝，轻松实现元宝自由！滴滴，你的终身福利在@你：签到全神将、无限双月卡，升级送万抽，还有真充卡无限领取！海量资源，让你成长无忧！策略至上，游戏加入热血国战玩法，集结军团攻破洛阳，入局称帝！放置养成不费神，策略对抗不无脑，立即下载，告别无脑挂机，体验有深度的策略征战！\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1660\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://www.u2game99.com/data/upload/game/20251201/692cfc9d0a0ec.gif\",\"id\":118,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1660\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-11-28 14:19:57\",\"name\":\"合体三国（0.1折送一亿打金版）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"0.1折打金送宝！\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/14059.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"卡牌\\\",\\\"addtime\\\":\\\"2025-11-28 14:19:57\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:0\\\",\\\"hw_cps_cpa\\\":\\\"CPS推广:30\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://www.u2game99.com/data/upload/game/20251201/692cfc9d0a0ec.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1660\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u