INSERT INTO `sys_oper_log` VALUES (983, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1530\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1530\",\"category\":\"挂机\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20251125/e1a8b47fc4ed827a6d1fa625c22d19d6.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:39\",\"description\":\"《敌机锁定》是一款末日废土战争题材ARPG手游，在遥远的2049年，全球战争引爆生化危机降临，使得全球未知生物全面复活。有成群结队的丧尸群，变异远古凶兽恐龙，未知星系的变种异形入侵，使得全人类陷入前所未有的危机。在这片废土之上，你将拿起AK、激光枪等多样武器，改造恐龙协助战斗，直面重重威胁，于战争与异兽交战的旅途中突围，带领幸存者重建家园，点燃人类最后的希望之火，恢复世界秩序！\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1530\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20251125/e6ab1b9a4f4831ab4e791600761bca2f.png\",\"id\":126,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1530\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-10-27 14:44:34\",\"name\":\"敌机锁定（3.5折爆炸福利版本）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"灾厄降临，末日废土重建昔日家园！\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13917.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"挂机\\\",\\\"addtime\\\":\\\"2025-10-27 14:44:34\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:0\\\",\\\"hw_cps_cpa\\\":\\\"CPS推广:30\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20251125/e6ab1b9a4f4831ab4e791600761bca2f.png\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1530\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/