INSERT INTO `sys_oper_log` VALUES (996, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1605\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1605\",\"category\":\"卡牌\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20251118/4da51e782e5a5460f0adef821f733e37.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:39\",\"description\":\"《逍遥九重天》是一款国风修仙养成手游。上古时期，魔尊罗睺与诸神决战，因力竭不敌，盛怒之下欲自爆元神与诸神同归于尽。此时无极仙尊站了出来，以自身化为结界，消弭了这场浩劫。\\r\\n魔尊罗睺和无极双双陨落后，徒留一缕神识堕入人间，在历经沧桑后，凝聚成为了天地灵胎。沧海桑田，须臾万年。作为天地灵胎转世的你，即将踏上入世修仙之路，寻觅属于自己的机缘。在你离开仙山那一刻，整个仙魔世界都有所感，于是，一场新的仙魔争端，就此展开……\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1605\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://www.u2game99.com/data/upload/game/20251125/6925026d12183.gif\",\"id\":134,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1605\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-11-14 14:06:19\",\"name\":\"逍遥九重天（登录送自选SP）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"登陆免费获取万抽\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/14000.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"卡牌\\\",\\\"addtime\\\":\\\"2025-11-14 14:06:19\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://www.u2game99.com/data/upload/game/20251125/6925026d12183.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1605\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1605.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1605\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1605\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1605\\\",\\\"gamename\\\":\\\"逍遥九重天（登录送自选SP）\\\",\\\"excerpt\\\":\\\"《逍遥九重天》是一款国风修仙养成手游。上古时期，魔尊罗睺与诸神决战，因力竭不敌，盛怒之下欲自爆元神与诸神同归于尽。此时无极仙尊站了出来，以自身化为结界，消弭了这场浩劫。\\\\r\\\\n魔尊罗睺和无极双双陨落后', '{\"msg\":\"操作成功\",\"code\":200,\"data\":134}', 0, NULL, '2025-12-26 08:42:40', 187);
