INSERT INTO `sys_oper_log` VALUES (1012, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1573\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1573\",\"category\":\"卡牌\",\"coverUrl\":\"https://www.u2game99.com/data/upload/game/20251203/692fe526e4540.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:40\",\"description\":\"天地巨变神明有缺，当诸神陨落成星，你作为被众神选中的指引者，将继承残缺神格踏入这场横跨三千维度、贯穿东西方神话的异界大陆，在这个多元种族魔法交织的世界里重塑秩序！\\r\\n在这里，常胜将军赵子龙的龙胆亮银枪尖迸发的星芒能冻结时间之河；战争女神雅典娜能与东方仙术共鸣，魔王撒旦与齐天大圣孙悟空在时空展开维度战争。\\r\\n他们都将成为你麾下最强战力，改写诸神黄昏的史诗由你执笔，此刻，觉醒神格，撕裂时空，以凡人之躯点燃全息魔幻世界的终极狂想盛宴，风之剑舞（0.1折神契）大门已经敞开，而你，就是那个主导一切命运的主宰者！\",\"deviceSupport\":\"android\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1573\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://www.u2game99.com/data/upload/game/20251203/692fe516dc3f8.gif\",\"id\":154,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1573\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-11-06 16:44:47\",\"name\":\"风之剑舞（0.1折神契）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"0.1折开启神明契约，缔造你的异世界传说！\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13962.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"卡牌\\\",\\\"addtime\\\":\\\"2025-11-06 16:44:47\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:0\\\",\\\"hw_cps_cpa\\\":\\\"CPS推广:30\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://www.u2game99.com/data/upload/game/20251203/692fe516dc3f8.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1573\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www