INSERT INTO `sys_oper_log` VALUES (1019, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1583\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1583\",\"category\":\"卡牌\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20251117/24a834f5d5c7117d10c09958befef9fb.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:40\",\"description\":\"即刻踏入二次元风格构筑的奇幻世界，开启一场交织着未知挑战与惊喜奇遇的塔防冒险之旅！在这里，没有枯燥的重复探索，只有充满新鲜感的关卡设计，每前进一步都可能遇见全新剧情与隐藏彩蛋。\\r\\n上百位风格迥异的精灵角色已整装待发，静待你的召唤。无论是萌系治愈型、酷飒输出型，还是辅助控场型，每个精灵都拥有独一无二的专属技能与背景故事。你可以自由搭配阵容，从技能互补到属性克制，在策略组合间打造出能横扫千军、无坚不摧的专属战队。\\r\\n随着冒险不断深入，丰厚福利将持续送达，稀有道具、限定资源轻松获取；全新卡牌也会逐步解锁，让你的队伍搭配有更多可能性，为旅程注入源源不断的新鲜与刺激。\\r\\n更值得期待的是，游戏采用放置对决的轻松操作模式，无需时刻紧盯屏幕，指尖轻点即可开启热血战斗。战斗时炫酷特效铺满全场，精灵技能释放极具冲击力，每一次交锋都是策略博弈与视觉盛宴的双重狂欢，带你沉浸式感受塔防卡牌对战的独特魅力！\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1583\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20251117/70a8b9fd367672e8ece316ba85e31ff5.gif\",\"id\":161,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1583\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-11-10 13:53:32\",\"name\":\"英雄如约而至(0.05折代金天天送)\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"主线通关原地暴富，代金券天天领花到手软！\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13973.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"卡牌\\\",\\\"addtime\\\":\\\"2025-11-10 13:53:32\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20251117/70a8b9fd367672e8ece316ba85e31ff5.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1583\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1583.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1583\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIV', '{\"msg\":\"操作成功\",\"code\":200,\"data\":161}', 0, NULL, '2025-12-26 08:42:41', 68);
