INSERT INTO `sys_oper_log` VALUES (1022, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1569\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1569\",\"category\":\"卡牌\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20251105/3ac7bec4f23d62aea16ff84690ff92be.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:40\",\"description\":\"在《破晓九天》中，玩家将扮演一位三国时期的主公，与历史上著名的战略家和勇猛的武将们并肩作战。你需要收集不同的卡牌，每张卡牌代表一个武将，通过合理的搭配组成强大的阵容。卡牌的属性和技能各不相同，玩家可以根据自己的战术喜好进行选择，制定独特的战略。 除了卡牌搭配，还有各种战役和挑战等待着玩家去完成，通过战胜敌人，提升自己的排名和声望。 《破晓九天》采用了精美写实的画面风格，每一个战斗场景都充满了震撼力和视觉享受。游戏还精心打磨了角色形象和细节，让玩家能够感受到历史上伟大将领的英勇和智慧。 如果你是一个喜欢策略游戏和历史文化的爱好者，那么《破晓九天》将带给你前所未有的游戏体验。快来组建属于自己的三国强大阵容，征服敌人，成为真正的三国霸主！！\\r\\n\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1569\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20251118/e20733113fac041acde3b7a5bbd41fb6.gif\",\"id\":163,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1569\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-11-05 15:02:11\",\"name\":\"破晓九天（0.05折返1倍现金券）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"《破晓九天》是一款以中国古代经典历史文学《三国演义》为世界观背景的大型回合制策略卡牌手游。\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13958.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"卡牌\\\",\\\"addtime\\\":\\\"2025-11-05 15:02:11\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20251118/e20733113fac041acde3b7a5bbd41fb6.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1569\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1569.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1569\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1569\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2gam', '{\"msg\":\"操作成功\",\"code\":200,\"data\":163}', 0, NULL, '2025-12-26 08:42:41', 83);
