INSERT INTO `sys_oper_log` VALUES (1024, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1563\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1563\",\"category\":\"角色扮演\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20251112/4ea3976a54f04174456e79511e3484c3.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:40\",\"description\":\"“你”作为主角，回到大明，出生贫寒，但刻苦读书，最终金榜题名，获得皇上御赐官位，从此身负重任，胸怀抱负，立志惩奸除恶，朝着成为“大官员”的目标砥砺前行，从九品芝麻官到一品官员，直至权倾朝野的故事，能够让玩家身临其境体检官场的尔虞我诈。\\r\\n游戏着重于玩法与剧情的相结合，让玩家回到古香古色的清廷世界。告别枯燥乏味的刷怪升级，抛弃模式单一的经营玩法，为玩家缔造了一出高潮迭起、剧情跌宕起伏的故事。\\r\\n钱权掌握手中，就必须有佳人作伴。柳叶眉，杏核眼，樱桃小口，杨柳细腰，说话燕语莺声，一顾倾城的佳人形象加上别具匠心的妻妾养成系统，让你在乱世之中尽显柔情。\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1563\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20251112/d869a7dff2147fb6f0f6576b8a730d77.gif\",\"id\":166,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1563\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-11-04 14:18:08\",\"name\":\"天下无双HD（0.1折官途风云记）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"一款角色扮演的当官游戏\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13950.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"角色扮演\\\",\\\"addtime\\\":\\\"2025-11-04 14:18:08\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20251112/d869a7dff2147fb6f0f6576b8a730d77.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1563\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1563.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1563\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1563\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1563\\\",\\\"gamename\\\":\\\"天下无双HD（0.1折官途风云记）\\\"', '{\"msg\":\"操作成功\",\"code\":200,\"data\":166}', 0, NULL, '2025-12-26 08:42:41', 56);
