.u2game99.com/down.html?ag=GMS123&gid=1555\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1555\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1555\\\",\\\"gamename\\\":\\\"天使纪元（送天使特权刷充）\\\",\\\"excerpt\\\":\\\"《天使纪元》 是一款人族魔族背景的3D魔幻MMORPG手游，游戏在极致呈现西方魔幻精髓的同时，还加入了一系列革新玩法，大天使变身，让战斗充满更多可能；全民打BOSS，让每个人都能享受到一战封神的畅爽体验！\\\",\\\"id\\\":1555,\\\"game_source\\\":\\\"\\\",\\\"device_type\\\":2,\\\"edition\\\":2,', '{\"msg\":\"操作成功\",\"code\":200,\"data\":189}', 0, NULL, '2025-12-26 08:42:41', 43);
INSERT INTO `sys_oper_log` VALUES (1048, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1535\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1535\",\"category\":\"卡牌\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20251105/49bf03dd92f7a1618f2b3601b92969f7.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:40\",\"description\":\"化身转世大能，执掌一方仙门 ——《剑开仙门》以高自由度放置玩法，圆你专属修仙掌门梦！开局多种身份任选，从富贵世家到半魔血脉，灵根天赋各有乾坤。​\\r\\n宗门发展全凭心意：是潜心培养弟子，激活祝融、九尾等山海经神话角色的仙缘羁绊，还是派遣 “工具人” 打理丹房、灵田？挂机即可累积修为，轻松突破筑基、元婴等境界，离线也能稳步飞升。​\\r\\n踏遍山海寻机缘：昆仑仙山藏珍宝，异兽秘境遇彩蛋，更能征服千宗习得独门功法，或送茶论道广结仙缘。全新山海经版本已上线，捕捉毕方、应龙等异兽，争夺东皇钟等上古灵宝，组队跨服对抗魔界，声望与实力并肩成长。​\\r\\n无需肝氪也能畅享乐趣，每一次选择都是独属于你的仙门传奇！\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1535\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20251105/06e890d9744305b2ec71dcb46ba54e7a.gif\",\"id\":190,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1535\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-10-28 16:12:54\",\"name\":\"剑开仙门(0.05折送无限抽)\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"执仙门，山海放置爽飞升\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13922.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"卡牌\\\",\\\"addtime\\\":\\\"2025-10-28 16:12:54\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20251105/06e890d9744305b2ec71dcb46ba54e7a.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1535\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1535.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1535\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1535\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1535\\\",\\\"gamename\\\":\\\"剑开', '{\"msg\":\"操作成功\",\"code\":200,\"data\":190}', 0, NULL, '2025-12-26 08:42:41', 51);
