INSERT INTO `sys_oper_log` VALUES (1050, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1451\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1451\",\"category\":\"角色扮演\",\"coverUrl\":\"https://www.u2game99.com/data/upload/game/20251121/6920152749667.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:40\",\"description\":\"神级美学魔幻RPG大作《魔法来袭》！游戏深度还原MMO核心玩法，多种突破乐趣更多。美术全面升级，超清画质高精度建模，震撼的战斗技能效果丝滑多变，自动挂机刷怪也能帧帧打得漂亮。上千套华美造型，强化流光表现让装备更炫：有大排面的高贵坐骑、炫彩夺目的大翅膀、给力强化不断生成的神器神装等，给你颜值新高度！更有精灵跟随助战，天神随时附体畅享实力碾压全场的痛快。游戏可在线转职自由体验多职业乐趣，进击血色之地、恶魔要塞暴涨经验，于新剧情中亦可追忆回味青春荣光！还有战盟盟主虚位以待，激烈的跨服战甚至百团大战一触即发，快来沉浸式探索唯美的魔幻世界，燃动你的战盟之魂吧！\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1451\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://www.u2game99.com/data/upload/game/20251121/692015204d565.gif\",\"id\":192,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1451\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-09-23 10:32:55\",\"name\":\"魔法来袭（0.1折神域纪元）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"神魔变身，暗黑神王君临天下！\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13835.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"角色扮演\\\",\\\"addtime\\\":\\\"2025-09-23 10:32:55\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://www.u2game99.com/data/upload/game/20251121/692015204d565.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1451\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1451.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1451\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1451\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1451\\\",\\\"gamename\\\":\\\"魔法来袭（0.1折神域纪元）\\\",\\\"excerpt\\\":\\\"神级美学魔幻RPG大作《魔法来袭》！游戏深度还原MMO核心玩法，多种突破乐趣更多。美', '{\"msg\":\"操作成功\",\"code\":200,\"data\":192}', 0, NULL, '2025-12-26 08:42:41', 65);
