INSERT INTO `sys_oper_log` VALUES (1055, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1543\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1543\",\"category\":\"卡牌\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20251103/fd15edaeb161c4d0a13b17d3ea4ef8ee.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:40\",\"description\":\"高福利三国策略塔防手游《塔防镇魂师》0.1折全新来袭！创角即享0.1折充值，还能直升VIP15，领绝版称号、千万钻石，开局即巅峰！闯关掉落福利币，兑换钻石无上限，永久有效，轻松发育不卡关！此版本特权加量不加价，福利币存储上限加倍！内置超级助手，自动升级、一键布阵、挂机养成，轻松躺赢不费力！魔乱三国，汉室将倾，妖道张角以邪术召来无尽妖魔，天下危在旦夕！你将集结三国英豪，共筑御魔防线！排兵布阵、巧设箭塔，在变幻莫测的塔防地图中，打造属于你的不破长城！玩法不止塔防，更有竞技场、神兽秘境等多元副本，随时点燃你的热血与谋略！即刻下载，改写天命！\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1543\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://www.u2game99.com/data/upload/game/20251103/69080fba9f150.gif\",\"id\":198,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1543\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-10-30 09:38:05\",\"name\":\"塔防镇魂师（降魔三国0.1折）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"0.1折三国神将斩妖除魔！\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13930.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"卡牌\\\",\\\"addtime\\\":\\\"2025-10-30 09:38:05\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://www.u2game99.com/data/upload/game/20251103/69080fba9f150.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1543\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1543.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1543\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1543\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1543\\\",\\\"gamename\\\":\\\"塔防镇魂师（降魔三国0.1折）\\\",\\\"excerpt\\\":\\\"高福利三国策略塔防手游《塔防镇魂师》0.1折全新来袭！创角即享0.1折', '{\"msg\":\"操作成功\",\"code\":200,\"data\":198}', 0, NULL, '2025-12-26 08:42:41', 46);
