INSERT INTO `sys_oper_log` VALUES (1057, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1501\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1501\",\"category\":\"角色扮演\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20251028/11d2fb37b871b89c821e567370c4fb2d.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:40\",\"description\":\"《魔之序曲》是一款西方魔幻题材的MMORPG手游。3D次世代旗舰画质，360度自由视角，DIY个性外显，昼夜实时光影渲染，重新定义唯美西方幻想大世界。变身天神进行战斗，与上古神明协同作战，在跨服大战场，体验极限刺激的屠魔猎龙之战。当暗黑降临、魔龙复苏，玩家将扮演被古神指引的勇士，打开探索多元宇宙的魔晶之门。\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1501\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20251028/d0b31b6f8cd98c63f3827a76dfed4593.gif\",\"id\":200,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1501\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-10-17 14:45:06\",\"name\":\"魔之序曲（5折送鬼新娘）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"《魔之序曲》是一款西方魔幻题材的MMORPG手游。\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13887.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"角色扮演\\\",\\\"addtime\\\":\\\"2025-10-17 14:45:06\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20251028/d0b31b6f8cd98c63f3827a76dfed4593.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1501\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1501.html\\\",\\\"webur