INSERT INTO `sys_oper_log` VALUES (1058, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1498\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1498\",\"category\":\"卡牌\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20251028/ecca626051ab1d5d49f63aabea130eb3.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:40\",\"description\":\"《勇者传承（0.1折死神激斗）》是一款以原作中的剧情脉络为核心，对人物、场景进行精细还原，对角色能力、游戏玩法进行深度定制，经典呈现玩家难以忘怀的死神世界。在游戏中，玩家以主角的身份与视角面对强敌、收集资源、磨练技巧，培养自己的最强死神。人气角色大集结，黑崎一护、朽木白哉、朽木露琪亚等数位死神人气角色登场，专属定制技能，每一位登场角色都将给你:“没错，这就是他(她)的感觉!\\\"。热血沸腾的梦幻对决到放置类游戏轻松休闲，重燃战斗之魂，体验热血酣畅的灵压对决!\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1498\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20251028/812b9d235e4bef375f20c9a86e02b6e3.png\",\"id\":197,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1498\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-10-16 15:57:02\",\"name\":\"勇者传承（0.1折死神激斗）\",\"params\":{},\"promotionDesc\":\"禁海外推广\",\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"魂息不绝，刃鸣不止\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13884.mp4\\\",\\\"text_cps\\\":\\\"禁海外推广\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"卡牌\\\",\\\"addtime\\\":\\\"2025-10-16 15:57:02\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20251028/812b9d235e4bef375f20c9a86e02b6e3.png\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1498\\\",\\\"qrcode\\\":\\