INSERT INTO `sys_oper_log` VALUES (1068, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1529\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1529\",\"category\":\"回合\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20251027/1fc7159d9c62c9b1f7fde86a25a70941.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:40\",\"description\":\"神龙降世《万灵山海之境》0.05折福利版本来袭！每天签到就送648充值代币！！\\r\\n【神龙护体！驭龙横击九万里！】\\r\\n神龙助战！——神龙幻化，技能觉醒，炫酷外观拉风体验！神龙绕体，龙魂祈愿，法力狂飙见面就干！\\r\\n【跨服称尊！神域之巅傲世间！】\\r\\n神域降临！——地图争夺，万人竞技，决出全服至高战力！阵营神兽，云顶天宫，万千玩法惟我独仙！\\r\\n【以宝证道！器法双修大宗师！】\\r\\n灵宝系统！——假面玉玦，如意宝玺，增益拉满修仙不累！圣痕镶嵌，器灵觉醒，法宝到位神王干废！\\r\\n【太上忘情？师姐师弟全都要！】\\r\\n情缘盛会！——美艳师姐，奶狗师弟，梦幻恋爱指尖实现！试炼同心，策略推本，仙路漫漫有你作伴！\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1529\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20251027/66dc50d5e7106fd554ddceaed8f3c9f1.gif\",\"id\":212,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1529\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-10-27 13:37:59\",\"name\":\"万灵山海之境(0.05折每日送648)\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"神龙幻化护主战，法力狂飙即刻战\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13916.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"回合\\\",\\\"addtime\\\":\\\"2025-10-27 13:37:59\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20251027/66dc50d5e7106fd554ddceaed8f3c9f1.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1529\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1529.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1529\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1529\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1529\\\"', '{\"msg\":\"操作成功\",\"code\":200,\"data\":212}', 0, NULL, '2025-12-26 08:42:41', 53);
INSERT INTO `sys_oper_log` VALUES (1069, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1510\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1510\",\"category\":\"卡牌\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20251021/8c2493482db8536920fdf780e152c1d1.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:40\",\"description\":\"游戏还原精英赛玩法，每3天会有精英比试。精英赛时任何玩家可以到场观赛交流，可以押注为自己支持的战队助威，并且真实体验不同战队斗智斗勇的较量，究竟是靠着精英赛和弗兰德一样发家致富还是倾家荡产，全靠你的慧眼识珠！\\r\\n在游戏中，你会遇到形形色色的好友，来来往往的魂师，他们都源于斗罗又脱离斗罗，这是一个全新的斗罗世界，而这个世界，正在等你。\\r\\n今日，召天下少年，赴武魂之约！\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1510\",\"gameType\":\"official\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20251021/b5b10101a16c1aa6378abfbf865891ed.png\",\"id\":211,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1510\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-10-20 14:14:51\",\"name\":\"斗罗大陆：武魂觉醒（打金版）\",\"params\":{},\"promotionDesc\":\"禁海外推广\",\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"打BOSS爆代币，你的消费游戏买单！\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13896.mp4\\\",\\\"text_cps\\\":\\\"禁海外推广\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"卡牌\\\",\\\"addtime\\\":\\\"2025-10-20 14:14:51\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:10\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:6\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20251021/b5b10101a16c1aa6378abfbf865891ed.png\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1510\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\"