INSERT INTO `sys_oper_log` VALUES (1073, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1512\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1512\",\"category\":\"角色扮演\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20251024/dfb749a8fda10be2faca9c4593bf6037.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:40\",\"description\":\"《大屠龙(复古三职六流派)》是一款1.80复古微变多职业版本传奇手游，它的“微变”是属性上融合微变设定，也可以理解为游戏玩法系统上“微微变化”，用创新设计对冲了复古版本的单一性，让玩家能够打得更爽。其中六大流派包括：战士的攻速真伤流剑圣、爆发烈火流狂战；法师的召唤控制流冰法、爆发团战流雷法；道士的双宝宝流兽道、爆发火符流符道；游戏内除了熟悉的微变套装加成外，还有天赋系统、成长盾牌、配饰、武器锻造、宝石镶嵌等玩法，激战沙城自然也必不可少，散人追梦热血铸就新传奇，快来加入吧。\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1512\",\"gameType\":\"bt\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://www.u2game99.com/data/upload/game/20251024/68fb3031b5f5c.gif\",\"id\":214,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1512\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-10-21 14:14:12\",\"name\":\"大屠龙(复古三职六流派)\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"《大屠龙(复古三职六流派)》是一款1.80复古微变多职业版本传奇手游\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13898.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"角色扮演\\\",\\\"addtime\\\":\\\"2025-10-21 14:14:12\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:65\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:45\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://www.u2game99.com/data/upload/game/20251024/68fb3031b5f5c.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1512\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https