INSERT INTO `sys_oper_log` VALUES (1085, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1159\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1159\",\"category\":\"割草\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20251013/b86f98c24c5f16c3b6c965cfdd80ec1d.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:40\",\"description\":\"《咕噜王国大冒险》是一款Rougelike勇者养成闯关类手游。这款游戏有着十分真实游戏画质，并且游戏角色Q萌可爱。玩家可以在游戏中开启异次元冒险之旅，玩家作为降临这个世界的勇者，需要召集伙伴一起挑战异世界未知的危险。这里有着超多可爱的宠物坐骑和生活在本土的勇者部落等待你的探索。这款游戏作为一款款Rougelike冒险手游，玩家每次进入游戏都可以获得随机的技能，通过这些技能可能有时候会给玩家极大的帮助哦。同时玩家每次进入关卡都可能会随机匹配到不一样的游戏地图。这往往能够获得更多的奖励。怪物、地图、障碍物、陷阱等，也是随机组合而成的。快来游戏中获取强大力量，或寻求珍宝，打造属性出色的神器快速提升战力吧。\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1159\",\"gameType\":\"bt\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20251013/80aa59ed8b897d1e43e2459efc6811e6.png\",\"id\":229,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1159\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-06-25 11:50:09\",\"name\":\"咕噜王国大冒险（内置0.1折）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"0.1割草手游，满屏暴击爽到飞起。\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13512.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"割草\\\",\\\"addtime\\\":\\\"2025-06-25 11:50:09\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:65\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:45\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20251013/80aa59ed8b897d1e43e2459efc6811e6.png\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html