\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1395\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1395\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1395\\\",\\\"gamename\\\":\\\"逆战三国（0.05原价十倍奖励）\\\",\\\"excerpt\\\":\\\"三分天下，乱世争雄，全新三国RPG炫技卡牌手游《逆战三国》，最大诚意的创新玩法让每个进入的玩家都能眼前一亮，开创三国卡牌里程碑的新系统等你探索，超多顶级三国美人神将，玩家在提升自身实力的同时审美也不会疲劳，美人常伴吾身，一手掌控三国绝色，一手平定天下乱世，尽在逆战三国。\\\",\\\"id\\\":1', '{\"msg\":\"操作成功\",\"code\":200,\"data\":270}', 0, NULL, '2025-12-26 08:42:42', 70);
INSERT INTO `sys_oper_log` VALUES (1130, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1333\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1333\",\"category\":\"回合\",\"coverUrl\":\"https://www.u2game99.com/data/upload/game/20251021/68f7400f25565.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:41\",\"description\":\"《轩辕剑龙舞云山》是网易获台湾大宇正版授权，基于 “轩辕剑” IP 自研的作品。融合网易成熟技术与创意，带来独特体验。\\r\\n游戏故事设定在唐朝由盛转衰之时。既有经典剧情，也有原创的时空穿越剧情，讲述安禄山叛乱、琉璃会高层失踪、墨家后人现世等情节，还涉及上古十大神器，各势力展开正邪较量。\\r\\n玩法上，在回合制战斗基础上创新，加入 “克制” 与 “追击” 系统，玩家需搭配阵容策略战斗，还有护驾灵佑，策略组合多样。游戏也有弹琴、画画等丰富休闲玩法，让玩家体验古人风雅。\\r\\n美术采用 “新国风轻写实” 画风，借鉴国画水墨技法并创新，展现传统国风场景。音乐上，《云山逸韵》专辑收录 11 首曲目，各场景旋律独特，营造沉浸式氛围。\\r\\n在这里，你将拥有一段独一无二的国风游戏记忆，不容错过。\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1333\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://www.u2game99.com/data/upload/game/20251021/68f73f5370419.gif\",\"id\":272,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1333\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-08-18 11:21:36\",\"name\":\"轩辕剑龙舞云山（0.1折网易国风回合）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"网易原班人马打造全新IP\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13705.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"回合\\\",\\\"addtime\\\":\\\"2025-08-18 11:21:36\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://www.u2game99.com/data/upload/game/20251021/68f73f5370419.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1333\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1333.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1333\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1333\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1333\\\",\\\"gamename\\\":\\\"轩辕剑龙舞云', '{\"msg\":\"操作成功\",\"code\":200,\"data\":272}', 0, NULL, '2025-12-26 08:42:42', 62);
INSERT INTO `sys_oper_log` VALUES (1131, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1363\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1363\",\"category\":\"卡牌\",\"coverUrl\":\"https://www.u2game99.com/data/upload/game/20250912/68c39749ad18b.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:41\",\"description\":\"《魔灵幻想》是一款竖屏日系二次元风格放置卡牌类放置手游。本游戏采用了怪物进化的特色题材，每个角色都具有幼年期、成长期、完全体，三个形态。每个形态都有独有的原画和战斗角色，特别是在三阶进化成了非常漂亮的二次元妹子，给玩家的成长感带来不一样的感受。在设定方面，我们拥有风、水、火、木、光、暗6个元素，在战斗的对抗上拥有更丰富的战斗策略维度。这是一个强调玩家相互对抗并在此环境下一起成长的游戏，最终的目标是在灭亡的危机中拯救精灵和人类两个世界。\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1363\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://www.u2game99.com/data/upload/game/20250902/68b65ff01fce3.png\",\"id\":273,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1363\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-08-26 09:57:52\",\"name\":\"魔灵幻想（0.1折免费版）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"一款日系二次元竖屏放置卡牌手游\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13738.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"卡牌\\\",\\\"addtime\\\":\\\"2025-08-26 09:57:52\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://www.u2game99.com/data/upload/game/20250902/68b65ff01fce3.png\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1363\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1363.html\\\",\\\"weburl_