INSERT INTO `sys_oper_log` VALUES (1133, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1361\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1361\",\"category\":\"卡牌\",\"coverUrl\":\"https://www.u2game99.com/data/upload/game/20250905/68ba926cb3adf.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:41\",\"description\":\"《都市冒险高手》是一款末日废土风格的卡牌角色扮演游戏，以未来都市为背景，玩家将面对不同的地图、关卡和变异生物来构筑最强\\\"异能者对抗都市中的破坏者。\\r\\n故事源于2077夏夜，一颗陨石划过天际，降落在G城中心处，一股神秘气体向外蔓延，被气体感染的生物变得凶暴异常。随着这些怪物增多，幸存者们无奈退至西部，建造“壁垒\'抵御怪物，休整生息。\\r\\n随着时间流逝，少部分幸存者们逐渐掌握神秘气体的力量，被称为\\\"异能者”，物资的圆乏令幸存者们不得不提起兵刃，组建“战队\\\",走出\\\"壁垒”，寻觅物资，建设家园。\\r\\n\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1361\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20250904/b82ed0a17ea1f62a5b730e1e7029c066.gif\",\"id\":276,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1361\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-08-25 15:00:16\",\"name\":\"都市冒险高手（0.1折千抽9星光暗）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"寻觅物资，建设家园\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13736.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"卡牌\\\",\\\"addtime\\\":\\\"2025-08-25 15:00:16\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20250904/b82ed0a17ea1f62a5b730e1e7029c066.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1361\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1361.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1361\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1361\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1361\\\",\\\"gamename\\\":\\\"都市冒险高手（0.1折千抽9星光暗）\\\",\\\"excerpt\\\":\\\"《都市冒险高手》是一款末日废土风格的卡牌角色扮演游戏，以', '{\"msg\":\"操作成功\",\"code\":200,\"data\":276}', 0, NULL, '2025-12-26 08:42:42', 65);
INSERT INTO `sys_oper_log` VALUES (1134, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1294\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1294\",\"category\":\"角色扮演\",\"coverUrl\":\"https://www.u2game99.com/data/upload/game/20251224/694b961ed5352.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:41\",\"description\":\"《文明与众神）》是一款以西方架空魔幻风格为背景的即时战斗类手机网络游戏。在游戏中，玩家将扮演“救世团”成员，踏上寻找五位创世神像的征程。玩家将在游戏中一步步了解到这个世界的背景，自身之前的经历，通过寻求伙伴，强化武器提升自己，通过加入佣兵团获得大家的帮助，与此同时，玩家还可以通过自身或多人组队对世界中的邪恶发起征讨以获得更加强力的武器装备，除此之外，通过竞技场，佣兵之王，泳池派对等玩法还可以让玩家一步一步成为这个世界的救世主，最终拯救这个世界。通过游戏，玩家能够获得逻辑思维的锻炼，体验异世界不同人生的乐趣。\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1294\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://www.u2game99.com/data/upload/game/20251224/694b96968f79c.png\",\"id\":275,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1294\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-08-06 17:35:46\",\"name\":\"文明与众神（0.1折云上圣歌送亿钻）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"超爽高爆异世界，极品时装免费送！\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13663.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"角色扮演\\\",\\\"addtime\\\":\\\"2025-08-06 17:35:46\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://www.u2game99.com/data/upload/game/20251224/694b96968f79c.png\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1294\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www