INSERT INTO `sys_oper_log` VALUES (1137, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1378\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1378\",\"category\":\"放置\",\"coverUrl\":\"https://www.u2game99.com/data/upload/game/20250904/68b901dece37f.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:41\",\"description\":\"踏入美轮美奂的 3D 修真世界，沉浸式体验云雾缭绕的仙山、波光粼粼的灵湖，每一处场景都细腻入微，仿佛身临其境。在这里，你将踏上寻找神兵利器的冒险之旅，多职业随心觉醒，无论是近身搏杀的热血，还是远程制敌的谋略，都能尽情施展。​\\r\\n游戏玩法丰富多样，组队对战中与好友并肩作战，修罗战场内挑战极限，排位赛上争夺荣耀之巅，还能在交易市场摆摊买卖，或是循着线索追踪仇敌。背负灭魔斩妖的重任，借助传说之力，一路披荆斩棘，成就属于你的修真传奇。​\\r\\n精致细腻的人物建模，搭配真实自然的环境渲染，呈现出媲美端游的次世代画面，带你领略一场极致的修真美学盛宴。\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1378\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20250904/65f3d290a39257fc93ef6b2d21223368.gif\",\"id\":279,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1378\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-08-29 17:08:17\",\"name\":\"奇门(0.05折送黑神话无常)\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"绝美3D修真，畅享多元仙旅\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13754.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"放置\\\",\\\"addtime\\\":\\\"2025-08-29 17:08:17\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20250904/65f3d290a39257fc93ef6b2d21223368.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1378\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1378.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1378\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1378\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1378\\\",\\\"gamename\\\":\\\"奇门(0.05折送黑神话无常)\\\",\\\"excerpt\\\":\\\"踏入美轮美奂的 3D 修真', '{\"msg\":\"操作成功\",\"code\":200,\"data\":279}', 0, NULL, '2025-12-26 08:42:42', 62);
INSERT INTO `sys_oper_log` VALUES (1138, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1371\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1371\",\"category\":\"卡牌\",\"coverUrl\":\"https://www.u2game99.com/data/upload/game/20250901/68b568f21b861.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:41\",\"description\":\"顶级画师联手打造的泛二次元6V6卡牌RPG手游，《旅行骑士》火爆来袭，7大养成系统，强大日语配音，精美立绘，酷炫合击大招，带你感受阿瓦隆大陆的绝美风貌。4大阵营，绝美SSSR神将，多种策略组合，丰富多样的养成体验荟萃集结！跨服竞技PK、怪盗来袭、航海奇遇、公会战、试炼之塔......玩法多样，探索乐趣无极限！ 聊天、吐槽、抢红包、实时语音，社交无所不能！一人刷副本，众人陪互动。撩妹分分钟，战斗再也不枯燥！\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1371\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20250901/1741061f37915c6f203cf5ddb3b50517.png\",\"id\":280,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1371\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-08-27 17:10:07\",\"name\":\"旅行骑士（0.1折买断版）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"二次元6V6卡牌RPG手游\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13747.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"卡牌\\\",\\\"addtime\\\":\\\"2025-08-27 17:10:07\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20250901/1741061f37915c6f203cf5ddb3b50517.png\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1371\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1371.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1371\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1371\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1371\\\",\\\"gamename\\\":\\\"旅行骑士（0.1折买断版）\\\",\\\"excerpt\\\":\\\"顶级画师联手打造的泛二次元6V6卡牌RPG手游，《旅行骑士》火爆来袭，7大养成系统，强大日语配音，精美立绘，酷炫合击大招，带你感受阿瓦隆大陆的绝美风貌。4大阵营，绝美SSSR', '{\"msg\":\"操作成功\",\"code\":200,\"data\":280}', 0, NULL, '2025-12-26 08:42:42', 68);
