INSERT INTO `sys_oper_log` VALUES (1141, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1315\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1315\",\"category\":\"放置\",\"coverUrl\":\"https://www.u2game99.com/data/upload/game/20250902/68b6424e66339.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:41\",\"description\":\"锦绣江湖是一款融合了卡牌、放置和RPG玩法精髓放置武侠手游，以奇情怪趣的“人形兵器与江湖百派纷争”为世界观，携数百位风情万千的高颜值侠客，开放式的江湖大世界探索玩法，带给你闲趣写意的全新江湖体验。上百个经典武林门派，通过丰富的背景故事将其串联起来。在这里，每个门派侠客技能设计都带有典型的武侠元素和门派特色，如狂浪不羁的海沙帮、劲飒十足的五毒教、侠气倾天的华山派、讲义气的峨眉派...玩家可根据自己的需要，搭配武侠阵容。在画风上写意国风，无论是人物立绘还是场景塑造，都展现出了锦绣特色的东方美学与江湖意境，在真实还原武侠江湖的同时又不显拘谨。\",\"deviceSupport\":\"android\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1315\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://www.u2game99.com/data/upload/game/20250902/68b667f3e20bd.png\",\"id\":283,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1315\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-08-12 14:00:38\",\"name\":\"锦绣江湖（永久0.05折）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"真实还原武侠江湖\\\",\\\"interchangeable_role\\\":0,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13686.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"放置\\\",\\\"addtime\\\":\\\"2025-08-12 14:00:38\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://www.u2game99.com/data/upload/game/20250902/68b667f3e20bd.png\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1315\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://ww