INSERT INTO `sys_oper_log` VALUES (1148, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1129\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1129\",\"category\":\"角色扮演\",\"coverUrl\":\"https://www.u2game99.com/data/upload/game/20251030/6903589fcb123.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:41\",\"description\":\"在这个充满东方玄幻色彩的仙侠世界中，你将体验到独特的游戏玩法与极致的战斗体验。游戏采用顶级3D超清画质，将宏伟的仙侠世界展现得淋漓尽致。从神秘的星辰秘境，到强大的上古神兽，每一个细节都为你精心打造。捕捉并培养专属神兽，让它与你并肩作战，助你在这片大陆上无往不胜！此外，多职业自由转职系统，让你在战斗中体验多种角色的乐趣，仙魔随心切换，任意选择你的成长之路。\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1129\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://www.u2game99.com/data/upload/game/20251030/69035519788a4.png\",\"id\":290,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1129\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-06-12 15:37:31\",\"name\":\"逍遥九歌行（0.1折免费机甲关羽）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"终身0.1折激爽版沉浸式仙侠手游\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13478.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"角色扮演\\\",\\\"addtime\\\":\\\"2025-06-12 15:37:31\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://www.u2game99.com/data/upload/game/20251030/69035519788a4.png\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1129\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1129.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1129\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1129\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1129\\\",\\\"gamename\\\":\\\"逍遥九歌行（0.1折免费机甲关羽）\\\",\\\"excerpt\\\":\\\"在这个充满东方玄幻色彩的仙侠世界中，你将体验到独特的游戏玩法与极致的战斗体验。游戏采用顶级3D超清画质，将宏伟的仙侠世界展现得淋漓尽致。从神秘的星辰秘境，到强大的上古神兽，每一个细节都为你精心打造。捕捉并培养专属神兽，让它与你并肩作战，助你在这片大陆上无往不胜！此外，', '{\"msg\":\"操作成功\",\"code\":200,\"data\":290}', 0, NULL, '2025-12-26 08:42:42', 68);
INSERT INTO `sys_oper_log` VALUES (1149, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1324\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1324\",\"category\":\"放置\",\"coverUrl\":\"https://www.u2game99.com/data/upload/game/20250826/68ad7e3bebd70.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:41\",\"description\":\"《无畏三国（0.1折魂将现世）》以Q萌画风重塑三国史诗！​​ 在这里，你既是运筹帷幄的主公，执掌三国名将自动挂机养成，离线也可坐收海量资源；更是统御千军的统帅，独创国战​玩法，实时指挥军团推进，攻城略地、剑指洛阳！轻松的放置养成搭配深度策略玩法彻底告别无脑挂机！游戏加入超越神魔将的顶级魂将，开服即可获取，战力飙升不再受限，助你平定乱世，一统天下！而今，0.1折破界狂欢​，上线即送无限续杯双月卡，每天签到直领T0神将，升级即送不限量真充卡及万抽，首充只需实付 ​0.01元，满V全靠白嫖，这乱世，等你以0.01元之资终结！\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1324\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://www.u2game99.com/data/upload/game/20250930/68db9507cd261.gif\",\"id\":288,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1324\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-08-14 13:57:16\",\"name\":\"无畏三国（0.1折魂将现世）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"战力飙升不再受限，助你平定乱世，一统天下\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13696.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"放置\\\",\\\"addtime\\\":\\\"2025-08-14 13:57:16\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://www.u2game99.com/data/upload/game/20250930/68db9507cd261.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1324\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1324.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1324\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1324\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1324\\\",\\\"gamename\\\":\\\"无畏三国（0.1折魂将现世）\\\",\\\"excerpt\\\":\\\"《无畏三国（0.1折魂将现世）》以Q萌画风重塑三国史诗！​​ 在这里，你既是运筹帷幄的主公，执掌三国名将自动挂机', '{\"msg\":\"操作成功\",\"code\":200,\"data\":288}', 0, NULL, '2025-12-26 08:42:42', 84);
INSERT INTO `sys_oper_log` VALUES (1150, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1245\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1245\",\"category\":\"放置\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20250729/8fd65eaeafba8bd7a6ef22a2572a5aba.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:41\",\"description\":\"《凡人修仙传（星海飞驰）》是由起点白金级作家忘语同名小说《凡人修仙传》正版授权改编的微社交组团修炼手游，\\r\\n游戏充分还原小说内庞大浩瀚的修仙体系，以组团模式连接道友与道友之间的缘法，比肩共赴坎坷难行的修仙之路。\\r\\n坚信只要像韩立那样拥有不曾动摇的修仙之心，所有道友终将超凡脱世登峰造极！\\r\\n\\r\\n游戏特色\\r\\n1、轻松放置修仙\\r\\n\\r\\n支持离线挂机，自动累积修为、淬炼灵根，灵宠养成、法宝蕴养全程托管。\\r\\n\\r\\n2、策略深度玩法\\r\\n\\r\\n跨服天梯实时竞技，挑战全服道友；宗门共修互助渡劫，万人仙盟共抗心魔入侵。\\r\\n\\r\\n3、视听沉浸体验\\r\\n\\r\\n水墨动态绘卷勾勒山河万象，飞剑凌空、丹炉凝雾，国风仙韵十足。\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1245\",\"gameType\":\"official\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://p1.277sy.com/2025/07/29/68882f9c82b64.gif\",\"id\":292,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1245\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-07-21 15:21:06\",\"name\":\"凡人修仙传：星海飞驰\",\"params\":{},\"promotionDesc\":\"禁止海外推广\",\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"正版授权改编手游\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13608.mp4\\\",\\\"text_cps\\\":\\\"禁止海外推广\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"放置\\\",\\\"addtime\\\":\\\"2025-07-21 15:21:06\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:1\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:1\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://p1.277sy.com/2025/07/29/68882f9c82b64.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1245\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1245.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1245\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1245\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1245\\\",\\\"gamename\\\":\\\"凡人修仙传：星海飞驰\\\",\\\"excerpt\\\":\\\"《凡人', '{\"msg\":\"操作成功\",\"code\":200,\"data\":292}', 0, NULL, '2025-12-26 08:42:42', 67);
