l\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1266\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1266\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1266\\\",\\\"gamename\\\":\\\"崛起：终极王者（0.1折免费版）\\\",\\\"excerpt\\\":\\\"《崛起：终极王者（0.1折免费版）》是一款三国题材的角色扮演卡牌类手游。天天送2000代金券，免费玩游戏，全场充值0.1折！精美丝滑的战斗画面、极高的抽卡率都成为了它独特的亮点，多维度玩法，全方位养成，更融合了多种PVE玩法，让玩家通过自己的谋略解锁更多意想不到的三国阵容，游戏内置一键闯关玩法', '{\"msg\":\"操作成功\",\"code\":200,\"data\":295}', 0, NULL, '2025-12-26 08:42:42', 63);
INSERT INTO `sys_oper_log` VALUES (1154, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1327\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1327\",\"category\":\"经营\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20250821/c8e2d6e49611f06931871fbe7bc18091.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:41\",\"description\":\"《梦境食旅》是一款美食类模拟养成游戏，融合了餐馆经营、员工收集，战斗和趣味小游戏等多种玩法。 在游戏中，你将享受亲自经营餐馆的乐趣，遇见各种奇怪的顾客，并带领来自异世界的伙伴们一起探索梦境灵界，寻找来自世界各地的美味食谱，展开一段奇妙的旅程。 \\r\\n\\r\\n【经营餐馆，邂逅美味】 \\r\\n-在梦境灵界中开一家属于你的餐馆，邂逅来自各个次元的奇异客人，用一份你的专属美食，换取一段精彩的故事，在经营中寻找烹饪的意义。\\r\\n \\r\\n【童话伙伴，携手同行】 \\r\\n-你不在孤身一人，在梦境灵界中破开次元，招募来自童话传说中的数十位伙伴，高冷优雅的红皇后，尊贵自信的青蛙王子，腹黑萝莉小红帽，闲云野鹤般的姜子牙… 与他们一同经营你的餐馆，经历梦境里一段段笑泪交加的大冒险。\\r\\n \\r\\n【绮丽装扮，随心搭配】 \\r\\n-在这里，我们为你准备了温馨古典的欧式家居，静谧祥和的动物森林，古朴典雅的东方韵味，奇幻迷人的魔法学院，神秘的阿拉伯之夜… 各式主题装扮，任你自由搭配，打造专属于你的梦幻餐馆。 \\r\\n\\r\\n【梦境冒险，寻觅佳肴】 \\r\\n-拉上伙伴勇闯梦灵岛，在出人意料的随机事件中，寻回散落的珍贵菜单，面对梦境世界中混沌的危机，与童话中的伙伴一起揭秘梦境世界不为人知的故事。\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1327\",\"gameType\":\"official\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20250821/babda6cf934e3e726f2c04212c60ac38.png\",\"id\":297,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1327\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-08-14 16:16:40\",\"name\":\"梦境食旅（送SSR员工嫦娥）\",\"params\":{},\"promotionDesc\":\"禁止海外推广\",\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"经营梦境餐馆，烹饪美味佳肴\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13699.mp4\\\",\\\"text_cps\\\":\\\"禁止海外推广\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"经营\\\",\\\"addtime\\\":\\\"2025-08-14 16:16:40\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:50\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:30\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20250821/babda6cf934e3e726f2c04212c60ac38.png\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1327\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1327.html\\\",\\', '{\"msg\":\"操作成功\",\"code\":200,\"data\":297}', 0, NULL, '2025-12-26 08:42:42', 78);
