INSERT INTO `sys_oper_log` VALUES (1156, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1278\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1278\",\"category\":\"卡牌\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20250814/e0fb678c0441427a12ff78fcdb9e4713.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:41\",\"description\":\"《魔灵军团》是一款以东方神话为背景的玄幻修仙题材手游，融合了国漫风格、策略战斗与社交养成玩法，拥有丰富的游戏内容体系，主打轻松操作与深度策略的结合。包含PVE副本和PVP竞技，跨服团战和巅峰竞技战，强调团队协作和策略搭配。\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1278\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20250814/7c58d9cf952d1b913689933420c0f747.gif\",\"id\":300,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1278\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-08-04 16:28:27\",\"name\":\"梦回西游记（0.05折送毕业阵容）\",\"params\":{},\"promotionDesc\":\"禁海外推广\",\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"要战就战神仙局，灵山未至再续真经\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13646.mp4\\\",\\\"text_cps\\\":\\\"禁海外推广\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"卡牌\\\",\\\"addtime\\\":\\\"2025-08-04 16:28:27\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20250814/7c58d9cf952d1b913689933420c0f747.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1278\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1278.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1278\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1278\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1278\\\",\\\"gamename\\\":\\\"梦回西游记（0.05折送毕业阵容）\\\",\\\"excerpt\\\":\\\"《魔灵军团》是一款以东方神话为背景的玄幻修仙题材手游，融合了国漫风格、策略战斗与社交养成玩法，拥有丰富的游戏内容体系，主打轻松操作与深度策略的结合。包含PVE副本和PVP竞技，跨服团战和巅峰竞技战，强调团队协作和策略搭配。\\\",\\\"id\\\":1', '{\"msg\":\"操作成功\",\"code\":200,\"data\":300}', 0, NULL, '2025-12-26 08:42:42', 62);
INSERT INTO `sys_oper_log` VALUES (1157, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1311\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1311\",\"category\":\"卡牌\",\"coverUrl\":\"https://www.u2game99.com/data/upload/game/20250821/68a67c3b8c72f.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:41\",\"description\":\"当三国名将齐齐穿越回石器时代，会产生什么样的碰撞？原创三国+石器时代+放置挂机！在这里，你可以化身一条“咸鱼主公”，带着你的部下，躺着变强——离线挂机也能收获资源，一键领取海量奖励！游戏采用q萌三国画风，武将们既能正经打仗，也能摆烂摸鱼：甄姬拿着羽毛扇、吕布扛着石头戟……爆笑剧情颠覆传统！体验不一样的三国！\\r\\n\\r\\n特色玩法：\\r\\n【全新三国】：原创石器时代的三国名将，Q版角色萌趣搞笑，战斗特效华丽而不浮夸!\\r\\n【放置养成】：采用自动战斗+离线收益的放置玩法，无需长时间在线，睡觉、上班也能轻松升级！\\r\\n【轻松战斗】：全自动战斗，轻策略，单手就能激情pk！\\r\\n【福利拉满】：登录即送蜀国名将SSR“张飞”，更有千抽福利，抽到爽。648？不存在的！\\r\\n\\r\\n口号：“躺平即正义，咸鱼终成王！”\\r\\n适合懒人玩家、三国爱好者和沙雕网友，快来体验最不卷的三国！\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1311\",\"gameType\":\"official\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20250820/9de0fb2e3b1c6e1afb39fddc897bc21f.png\",\"id\":296,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1311\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-08-11 15:06:59\",\"name\":\"我守护的家园（千抽福利）\",\"params\":{},\"promotionDesc\":\"禁止海外推广\",\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"躺平即正义，咸鱼终成王！\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13681.mp4\\\",\\\"text_cps\\\":\\\"禁止海外推广\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"卡牌\\\",\\\"addtime\\\":\\\"2025-08-11 15:06:59\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:0\\\",\\\"hw_cps_cpa\\\":\\\"CPS推广:15\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20250820/9de0fb2e3b1c6e1afb39fddc897bc21f.png\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1311\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1311.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1311\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1311', '{\"msg\":\"操作成功\",\"code\":200,\"data\":296}', 0, NULL, '2025-12-26 08:42:42', 94);
INSERT INTO `sys_oper_log` VALUES (1158, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1312\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1312\",\"category\":\"卡牌\",\"coverUrl\":\"https://www.u2game99.com/data/upload/game/20250819/68a3d0afb2326.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:41\",\"description\":\"天马流星拳划破次元，圣斗士集结，《破阵勇士》黄金圣衣闪耀再现！小宇宙系统点燃，觉醒你的第八感，全系斗士待你召唤，共同为守卫和平而战！\\t\\t\\t\\t\\r\\n\\t\\t\\t\\t\\r\\n【3D还原 忠于原著】\\t\\t\\t\\t\\r\\n环绕音效重现热血战役，逼真的场景，呐喊式的战斗，与儿时记忆重叠的主线剧情，是幻想？不！是真实！\\t\\t\\t\\t\\r\\n\\t\\t\\t\\t\\r\\n【玩转策略 热血激情】\\t\\t\\t\\t\\r\\n顶级音效，奏响热血战斗的乐章！拳拳到肉的热血对决，圣衣带来的属性质变，用智力达成你的目标！\\t\\t\\t\\t\\r\\n\\t\\t\\t\\t\\r\\n【星座加成 合成革新】\\t\\t\\t\\t\\r\\n陪伴角色成长，解锁更深层的星座故事，多种策略玩法多维养成，技能装备全新合成思路，创新才耐玩！\\t\\t\\t\\t\\r\\n\\t\\t\\t\\t\\r\\n【数值平衡 福利白给】\\t\\t\\t\\t\\r\\n新服狂欢豪礼送足一个月！人均欧皇轻松集卡轻松养成，高概率高收益，每个玩家都能爆发小宇宙！\\t\\t\\t\\t\\r\\n\\t\\t\\t\\t\\r\\n准备好成为圣斗士了吗！用拳头守护大地，用爱见证每个蜕变，快来释放小宇宙，创造属于你的神话！\\t\\t\\t\\t\\r\\n\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1312\",\"gameType\":\"official\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://p1.277sy.com/2025/08/18/68a29a9ca83dd.png\",\"id\":299,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1312\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-08-11 15:07:59\",\"name\":\"破阵勇士（燃烧小宇宙）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"圣斗士集结圣域，黄金圣衣闪耀觉醒\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13682.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"卡牌\\\",\\\"addtime\\\":\\\"2025-08-11 15:07:59\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:0\\\",\\\"hw_cps_cpa\\\":\\\"CPS推广:15\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://p1.277sy.com/2025/08/18/68a29a9ca83dd.png\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1312\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1312.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1312\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?', '{\"msg\":\"操作成功\",\"code\":200,\"data\":299}', 0, NULL, '2025-12-26 08:42:42', 75);
