INSERT INTO `sys_oper_log` VALUES (1171, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1157\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1157\",\"category\":\"放置\",\"coverUrl\":\"https://www.u2game99.com/data/upload/game/20250905/68baa2288b9b9.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:41\",\"description\":\"浩瀚仙魔界，万族争锋！你自凡尘觉醒天命血脉，踏破九霄，执掌上古神器，驯服洪荒灵宠，逆天改命！\\r\\n挂机自动修炼：离线也能斩妖除魔，经验狂飙，躺赢飞升！装备高爆觉醒：秘境BOSS掉神装，刀刀暴击，金光漫天，传说仙器、至尊坐骑爆率翻倍，战力秒升巅峰！\\r\\n仙盟激战、跨服争霸，指尖操控无双神通，一键释放毁天灭地！百变仙缘奇遇，邂逅狐妖剑灵，解锁禁忌情缘……这方天地，由你主宰！\\r\\n即刻登录，立成至尊仙尊！\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1157\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://www.u2game99.com/data/upload/game/20250828/68b01f02038c0.gif\",\"id\":310,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1157\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-06-24 16:41:59\",\"name\":\"少年封神（0.1折十万抽千个648）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"十万连抽千个648随意拿\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13509.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"放置\\\",\\\"addtime\\\":\\\"2025-06-24 16:41:59\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://www.u2game99.com/data/upload/game/20250828/68b01f02038c0.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1157\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1157.html\\\",\\\"weburl_qr\\\":