INSERT INTO `sys_oper_log` VALUES (1172, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1247\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1247\",\"category\":\"角色扮演\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20250801/42bd6bb53f79ba9480edac19d7280954.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:41\",\"description\":\"冥王神殿里是何人悄然苏醒？九重尖塔上是谁的阴影盘旋？征服之岛中又是什么蠢蠢欲动？古神的低语，令天空变色！\\r\\n恶魔的咆哮，让大地战栗！幻兽的崛起，让沧海惊惧！勇士游侠，法师贤者，全都集结于此！\\r\\n用勇气、智慧、坚毅、决心突破重重难关，击败邪恶强敌！拨开云雾吹散阴霾，让《黎明召唤》照耀这个世界！\\r\\n\\r\\n游戏特色：\\r\\n暗黑美术 魔幻纪元\\r\\n全3D精致建模，次世代渲染技术，再现经典暗黑美术。玩家化身英雄。勇者集结于此，探索神秘的天使大陆，协助天使击溃恶魔，体验不一样的魔幻史诗。\\r\\n\\r\\n百变造型 随从坐骑\\r\\n霸气铠甲、优雅礼服、休闲泳装??百种时装自由搭配，打造个性十足，实力爆表的角色。更有数十种坐骑、随从供你挑选，伴你一起在这个神秘的魔幻世界冒险。\\r\\n\\r\\n花式冒险 多种副本\\r\\n装备超高爆率，一键挂机，暴打BOSS，轻松护肝，神装入手就是这么简单。随机副本，多种玩法，告别无聊的刷刷刷，一起来开动脑筋，挑战极速通关！\\r\\n\\r\\n热血PK 激情对战\\r\\n你若要战，随时奉陪！野外PK突袭玩家，世界BOSS全服乱斗，天梯对决冲击排名，公会开战制霸全服，多种PVP玩法搭配炫酷特效，让你尽情释放战斗热血！\\r\\n\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1247\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://p1.277sy.com/2025/07/31/688b35048b900.gif\",\"id\":314,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1247\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-07-22 09:24:29\",\"name\":\"黎明召唤（0.05折返100%代金券）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"0.05折神魔之争，100%反代金券\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13611.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"角色扮演\\\",\\\"addtime\\\":\\\"2025-07-22 09:24:29\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://p1.277sy.com/2025/07/31/688b35048b900.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1247\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1247.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1247\\\",\\\"do', '{\"msg\":\"操作成功\",\"code\":200,\"data\":314}', 0, NULL, '2025-12-26 08:42:42', 74);
