INSERT INTO `sys_oper_log` VALUES (1175, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1189\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1189\",\"category\":\"角色扮演\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20250731/4d3c79d204e0b4edd1194ab1698cbb62.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:42\",\"description\":\"次时代3DMMO仙魔手游《绝世仙王》隆重登场。混沌初开，寰宇新诞。魔族残害生灵，嗜血成性。天帝少昊，悲天悯人，封魔族于无尽深渊，遣仙族以镇之。千年后，政通人和，百废俱兴，天明地清，四海升平。天帝见心愿已了，遂遨游天外，不问苍生。然魔族贼心不死，无尽深渊封印动荡，诛魔宝塔摇摇欲坠，昆仑蜀山先后失守，作为天帝之子的你，是否能百战成神，继承众生之意志，一举消灭魔族！\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1189\",\"gameType\":\"official\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://p1.277sy.com/2025/07/24/6881deec5869e.png\",\"id\":317,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1189\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-07-02 10:00:40\",\"name\":\"绝世仙王（我欲封天）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"继承众生之意志，一举消灭魔族\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/12198.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"角色扮演\\\",\\\"addtime\\\":\\\"2025-07-02 10:00:40\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:55\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:35\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://p1.277sy.com/2025/07/24/6881deec5869e.png\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1189\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1189.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://