INSERT INTO `sys_oper_log` VALUES (1176, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1237\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1237\",\"category\":\"角色扮演\",\"coverUrl\":\"https://www.u2game99.com/data/upload/game/20250924/68d3aeecaf9cf.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:42\",\"description\":\"天下大乱，游龙辈出。这原本是一个承平已久，青云圣教与普通凡人和谐相处的世界，但一场突如其来的阴谋颠覆了这一切。面对晦暗不明的局面，层出不穷的强大敌人、上古凶兽，你能否保持初心不断变强，一步步揭开导致天下大乱的真相，并成为天下第一的强者？\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1237\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://www.u2game99.com/data/upload/game/20250924/68d3aededdf63.gif\",\"id\":319,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1237\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-07-17 15:39:10\",\"name\":\"封灵诀（0.05十倍返利免单版）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"0.05折10倍返利，灵玉多到花不完！\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13599.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"角色扮演\\\",\\\"addtime\\\":\\\"2025-07-17 15:39:10\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://www.u2game99.com/data/upload/game/20250924/68d3aededdf63.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1237\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1237.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1237\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1237\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1237\\\",\\\"gamename\\\":\\\"封灵诀（0.05十倍返利免单版）\\\",\\\"excerpt\\\":\\\"天下大乱，游龙辈出。这原本是一个承平已久，青云圣教与普通凡人和谐相处的世界，但一场突如其来的阴谋颠覆了这一切。面对晦暗不明的局面，层出不穷的强大敌人、上古凶兽，你能否保持初心不断变强，一步步揭开导致天下大乱的真相，并成为天下第一的强者？\\\",\\\"id\\\":1237,\\\"game_source\\\":\\\"\\\",\\\"device_type\\\":2,\\\"edition\\\":1,\\\"pic_x', '{\"msg\":\"操作成功\",\"code\":200,\"data\":319}', 0, NULL, '2025-12-26 08:42:42', 79);
INSERT INTO `sys_oper_log` VALUES (1177, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1130\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1130\",\"category\":\"卡牌\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20250724/2e0614031d29ac70d56f42f30348de1a.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:42\",\"description\":\"魔幻风女神养成卡牌RPG手游《女神联盟2》震撼来袭！游戏根据《女神联盟》系列故事背景衍生全新剧情及人设，经典女神将以更唯美的形象重现，长达2万+的深度剧情刻画让游戏征程刺激而动人心弦。集结全球顶级画师打造游戏卓越画面表现，韩式写实风立绘令人惊艳。 魔幻感十足的场景尽现主机级游戏场景品质。原画柔和精致，3D效果逼真，更有动态场景带来生动酷炫的战场效果。\\r\\n\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1130\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://p1.277sy.com/2025/07/28/6887267f0dcc8.png\",\"id\":320,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1130\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-06-12 15:41:06\",\"name\":\"女神联盟2（0.05折版）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"唯有女神超越女神\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13479.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"卡牌\\\",\\\"addtime\\\":\\\"2025-06-12 15:41:06\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://p1.277sy.com/2025/07/28/6887267f0dcc8.png\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1130\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1130.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2g