INSERT INTO `sys_oper_log` VALUES (1183, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1238\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1238\",\"category\":\"角色扮演\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20250724/d3b17afa4da5e6b2ddc9f423ab5c12dc.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:42\",\"description\":\"《漂在江湖》是以江湖武侠为题材玄幻MMO手游，以顶尖的次世代技术打造最精致细腻的仙武侠大世界。这里拥有开放式全景大地图，百人组队开荒首杀，全图PK爆神装、自由交易，多重职业自由转职，全3D视角自由操作，360度自由轻功翱翔等玩法体验，均能让你沉浸式体验真实的江湖。跨服社交，炫酷特效，流光仙翼，旷世神兵，卓越坐骑，情缘修仙，盛世婚礼等等，无不体现着这个有血有肉的江湖\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1238\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20250724/1ac67bf7d7709cbf7bf65a8dc668d7d5.png\",\"id\":325,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1238\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-07-17 17:21:55\",\"name\":\"漂在江湖（0.1折剑指天下）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"无刀不江湖，经典武侠重磅回归！\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13600.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"角色扮演\\\",\\\"addtime\\\":\\\"2025-07-17 17:21:55\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20250724/1ac67bf7d7709cbf7bf65a8dc668d7d5.png\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1238\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1238.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1238\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1238\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1238\\\",\\\"gamename\\\":\\\"漂在江湖（0.1折剑指天下）\\\",\\\"excerpt\\\":\\\"《漂在江湖》是以江湖武侠为题材玄幻MMO手游，以顶尖的次世代技术打造最精致细腻的仙武侠大世界。这里拥有开放式全景大地图，百人组队开荒首杀，全图PK爆神装、自由交易，', '{\"msg\":\"操作成功\",\"code\":200,\"data\":325}', 0, NULL, '2025-12-26 08:42:43', 62);
