INSERT INTO `sys_oper_log` VALUES (1201, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1160\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1160\",\"category\":\"卡牌\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20250912/0f42ce6845d14560e1ed6497ee56e01f.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:42\",\"description\":\"《新斗罗大陆》是阅文游戏制作发行的手机游戏。该作由唐家三少原著正版改编，是动画《斗罗大陆》官方合作手游，正版授权，100%遵循原著，真实还原小说经典剧情和场景，代入感爆棚；\\r\\n游戏背景设定在一个名为斗罗大陆的武魂世界，玩家将跟随主角唐三，从十二岁入学史莱克学院开始，与小舞等伙伴一起经历层层考验，踏上魂师修炼之路。游戏特色包括正版授权的剧情还原、自由操控的战斗系统、超萌Q版画风和丰富的培养系统。玩家可以体验到冲锋、瞬间闪移、集火、残血斩杀等战斗激情，同时游戏还提供了副本系统、杀戮之都、斗魂场、猎魂森林等多种玩法。 \",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1160\",\"gameType\":\"bt\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20250630/56e4cda9d30fe2f9b668ec5e24887713.png\",\"id\":343,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1160\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-06-25 14:30:32\",\"name\":\"新斗罗大陆（GM免费版）\",\"params\":{},\"promotionDesc\":\"禁海外推广\",\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"官方正版授权合作手游\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13513.mp4\\\",\\\"text_cps\\\":\\\"禁海外推广\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"卡牌\\\",\\\"addtime\\\":\\\"2025-06-25 14:30:32\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:6\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:6\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20250630/56e4cda9d30fe2f9b668ec5e24887713.png\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1160\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1160.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1160\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1160\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1160\\\",\\\"gamename\\\":\\\"新斗罗大陆（GM免费版）\\\",\\\"excerpt\\', '{\"msg\":\"操作成功\",\"code\":200,\"data\":343}', 0, NULL, '2025-12-26 08:42:43', 64);
INSERT INTO `sys_oper_log` VALUES (1202, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1079\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1079\",\"category\":\"回合\",\"coverUrl\":\"https://www.u2game99.com/data/upload/game/20251225/694ce7aae938c.png\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:42\",\"description\":\"《少年三国志：零》是游族「少年三国志」系列全新力作。独创4x4布局，流派组合千变万化，兵将军师皆有可为。品质升级，龙魂觉醒，称霸九州战场！\\r\\n【4X4布阵，策略制胜】\\r\\n4×4布阵，独创颠覆性策略卡牌玩法！三国名将划至重、轻、步、盾、弓、谋六种职业，玩家可以根据兵种相克的特点自由部署，以奇制胜！\\r\\n【公平竞技，跨服争锋】\\r\\n全新赛季制玩法，豪华福利，多样副本等你探索！实时匹配，激烈对决一触即发！\\r\\n【军师控场，奇计百出】\\r\\n军师出战，神机妙算掌控全局！技能融合、威力叠加，实时决策、局势扭转，尽享即时战略快感！\\r\\n【猛将强兵，自由搭配】\\r\\n不同流派，豪华阵容，打造极富创意的战斗体系。小兵能逆袭，武将皆C位！快来pick你心目中的神将精兵！\",\"developer\":\"https://www.u2game99.com/data/upload/source/20250926/68d65bf42615b.jpg\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1079\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://www.u2game99.com/data/upload/game/20251202/692e81ef1d4f8.png\",\"id\":344,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1079\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-05-22 14:00:06\",\"name\":\"少年三国志：零（首款少三系0.1折） \",\"params\":{},\"promotionDesc\":\"禁海外推广\",\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"少年三国志系列首款0.1折\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13420.mp4\\\",\\\"text_cps\\\":\\\"禁海外推广\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"回合\\\",\\\"addtime\\\":\\\"2025-05-22 14:00:06\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://www.u2game99.com/data/upload/game/20251202/692e81ef1d4f8.png\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1079\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1079.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1079\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1', '{\"msg\":\"操作成功\",\"code\":200,\"data\":344}', 0, NULL, '2025-12-26 08:42:43', 52);
INSERT INTO `sys_oper_log` VALUES (1203, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1140\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1140\",\"category\":\"卡牌\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20250624/567e58c764c27fa50e2e83f5223b4a83.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:42\",\"description\":\"《龙神万相：神战》是由热血国漫《西行纪》正版授权改编而成的策略卡牌手游，你将成为西行小队中的一员，重启西行之路，游戏中设计了丰富的PVP和PVE玩法，如：跨越阴阳、巅峰竞技、龙神八部、修罗来袭、王者之战、跨越阴阳等，每个玩法别具趣味性和竞技感，满足玩家对西行路上的挑战和探索。一起重燃热血西行魂，这一次，不为苍生，只为自己！ \",\"deviceSupport\":\"android\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1140\",\"gameType\":\"official\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20250624/eac7a37e9400e4f8a10132f43765245f.png\",\"id\":345,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1140\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-06-17 17:16:47\",\"name\":\"龙神万相：神战\",\"params\":{},\"promotionDesc\":\"禁海外推广\",\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"真实还原热血西行之旅\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13490.mp4\\\",\\\"text_cps\\\":\\\"禁海外推广\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"卡牌\\\",\\\"addtime\\\":\\\"2025-06-17 17:16:47\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:0\\\",\\\"hw_cps_cpa\\\":\\\"CPS推广:15\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20250624/eac7a37e9400e4f8a10132f43765245f.png\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1140\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1140.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1140\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1140\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1140\\\",\\\"gamename\\\":\\\"龙神万相：神战\\\",\\\"excerpt\\\":\\\"《龙神万相：神战》是由热血国漫《西行纪》正版授权改编而成的策略卡牌手游，你将成为西行小队中的一员，重启西行之路，游戏中设计了丰富的PVP和PVE玩法，如：跨越阴阳、巅峰竞技、龙神八部、修罗来袭', '{\"msg\":\"操作成功\",\"code\":200,\"data\":345}', 0, NULL, '2025-12-26 08:42:43', 61);
INSERT INTO `sys_oper_log` VALUES (1204, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1007\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1007\",\"category\":\"卡牌\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20250731/9098f05168cde8cd6ea0bb06b00322f2.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:42\",\"description\":\"拯救小宇宙（0.1折鬼灭之刃）是一款改编自热门动漫《鬼灭之刃》的卡牌手游，高度还原的原著精彩剧情，是体验游戏玩法的特色之一，游戏人物和技能也都设计的十分精美，旨在给玩家营造一个身临其境的“鬼灭”环境。玩法上属于卡牌策略手游，下收集不同卡牌，组成最强阵容，根据敌属性制定正确战术，不断培养并强化卡牌能力，提高队伍实力。此外游戏内提供了多种社交玩法，加入公会，与其他玩家组队探索，挑战强敌；参加公会战，增进互动及提高游戏黏性。其次丰富的PvE与PvP玩法亦可满足不同玩家需求，可千万不要错过哟~ \\r\\n\\r\\n===【特色亮点】===\\r\\n1、高人气动漫IP转化：《拯救小宇宙》基于热门动漫《鬼灭之刃》改编而至，游戏里拥有相同的人物，故事和世界观，深受动漫迷的喜爱。\\r\\n2、卡牌策略游戏：玩家需要收集不同的卡牌来发展阵容和进行关卡 challenge。需要合理的阵容搭配和策略应用来决定战斗结果。\\r\\n3、放置养成元素：融入放置养成手游的玩法，玩家需要通过擂台等手段来获得资源，并利用这些资源来养成和强化卡牌，提高战斗力。\\r\\n4、多元化战斗角色：游戏中玩家可以扮演动漫人物如炭治郎，祢豆子，我妻善逸等，并选择不同属性的阵容如烈火，流水，风雷，血鬼来进行战斗。\\r\\n5、剧情关卡设计：游戏按动漫剧情设计了不同的副本关卡，玩家可以体验动漫中的剧情設定，边缘角色也在游戏中起到重要作用，增加玩家乐趣。\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1007\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://www.u2game99.com/data/upload/game/20250731/688ae5c325e2d.gif\",\"id\":349,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1007\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-04-28 11:50:30\",\"name\":\"拯救小宇宙（0.1折鬼灭之刃）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"0.1折高人气IP动漫鬼灭之刃\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13344.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"卡牌\\\",\\\"addtime\\\":\\\"2025-04-28 11:50:30\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://www.u2game99.com/data/upload/game/20250731/688ae5c325e2d.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1007\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1007.html\\\",\\\"webu', '{\"msg\":\"操作成功\",\"code\":200,\"data\":349}', 0, NULL, '2025-12-26 08:42:43', 53);
