":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1132\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1132\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1132\\\",\\\"gamename\\\":\\\"塔防召唤师(0.1折暴打策划)\\\",\\\"excerpt\\\":\\\"《塔防召唤师》是一款以著名三国历史时代中的故事、武将为题材搭配国漫国风画风制作，拥有极高品质的3D塔防卡牌融合游戏！策略丰富的塔防部署与超爽回合对战完美融合；以战区为单位，还有、军团、组队系统应有尽有，远交近攻，合纵连', '{\"msg\":\"操作成功\",\"code\":200,\"data\":347}', 0, NULL, '2025-12-26 08:42:43', 72);
INSERT INTO `sys_oper_log` VALUES (1207, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=997\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=997\",\"category\":\"角色扮演\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20250604/1949abe709a2c76b8c951374be0adca8.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:42\",\"description\":\"神州世界烽烟四起\\r\\n神秘人携其爪牙为祸四方\\r\\n救世主们\\r\\n唤醒被封印的侍从\\r\\n与神秘人抗争，拯救神州世界吧！\\r\\n\\r\\n《神州风闻录》作为一款以山海经为题材的策略放置卡牌，将致力于打造神话世界，与玩家们共同书写神话故事。\\r\\n\\r\\n- 超萌治愈，飒气十足\\r\\n不同于市面上千篇一律的大长腿，黑丝或萝莉，独特的画风带你领略山海异兽也有Q萌的一面。\\r\\n\\r\\n- 放置休闲，轻松娱乐\\r\\nPvE/PvP/GvG，可同时多线并行多个玩法，更有自动挂机保肝护肾！\\r\\n\\r\\n- 搭配至上，越战逆袭\\r\\n变换阵法及侍从站位，动动指尖实现越战逆袭，体验丰富策略纵深！\\r\\n\\r\\n- 活动丰富，挑战自我\\r\\n定期开放特色活动，即可轻松完成领取保底，也可向最高难度发起挑战，赢取最高荣耀！\",\"deviceSupport\":\"android\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=997\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://p1.277sy.com/2025/06/05/6841525716e18.png\",\"id\":348,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=997\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-04-25 13:47:26\",\"name\":\"神州风闻录（0.1免费版）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"结缘异兽来冒险！\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13333.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"角色扮演\\\",\\\"addtime\\\":\\\"2025-04-25 13:47:26\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://p1.277sy.com/2025/06/05/6841525716e18.png\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=997\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/997.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=997\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=997\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=997\\\",\\\"gamename\\\":\\\"神州风闻录（0.1免费版）\\\",\\\"excerpt\\', '{\"msg\":\"操作成功\",\"code\":200,\"data\":348}', 0, NULL, '2025-12-26 08:42:43', 57);
INSERT INTO `sys_oper_log` VALUES (1208, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1118\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1118\",\"category\":\"卡牌\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20250612/b6cdc6f9bf8567ac564a148bd7f805fe.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:42\",\"description\":\"《暗夜格斗》由鬼灭动漫改编，以最新形式策略卡牌手游。游戏内高度还原所有动漫角色及剧情玩法，沿着故事篇章探索，可收集到的大量动漫角色人物。通过剧情篇章内容，制作关联性独特玩法，使游戏内容更贴切原著。体验刺激的战斗、炫酷技能的表现、深度策略卡组搭配。\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1118\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://www.u2game99.com/data/upload/game/20250612/684a73c239d2d.gif\",\"id\":350,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1118\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-06-09 16:18:37\",\"name\":\"暗夜格斗（0.05折免费版）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"《暗夜格斗》是高人气鬼灭卡牌手游\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13468.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"卡牌\\\",\\\"addtime\\\":\\\"2025-06-09 16:18:37\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://www.u2game99.com/data/upload/game/20250612/684a73c239d2d.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1118\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1118.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1118\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1118\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1118\\\",\\\"gamename\\\":\\\"暗夜格斗（0.05折免费版）\\\",\\\"excerpt\\\":\\\"《暗夜格斗》由鬼灭动漫改编，以最新形式策略卡牌手游。游戏内高度还原所有动漫角色及剧情玩法，沿着故事篇章探索，可收集到的大量动漫角色人物。通过剧情篇章内容，制作关联性独特玩法，使游戏内容更贴切原著。体验刺激的战斗、炫酷技能的表现、深度策略卡组搭配。\\\",\\\"id\\\":1118,\\\"game_source\\\":\\\"\\\",\\\"device_type\\\":2,\\\"ed', '{\"msg\":\"操作成功\",\"code\":200,\"data\":350}', 0, NULL, '2025-12-26 08:42:43', 48);
INSERT INTO `sys_oper_log` VALUES (1209, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1105\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1105\",\"category\":\"卡牌\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20250610/d46e40157d2ececc054c5d752bf719cc.png\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:42\",\"description\":\"《战魂旅人》创新手办风打造航海新征途！全新玩法诠释剧情，视觉观赏效果提升，音效搭配战斗节奏，让每位船长都能用上钟爱的伙伴组成强大旅团，共同踏上一段充满挑战与奇遇的航海宝藏寻觅之路，将传奇书写在每一寸海域！\\r\\n\\r\\n----游戏特色----\\r\\n【浪尖传奇 动画体验】\\r\\n匠心打造3D超长主线新剧情，高质感立体角色，场景一比一还原！\\r\\n\\r\\n【豪华阵容 零损卡池】\\r\\n十大伙伴齐上阵，多种阵型搭配，无损换角，你喜爱的角色都能用！\\r\\n\\r\\n【全屏特效 热血启航】\\r\\n大制作定制角色性格打斗技能特效，指尖上演绎航海传说的奥义！\\r\\n\\r\\n【资源满舱 供应不停】\\r\\n登录享特权，签到福利常刷新，资源不停送，每次航海都满载而归！\\r\\n\\r\\n【社交互动 跨服竞技】\\r\\n分时段竞技场合理安排，跨服公会对决，新增家园社区，趣味互动！\\r\\n\\r\\n海浪翻涌，大海在呼唤各位勇者！伙伴的意志支撑起不灭的火种！燃烧吧！让神明见证，把船长的名字刻进传说！命运的齿轮转动了，属于各位船长的时代来临了！集结伙伴，扬起风帆，向着宝藏，全速前进！\",\"deviceSupport\":\"android\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1105\",\"gameType\":\"official\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20250610/173081c49d6c84de6fa94041ca2eac49.png\",\"id\":351,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1105\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-06-03 16:17:27\",\"name\":\"战魂旅人（新世界伟大航道）\",\"params\":{},\"promotionDesc\":\"禁海外推广\",\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"航海3D横板策略卡牌手游，成为航海王者！\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13455.mp4\\\",\\\"text_cps\\\":\\\"禁海外推广\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"卡牌\\\",\\\"addtime\\\":\\\"2025-06-03 16:17:27\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:0\\\",\\\"hw_cps_cpa\\\":\\\"CPS推广:35\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20250610/173081c49d6c84de6fa94041ca2eac49.png\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1105\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1105.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u', '{\"msg\":\"操作成功\",\"code\":200,\"data\":351}', 0, NULL, '2025-12-26 08:42:43', 47);
INSERT INTO `sys_oper_log` VALUES (1210, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1020\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1020\",\"category\":\"放置\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20250528/4badd212ae8525eb42c199250395d2fa.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:42\",\"description\":\"正版动画授权的3D放置卡牌手游《我叫 MT：归来》0.05 折版本重磅来袭！它完美再现动漫角色，让你与哀木涕、傻馒等经典形象再度相聚，带来纯正卡牌体验。玩家能组建五人小队勇闯艾泽大陆，这里上百种 BOSS、数十个大型副本，每日都有全新冒险涌现，时刻刺激着你的挑战欲。海量坐骑、宠物、神器散落各处，收集它们可大幅增强实力，助你在战斗中更胜一筹。战斗机制丰富多样，面对狂暴、复活等特色鲜明的 BOSS，需巧用 “集火”“控制” 策略应对，极其考验策略与操作。而且游戏充满欢乐氛围，在体验与动漫角色并肩作战的热血激情同时，还能尽享社交互动的无穷乐趣，快来加入《我叫 MT：归来》开启属于你的传奇冒险之旅吧！\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1020\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20250528/eef7567ccc4821b498538dffed676f29.gif\",\"id\":352,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1020\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-05-06 15:15:48\",\"name\":\"我叫MT：归来（保真0.05折福利版）\",\"params\":{},\"promotionDesc\":\"禁海外推广\",\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"保真0.05折福利版\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13360.mp4\\\",\\\"text_cps\\\":\\\"禁海外推广\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"放置\\\",\\\"addtime\\\":\\\"2025-05-06 15:15:48\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20250528/eef7567ccc4821b498538dffed676f29.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1020\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1020.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1020\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1020\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVB', '{\"msg\":\"操作成功\",\"code\":200,\"data\":352}', 0, NULL, '2025-12-26 08:42:43', 66);
INSERT INTO `sys_oper_log` VALUES (1211, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1107\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1107\",\"category\":\"策略\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20250611/0c79a957a9cad95de161c10584119fa1.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:42\",\"description\":\"生死行动是一款地牢式Roguelike+射击手游。 探索未知，射击敌人，成就你的射击传奇。解锁每一个城堡，拾取不同的武器和装备，战胜各式各样的敌人，解救城堡里的小人儿。每一次的选择，将会带来不一样的结果。丰富的元素，开启多样的结局...... 每个城堡中隐藏有很多的秘密，每个角色，每个NPC都有自己的故事，需要你有足够的耐心，才会看到里面的联结，发现需要收集的东西！ 快来开启你的发现之旅吧！\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1107\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20250611/a587ba60111e6d9228d938068495d849.gif\",\"id\":354,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1107\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-06-04 12:01:01\",\"name\":\"生死行动（0.05折荒野射击免费版）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"0.05折射击游戏，指尖休闲超爽竞技\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13457.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"策略\\\",\\\"addtime\\\":\\\"2025-06-04 12:01:01\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20250611/a587ba60111e6d9228d938068495d849.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1107\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game