om/down.html?ag=GMS123&gid=1078\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1078\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1078\\\",\\\"gamename\\\":\\\"仙剑奇侠传五（1折免费版）\\\",\\\"excerpt\\\":\\\"《仙剑奇侠传五》是一款角色扮演对的卡牌游戏。游戏以中国古代神话故事为背景，讲述了主角从平凡少年成长为能够拯救世界的英雄的故事。游戏不仅受到了广大玩家的喜爱，也在游戏史上留下了浓重的一笔。\\\",\\\"id\\\":1078,\\\"game_source\\\":\\\"\\\",\\\"device_type\\\":2,\\\"edition\\\":1,\\\"pic_xuanchuan\\\":\\\"', '{\"msg\":\"操作成功\",\"code\":200,\"data\":356}', 0, NULL, '2025-12-26 08:42:43', 61);
INSERT INTO `sys_oper_log` VALUES (1214, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1064\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1064\",\"category\":\"卡牌\",\"coverUrl\":\"https://www.u2game99.com/data/upload/game/20250630/6861eba32e1b7.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:42\",\"description\":\"《美食大乱斗》是一款以美食拟人化的高颜值手游，在游戏中玩家将会化身为命运之子，穿越到灵界大陆之中，通过招募并培养来自世界各地的食之精灵组件最强战队，突破重重险阻，探险神秘的灵界，寻找迷雾背后隐藏的真相。\\r\\n\\r\\n【吃货的美食江湖】\\t\\t\\r\\n各具地域特色的食之精灵，美食的每一个瞬间，无不是画师的精心绘制\\t\\t\\r\\n\\t\\t\\r\\n【美食之间的羁绊】\\t\\t\\r\\n不同的食物间既可是挚友，也能是死敌，不同的食物间碰撞出全新的美味\\t\\t\\r\\n\\t\\t\\r\\n【挂机即可来白嫖】\\t\\t\\r\\n只要每日坚持挂机即可白嫖各种免费资源，如果你能微氪会让你游戏更爽\\t\\t\\r\\n\\t\\t\\r\\n【收集各色美味】\\t\\t\\r\\n作为一个干饭人，还有什么能比收集到各种不同口味，不同特色的美食更有吸引力？\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1064\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://www.u2game99.com/data/upload/game/20250630/6861ec62862ad.gif\",\"id\":355,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1064\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-05-19 16:51:09\",\"name\":\"美食大乱斗（0.1折免费版）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"全场享0.1折，天天送6480代金劵\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13410.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"卡牌\\\",\\\"addtime\\\":\\\"2025-05-19 16:51:09\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://www.u2game99.com/data/upload/game/20250630/6861ec62862ad.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1064\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/1064.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1064\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1064\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=1064\\\",\\\"gamename', '{\"msg\":\"操作成功\",\"code\":200,\"data\":355}', 0, NULL, '2025-12-26 08:42:43', 70);
INSERT INTO `sys_oper_log` VALUES (1215, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1046\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1046\",\"category\":\"卡牌\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20250710/2836aa39be728bc73a2fefbbe9cc3679.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:42\",\"description\":\"《西游记之托塔天王》三界全员颜值在线，国风立绘令人眼前一亮，西游人物形象还原。玩家在完成西游取经的世界中冒险战斗，提升自己，打造神将队伍。每个玩家拥有属于自己的洞天福地，可以进行种植仙树。也可前往灵界试炼探索。休闲挂机玩法，玩家可以用过挂机、云游、灵界试炼放置玩法获取游戏资源来提升自己，养成神将。神将分解、重置可以返还养成资源，万象法阵玩法可以同步神将等级，减少了养成压力。新的西行即将开始，期待与仙友们共闯三界。\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1046\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20250710/c3c2223cddce0e5791a0a1d4c7fbceac.gif\",\"id\":357,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1046\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-05-13 16:33:48\",\"name\":\"西游记之托塔天王（0.05折天天送代金）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"宿命轮回，因果未了再西行。\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13388.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"卡牌\\\",\\\"addtime\\\":\\\"2025-05-13 16:33:48\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20250710/c3c2223cddce0e5791a0a1d4c7fbceac.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=1046\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://ww