\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=944\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=944\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=944\\\",\\\"gamename\\\":\\\"究极宝贝（0.1折超究破限）\\\",\\\"excerpt\\\":\\\"《究极宝贝（0.1折超究破限）》 是一款卡牌养成游戏，熟悉的主角带你回到童年重温经典剧情，收集心仪的数码兽，通过探险夺宝、冒险岛、资源工厂等特色玩法收集资源养成数码兽，最终合体进化，打败最大的反派，拯救数码大陆! \\\",\\\"id\\\":944,\\\"game_source\\\":\\\"\\\"', '{\"msg\":\"操作成功\",\"code\":200,\"data\":367}', 0, NULL, '2025-12-26 08:42:43', 46);
INSERT INTO `sys_oper_log` VALUES (1225, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=924\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=924\",\"category\":\"策略\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20250427/4af94f8b92510fa9b4a2b50b19d745db.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:42\",\"description\":\"《乱世逐鹿(0.1折权谋天下》是一款是三国时代为背景所打造的次世代策略手游，该游戏内世界观和关卡设定由著名作家打造，其游戏剧情完美还原了汉末和三国时代的风云变幻，即温酒斩华雄、火烧洛阳到后面的三分天下等壮阔场景，玩家可以参与其中，招募熟悉的历史人物，无论是风华绝代的貂蝉还是人中吕布的奉先，都可以收集起来并组成流派打法，游戏内采用即时制战斗玩法，需要玩家时刻把控局势的变化，操作你手下的士兵取得一场场战斗的胜利，且还得需要注意关卡的层层设定，你需要灵活运用武将的特性来进行挑战。让我们一起亲历群雄逐鹿中原，成就一方霸主！\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=924\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://p1.277sy.com/2025/04/25/680b5ce3003a9.gif\",\"id\":366,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=924\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-04-10 14:59:09\",\"name\":\"乱世逐鹿（0.1折权谋天下）\",\"params\":{},\"promotionDesc\":\"禁海外推广\",\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"三国时代背景次世代策略手游\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13248.mp4\\\",\\\"text_cps\\\":\\\"禁海外推广\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"策略\\\",\\\"addtime\\\":\\\"2025-04-10 14:59:09\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://p1.277sy.com/2025/04/25/680b5ce3003a9.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=924\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/924.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=924\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=924\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=924\\\",\\\"gamename\\\":\\\"乱世逐鹿（0.1折权谋天下）\\\",\\\"excerpt\\\":\\\"《乱世逐鹿(0.1折权谋天下》是一款是三国时代为背景所打造的次世代策略手游，该游戏内世界观和关卡设定由著名作家打造，其游戏剧情完美', '{\"msg\":\"操作成功\",\"code\":200,\"data\":366}', 0, NULL, '2025-12-26 08:42:43', 58);
INSERT INTO `sys_oper_log` VALUES (1226, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=882\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=882\",\"category\":\"卡牌\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20250627/be28cbbc0d8fbeb1a0622ae99a759e70.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:42\",\"description\":\"新版本，新龙珠，天天648代金券畅游整个宇宙。为了保卫地球免遭毁坏，孙悟空和伙伴一起，不断修行并打败入侵者。悟空、库林、贝吉塔等全龙珠人气角色大集结，集结宇宙最强战士，组建个人专属战队与最爱角色一起修炼成长，共同守卫地球。\\r\\n\\r\\n玩家可通过角色召唤，或者收集角色碎片合成等方法，可以获得各种角色。玩家可以在布阵里，设置前后两排任意5名角色出战，前排两名近战角色，后排三名远程角色。角色有攻、技、防3种类型，这3种类型的角色或怪物之间，有克制关系，攻克制技，技克制防，防克制攻。玩家作战过程中，可以根据攻、技、防类型，合理搭配角色，提高战斗力。\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=882\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://www.u2game99.com/data/upload/game/20250627/685e630ccadf6.gif\",\"id\":368,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=882\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-03-31 13:41:53\",\"name\":\"迷失星球（0.1折·送超四悟空）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"天天648无门槛可拆分不限时代金券\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13198.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"卡牌\\\",\\\"addtime\\\":\\\"2025-03-31 13:41:53\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://www.u2game99.com/data/upload/game/20250627/685e630ccadf6.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=882\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/882.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=882\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=882\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=882\\\",\\\"gamename\\\":\\\"迷失星球（0.1折·送超四悟空）\\\",\\\"excerpt\\\":\\\"新版本，新龙珠，天天648代金券畅游整个宇宙。为了保卫地球免遭毁坏', '{\"msg\":\"操作成功\",\"code\":200,\"data\":368}', 0, NULL, '2025-12-26 08:42:43', 56);
