INSERT INTO `sys_oper_log` VALUES (1229, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=688\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=688\",\"category\":\"挂机\",\"coverUrl\":\"https://www.u2game99.com/data/upload/game/20250711/68708538e65b2.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:42\",\"description\":\"《深渊契约》是一款魔幻冒险挂机手游。故事发生在遥远而神秘的舞刃大陆，因受到外来邪恶势力的入侵，整个大陆支离破碎，为了保护最后的净土-光熙城邦，你将化身为一名天赋异禀的英雄战士，深入深渊领域，一路过关斩将、披荆斩棘，解锁海量装备技能，挑战深渊跨服Boss，更有多人副本、公会争霸、秘境寻宝、转职觉醒、战宠养成等海量特色玩法。亲爱的勇士，属于你的冒险之旅即将开启，快来挑战吧\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=688\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://www.u2game99.com/data/upload/game/20250711/68708529f154e.gif\",\"id\":371,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=688\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-02-14 14:33:09\",\"name\":\"深渊契约（0.1折送天空套）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"0.1折魔幻冒险挂机手游\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/12979.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"挂机\\\",\\\"addtime\\\":\\\"2025-02-14 14:33:09\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://www.u2game99.com/data/upload/game/20250711/68708529f154e.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=688\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/688.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\