INSERT INTO `sys_oper_log` VALUES (1230, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=921\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=921\",\"category\":\"卡牌\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20250410/ff511d19abaf2da552b4a57b421ee2da.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:42\",\"description\":\"我们基于经典动漫《海贼王》为背景，致力于精准还原经典剧情，旨在为玩家提供身临其境的沉浸式体验。在游戏中，身为船长，你将肩负重大使命，招募志同道合的伙伴，共同开启那段伟大的冒险之旅。本游戏在玩法上力求丰富多样，战斗特效与技能动作皆以动漫原著为基准进行精细还原。旅途中，你将面临诸多挑战与困难，但正是这些挑战，才能磨砺你的意志，锻炼你的能力，最终使你战胜一切，赢得那份属于你的宝藏。\\r\\n\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=921\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://www.u2game99.com/data/upload/game/20250410/67f78ab472154.png\",\"id\":372,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=921\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-04-09 17:33:35\",\"name\":\"超神觉醒（0.1折新世界冒险）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"《超神觉醒》是超高人气海贼王卡牌手游\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13245.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"卡牌\\\",\\\"addtime\\\":\\\"2025-04-09 17:33:35\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://www.u2game99.com/data/upload/game/20250410/67f78ab472154.png\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=921\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/921.html\\\",\\\"weburl_qr\\\":