INSERT INTO `sys_oper_log` VALUES (1232, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=916\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=916\",\"category\":\"角色扮演\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20250409/4959051345f72d306a0828ab3a0fd9ac.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:42\",\"description\":\"《神州豪侠》游戏是一款修真主题风格人物角色游戏，让玩家感受到3D精致的修真情景，游戏中玩家必须寻找武器的所属，多种多样岗位可随意觉醒，近身武器远程控制各有千秋，心爱岗位随你饰演。游戏还有着极其丰富多彩的游戏玩法，组队对战、修罗战场、排位赛比赛、销售市场摆地摊、跟踪仇敌这些，造就你的冠军之路。依靠传说故事的能量进行灭魔斩妖的重担，在这儿体会修真世界的精致历险。精美的人物建模与真实的自然环境层次感，匹敌电脑网游级次世代游戏界面。\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=916\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20250409/7f224c51be2c3c80b4eae1fb4b5634a9.gif\",\"id\":373,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=916\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-04-09 13:46:39\",\"name\":\"神州豪侠（0.05折千元代金福利版）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"每日免费领1000代金券\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13239.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"角色扮演\\\",\\\"addtime\\\":\\\"2025-04-09 13:46:39\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20250409/7f224c51be2c3c80b4eae1fb4b5634a9.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=916\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://