INSERT INTO `sys_oper_log` VALUES (1234, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=501\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=501\",\"category\":\"角色扮演\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20251218/14c32f5badd8b6a834a51c36ddf999aa.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:42\",\"description\":\"【2025年度巨献】3D仙侠手游巅峰之作《天堂魔狱》震撼登场！踏入绝美仙境，启程主线奇缘，由顶尖引擎精心雕琢的仙侠世界全面展开。无界大地图，随心瞬移，每一处细腻场景等你来自由探索。五大职业，各具特色，任你挑选，开启专属修仙之旅。即时战斗，热血江湖，恩怨情仇即刻上演！历经磨砺，等级飙升，转生飞仙，攀登魔狱之巅，成就无上荣耀。真实社交，精准匹配，修仙路上不再孤单。《天堂魔狱》独创情缘系统，助你邂逅命中注定的另一半，共建梦幻家园，双修共进，修为提升快人一步！此刻，仙侠之旅已为你铺展，你，准备好了吗？《天堂魔狱》，等你来战！\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=501\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20251218/26c43e5d451a911a3436f45432f54531.png\",\"id\":376,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=501\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2024-12-25 17:12:06\",\"name\":\"天堂魔狱（0.05折百倍爆率千金版）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"全场尊享0.05折，解锁百倍爆率，获千元通票！\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/12786.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"角色扮演\\\",\\\"addtime\\\":\\\"2024-12-25 17:12:06\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20251218/26c43e5d451a911a3436f45432f54531.png\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=501\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/501.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=501\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=501\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=501\\\",\\\"gamename\\\":\\\"天堂魔狱（0.05折百倍爆率千金版）\\\",\\\"excerpt\\\"', '{\"msg\":\"操作成功\",\"code\":200,\"data\":376}', 0, NULL, '2025-12-26 08:42:43', 61);
INSERT INTO `sys_oper_log` VALUES (1235, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=812\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=812\",\"category\":\"角色扮演\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20250326/8c5cc9db1343b32c239e79159919c819.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:42\",\"description\":\"《武林争霸》是一款模拟当官类手游，玩家穿越回大清，寒窗苦读，金榜题名；游戏中编写了大量当官破案剧情，让玩家沉浸到断案的游戏中。\\r\\n游戏着重于玩法与剧情的相结合，让玩家回到古香古色的清廷世界。告别枯燥乏味的刷怪升级，抛弃模式单一的经营玩法，为玩家缔造了一出高潮迭起、剧情跌宕起伏的故事。\\r\\n游戏中还融入了古风精致场景设计，华丽服装随心切换，官场对决指尖厮杀，全服激斗战斗到底，联姻拉拢官场势力，在大清执掌朝纲。断案追凶声名鹊起，妻妾相伴逍遥自在，多角度呈现官场如鱼得水的快乐生活；体会古色古香的清廷世界，感受一段逍遥的当官生活。\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=812\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20250326/427052a092cb58f6ce30293c93a80fd0.gif\",\"id\":377,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=812\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-03-12 17:33:43\",\"name\":\"武林争霸（0.1折九品芝麻官）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"智斗官场，权谋天下\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13120.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"角色扮演\\\",\\\"addtime\\\":\\\"2025-03-12 17:33:43\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20250326/427052a092cb58f6ce30293c93a80fd0.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=812\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/812.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=812\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=812\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=812\\\",\\\"gamename\\\":\\\"武林争霸（0.1折九品芝麻官）\\\",\\\"excerpt\\\":\\\"《武林争霸》是一款模拟', '{\"msg\":\"操作成功\",\"code\":200,\"data\":377}', 0, NULL, '2025-12-26 08:42:43', 73);
INSERT INTO `sys_oper_log` VALUES (1236, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=839\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=839\",\"category\":\"放置\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20250326/2e6cf6182fe625470f87619fa6eba40f.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:42\",\"description\":\"《公元（魔法波特内置0.1折）》是一款充满魔法与冒险的手游游戏，玩家将踏上一段充满挑战和神秘的旅程。在这个充满魔法的世界中，玩家将扮演一名年轻的魔法学徒，开启一场前所未有的魔幻冒险之旅。\\r\\n\\r\\n玩家将穿越神秘的森林、古老的城市废墟和神秘的魔法学院，面对各种魔法生物和邪恶势力的挑战。在这里，点亮神秘魔晶球是冒险的开端。魔晶球散发的光芒不仅照亮前行的路，更能激发强大的魔法力量，帮助你在探索中披荆斩棘。\\r\\n\\r\\n在游戏中，玩家需要学习各种强大的魔法技能，与拥有特殊能力的伙伴同行，解开古老魔法的秘密，与黑暗势力对抗，并最终成长为屹立在整片大陆上的传奇人物。\\r\\n\\r\\n游戏中充满了各种挑战和隐藏的宝藏，玩家需要通过点亮魔晶球和战斗来不断提升自己的魔法能力。同时，玩家还可以与其他玩家组成公会，共同探索世界、挑战强大的魔法生物和参加激烈的公会战。\\r\\n\\r\\n《公元（魔法波特内置0.1折）》以其精美的画面、丰富的剧情和刺激的游戏玩法，为玩家打造了一个充满魔法与冒险的奇幻世界，让玩家沉浸其中，体验无尽的乐趣与刺激。\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=839\",\"gameType\":\"bt\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20250326/407fe2942e0f11b31e86e720eeeaef33.png\",\"id\":378,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=839\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-03-18 15:38:16\",\"name\":\"公元（魔法波特内置0.1折）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"玩家将扮演一名年轻的魔法学徒，开启一场前所未有的魔幻冒险之旅\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13150.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"放置\\\",\\\"addtime\\\":\\\"2025-03-18 15:38:16\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:65\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:45\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20250326/407fe2942e0f11b31e86e720eeeaef33.png\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=839\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/839.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=839\\\",\\\"do', '{\"msg\":\"操作成功\",\"code\":200,\"data\":378}', 0, NULL, '2025-12-26 08:42:43', 66);
INSERT INTO `sys_oper_log` VALUES (1237, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=751\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=751\",\"category\":\"卡牌\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20250325/3bacf77a24f12977053688c0bc5973d1.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:42\",\"description\":\"高颜值放置少女《战火使命》融合多种创新玩法，重构末世剧情，与少女一起拯救世界；多种阵营流派，构建你的专属队伍；佛系放置养成，随玩随停不掉队；更有超多福利等你领取，不同阵营少女任你挑选择。\\r\\n\\r\\n\\r\\n【精美动态立绘，百变人设丰富养成】\\r\\n60+高颜值机甲美少女，拥有多款可交互的动态立绘、皮肤时装可供更换，汇集众多专业声优，萝莉、御姐、少女等风格迥异的小姐姐，让你享受视觉和听觉的双重盛宴~\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=751\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://www.u2game99.com/data/upload/game/20251029/6901d649a3473.gif\",\"id\":379,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=751\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-02-27 14:08:20\",\"name\":\"战火使命（0.1折送可触碰战姬）\",\"params\":{},\"promotionDesc\":\"禁海外推广\",\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"登录送无限抽，每日登录至少领取十连抽\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/13050.mp4\\\",\\\"text_cps\\\":\\\"禁海外推广\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"卡牌\\\",\\\"addtime\\\":\\\"2025-02-27 14:08:20\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://www.u2game99.com/data/upload/game/20251029/6901d649a3473.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=751\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/751.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=751\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=751\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=751\\\",\\\"gamename\\\":\\\"战火使命（0.1折送可触碰战姬）\\\",\\\"excerpt\\\":\\\"高颜值放置少女《战火使命》融合多种创新玩法，重构末世剧情，与少女一起拯救世界；多种阵营流派，构建你的专属队伍；佛系放置养成，随玩随停不掉队；更有超多福利', '{\"msg\":\"操作成功\",\"code\":200,\"data\":379}', 0, NULL, '2025-12-26 08:42:43', 52);
