INSERT INTO `sys_oper_log` VALUES (1256, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=550\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=550\",\"category\":\"卡牌\",\"coverUrl\":\"https://p1.277sy.com/2025/01/16/67887155e07af.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:42\",\"description\":\"《敢达决战》为中国大陆首款授权敢达题材手游，由株式会社万代南梦宫娱乐与DeNA中国合力打造。《机动战士敢达》《机动战士Z敢达》《机动战士敢达SEED》《机动战士敢达UC》等经典人气作品悉数登场。历代敢达机体机师大集结，武器数据中心、联合作战、机师挑战，多种策略玩法，高度还原一个真实而经典的敢达世界。每一台主战机体都有独特动作和酷炫大招，配合专属队长技合体技，弹指间逆转战场形势。升级进阶，机师培养，打造专属于你的机动战士部队。\",\"deviceSupport\":\"android\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=550\",\"gameType\":\"official\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://www.u2game99.com/data/upload/game/20251125/69256da703e5e.png\",\"id\":398,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=550\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-01-03 16:54:14\",\"name\":\"敢达决战\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"升级进阶，机师培养，打造专属于你的机动战士部队。\\\",\\\"interchangeable_role\\\":0,\\\"video\\\":\\\"https://mp4.277sy.com/sp/12838.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"卡牌\\\",\\\"addtime\\\":\\\"2025-01-03 16:54:14\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:6\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:6\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://www.u2game99.com/data/upload/game/20251125/69256da703e5e.png\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=550\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/550.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\