INSERT INTO `sys_oper_log` VALUES (1257, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=544\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=544\",\"category\":\"卡牌\",\"coverUrl\":\"https://www.u2game99.com/data/upload/game/20251111/6912e680e9901.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:42\",\"description\":\"西游风华，少年无双\\r\\n5亿玩家期待的西游卡牌王者《少年西游记》，携豪华全免升级福利登场：送天金毕业阵容，每日领千元免单券；玩就送5+5满星神将法宝；返利商城，0.1折买到爽；全新内部指令，游戏数据改改改，福利刷刷刷；登录即送主角直升紫金材料包，更有GM刷充特权助你征战西游世界；开局豪送神龙蛋，吞噬碎片连续进化；全民冲级，狂送10万真充卡，0氪直接起飞；送自动推图，解放双手一键托管，内置加速器，8倍助力加速，单手轻松操作，爽快通关激斗，酷炫法宝合击，唯美清新画风，海量福利不容错过，焰金品质神将陆续登场中…热血福利带你畅游三界轻松无压力！\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=544\",\"gameType\":\"official\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://www.u2game99.com/data/upload/game/20250804/68902484caf45.gif\",\"id\":399,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=544\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2025-01-03 16:27:46\",\"name\":\"少年西游记（天金免费版）\",\"params\":{},\"promotionDesc\":\"禁海外推广\",\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"送天金阵容  每日千元免单\\\",\\\"interchangeable_role\\\":0,\\\"video\\\":\\\"https://mp4.277sy.com/sp/12834.mp4\\\",\\\"text_cps\\\":\\\"禁海外推广\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"卡牌\\\",\\\"addtime\\\":\\\"2025-01-03 16:27:46\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:6\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:6\\\",\\\"coupon_repeat\\\":\\\"可重复领取\\\",\\\"pic1\\\":\\\"https://www.u2game99.com/data/upload/game/20250804/68902484caf45.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=544\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/544.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=544\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=544\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=544\\\",\\\"gamename\\\":\\\"少年西游记（天金免费版）\\\",\\\"excerpt\\\":\\\"西游风华，少年无双\\\\r\\\\n5亿玩家期待的西游卡牌王者《少年西游记', '{\"msg\":\"操作成功\",\"code\":200,\"data\":399}', 0, NULL, '2025-12-26 08:42:43', 59);
INSERT INTO `sys_oper_log` VALUES (1258, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=533\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=533\",\"category\":\"卡牌\",\"coverUrl\":\"https://p1.277sy.com/2025/01/13/6784dfd0146d1.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:42\",\"description\":\"《魂色》是一款鬼灭3D横板即时战斗卡牌游戏。在这款游戏中，你将邂逅一系列耳熟能详的动漫角色。通过不同的抽卡形式，你将收集到心仪的人物，与你并肩作战。共同开启一段充满挑战与惊喜的冒险旅程。你将带领众多鬼杀队员，踏上一段充满未知与挑战的探索之旅。\\t\",\"deviceSupport\":\"android\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=533\",\"gameType\":\"official\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20250111/6016c0866815d76babf30ff474eba78e.png\",\"id\":400,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=533\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2024-12-31 15:05:50\",\"name\":\"魂色（决战无限城）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"鬼灭3D横板即时战斗卡牌游戏\\\",\\\"interchangeable_role\\\":0,\\\"video\\\":\\\"https://mp4.277sy.com/sp/12822.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"卡牌\\\",\\\"addtime\\\":\\\"2024-12-31 15:05:50\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:40\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:20\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20250111/6016c0866815d76babf30ff474eba78e.png\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=533\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/533.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=533\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=533\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=533\\\",\\\"gamename\\\":\\\"魂色（决战无限城）\\\",\\\"excerpt\\\":\\\"《魂色》是一款鬼灭3D横板即时战斗卡牌游戏。在这款游戏中，你将邂逅一系列耳熟能详的动漫角色。通过不同的抽卡形式，你将收集到心仪的人物，与你并肩作战。共同开启一段充满挑战与惊喜的冒险旅程。你将带领众多鬼杀队员，踏上一段充满未知与挑战的探索之旅。\\\\t\\\",\\\"id\\\":533,\\\"game_source\\\":\\\"\\\",\\\"device_type\\\":0,\\\"edition\\\":0,\\\"pic_xua', '{\"msg\":\"操作成功\",\"code\":200,\"data\":400}', 0, NULL, '2025-12-26 08:42:43', 57);
INSERT INTO `sys_oper_log` VALUES (1259, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=529\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=529\",\"category\":\"卡牌\",\"coverUrl\":\"https://p1.277sy.com/2025/01/06/677b7aefee912.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:42\",\"description\":\"幻想异世界，养成自走棋，高颜值卡牌《幻想神话志》与大家见面啦！\\r\\n\\r\\n【养成自走棋，高能双羁绊】\\r\\n四大职业：战士、法师、射手、刺客\\r\\n七大种族：人族、灵族、妖族、鬼族、仙族、神族、魔族\\r\\n自走棋模式的双重羁绊设定，阵容与布阵决定一切！而且英雄的种族并非唯一，[人仙]两族的姜子牙、[神妖]两族的哪吒、[魔鬼]两族的共工、[妖仙]两族的猪八戒...阵容更加多变，善于布阵就有无限的可能！\\r\\n\\r\\n【全视频立绘，轻科技国风】\\r\\n独特的科技中国风+全英雄动态视频=不一样的视觉享受！突破传统国风的束缚，轻科技与神话异世界的完美结合，带来全新的体验！全英雄动态视频展现是我们不拘一格的态度，只为呈现一个绮丽的三界。\\r\\n\\r\\n【真一键升级，真轻松游戏】\\r\\n所有英雄等级共享，真正的一键升级，不需要繁琐得回退资源，加上自动爬塔、后台推图，轻松护肝，享受游戏！\\r\\n\\r\\n【跨服竞技场，押注神魔抽】\\r\\n[仙道大会]每周一开启，自由报名，选择一个合适的分组可能有惊喜哦！冠军赛阶段开启押注模式，甚至能押神魔抽卡券，各位预测达人们大显身手的时候到了！\\r\\n\\r\\n【探索大世界，装备自己造】\\r\\n英雄达到100级之后，神话大世界开启！多人同屏，自由探索，搜集材料，打造游戏中提升大量属性的团队装备[灵宝]，上百个不同的随机词条让你的灵宝绝对独一无二！\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=529\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20250107/ca74adbef94a1feac40aa43b268c2d26.png\",\"id\":401,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=529\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2024-12-30 16:05:17\",\"name\":\"幻想神话志（0.1折免费版）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"幻想异世界，养成自走棋\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/12815.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"卡牌\\\",\\\"addtime\\\":\\\"2024-12-30 16:05:17\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20250107/ca74adbef94a1feac40aa43b268c2d26.png\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=529\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/529.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\', '{\"msg\":\"操作成功\",\"code\":200,\"data\":401}', 0, NULL, '2025-12-26 08:42:43', 58);
