\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=506\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=506\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=506\\\",\\\"gamename\\\":\\\"全城警戒（0.1折极速版）\\\",\\\"excerpt\\\":\\\"《全城警戒》是一款以策略、战争、军事为题材的战争策略手游。\\\\r\\\\n游戏采用独特的3D建模2D渲染技术，使画面更加精细、逼真，立体感更强，技术支持更全面，功能更完善，制作更精美！采用策略战斗，6个位置4种兵种巧妙搭配，多种战斗场景，体验不同地形和战役的趣味！\\\",\\\"id\\\":506,\\\"game_so', '{\"msg\":\"操作成功\",\"code\":200,\"data\":404}', 0, NULL, '2025-12-26 08:42:43', 64);
INSERT INTO `sys_oper_log` VALUES (1266, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=460\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=460\",\"category\":\"角色扮演\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:43\",\"description\":\"千人同屏，激情国战——首次在MMO游戏中引入大陆漂移合纵、跨服国家结盟、国战赛季等全新玩法。同时全职业可自由转职，通过技能与天赋的自由搭配，给玩家带来多种成长选择，游戏体验重磅升级。\\r\\n同时在全新渲染技术，加入实时拟真天气变幻，呈现出真实细腻而恢弘壮阔的国战世界，带来君临天下的沉浸感受。玩国战，就玩《远征2》，击败强国大一统，书写属于你的王者篇章！\",\"deviceSupport\":\"android\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=460\",\"gameType\":\"official\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://p1.277sy.com/2024/12/16/675ff3ec8c7fa.png\",\"id\":409,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=460\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2024-12-16 15:44:34\",\"name\":\"远征2\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"经典国战还原，让你肾上腺素飙升，战个痛快\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/12740.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"角色扮演\\\",\\\"addtime\\\":\\\"2024-12-16 15:44:34\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:55\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:35\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://p1.277sy.com/2024/12/16/675ff3ec8c7fa.png\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=460\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/460.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=460\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=460\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=460\\\",\\\"gamename\\\":\\\"远征2\\\",\\\"excerpt\\\":\\\"千人同屏，激情国战——首次在MMO游戏中引入大陆漂移合纵、跨服国家结盟、国战赛季等全新玩法。同时全职业可自由转职，通过技能与天赋的自由搭配，给玩家带来多种成长选择，游戏体验重磅升级。\\\\r\\\\n同时在全新渲染技术，加入实时拟真天气变幻，呈现出真实细腻而恢弘壮阔的国战世界，带来君临天下的沉浸感受。玩国战，就玩《远征2》，击败强国大一统，书写属于你的王者篇章！\\\",\\\"id\\\":460,\\\"game_source\\\":\\\"\\\",\\\"device_type\\\":0,\\\"edition\\\":0,\\\"pic_xuanchuan\\\":\\\"\\\",\\\"strict\\\":0,\\\"u', '{\"msg\":\"操作成功\",\"code\":200,\"data\":409}', 0, NULL, '2025-12-26 08:42:43', 43);
INSERT INTO `sys_oper_log` VALUES (1267, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=449\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=449\",\"category\":\"经营\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20241218/021a8524094383d7d7461be0e0a392e6.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:43\",\"description\":\"《魔法战线》是一款集模拟经营、放置卡牌、开箱子及多种消消乐于一体的Q版手游0.1版本全民爽玩，开局就送神将孙悟空，每日再送100连抽和100把钥匙，豪华阵容任你搭配，开箱开到爽！\\r\\n三国、西游、封神等众多经典角色共同登场，爆笑超无厘头剧情，故事从一只猪妖讲起，不知从何而来，竟要抢夺三界食谱......你将从摆摊开始，收购酒楼、靠积累资源把酒楼做大做强，吸引更多客人从客人描述的故事获取美食线索，在冒险过程中获取食材和食谱，开发更多名菜，吸引奇人异士并和他们一起闯荡这个江湖！\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=449\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20241218/760966dedc5c8040f332d8c45a01f51d.gif\",\"id\":407,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=449\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2024-12-12 14:39:07\",\"name\":\"魔法战线（0.1折趣味卡牌无限抽）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"全新0.1折趣味卡牌，每日领取100连抽和100把钥匙，无限招募无限开箱！\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/12727.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"经营\\\",\\\"addtime\\\":\\\"2024-12-12 14:39:07\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20241218/760966dedc5c8040f332d8c45a01f51d.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=449\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/449.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=449\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=449\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=449\\\",\\\"gamename\\\":\\\"魔法战线（0.1折趣味卡牌无限抽）\\\",\\\"excerpt\\\":\\\"《魔法战线》是一款集', '{\"msg\":\"操作成功\",\"code\":200,\"data\":407}', 0, NULL, '2025-12-26 08:42:43', 50);
INSERT INTO `sys_oper_log` VALUES (1268, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=367\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=367\",\"category\":\"回合\",\"coverUrl\":\"https://cp.u2game99.com/storage/operator/20241127/4c1fcb18db1e634be3ca7b46f7796f68.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:43\",\"description\":\"游戏介绍：这是一款把各种福利拉满的末世科幻风卡牌，一款你从未体验过的二次元卡牌。上线即送VIP8，登陆即送万抽、648奖励；0.05折即可轻松养成神魔。无限资源包来袭，一次购买天天领取，还有MAX版的外挂特权每天享受双倍无限资源！只要升级变强立送特殊阵营卡、经验、光暗卡，0氪也能轻松毕业。上线送自选呼叫大礼包，想抽哪个池就抽哪个池！统统永久，月卡特权一次购买终身享受！来自旺德兰星全人类联盟的要员啊，超次元计划要启动了，与我一起踏上征途吧！\\r\\n\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=367\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://cp.u2game99.com/storage/operator/20241127/075691383dd6890cc1701db15ea94971.gif\",\"id\":410,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=367\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2024-11-21 16:23:39\",\"name\":\"超次元女神（0.05折送648无限抽）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"永久0.05折 二次元放置卡牌\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/12637.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"回合\\\",\\\"addtime\\\":\\\"2024-11-21 16:23:39\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://cp.u2game99.com/storage/operator/20241127/075691383dd6890cc1701db15ea94971.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=367\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\"