INSERT INTO `sys_oper_log` VALUES (1269, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=11\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=11\",\"category\":\"三国\",\"coverUrl\":\"https://www.u2game99.com/data/upload/game/20250625/685ba511662a8.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:43\",\"description\":\"【延续经典 双倍经验乐翻天】\\r\\n新区“鹊桥相会”将延续经典,开区即享双倍经验活动在新服展开,让广大英雄做任务、打怪升级腾云驾雾一般！瞬间成为一代名将,做你的“牛人”,让别人瞻仰去吧！\\r\\n\\r\\n【开放新服 升级送新手礼包】\\r\\n新区新手玩家注册上线之后,将获得三国为新手玩家准备了丰厚的新手礼包,其囊括了双倍经验符、坐骑经验双倍符、坐骑口粮、还魂香包,通过奖励保送玩家70级,玩家将在短时间内完成华丽的蜕变！\\r\\n\\r\\n【开放新服 战功雨好礼不断】\\r\\n新区开放后,大汉朝廷将犒赏众将！每日12点-13点及19点-20点期间,只要英雄身处中立地区即可获得海量战功,更有雪岩白虎砸到你哦!惊喜不断不容错过!\\r\\n\\r\\n【新手福利 你冲VIP我买单】\\r\\n新手福利第一波,你冲VIP我买单,VIP等级满足活动要求的新用户,可在活动结束后获得该VIP等级所需元宝100%的返利，最高可享返利20万绑元，每个账号下仅限1个角色参与！\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=11\",\"gameType\":\"official\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://www.u2game99.com/data/upload/game/20250625/685ba464044c2.png\",\"id\":411,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=11\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2024-09-27 10:03:00\",\"name\":\"明珠三国\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"延续JAVA时代经典的MMORPG手游\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/1576.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"三国\\\",\\\"addtime\\\":\\\"2024-09-27 10:03:00\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:12\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:0\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://www.u2game99.com/data/upload/game/20250625/685ba464044c2.png\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=11\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/11.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=11\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=11\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.', '{\"msg\":\"操作成功\",\"code\":200,\"data\":411}', 0, NULL, '2025-12-26 08:42:43', 53);
