.u2game99.com/down.html?mash=TbZIVBOR&gid=16\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=16\\\",\\\"gamename\\\":\\\"御剑红尘（0.1折每日送648）\\\",\\\"excerpt\\\":\\\"《御剑红尘》手游由经典端游IP改编，将休闲社交体系融入经典回合玩法。帮派互助、结婚系统、温馨家园，打造多元社交体系；跨服组队、智能战斗、离线经验，解放双手，享受互动乐趣；一起御剑江湖，红尘作伴。\\\",\\\"id\\\":16,\\\"game_source\\\":\\\"\\\",\\\"device_type\\\":2,\\\"edition\\\":1,\\\"pic_xuanchuan\\\":\\\"\\\",\\\"strict\\\":0,\\\"userfc\\\":1,\\\"updatetime\\\":\\\"2024-09-30 00:00:00', '{\"msg\":\"操作成功\",\"code\":200,\"data\":423}', 0, NULL, '2025-12-26 08:42:44', 63);
INSERT INTO `sys_oper_log` VALUES (1281, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=13\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=13\",\"category\":\"卡牌\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:43\",\"description\":\"《女神危机》是一款融合卡牌、养成、互动，以解救小姐姐为主题的潮酷手游！优美立绘，真实互动、福利声优、精美时装！高度还原立绘的Live2D互动和战斗，杜绝一动起来就变“大头娃娃”的尴尬！故事以幻想都市为背景，讲述被召唤进次元世界的男主在这座城市面临堕落的危机边缘，摧毁维兰德公司的阴谋计划，拯救被害异能少女的奇幻之旅。原罪初醒，女神降临，你会是那个天命之子么?\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=13\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://p1.277sy.com/2024/11/18/673b03847dad3.gif\",\"id\":424,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=13\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2024-09-30 15:16:41\",\"name\":\"女神危机(0.1折原味女神)\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"都市二次元，等你来攻略女神\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/11916.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"卡牌\\\",\\\"addtime\\\":\\\"2024-09-30 15:16:41\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://p1.277sy.com/2024/11/18/673b03847dad3.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=13\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/13.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=13\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=13\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=13\\\",\\\"gamename\\\":\\\"女神危机(0.1折原味女神)\\\",\\\"excerpt\\\":\\\"《女神危机》是一款融合卡牌、养成、互动，以解救小姐姐为主题的潮酷手游！优美立绘，真实互动、福利声优、精美时装！高度还原立绘的Live2D互动和战斗，杜绝一动起来就变“大头娃娃”的尴尬！故事以幻想都市为背景，讲述被召唤进次元世界的男主在这座城市面临堕落的危机边缘，摧毁维兰德公司的阴谋计划，拯救被害异能少女的奇幻之旅。原罪初醒，女神降临，你会是那个天命之子么?\\\",\\\"id\\\":13,\\\"game_source\\\":\\\"\\\",\\\"device_type\\\":2,\\\"edition\\\":1,\\\"pic_xuanchuan\\\":\\\"\\\",\\\"strict\\\":0,\\\"u', '{\"msg\":\"操作成功\",\"code\":200,\"data\":424}', 0, NULL, '2025-12-26 08:42:44', 53);
INSERT INTO `sys_oper_log` VALUES (1282, '游戏管理', 1, 'com.ruoyi.web.controller.gamebox.GbGameController.add()', 'POST', 1, 'admin', '研发部门', '/gamebox/game', '127.0.0.1', '内网IP', '{\"androidUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=23\",\"apkUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=23\",\"category\":\"放置\",\"coverUrl\":\"https://www.u2game99.com/data/upload/game/20251224/694b8719d57d7.jpg\",\"createBy\":\"admin\",\"createTime\":\"2025-12-26 08:42:43\",\"description\":\"《上古修仙0.1》是一款以收集养成各类神将，渡劫修仙百变外观，超爽3D打击感的RPG修仙类H5游戏，突破了传统仙侠的宠物模式，你可以在骑乘酷炫坐骑遨游三界的同时，收服上百个神将统统纳为己用。任意搭配最强的出战神将组合，配合神级灵将变身，天上地下，唯你独尊！\\r\\n\\r\\n一款2.5D修仙为背景的RPG手机游戏。游戏中玩家将扮演一名修仙者在各位神将的帮助下闯过各种关卡，玩家可以通过挑战BOSS、试炼获取装备，不断提升自身实力，最终成为一个逍遥自在的仙尊。\\r\\n\\r\\n游戏为修仙题材，在一个修仙的世界，主角为了自己能成为无拘无束的仙，不受世俗的束缚，踏上修仙之路，一路修行，只为成为独一无二的仙，剧情在一处神秘的上古遗迹开启，主角为了提升修为进入上古遗迹寻求机缘开始。\",\"deviceSupport\":\"both\",\"downloadCount\":0,\"downloadUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=23\",\"gameType\":\"discount\",\"hasLowDeductCoupon\":\"0\",\"hasSupport\":\"0\",\"iconUrl\":\"https://www.u2game99.com/data/upload/game/20251224/694b87111ab0f.gif\",\"id\":421,\"iosUrl\":\"https://qd.u2game99.com/down.html?ag=GMS123&gid=23\",\"isHot\":\"0\",\"isNew\":\"0\",\"isRecommend\":\"0\",\"launchTime\":\"2024-09-30 15:35:25\",\"name\":\"上古修仙（0.1折封神归来）\",\"params\":{},\"remark\":\"[导入源数据] {\\\"h5url\\\":\\\"\\\",\\\"h5\\\":0,\\\"welfare\\\":\\\"0.1折一路斩仙，神将集结问鼎仙尊\\\",\\\"interchangeable_role\\\":1,\\\"video\\\":\\\"https://mp4.277sy.com/sp/11350.mp4\\\",\\\"text_cps\\\":\\\"\\\",\\\"new\\\":0,\\\"yuyue\\\":0,\\\"gametype\\\":\\\"放置\\\",\\\"addtime\\\":\\\"2024-09-30 15:35:25\\\",\\\"gn_extension\\\":1,\\\"hw_extension\\\":1,\\\"cps_cpa\\\":\\\"CPS推广:60\\\",\\\"hw_cps_cpa\\\":\\\"CPS海外推广:40\\\",\\\"coupon_repeat\\\":\\\"\\\",\\\"pic1\\\":\\\"https://www.u2game99.com/data/upload/game/20251224/694b87111ab0f.gif\\\",\\\"version\\\":0,\\\"c_version\\\":0,\\\"downurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=23\\\",\\\"qrcode\\\":\\\"[base64已省略]\\\",\\\"weburl\\\":\\\"https://www.u2game99.com/wg/1037/23.html\\\",\\\"weburl_qr\\\":\\\"[base64已省略]\\\",\\\"dwzdownurl\\\":\\\"https://qd.u2game99.com/down.html?ag=GMS123&gid=23\\\",\\\"downurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=23\\\",\\\"dwzdownurlmash\\\":\\\"https://qd.u2game99.com/down.html?mash=TbZIVBOR&gid=23\\\",\\\"gamename\\\":\\\"上古修仙（0.1折封神归来）\\\",\\\"excerpt\\\":\\\"《上古', '{\"msg\":\"操作成功\",\"code\":200,\"data\":421}', 0, NULL, '2025-12-26 08:42:44', 79);
